/** Mini grid example for rules slides */
function RulesMiniGrid({ grid, slideColor, eurovisionMode }: { grid: NonNullable<RulesSlide['grid']>; slideColor: string; eurovisionMode?: boolean }) {
  const rows = grid.cells.length;
  const cols = grid.cells[0].length;
  const cellSz = Math.min(84, Math.floor(340 / Math.max(rows, cols)));
  const gap = 5;
  return (
    <div style={{
      display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 10,
      animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.35s both',
    }}>
      <div style={{
        display: 'grid',
        gridTemplateColumns: `repeat(${cols}, ${cellSz}px)`,
        gridTemplateRows: `repeat(${rows}, ${cellSz}px)`,
        gap,
      }}>
        {grid.cells.flatMap((row, r) => row.map((cell, c) => {
          const isTeamA = cell === 'A';
          const isStar = cell === '⭐';
          const isPin = cell === '🏯';
          const filled = isTeamA || isStar || isPin;
          const bg = isStar
            ? `linear-gradient(135deg, ${grid.colorA}cc, #EC4899cc)`
            : isPin
              ? `linear-gradient(135deg, ${grid.colorA}cc, #10B981cc)`
              : isTeamA
                ? `${grid.colorA}aa`
                : 'rgba(255,255,255,0.06)';
          // 2026-05-09 (Wolf-Wunsch): Joker-Cells nutzen die echten Joker-PNGs
          // (boy/girl alternierend per row+col-index) statt 🃏-Emoji + Wiggle-
          // Animation für „der Joker leuchtet auf, wenn das Pattern gebildet ist".
          const inDelay = 0.3 + (r * cols + c) * 0.06;
          const jokerVariantIndex = r + c;
          return (
            <div key={`${r}-${c}`} style={{
              width: cellSz, height: cellSz,
              borderRadius: Math.max(4, cellSz * 0.18),
              background: bg,
              border: filled ? `2px solid ${isStar ? '#EC4899' : isPin ? '#10B981' : grid.colorA}` : '1px solid rgba(255,255,255,0.08)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: cellSz * 0.5,
              boxShadow: filled ? `0 0 12px ${isStar ? '#EC489988' : isPin ? '#10B98144' : grid.colorA + '44'}` : 'none',
              animation: filled
                ? isStar
                  // Joker: erst rein-fade, dann wiggle-Pulse infinite
                  ? `gridCellIn 0.4s ease ${inDelay}s both, qqJokerWiggle 2.4s ease-in-out ${inDelay + 0.5}s infinite`
                  : `gridCellIn 0.4s ease ${inDelay}s both`
                : undefined,
              overflow: 'hidden',
            }}>
              {isStar
                ? <JokerIcon
                    i={jokerVariantIndex}
                    size={Math.floor(cellSz * 0.85)}
                    eurovisionMode={!!eurovisionMode}
                    alt=""
                  />
                : isPin
                  ? <QQEmojiIcon emoji="🏯"/>
                  : ''}
            </div>
          );
        }))}
      </div>
      {grid.label && (
        <div style={{
          fontSize: 'clamp(18px,2.2vw,30px)', fontWeight: 900,
          color: slideColor, letterSpacing: '0.04em',
        }}>{grid.label}</div>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// AnimatedCozyWolf — Multi-Mode-Wolf-Animation.
//
// Modi:
//   speaking — Original-Verhalten: Idle-Blink + Mund-Flap waehrend speaking=true.
//              4 Base-Posen (augen[auf|zu].mund[auf|zu]).
//   winken   — Idle Pre-Game-Mode: alterniert zwischen wachem Winken (augenauf+
//              mundauf+winken) und kurzem Augen-zu-Moment (augenzu+mundzu+
//              winken). ~700ms-Cycle, gelegentlich pausiert.
//   jubel    — Jubelnder Wolf: cycelt durch 3 Jubel-Posen (mund-zu, mund-auf-jubel,
//              eyes-zu+jubel). Wirkt wie 'YEAH!'.
//   trinken  — Pause-Mode-Wolf: ueberwiegend trinken-pose (augenauf+mundzu+
//              trinken), gelegentlicher Sip-Blink (augenzu+mundzu+trinken).
//   schlafen — Pause-Mode-Wolf-Variante: cycelt durch 3 Z-Stufen (1z→2z→3z),
//              ~900ms pro Stufe. Wirkt wie 'leise schnarchen'.
//
// 2026-05-06 (Wolf 'noch mehr Wolf-Varianten + erstmal nur fuer pause und
// lobby'): mode prop hinzugefuegt mit Default 'speaking' fuer Backwards-Compat.
// Alle relevanten PNGs einer Mode werden ueberlagert vorgeladen, opacity-Switch
// haelt das Flackern aus.
// ─────────────────────────────────────────────────────────────────────────────
type WolfMode = 'speaking' | 'winken' | 'jubel' | 'trinken' | 'schlafen' | 'ueberrascht' | 'daumen' | 'flagge' | 'troete';

function AnimatedCozyWolf({ widthCss, speaking, mode, wink, mirror, troeteBoost }: {
  widthCss: string; speaking?: boolean; mode?: WolfMode; wink?: boolean; mirror?: boolean;
  /**
   * 2026-05-07 (Wolf 'troete in eurovision edition mehr einbauen'): wenn true,
   * feuert die Troete-Pose im jubel-Mode haeufiger (alle 2.5-4s statt 6-10s)
   * und bleibt laenger sichtbar (1800ms statt 1200ms). Nur sinnvoll im
   * jubel-Mode — andere Modi ignorieren das.
   */
  troeteBoost?: boolean;
}) {
  // Default-Mode: 'speaking' (alte API). Wenn mode gesetzt, ignoriert speaking-Prop
  // (Ausnahme: winken/jubel/daumen-Modes lesen speaking als externes Mund-Flap-Gate).
  const effectiveMode: WolfMode = mode ?? 'speaking';

  // 2026-05-06 v4 (Wolf 'kannst du den Mund so bewegen, als wuerde er das
  // wirklich sagen — gutes Timing'): speaking als externer Gate fuer winken.
  // Wenn der Parent `speaking` setzt, lippen-flap nur waehrend speaking=true,
  // synchron zur Sprechblase. Ref-Pattern, damit der einmal gestartete Tick-
  // Loop nicht bei jedem speaking-Toggle neu aufgesetzt werden muss (sonst
  // verlieren wir die Blink-Schedule).
  const speakingRef = useRef<boolean | undefined>(speaking);
  useEffect(() => { speakingRef.current = speaking; }, [speaking]);

  // 2026-05-07 (Wolf 'zwinkern wenn ein team reinkommt'): wink-Gate fuer
  // daumen-Mode. Wenn true, augen sind augenzwinkern statt augenauf.
  const winkRef = useRef<boolean | undefined>(wink);
  useEffect(() => { winkRef.current = wink; }, [wink]);

  // Aktuell sichtbares PNG (Filename ohne .png). State pro Mode.
  const [currentFile, setCurrentFile] = useState<string>('augenauf.mundzu');

  // ── speaking-Mode ──────────────────────────────────────────────────────
  const [eyesOpen, setEyesOpen] = useState(true);
  const [mouthOpen, setMouthOpen] = useState(false);

  useEffect(() => {
    if (effectiveMode !== 'speaking') return;
    let alive = true;
    let timer: number | undefined;
    const scheduleBlink = () => {
      timer = window.setTimeout(() => {
        if (!alive) return;
        setEyesOpen(false);
        timer = window.setTimeout(() => {
          if (!alive) return;
          setEyesOpen(true);
          scheduleBlink();
        }, 130);
      }, 3000 + Math.random() * 2200);
    };
    scheduleBlink();
    return () => { alive = false; if (timer) window.clearTimeout(timer); };
  }, [effectiveMode]);

  useEffect(() => {
    if (effectiveMode !== 'speaking' || !speaking) { setMouthOpen(false); return; }
    let alive = true;
    let timer: number | undefined;
    let phase: 'speak' | 'pause' = 'speak';
    let phaseUntil = Date.now() + 2200 + Math.random() * 1200;
    const tick = () => {
      if (!alive) return;
      const now = Date.now();
      if (now >= phaseUntil) {
        if (phase === 'speak') {
          phase = 'pause';
          setMouthOpen(false);
          phaseUntil = now + 1100 + Math.random() * 900;
          timer = window.setTimeout(tick, phaseUntil - now);
          return;
        } else {
          phase = 'speak';
          phaseUntil = now + 2000 + Math.random() * 1500;
        }
      }
      if (phase === 'speak') {
        setMouthOpen(m => !m);
        timer = window.setTimeout(tick, 200 + Math.random() * 80);
      } else {
        timer = window.setTimeout(tick, 200);
      }
    };
    tick();
    return () => { alive = false; if (timer) window.clearTimeout(timer); };
  }, [effectiveMode, speaking]);

  // ── Mode-spezifischer Cycle (winken/jubel/trinken/schlafen) ────────────
  useEffect(() => {
    if (effectiveMode === 'speaking') return;
    let alive = true;
    let timer: number | undefined;

    if (effectiveMode === 'winken') {
      // 2026-05-06 v3 (Wolf 'jetzt gerade blinkt der Wolf'): konstanter
      // 200ms-Mund-Flap mit Snap-Cut sah aus als wuerde der ganze Wolf
      // flackern. Jetzt analog zur Speaking-Logic: Speak-Phase mit Mund-
      // Flap (2-3s), dann Pause-Phase mit Mund zu (1-2s). Der Wolf wirkt
      // dadurch ruhiger — winkt + 'sagt' was, dann Atempause.
      // Idle-Blink scheduled deterministisch alle 3.5-5.5s, NICHT random
      // pro tick (sonst Doppel-Trigger).
      // 2026-05-06 v4 (Wolf 'gutes Timing'): Wenn parent `speaking` als
      // Prop steckt, ueberschreibt das die interne Speak-Pause-Phase —
      // Mund-Flap synchron zur Sprechblase, Pause sobald Sprechblase fadet.
      let mouthOpenLocal = false;
      let phase: 'speak' | 'pause' = 'speak';
      let phaseUntil = Date.now() + 2200 + Math.random() * 1200;
      let nextBlinkAt = Date.now() + 3500 + Math.random() * 2000;
      let blinkUntil = 0;
      const tick = () => {
        if (!alive) return;
        const now = Date.now();
        // Blink hat Vorrang
        if (now < blinkUntil) {
          setCurrentFile('augenzu.mundzu.winken');
          timer = window.setTimeout(tick, blinkUntil - now);
          return;
        }
        // Blink-Trigger faellig?
        if (now >= nextBlinkAt) {
          blinkUntil = now + 130;
          nextBlinkAt = now + 130 + 3500 + Math.random() * 2000;
          setCurrentFile('augenzu.mundzu.winken');
          timer = window.setTimeout(tick, 130);
          return;
        }
        // External speaking-Gate (Parent-controlled) hat Vorrang vor interner
        // Speak-Pause-Phase, falls speakingRef definiert.
        const externalSpeak = speakingRef.current;
        const isSpeaking = externalSpeak !== undefined
          ? externalSpeak
          : (() => {
              if (now >= phaseUntil) {
                if (phase === 'speak') {
                  phase = 'pause';
                  phaseUntil = now + 1200 + Math.random() * 900;
                } else {
                  phase = 'speak';
                  phaseUntil = now + 2000 + Math.random() * 1500;
                }
              }
              return phase === 'speak';
            })();
        if (isSpeaking) {
          mouthOpenLocal = !mouthOpenLocal;
          setCurrentFile(mouthOpenLocal ? 'augenauf.mundauf.winken' : 'augenauf.mundzu.winken');
          timer = window.setTimeout(tick, 220 + Math.random() * 100);
        } else {
          // pause: mund bleibt zu
          mouthOpenLocal = false;
          setCurrentFile('augenauf.mundzu.winken');
          timer = window.setTimeout(tick, 250);
        }
      };
      tick();
    } else if (effectiveMode === 'jubel') {
      // 2026-05-06 v3 (Wolf neue 4. Pose augenzu.mundauf.jubel geliefert):
      // Jetzt 4 Jubel-Posen → Mund-Flap-Loop wie im Winken-Mode mit Speak-
      // Pause-Phasen + Idle-Blink. Wolf jubelt mit Howl, schliesst gelegent-
      // lich die Augen (joyful squint), atmet kurz durch.
      // 2026-05-06 v6 (Wolf 'wenn er den Mund bewegt, soll er was sagen'):
      // Externes speaking-Gate analog winken — Mund-Flap synchron zur
      // Sprechblase im GameOver.
      // 2026-05-06 v7 (Wolf neue Posen 'troete im mund' + 'augenzwinkern'):
      //  - Troete-Burst: alle ~6-10s 400ms 'augenauf.troete.jubel' = Party-
      //    Horn-Tooot-Moment, ueberschreibt allen anderen State.
      //  - Zwinker statt Blink (35% Chance, nur wenn Mund offen): zeigt
      //    'augenzwinker.mundauf.jubel' statt regulaerem augenzu-Blink.
      let mouthOpenLocal = false;
      let phase: 'speak' | 'pause' = 'speak';
      let phaseUntil = Date.now() + 1800 + Math.random() * 1000;
      let nextBlinkAt = Date.now() + 2500 + Math.random() * 1500;
      let blinkUntil = 0;
      let blinkIsZwinker = false;
      // 2026-05-07 v2 (Wolf 'troete in eurovision edition mehr einbauen'):
      // Mit troeteBoost-Prop feuert die Troete im 2.5-4s-Cycle (statt 6-10s)
      // und bleibt 1800ms (statt 1200ms). Erste Troete kommt nach ~1.5s damit
      // der Sieger-Wolf direkt mit Toot startet.
      const TROETE_DUR_MS = troeteBoost ? 1800 : 1200;
      const troeteCycleBaseMs = troeteBoost ? 2500 : 6000;
      const troeteCycleJitterMs = troeteBoost ? 1500 : 4000;
      let nextTroeteAt = Date.now() + (troeteBoost ? 1500 : 4000) + Math.random() * (troeteBoost ? 1000 : 4000);
      let troeteUntil = 0;
      const tick = () => {
        if (!alive) return;
        const now = Date.now();
        // Troete hat absoluten Vorrang
        if (now < troeteUntil) {
          setCurrentFile('augenauf.troete.jubel');
          timer = window.setTimeout(tick, troeteUntil - now);
          return;
        }
        if (now >= nextTroeteAt) {
          troeteUntil = now + TROETE_DUR_MS;
          nextTroeteAt = now + TROETE_DUR_MS + troeteCycleBaseMs + Math.random() * troeteCycleJitterMs;
          setCurrentFile('augenauf.troete.jubel');
          timer = window.setTimeout(tick, TROETE_DUR_MS);
          return;
        }
        if (now < blinkUntil) {
          setCurrentFile(blinkIsZwinker
            ? 'augenzwinker.mundauf.jubel'
            : (mouthOpenLocal ? 'augenzu.mundauf.jubel' : 'augenzu.mundzu.jubel'));
          timer = window.setTimeout(tick, blinkUntil - now);
          return;
        }
        if (now >= nextBlinkAt) {
          blinkUntil = now + 200;
          // Zwinker nur wenn Mund offen (Pose ist mundauf)
          blinkIsZwinker = mouthOpenLocal && Math.random() < 0.35;
          nextBlinkAt = now + 200 + 2500 + Math.random() * 1500;
          setCurrentFile(blinkIsZwinker
            ? 'augenzwinker.mundauf.jubel'
            : (mouthOpenLocal ? 'augenzu.mundauf.jubel' : 'augenzu.mundzu.jubel'));
          timer = window.setTimeout(tick, 200);
          return;
        }
        const externalSpeak = speakingRef.current;
        const isSpeaking = externalSpeak !== undefined
          ? externalSpeak
          : (() => {
              if (now >= phaseUntil) {
                if (phase === 'speak') {
                  phase = 'pause';
                  phaseUntil = now + 700 + Math.random() * 600;
                } else {
                  phase = 'speak';
                  phaseUntil = now + 1800 + Math.random() * 1000;
                }
              }
              return phase === 'speak';
            })();
        if (isSpeaking) {
          mouthOpenLocal = !mouthOpenLocal;
          setCurrentFile(mouthOpenLocal ? 'augenauf.mundauf.jubel' : 'augenauf.mundzu.jubel');
          timer = window.setTimeout(tick, 200 + Math.random() * 80);
        } else {
          mouthOpenLocal = false;
          setCurrentFile('augenauf.mundzu.jubel');
          timer = window.setTimeout(tick, 250);
        }
      };
      tick();
    } else if (effectiveMode === 'trinken') {
      // Mostly open-eye trinken, gelegentlicher Sip-Blink (eyes-zu)
      let idx = 0; // 0 = open, 1 = closed
      const tick = () => {
        if (!alive) return;
        if (idx === 0) {
          setCurrentFile('augenauf.mundzu.trinken');
          timer = window.setTimeout(() => { idx = 1; tick(); }, 2200 + Math.random() * 1500);
        } else {
          setCurrentFile('augenzu.mundzu.trinken');
          timer = window.setTimeout(() => { idx = 0; tick(); }, 280 + Math.random() * 220);
        }
      };
      tick();
    } else if (effectiveMode === 'schlafen') {
      // Z-Cycle: 1z → 2z → 3z → 1z (wie Z-Animation)
      const seq = ['augenzu.mundzu.schlafen1z', 'augenzu.mundzu.schlafen2z', 'augenzu.mundzu.schlafen3z'];
      let idx = 0;
      const tick = () => {
        if (!alive) return;
        setCurrentFile(seq[idx]);
        timer = window.setTimeout(() => {
          idx = (idx + 1) % seq.length;
          tick();
        }, 900);
      };
      tick();
    } else if (effectiveMode === 'ueberrascht') {
      // 'Oh!' — alterniert zwischen zwei Gestik-Phasen mit gelegentlichen
      // Blinks. Phase 'mund' = klassisches mundueberrascht (offener Schock-
      // Mund). Phase 'haende' = haendeueberrascht (Haende vor der Brust
      // verschraenkt, leicht gespannt-laechelnd). 2026-05-06 v8 (Wolf neue
      // Posen 'haende ueberrascht' geliefert): Dadurch kein statisches
      // 'Mund offen'-Frieren mehr, der Wolf 'reagiert' lebendiger.
      let phase: 'mund' | 'haende' = 'mund';
      let phaseUntil = Date.now() + 2200 + Math.random() * 1000;
      let nextBlinkAt = Date.now() + 2800 + Math.random() * 1500;
      let blinkUntil = 0;
      const tick = () => {
        if (!alive) return;
        const now = Date.now();
        const fileFor = (eyes: 'auf' | 'zu') => phase === 'mund'
          ? `augen${eyes}.mundueberrascht`
          : `augen${eyes}.haendeueberrascht`;
        if (now < blinkUntil) {
          setCurrentFile(fileFor('zu'));
          timer = window.setTimeout(tick, blinkUntil - now);
          return;
        }
        if (now >= nextBlinkAt) {
          blinkUntil = now + 200;
          nextBlinkAt = now + 200 + 2800 + Math.random() * 1500;
          setCurrentFile(fileFor('zu'));
          timer = window.setTimeout(tick, 200);
          return;
        }
        if (now >= phaseUntil) {
          phase = phase === 'mund' ? 'haende' : 'mund';
          phaseUntil = now + 2200 + Math.random() * 1000;
        }
        setCurrentFile(fileFor('auf'));
        timer = window.setTimeout(tick, 250);
      };
      tick();
    } else if (effectiveMode === 'daumen') {
      // 2026-05-07 (Wolf 'daumen Posen fuer QR-Code-Seite, zwinkern wenn ein
      // team reinkommt'): Daumen-hoch-Mode analog winken — Mund-Flap synchron
      // zur Sprechblase via speakingRef, regulaere Idle-Blinks. Wenn winkRef
      // true ist, wechselt der Wolf auf augenzwinker-Variante (1 Auge zu) →
      // 'Hallo!'-Reaktion auf Team-Joins. Idle-Blink wird waehrend wink-Phase
      // ausgesetzt (zwinker IST schon ein Halb-Blink).
      let mouthOpenLocal = false;
      let phase: 'speak' | 'pause' = 'speak';
      let phaseUntil = Date.now() + 2200 + Math.random() * 1200;
      let nextBlinkAt = Date.now() + 3500 + Math.random() * 2000;
      let blinkUntil = 0;
      const tick = () => {
        if (!alive) return;
        const now = Date.now();
        const winking = winkRef.current === true;
        const eyePrefix = winking ? 'augenzwinker' : 'augenauf';
        // Idle-Blink hat Vorrang — aber nur wenn NICHT zwinkern (sonst doppel)
        if (!winking && now < blinkUntil) {
          setCurrentFile('augenzu.mundzu.daumen');
          timer = window.setTimeout(tick, blinkUntil - now);
          return;
        }
        if (!winking && now >= nextBlinkAt) {
          blinkUntil = now + 130;
          nextBlinkAt = now + 130 + 3500 + Math.random() * 2000;
          setCurrentFile('augenzu.mundzu.daumen');
          timer = window.setTimeout(tick, 130);
          return;
        }
        // External speaking-Gate (Parent-controlled) hat Vorrang vor interner
        // Speak-Pause-Phase, falls speakingRef definiert.
        const externalSpeak = speakingRef.current;
        const isSpeaking = externalSpeak !== undefined
          ? externalSpeak
          : (() => {
              if (now >= phaseUntil) {
                if (phase === 'speak') {
                  phase = 'pause';
                  phaseUntil = now + 1200 + Math.random() * 900;
                } else {
                  phase = 'speak';
                  phaseUntil = now + 2000 + Math.random() * 1500;
                }
              }
              return phase === 'speak';
            })();
        if (isSpeaking) {
          mouthOpenLocal = !mouthOpenLocal;
          setCurrentFile(`${eyePrefix}.${mouthOpenLocal ? 'mundauf' : 'mundzu'}.daumen`);
          timer = window.setTimeout(tick, 220 + Math.random() * 100);
        } else {
          mouthOpenLocal = false;
          setCurrentFile(`${eyePrefix}.mundzu.daumen`);
          timer = window.setTimeout(tick, 250);
        }
      };
      tick();
    } else if (effectiveMode === 'troete') {
      // 2026-05-09 v8 (Wolf 'nur Tröte im Mund mit Augen auf und zu'):
      // Konstante Tröte-Pose, periodische Blinks. Da kein augenzu.troete-Asset
      // existiert, nutzt Blink-Frame augenzu.mundzu.jubel (130ms = quick blink,
      // Tröte fehlt nur kurz). Idle-Blink alle 2.5-4s.
      let nextBlinkAt = Date.now() + 2500 + Math.random() * 1500;
      let blinkUntil = 0;
      const tick = () => {
        if (!alive) return;
        const now = Date.now();
        if (now < blinkUntil) {
          setCurrentFile('augenzu.mundzu.jubel');
          timer = window.setTimeout(tick, blinkUntil - now);
          return;
        }
        if (now >= nextBlinkAt) {
          blinkUntil = now + 130;
          nextBlinkAt = now + 130 + 2500 + Math.random() * 1500;
          setCurrentFile('augenzu.mundzu.jubel');
          timer = window.setTimeout(tick, 130);
          return;
        }
        setCurrentFile('augenauf.troete.jubel');
        timer = window.setTimeout(tick, 250);
      };
      tick();
    } else if (effectiveMode === 'flagge') {
      // 2026-05-07 (Wolf-ESC): Eurovision-Variante des winken-Modes — Wolf
      // haelt eine EU-Flagge in der Hand statt zu winken. Logik 1:1 wie
      // winken: Speak/Pause-Phase mit Mund-Flap, Idle-Blink alle 3.5-5.5s.
      // Externes speaking-Gate respektiert (synchron zur Sprechblase).
      let mouthOpenLocal = false;
      let phase: 'speak' | 'pause' = 'speak';
      let phaseUntil = Date.now() + 2200 + Math.random() * 1200;
      let nextBlinkAt = Date.now() + 3500 + Math.random() * 2000;
      let blinkUntil = 0;
      const tick = () => {
        if (!alive) return;
        const now = Date.now();
        if (now < blinkUntil) {
          setCurrentFile('augenzu.mundzu.flagge');
          timer = window.setTimeout(tick, blinkUntil - now);
          return;
        }
        if (now >= nextBlinkAt) {
          blinkUntil = now + 130;
          nextBlinkAt = now + 130 + 3500 + Math.random() * 2000;
          setCurrentFile('augenzu.mundzu.flagge');
          timer = window.setTimeout(tick, 130);
          return;
        }
        const externalSpeak = speakingRef.current;
        const isSpeaking = externalSpeak !== undefined
          ? externalSpeak
          : (() => {
              if (now >= phaseUntil) {
                if (phase === 'speak') {
                  phase = 'pause';
                  phaseUntil = now + 1200 + Math.random() * 900;
                } else {
                  phase = 'speak';
                  phaseUntil = now + 2000 + Math.random() * 1500;
                }
              }
              return phase === 'speak';
            })();
        if (isSpeaking) {
          mouthOpenLocal = !mouthOpenLocal;
          setCurrentFile(mouthOpenLocal ? 'augenauf.mundauf.flagge' : 'augenauf.mundzu.flagge');
          timer = window.setTimeout(tick, 220 + Math.random() * 100);
        } else {
          mouthOpenLocal = false;
          setCurrentFile('augenauf.mundzu.flagge');
          timer = window.setTimeout(tick, 250);
        }
      };
      tick();
    }

    return () => { alive = false; if (timer) window.clearTimeout(timer); };
  }, [effectiveMode, troeteBoost]);

  // Welche Datei ist im speaking-Mode sichtbar
  const speakingFile = `augen${eyesOpen ? 'auf' : 'zu'}.mund${mouthOpen ? 'auf' : 'zu'}`;
  const visibleFile = effectiveMode === 'speaking' ? speakingFile : currentFile;

  // Alle moeglichen Posen (alle PNGs vorgeladen, opacity-toggle).
  // 2026-05-06 v2: augenauf.mundzu.winken (war NICHT in der Liste → Wolf
  // verschwand bei Mund-Flap-Animation), augenzu.mundauf.jubel,
  // augen[auf|zu].mundueberrascht ergaenzt.
  const allPoses: string[] = [
    'augenauf.mundauf', 'augenauf.mundzu',
    'augenzu.mundauf', 'augenzu.mundzu',
    'augenauf.mundauf.winken', 'augenauf.mundzu.winken', 'augenzu.mundzu.winken',
    'augenauf.mundauf.jubel', 'augenauf.mundzu.jubel',
    'augenzu.mundauf.jubel', 'augenzu.mundzu.jubel',
    'augenauf.troete.jubel', 'augenzwinker.mundauf.jubel',
    'augenauf.mundzu.trinken', 'augenzu.mundzu.trinken',
    'augenzu.mundzu.schlafen1z', 'augenzu.mundzu.schlafen2z', 'augenzu.mundzu.schlafen3z',
    'augenauf.mundueberrascht', 'augenzu.mundueberrascht',
    'augenauf.haendeueberrascht', 'augenzu.haendeueberrascht',
    'augenauf.mundauf.daumen', 'augenauf.mundzu.daumen',
    'augenzu.mundauf.daumen', 'augenzu.mundzu.daumen',
    'augenzwinker.mundauf.daumen', 'augenzwinker.mundzu.daumen',
    // 2026-05-07 (Wolf-ESC): Flagge-Posen
    'augenauf.mundauf.flagge', 'augenauf.mundzu.flagge',
    'augenzu.mundauf.flagge', 'augenzu.mundzu.flagge',
  ];

  // Pro Mode nur die relevanten Posen rendern (sparen 60-70% Memory)
  const posesForMode = effectiveMode === 'speaking'
    ? allPoses.slice(0, 4)
    : effectiveMode === 'winken'
      ? allPoses.filter(p => p.includes('winken'))
      : effectiveMode === 'jubel'
        ? allPoses.filter(p => p.includes('jubel'))
        : effectiveMode === 'trinken'
          ? allPoses.filter(p => p.includes('trinken'))
          : effectiveMode === 'schlafen'
            ? allPoses.filter(p => p.includes('schlafen'))
            : effectiveMode === 'daumen'
              ? allPoses.filter(p => p.includes('daumen'))
              : effectiveMode === 'flagge'
                ? allPoses.filter(p => p.includes('flagge'))
                : effectiveMode === 'troete'
                  ? ['augenauf.troete.jubel', 'augenzu.mundzu.jubel']
                  : allPoses.filter(p => p.includes('ueberrascht'));

  return (
    <div style={{
      position: 'relative',
      width: widthCss,
      aspectRatio: '1 / 1',
      transformOrigin: 'bottom center',
      // 2026-05-07 v3 (Wolf 'Wolf flackert immernoch'): mirror direkt am
      // Haupt-Wrapper statt extra-Wrapper drumherum — verhindert Stack-
      // Filter-Glitches beim Mund-Flap.
      transform: mirror ? 'scaleX(-1)' : undefined,
      animation: 'qqIntroWolfBreathe 4.2s ease-in-out infinite',
      // 2026-05-07 v4 (Wolf 'Hintergrund loest Flackern aus wenn Bilder
      // sich abwechseln'): Drop-Shadow-Filter (war yellow halo) hat bei
      // jedem Mund-Flap die Silhouette neu gerechnet → BG-Composite hat
      // dadurch repaintet → sichtbares Flicker durch BG-Animation
      // (Fireflies, Spotlight). Filter raus, Halo wird unten ueber ein
      // ::before-aehnliches absolutes Glow-Element gemacht (statisch,
      // unabhaengig von Bilder-Swap).
      // isolation: isolate erzwingt eigenen Stacking Context → BG hinter
      // dem Wrapper kann nicht mehr durch Image-Swap-Repaint stoeren.
      isolation: 'isolate',
    }}>
      {/* Statischer Halo-Glow hinter dem Wolf — ersetzt das ehemalige
          drop-shadow filter. Aendert sich NICHT mit Frame-Wechsel,
          deshalb kein Flicker mehr. */}
      <div aria-hidden style={{
        position: 'absolute',
        inset: '8% 8% -2% 8%',
        background: 'radial-gradient(ellipse at center 60%, rgba(236,72,153,0.35) 0%, rgba(236,72,153,0.15) 40%, transparent 70%)',
        filter: 'blur(18px)',
        pointerEvents: 'none',
        zIndex: 0,
      }} />
      {/* Pre-Cache: alle Posen mit opacity:0 + width/height 1px gerendert,
          damit Browser sie laedt + decodiert. Verhindert 1-Frame-Flicker
          beim ersten Anzeigen einer noch ungecacheten Pose. Nur einmal
          beim Mount. <picture> sorgt dafuer dass auch die AVIF-Variante
          (die der Browser tatsaechlich anzeigen wird) vor-decodiert wird,
          nicht nur die PNG-Fallback-Datei. */}
      {posesForMode.filter(p => p !== visibleFile).map(p => (
        <CozyWolfImage
          key={p}
          pose={p}
          alt=""
          aria-hidden
          loading="eager"
          decoding="sync"
          style={{
            position: 'absolute', width: 1, height: 1,
            opacity: 0, pointerEvents: 'none',
          }}
        />
      ))}
      {/* Sichtbarer Wolf — nur EIN <picture>-Element, pose wechselt mit visibleFile.
          2026-05-07 v5 (Wolf 'Wolf flackert immernoch — wirkt als kommen
          neue Bilder nicht schnell genug'): vorher 6 gestackte imgs mit
          opacity-Toggle — Browser hatte bei Compositing-Swap gelegentlich
          1-Frame-Luecke wo alle imgs als opacity:0 dargestellt wurden.
          Single-img + src-swap: Browser zeigt das alte Bild bis das neue
          im Cache geladen ist (ist es, weil alle Posen vor-gecached sind),
          dann sofortiger Atomic-Replace ohne Transparent-Frame.
          2026-05-08: <picture>-Wrapper fuer AVIF (-84 %) → WebP → PNG
          Fallback. Browser-Pick passiert atomar bei pose-Aenderung. */}
      <CozyWolfImage
        pose={visibleFile}
        alt=""
        loading="eager"
        decoding="sync"
        style={{
          position: 'absolute', inset: 0,
          width: '100%', height: '100%',
          objectFit: 'contain',
          display: 'block',
          zIndex: 1,
          pointerEvents: 'none',
        }}
      />
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// MuchoOptionsReveal — 2-Akt-Choreografie für MUCHO:
//   Akt 1 (moderator-gesteuert via revealStep): pro Klick poppen die Voter einer
//         nicht-leeren Option rein. Leere Options werden übersprungen — der
//         Backend-Handler „qq:muchoRevealStep" zählt nur Optionen mit ≥1 Voter.
//   Akt 2 (moderator-gesteuert, revealStep = nonEmpty+1): Doppelblink auf die
//         richtige Option → permanent grün + Speedrun-Highlight (⚡ Goldrand).
// ─────────────────────────────────────────────────────────────────────────────
function MuchoOptionsReveal({
  options, optionsEn, correctOptionIndex, optionImages, answers, teams, lang,
  cardBg, timerEndsAt, timerDurationSec, revealStep,
}: {
  options: string[];
  optionsEn?: string[];
  correctOptionIndex?: number;
  optionImages?: Array<QQOptionImage | null | undefined>;
  answers: Array<{ teamId: string; text: string; submittedAt: number }>;
  teams: Array<{ id: string; name: string; avatarId: string; color?: string; emoji?: string }>;
  lang: 'de' | 'en';
  cardBg: string;
  timerEndsAt: number | null;
  timerDurationSec: number;
  revealStep: number;
}) {
  const N = options.length;
  // Nicht-leere Optionen in Reihenfolge (identisch zur Backend-Zählung).
  const nonEmptyOrdered = useMemo(() => {
    const res: number[] = [];
    for (let i = 0; i < N; i++) {
      if (answers.some(a => a.text === String(i))) res.push(i);
    }
    return res;
  }, [answers, N]);
  const akt1Max = nonEmptyOrdered.length;
  const lockStep = akt1Max + 1;
  const locked = revealStep >= lockStep && correctOptionIndex != null && N > 0;
  // Auto-Stagger ab 2026-04-26: Backend springt bei Klick 1 direkt auf akt1Max,
  // Frontend zaehlt intern hoch (auto-Reveal jeder Option im 750ms-Takt) damit
  // die Voter nacheinander einfliegen statt alle gleichzeitig.
  const [autoCap, setAutoCap] = useState(0);
  useEffect(() => {
    if (revealStep <= 0) {
      setAutoCap(0);
      return;
    }
    const target = Math.min(revealStep, akt1Max);
    if (autoCap >= target) return;
    const t = setTimeout(() => setAutoCap(prev => Math.min(prev + 1, target)), 750);
    return () => clearTimeout(t);
  }, [revealStep, autoCap, akt1Max]);
  const shownVoterSet = useMemo(() => {
    const cap = Math.min(autoCap, akt1Max);
    return new Set(nonEmptyOrdered.slice(0, cap));
  }, [autoCap, akt1Max, nonEmptyOrdered]);

  const showLock = locked;
  const akt3On = locked;
  const MUCHO_COLORS = ['#3B82F6', '#EF4444', '#EC4899', '#22C55E'];
  // 2026-05-09 (Wolf): Negative-Squared-Latin-Emojis statt Plain-Text.
  // 2026-05-09 v2 (Wolf): zurück auf Plain Text — Emoji-Version 🅰🅱🅲🅳
  // wurde auf Mac/iPhone als blaue OS-Squares mit weißem Buchstaben gerendert,
  // hat den existing Square-Box-Look doppelt-eingerahmt. Plain-Text in der
  // farbigen Box ist cleaner.
  const muchoLabels = ['A', 'B', 'C', 'D'];

  // Waehrend QUESTION_ACTIVE (revealStep=0): kompaktes Layout, keine Luecken
  // zwischen A/B und C/D. Erst wenn Voter-Avatare einfliegen (revealStep>=1)
  // ziehen die Rows smooth auseinander, damit die Chips Platz unter der Card
  // bekommen ohne die naechste Card zu verdecken.
  const expandedLayout = revealStep >= 1;
  return (
    <div style={{
      display: 'grid',
      gridTemplateColumns: '1fr 1fr',
      columnGap: 18,
      rowGap: expandedLayout ? 'clamp(80px, 10vh, 120px)' : 18,
      // 2026-05-09 (Wolf 'gewinnercard stand unten raus'): paddingBottom
      // hochgezogen damit Voter-Reihe (translateY 80%) + Card-Pop-Scale
      // 1.06 + Time-Pill in der unteren Reihe nicht aus dem Container
      // hängen. 110 → 160 max, 70 → 100 min.
      paddingBottom: expandedLayout ? 'clamp(100px, 12vh, 160px)' : 0,
      marginBottom: 'clamp(14px, 1.8vh, 28px)',
      width: '100%', maxWidth: 1400,
      animation: 'contentReveal 0.35s var(--qq-ease-pop-fast) 0.1s both',
      // 2026-04-30 v2: 0.6s → 0.9s entspanntes Easing — User-Feedback
      // 'cards verschieben sich zu hektisch'. ≥0.45s ist die neue Faustregel.
      transition: 'row-gap 0.9s var(--qq-ease-smooth), padding-bottom 0.9s var(--qq-ease-smooth), margin-bottom 0.9s ease',
    }}>
      {options.map((opt, i) => {
        const optImg = optionImages?.[i];
        const isCorrect = showLock && i === correctOptionIndex;
        const isWrong = showLock && i !== correctOptionIndex;
        const optColor = MUCHO_COLORS[i] ?? '#64748B';
        const optText = lang === 'en' && optionsEn?.[i] ? optionsEn[i] : opt;
        const voterShow = shownVoterSet.has(i);
        // Voter pro Option vorberechnen — wir brauchen sie ausserhalb der Card
        const voters = answers
          .filter(a => a.text === String(i))
          .sort((a, b) => a.submittedAt - b.submittedAt)
          .map(a => {
            const team = teams.find(t => t.id === a.teamId);
            return team ? { team, submittedAt: a.submittedAt } : null;
          })
          .filter((x): x is { team: NonNullable<ReturnType<typeof teams.find>>; submittedAt: number } => !!x);
        const t0 = timerEndsAt && timerDurationSec
          ? timerEndsAt - timerDurationSec * 1000
          : voters[0]?.submittedAt;
        return (
          // 2026-05-07 (Audit P1): MUCHO-Cards gleich-hoch via flex:1+height:100%,
          // analog zu ZvZ. Wrapper bekommt display:flex + height:100%, Inner-Card
          // flex:1 — bei laengeren Optionen (zweizeilig) wachsen alle Cards mit.
          <div key={i} style={{ position: 'relative', display: 'flex', height: '100%' }}>
            <div style={{
              flex: 1,
              position: 'relative', overflow: 'hidden',
              borderRadius: 24, padding: '24px 28px',
              // 2026-05-09 (Wolf 'Mini-Sprung in Reihe wenn Sieger-Card kommt'):
              // Border einheitlich 3px ausgeführt (vorher 2/3/2) + box-sizing
              // border-box, sonst wuchs die korrekte Card 2px höher und alle
              // Cards in derselben Row schoben sich nach. Wrong-Border in
              // Transparent damit visuell nichts da ist, Höhe aber konstant.
              boxSizing: 'border-box',
              background: isCorrect ? 'rgba(34,197,94,0.22)' : cardBg,
              border: isCorrect ? '3px solid #22C55E'
                : isWrong ? '3px solid rgba(255,255,255,0.06)'
                : `3px solid ${optColor}55`,
              boxShadow: isCorrect ? '0 0 44px rgba(34,197,94,0.48), 0 0 90px rgba(34,197,94,0.18)'
                : '0 4px 16px rgba(0,0,0,0.3)',
              display: 'flex', alignItems: 'center', gap: 16,
              transition: 'background 0.25s ease, border-color 0.25s ease, box-shadow 0.25s ease',
              animation: isCorrect
                ? 'revealDoubleBlink 1.1s ease both, revealCorrectPop 0.6s var(--qq-ease-bounce) both'
                : isWrong
                  // 2026-05-04 (Wolf #4): Wrong-Drama — kurzer horizontaler
                  // Shake (0.5s) mit rotem Pulse-Glow, danach revealWrongDim
                  // (1.6s delay matcht Shake-End). Macht Falsch-Tipps spuerbar.
                  ? 'revealWrongShake 0.5s var(--qq-ease-bounce) both, revealWrongDim 0.5s ease 0.55s both'
                  : undefined,
            }}>
              {optImg?.url && (
                <img src={optImg.url} alt="" style={{
                  position: 'absolute', inset: 0, width: '100%', height: '100%',
                  objectFit: optImg.fit ?? 'cover', opacity: optImg.opacity ?? 0.4,
                  pointerEvents: 'none',
                }} />
              )}
              {optImg?.url && (
                <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(90deg, rgba(0,0,0,0.7) 0%, rgba(0,0,0,0.3) 100%)', pointerEvents: 'none' }} />
              )}
              <div style={{
                position: 'relative', zIndex: 1,
                width: 56, height: 56, borderRadius: 16,
                background: isCorrect ? '#22C55E' : isWrong ? '#374151' : optColor,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: isCorrect ? 32 : 28, fontWeight: 900, color: '#fff', flexShrink: 0,
                boxShadow: isCorrect
                  ? '0 0 16px rgba(34,197,94,0.6)'
                  : `0 2px 8px ${optColor}44`,
                transition: 'background 0.3s ease, box-shadow 0.3s ease',
              }}>{muchoLabels[i]}</div>
              <div style={{
                position: 'relative', zIndex: 1,
                flex: 1, minWidth: 0,
                fontSize: 'clamp(26px, 3.2vw, 44px)', fontWeight: 900,
                color: isWrong ? '#475569' : '#F1F5F9', lineHeight: 1.3,
                textShadow: optImg?.url ? '0 2px 8px rgba(0,0,0,0.8)' : 'none',
                transition: 'color 0.3s ease',
              }}>{optText}</div>
            </div>
            {/* Voter-Reihe: haengt unter der Card (Avatare 80% rausragend, nur
                der obere Top-Edge scrapt die Card-Unterkante) damit der
                Antwort-Text nicht verdeckt wird. Zeit-Pill direkt unter dem
                Avatar-Kreis. justifyContent:center damit einzelne Avatare
                unter der Card zentriert stehen. */}
            {voterShow && voters.length > 0 && (
              <div style={{
                position: 'absolute', left: 8, right: 8, bottom: 0,
                transform: 'translateY(80%)',
                display: 'flex', flexWrap: 'wrap', alignItems: 'flex-start',
                justifyContent: 'center',
                gap: voters.length > 4 ? 6 : 10,
                pointerEvents: 'none', zIndex: 5,
              }}>
                {voters.map((v, vi) => {
                  const tm = v.team;
                  const timeSec = t0 ? Math.max(0, (v.submittedAt - t0) / 1000) : null;
                  const isFastest = akt3On && isCorrect && vi === 0;
                  const voterDelay = vi * 0.18;
                  // Viele Voter (>4) = etwas kleinere Avatare, damit sie in eine Reihe passen
                  const many = voters.length > 4;
                  const avatarSz = isFastest
                    ? (many ? 'clamp(56px, 6vw, 80px)' : 'clamp(64px, 7vw, 92px)')
                    : (many ? 'clamp(44px, 4.8vw, 64px)' : 'clamp(52px, 5.6vw, 76px)');
                  // Wrong-Option-Voter: dezent dimmen (Grayscale + Opacity) →
                  // signalisiert visuell „haben falsch geraten".
                  const dim = isWrong;
                  return (
                    <div key={tm.id} style={{
                      position: 'relative',
                      display: 'flex', flexDirection: 'column', alignItems: 'center',
                      animation: `muchoVoterDrop 0.55s cubic-bezier(0.34,1.5,0.64,1) ${voterDelay}s both`,
                      opacity: dim ? 0.55 : 1,
                      filter: dim ? 'grayscale(0.6)' : 'none',
                      transition: 'opacity 0.4s ease, filter 0.4s ease',
                    }}>
                      <div title={tm.name} style={{ position: 'relative', display: 'inline-block' }}>
                        <QQTeamAvatar
                          avatarId={tm.avatarId} teamEmoji={tm.emoji}
                          size={avatarSz}
                          style={{
                            // Kein Doppel-Rand mehr: das Avatar-Artwork hat eh
                            // einen farbigen Kapuzen-/Kreis-Rim. Nur der schnellste
                            // Voter bekommt den Gold-Ring als Winner-Indikator.
                            border: isFastest ? '4px solid #EC4899' : 'none',
                            boxShadow: isFastest
                              ? '0 0 22px rgba(236,72,153,0.6), 0 6px 14px rgba(0,0,0,0.55)'
                              : `0 6px 14px rgba(0,0,0,0.55), 0 0 10px ${tm.color}55`,
                            background: '#0A0814',
                          }}
                        />
                        {/* Zeit-Pill: direkt unter dem Kreis, zentriert, leicht ueberlappend */}
                        {timeSec != null && isCorrect && akt3On && (
                          <span style={{
                            position: 'absolute',
                            left: '50%', bottom: -8,
                            transform: 'translate(-50%, 50%)',
                            padding: '2px 9px', borderRadius: 999,
                            background: isFastest ? 'rgba(236,72,153,0.95)' : 'rgba(15,23,42,0.95)',
                            border: isFastest ? '1.5px solid rgba(236,72,153,1)' : `1.5px solid ${tm.color}`,
                            color: isFastest ? '#0A0814' : '#e2e8f0',
                            fontWeight: 900,
                            fontSize: 'clamp(11px, 1.2vw, 15px)',
                            whiteSpace: 'nowrap',
                            boxShadow: '0 4px 10px rgba(0,0,0,0.5)',
                            lineHeight: 1.1,
                          }}>
                            {timeSec.toFixed(1)}s
                          </span>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// QuizIntroOverlay — epische Begrüßungs-Folie "Willkommen beim BLOCK QUIZ
// / QUARTER QUIZ by cozywolf". Spielt einmal pro Session beim ersten Wechsel
// in RULES-Phase und blendet dann in die Rules-Ansicht über.
// ─────────────────────────────────────────────────────────────────────────────
function QuizIntroOverlay({ language, visible, eurovisionMode, logoUrl, welcomeVideoUrl }: { language: QQLanguage; visible: boolean; eurovisionMode?: boolean; logoUrl?: string; welcomeVideoUrl?: string }) {
  const lang = useLangFlip(language);
  const title = 'CozyQuiz';
  const welcome = lang === 'en' ? 'A WARM WELCOME TO' : 'HERZLICH WILLKOMMEN ZUM';
  const greeting = lang === 'en'
    ? 'Get comfy — here we go!'
    : 'Macht\'s euch bequem – gleich geht\'s los!';
  // 2026-05-07 v6 (Wolf 'video VOR cascade, cascade erst nach video einblenden'):
  // hasIntroVideo = wenn eurovisionMode + welcomeVideoUrl + sichtbar. Solange
  // das Video laeuft (videoEnded=false), wird die komplette Cascade-Stage
  // unterdrueckt. onEnded triggert videoEnded=true, dann fadet Video auf
  // 0.25 BG-Opacity zurueck und Cascade-Animation startet frisch.
  const hasIntroVideo = !!(eurovisionMode && welcomeVideoUrl && visible);
  const [videoEnded, setVideoEnded] = useState(false);
  // Reset wenn Overlay neu angezeigt wird oder Video-URL aendert.
  useEffect(() => {
    if (!hasIntroVideo) { setVideoEnded(true); return; }
    setVideoEnded(false);
    // Safety-Timeout: falls onEnded nie feuert (404, autoplay-block etc.),
    // nach 15s zwangsweise Cascade einblenden.
    const t = window.setTimeout(() => setVideoEnded(true), 15000);
    return () => window.clearTimeout(t);
  }, [hasIntroVideo, welcomeVideoUrl]);
  const cascadeReady = !hasIntroVideo || videoEnded;
  // 2026-05-07 v9 (Wolf 'in der lobby hast du gelb fuer den text? wieso?'):
  // Der Welcome-Cascade hat sein eigenes Farb-Schema in Gold (Subtitle,
  // Goldlinien, Ambient-Glow, Sunrise, Fireflies). Mein Pink-Pass hatte das
  // uebersehen — jetzt im eurovisionMode auf ESC-Pink/Lila gemappt.
  // 2026-05-08 (Aurora-Vivid): Standard-Accent jetzt Brand-Pink (#EC4899)
  // statt Amber-Gold (#EC4899). Eurovision behaelt sein Hot-Pink (#FF2D7B).
  // accentSoft/accentWarm sind Pink-Spektrum statt Gold-Spektrum.
  const accentHex     = eurovisionMode ? '#FF2D7B' : '#EC4899';
  const accentRgb     = eurovisionMode ? '255,45,123' : '236,72,153';
  const accentSoftHex = eurovisionMode ? '#fde6f0' : '#FBCFE8';
  const accentWarmHex = eurovisionMode ? '#C084FC' : '#F9A8D4'; // accent-2 fuer Fireflies-Variation
  // Wolf 2026-05-05 'episch aber professionell': Phasen-Choreographie:
  //   0.0–0.9s  Subtitle „HERZLICH WILLKOMMEN ZUM" letter-cascade aus weitem
  //             letter-spacing zoomt auf normal, gold-glow.
  //   0.9–1.4s  Goldlinie zieht sich von Mitte nach beiden Seiten aus.
  //   1.4–1.6s  Light-Flash ueber den ganzen Screen (gold-warmer Pulse).
  //   1.6–2.4s  „CozyQuiz" letter-by-letter scaleIn von 0.4→1.05→1 mit elastic
  //             bounce, je 0.06s Stagger. Goldglow um Schriftzug pulsiert 1×.
  //   2.4–3.4s  Shimmer-Lichtreflex wandert links→rechts ueber den Title.
  //   3.4–4.4s  Wolf-Avatar swoosht von unten links rein, Sprechblase pop.
  // Background-Atmosphaere (Sterne, Glow) bleibt ueber alles hinweg ruhig + atmend.
  // 2026-05-05 (Animation-Audit #6): waehrend Welcome sichtbar ist, body
  // markieren mit data-cinematic damit andere Ambient-Loops auf der Page
  // pausieren (CSS-Selektor in main.css).
  useEffect(() => {
    if (!visible) return;
    document.body.setAttribute('data-cinematic', 'true');
    return () => { document.body.removeAttribute('data-cinematic'); };
  }, [visible]);
  const fireflies = Array.from({ length: 14 }, (_, i) => ({
    left: 6 + ((i * 37) % 88),
    top: 8 + ((i * 53) % 84),
    dur: 5 + (i % 4) * 0.7,
    delay: (i * 0.4) % 4,
    size: 2.5 + (i % 3) * 1.4,
  }));
  return (
    <BeamerOverlay
      visible={visible}
      zIndex={9990}
      // Wolf 2026-05-05 'sehe da aktuell nichts': Mount-Anim deutlich
      // dramatischer — Folie zoomt aus 1.18 → 1 (war 1.04, kaum sichtbar).
      hiddenScale={1.18}
      background="radial-gradient(ellipse at center, #0f172a 0%, #0a0f1c 55%, #050810 100%)"
    >
      {/* 2026-05-07 (Wolf-ESC 'wie geil waere ein 10sec intro video — video
          ist drin'): Welcome-Video laeuft als BG-Layer hinter allen anderen
          Elementen. autoPlay+muted+playsInline → cross-browser autoplay-
          policy-konform (kein User-Gesture noetig). object-fit: cover damit
          das Video den ganzen Overlay fuellt. Sichtbar nur im eurovisionMode
          + wenn welcomeVideoUrl gesetzt. Hearts/Wordmark/Logo overlay wie
          gewohnt drueber, leichter dunkler Schleier um die Lesbarkeit der
          Letter-Cascade nicht zu verlieren. */}
      {hasIntroVideo && (
        <>
          <video
            key={welcomeVideoUrl}
            src={welcomeVideoUrl}
            autoPlay
            muted
            playsInline
            preload="auto"
            onEnded={() => setVideoEnded(true)}
            style={{
              position: 'absolute', inset: 0,
              width: '100%', height: '100%',
              objectFit: 'cover',
              // 2026-05-07 v7 (Wolf 'video etwas frueher ausfaden — der Vienna-
              // 2026-Text vom Video sieht man noch hinter dem Wordmark'):
              // Post-End-Opacity 0.25 -> 0 (komplett weg) plus schnellere
              // Transition 0.8s -> 0.5s. Cascade hat eh eigene Hearts/Fireflies,
              // braucht keinen Video-BG-Layer.
              opacity: videoEnded ? 0 : 1,
              transition: 'opacity 0.5s ease',
              pointerEvents: 'none',
              zIndex: 0,
            }}
          />
          {/* 2026-05-07 v16 (Wolf 'nimm 3.png als BG nach dem Video — fast
              exakt der gleiche Pink/Blau-Look wie im Video, krasser Continuity-
              Effekt'): nach Video-Ende fadet 3.png ein als BG. Plus Dim-Overlay
              fuer Lesbarkeit der Cascade-Texte. */}
          <div aria-hidden style={{
            position: 'absolute', inset: 0,
            backgroundImage: 'url(/themes/3.png)',
            backgroundSize: 'cover',
            backgroundPosition: 'center',
            backgroundRepeat: 'no-repeat',
            opacity: videoEnded ? 0.7 : 0,
            transition: 'opacity 0.6s ease 0.1s',
            pointerEvents: 'none', zIndex: 0,
          }} />
          {/* Dim-Overlay ueber dem 3.png-BG — duenkelt das Bild leicht ab
              damit Pink-Cascade-Texte gut lesbar bleiben. */}
          <div aria-hidden style={{
            position: 'absolute', inset: 0,
            background: 'radial-gradient(ellipse at center, rgba(5,8,16,0.35) 0%, rgba(5,8,16,0.65) 100%)',
            opacity: videoEnded ? 1 : 0,
            transition: 'opacity 0.5s ease',
            pointerEvents: 'none', zIndex: 0,
          }} />
        </>
      )}
      {/* 2026-05-07 v6: Cascade-Stage erst nachdem das Video zu Ende ist
          (oder wenn kein Video gesetzt). Container re-mounted bei
          cascadeReady-Flip → alle CSS-Animations starten frisch mit ihren
          Delay-Werten. */}
      {cascadeReady && (
      <>
      {/* Cinematic-Focus-In: BG-blur fadet in den ersten 0.7s aus.
          Wirkt wie Kamera die scharfstellt. Wolf 2026-05-05. */}
      <div aria-hidden style={{
        position: 'absolute', inset: 0,
        backdropFilter: 'blur(0px)',
        WebkitBackdropFilter: 'blur(0px)',
        animation: 'qqIntroFocusIn 0.9s cubic-bezier(0.2, 0.7, 0.3, 1) both',
        pointerEvents: 'none', zIndex: 0,
      }} />
      {/* Light-Streifen-Sweep beim Mount — diagonaler Glanz wandert von
          oben-links nach unten-rechts, einmal als Eintritts-Statement. */}
      <div aria-hidden style={{
        position: 'absolute', top: 0, left: '-30%',
        width: '60%', height: '100%',
        background: `linear-gradient(115deg, transparent 35%, rgba(${accentRgb},0.18) 48%, rgba(255,255,255,0.22) 50%, rgba(${accentRgb},0.18) 52%, transparent 65%)`,
        animation: 'qqIntroEntrySweep 1.4s cubic-bezier(0.2, 0.7, 0.3, 1) 0.1s both',
        pointerEvents: 'none', zIndex: 1,
        filter: 'blur(2px)',
      }} />
      {/* Ambient title-glow — wide warm halo behind the title area, atmend. */}
      <div style={{
        position: 'absolute', left: '50%', top: '40%',
        width: '95vmin', height: '55vmin',
        transform: 'translate(-50%, -50%)',
        background: eurovisionMode
          ? 'radial-gradient(ellipse at center, rgba(255,45,123,0.20) 0%, rgba(168,85,247,0.10) 38%, transparent 68%)'
          : 'radial-gradient(ellipse at center, rgba(236,72,153,0.20) 0%, rgba(249,115,22,0.10) 38%, transparent 68%)',
        filter: 'blur(34px)',
        animation: 'qqIntroAmbientPulse 6s ease-in-out infinite',
        pointerEvents: 'none',
      }} />
      {/* 2026-05-06 (Wolf 'reinfliegen ist nice, blitz am ende nicht so —
          cozier machen, sonnenaufgang + lichter-schwarm'):
          (c) Sanfter Sonnenaufgang — radial-gradient pulsiert von Center nach
          aussen, langsamer und weicher als der vorherige Lichtblitz. Wirkt
          wie ein Vorhang der sich hebt, statt Donner.
          Vorher: qqIntroLightFlash 0.9s, 25% peak opacity 1.0 → grell.
          Jetzt: qqIntroSunrise 1.6s, 40% peak opacity 0.7 → warm und ruhig. */}
      <div style={{
        position: 'absolute', inset: 0,
        background: eurovisionMode
          ? 'radial-gradient(ellipse at center, rgba(255,45,123,0.42) 0%, rgba(168,85,247,0.18) 38%, rgba(59,130,246,0.06) 65%, transparent 80%)'
          : 'radial-gradient(ellipse at center, rgba(236,72,153,0.42) 0%, rgba(249,115,22,0.18) 38%, rgba(236,72,153,0.06) 65%, transparent 80%)',
        opacity: 0,
        transformOrigin: 'center',
        animation: 'qqIntroSunrise 1.6s cubic-bezier(0.16, 0.84, 0.44, 1) 1.4s both',
        pointerEvents: 'none', mixBlendMode: 'screen',
      }} />
      {/* (d) Lichter-Schwarm-Burst — alle Fireflies blitzen einmal synchron
          hell auf (kurz nach dem Title-Pop), dann beruhigen sie sich auf den
          normalen Drift-Loop. Wir layern dafuer eine zweite Element-Reihe an
          den gleichen Positionen, die einmal aufflammt und dann verschwindet. */}
      {fireflies.map((f, i) => (
        <div key={`burst-${i}`} aria-hidden style={{
          position: 'absolute',
          left: `${f.left}%`, top: `${f.top}%`,
          width: f.size * 1.8, height: f.size * 1.8, borderRadius: '50%',
          background: i % 3 === 0 ? accentSoftHex : i % 3 === 1 ? accentHex : accentWarmHex,
          boxShadow: `0 0 24px rgba(${accentRgb},0.85), 0 0 6px rgba(255,255,255,0.7)`,
          opacity: 0,
          animation: `qqIntroFireflyBurst 1.4s cubic-bezier(0.2, 0.8, 0.3, 1) ${1.5 + (i % 6) * 0.04}s both`,
          pointerEvents: 'none',
          transform: 'translate(-50%, -50%)',
        }} />
      ))}
      {/* Fireflies (continuous drift) */}
      {fireflies.map((f, i) => (
        <div key={i} style={{
          position: 'absolute',
          left: `${f.left}%`, top: `${f.top}%`,
          width: f.size, height: f.size, borderRadius: '50%',
          background: i % 2 ? accentHex : accentSoftHex,
          boxShadow: `0 0 10px rgba(${accentRgb},0.55), 0 0 2px rgba(255,255,255,0.4)`,
          opacity: 0.65,
          animation: `qqIntroFireflyDrift ${f.dur}s ease-in-out ${f.delay}s infinite`,
          pointerEvents: 'none',
        }} />
      ))}
      {eurovisionMode && <EurovisionHearts />}
      {/* Content-Stack */}
      <div style={{
        position: 'relative', zIndex: 5,
        display: 'flex', flexDirection: 'column', alignItems: 'center',
        gap: 'clamp(14px, 2vh, 28px)',
        textAlign: 'center',
        padding: '0 6vw',
      }}>
        {/* 2026-05-09 (Wolf-Wunsch 'CozyQuiz in eine typische App-Card —
            konsistenter, etwas grösser, schön prominent mittig'): Subtitle +
            Title in einer Pink-Border-Card mit Glow + dark BG + Cross-Hatch-
            Pattern — gleicher Look wie Format-Cards auf /formats und Card-Backs
            in TeamsRevealView. Goldlinien bleiben als Innen-Decorations.
            Card poppt nach dem Sunrise-Light rein (Delay 1.2s). */}
        <div style={{
          position: 'relative',
          padding: 'clamp(28px, 4.5vh, 60px) clamp(36px, 6.5vw, 100px)',
          borderRadius: 'clamp(20px, 2.4vw, 32px)',
          background:
            'radial-gradient(ellipse at 50% 30%, rgba(236,72,153,0.28) 0%, transparent 60%),' +
            'radial-gradient(ellipse at 50% 80%, rgba(162,18,71,0.22) 0%, transparent 55%),' +
            'linear-gradient(135deg, rgba(31,26,46,0.92) 0%, rgba(20,16,31,0.92) 60%, rgba(15,8,23,0.92) 100%)',
          border: `2.5px solid rgba(${accentRgb},0.65)`,
          boxShadow: `0 16px 56px rgba(0,0,0,0.55), 0 0 80px rgba(${accentRgb},0.32), inset 0 0 48px rgba(${accentRgb},0.14)`,
          backdropFilter: 'blur(6px)',
          WebkitBackdropFilter: 'blur(6px)',
          overflow: 'hidden',
          display: 'flex', flexDirection: 'column', alignItems: 'center',
          gap: 'clamp(14px, 2vh, 28px)',
          animation: 'qqIntroWelcomeCard 0.9s cubic-bezier(0.2, 0.85, 0.3, 1) 1.2s both',
          opacity: 0,
        }}>
          {/* Cross-Hatch-Pattern (matcht Card-Back-Look in TeamsReveal) */}
          <div aria-hidden style={{
            position: 'absolute', inset: 0,
            backgroundImage:
              `repeating-linear-gradient(45deg, rgba(${accentRgb},0.05) 0 2px, transparent 2px 22px),` +
              `repeating-linear-gradient(-45deg, rgba(${accentRgb},0.04) 0 2px, transparent 2px 22px)`,
            pointerEvents: 'none',
          }} />

        {/* Subtitle — Letter-Cascade. Jeder Buchstabe erscheint mit eigenem
            stagger 0.04s, fade-in + letter-spacing-zoom (von weit zu normal). */}
        <div style={{
          position: 'relative',
          display: 'inline-flex',
          fontSize: 'clamp(15px, 1.6vw, 24px)', fontWeight: 900,
          letterSpacing: '0.32em', textTransform: 'uppercase',
          color: accentHex,
          opacity: 0.92,
          // 2026-05-07 v12 (Wolf 'kontrast teilweise unleserlich'): zusaetzlich
          // dunkler Halo (rgba(0,0,0,0.55) Drop-Shadow) zur Lesbarkeit auf
          // Pink/Lila-BG. Pink-Glow bleibt fuer Atmosphaere.
          textShadow: `0 1px 6px rgba(0,0,0,0.55), 0 0 28px rgba(${accentRgb},0.55), 0 0 8px rgba(${accentRgb},0.35)`,
        }} aria-label={welcome}>
          {Array.from(welcome).map((ch, i) => (
            <span key={i} style={{
              display: 'inline-block',
              opacity: 0,
              animation: `qqIntroSubLetter 0.55s cubic-bezier(0.2, 0.8, 0.3, 1) ${i * 0.04}s both`,
              whiteSpace: 'pre',
            }}>{ch === ' ' ? ' ' : ch}</span>
          ))}
        </div>

        {/* Title-Block: Goldlinie oben + Letter-Cascade Title + Goldlinie unten */}
        <div style={{
          display: 'flex', flexDirection: 'column', alignItems: 'center',
          gap: 'clamp(10px, 1.4vh, 22px)',
          position: 'relative',
        }}>
          {/* Goldlinie OBEN — zieht sich von Mitte nach außen aus (0.9s delay). */}
          <div style={{
            width: 'clamp(380px, 50vw, 760px)', height: 2, borderRadius: 999,
            background: `linear-gradient(90deg, transparent 0%, rgba(${accentRgb},0.6) 25%, ${accentHex} 50%, rgba(${accentRgb},0.6) 75%, transparent 100%)`,
            backgroundSize: '200% 100%',
            boxShadow: `0 0 14px rgba(${accentRgb},0.55)`,
            transformOrigin: 'center',
            animation: 'qqIntroLineExpand 0.7s cubic-bezier(0.16, 1, 0.3, 1) 0.9s both, qqIntroAccentShimmer 3.5s linear 2.6s infinite',
            opacity: 0,
          }} />

          {/* Title — Letter-Cascade mit elastic ScaleIn pro Buchstabe.
              Stagger 0.06s, scale 0.4 → 1.08 → 1. Whole-screen white text mit
              dichtem Goldglow.
              2026-05-07 v13 (Wolf 'cozyquiz x eurovision songcontest stinger
              eingebaut?'): im ESC-Mode ist der Title jetzt eine horizontale
              Stinger-Row [COZYQUIZ × EUROVISION-LOGO] — alle drei Elemente
              inline-flex children, Letters cascaden weiter, X poppt nach
              Letters, Logo poppt nach X. Gemeinsame baseline ueber
              alignItems:center. */}
          <div
            aria-label={eurovisionMode ? `${title} × Eurovision Song Contest` : title}
            style={{
              display: 'inline-flex',
              alignItems: 'center',
              gap: eurovisionMode ? 'clamp(20px, 2vw, 40px)' : 0,
              // 2026-05-08 (Wolf-Wunsch 'logo text in standard wie eurovision'):
              // Stinger-Look jetzt fuer ALLE Drafts (nicht nur ESC). Wordmark
              // wird in Stinger Fit + Brand-Pink gerendert. Eurovision behaelt
              // zusaetzlich × + ESC-Logo daneben (Stinger-Composition); Standard
              // zeigt nur den Wordmark Solo.
              fontFamily: "'Stinger Fit', 'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif",
              // 2026-05-09 (Wolf 'etwas größer und schön prominent mittig'):
              // Standard-Wordmark von clamp(72px,9vw,158px) auf (82px,10vw,178px)
              // — ~13% größer. Eurovision behält Komposition (X + Logo brauchen
              // Platz daneben).
              fontSize: eurovisionMode ? 'clamp(52px, 7vw, 118px)' : 'clamp(82px, 10vw, 178px)',
              fontWeight: 400,
              letterSpacing: '0.04em',
              lineHeight: 0.96,
              color: eurovisionMode ? accentHex : '#EC4899',
              textShadow: eurovisionMode
                ? `0 0 28px rgba(${accentRgb},0.65), 0 0 72px rgba(${accentRgb},0.28)`
                : '0 0 28px rgba(236,72,153,0.65), 0 0 72px rgba(236,72,153,0.28)',
              position: 'relative', zIndex: 1,
              animation: 'qqIntroTitleSettle 1.1s cubic-bezier(0.16, 1, 0.3, 1) 2.5s both',
              filter: 'drop-shadow(0 6px 30px rgba(0,0,0,0.55))',
            }}
          >
            {/* CozyQuiz-Wordmark als Letter-Cascade-Container.
                2026-05-08: Hover-Float jetzt fuer ALLE Themes — Stinger-Look
                ist Standard-Wordmark, Hover macht ihn lebendig. */}
            <span style={{
              position: 'relative',
              display: 'inline-flex',
              animation: 'qqStingerHover 4.2s ease-in-out 3.4s infinite',
            }}>
              {/* 2026-05-08 (Wolf 'shimmer-effekt wirkt billig'): Sweep-Overlay
                  entfernt. Vorher zog ein weißer Linear-Gradient diagonal
                  über den Wordmark — wirkte wie Cheap-CSS-Sheen-Effekt.
                  Stinger-Hover-Animation auf dem Container reicht für
                  Lebendigkeit. */}
              {Array.from(eurovisionMode ? title.toUpperCase() : title).map((ch, i) => (
                <span key={i} style={{
                  display: 'inline-block',
                  opacity: 0,
                  animation: `qqIntroTitleLetter 0.85s cubic-bezier(0.16, 1.2, 0.3, 1) ${1.6 + i * 0.06}s both`,
                  whiteSpace: 'pre',
                }}>{ch}</span>
              ))}
            </span>
            {/* ESC-Stinger: × in Standard-Nunito-Font (Wolf-Wunsch 'X in
                standard font mit aktueller standard farbe') + Eurovision-
                Logo-Image. Beide popen NACH dem CozyQuiz-Cascade rein. */}
            {eurovisionMode && (
              <>
                {/* 2026-05-07 v15 (Wolf 'X bitte mittig + animieren dass es
                    schimmert'): inline-flex Container fuer perfekt zentriertes
                    X. Doppel-Animation: pop-in @ 2.4s, dann Shimmer-Loop ab
                    3.0s (alle 2.5s pulsiert). */}
                <span aria-hidden style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  // 2026-05-07 v17: line-height + height fest, damit X
                  // perfekt vertikal mittig sitzt zwischen CozyQuiz-Letters
                  // und Logo. lineHeight 1, height 1em fixiert die Box.
                  // 2026-05-07 v19 (Wolf 'jetzt ist das x doch noch weniger
                  // mittig'): top:-0.08em von v18 wieder raus — wirkte falsch
                  // herum/uebertrieben. Stattdessen: COZYQUIZ + Logo geshrinkt
                  // damit × proportional dominanter wirkt und natuerlicher
                  // mittig erscheint (Wolfs eigener Vorschlag).
                  fontFamily: "'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif",
                  fontWeight: 900,
                  fontSize: '0.85em',
                  lineHeight: 1,
                  height: '1em',
                  color: '#fde6f0',
                  opacity: 0,
                  // qqStingerXShine: Tilt + Multi-Layer-Glow-Pulse, 3.5s cycle.
                  animation: 'qqIntroEurovisionPop 0.5s cubic-bezier(0.34, 1.56, 0.64, 1) 2.4s both, qqStingerXShine 3.5s ease-in-out 3.0s infinite',
                  textShadow: '0 2px 10px rgba(0,0,0,0.5)',
                }}>×</span>
                {logoUrl && (
                  /* Wrapper-Span traegt die Hover-Float-Animation; das img selbst
                     den Pop-In + Drop-Shadow. */
                  <span style={{
                    display: 'inline-flex',
                    alignItems: 'center',
                    animation: 'qqStingerHover 4.2s ease-in-out 3.4s infinite',
                  }}>
                    <img
                      src={logoUrl}
                      alt="Eurovision Song Contest"
                      draggable={false}
                      style={{
                        // 2026-05-07 v17 (Wolf 'beide schriftarten etwa
                        // aehnlich gross'): Logo-Bild enthaelt Text +
                        // Padding/Hintergrund — visible-Letter-Height ist
                        // ~50 % der Bild-Hoehe. 1.15em -> 1.7em damit die
                        // 'Eurovision Song Contest'-Buchstaben optisch
                        // gleich gross sind wie 'COZYQUIZ'.
                        height: '1.7em',
                        width: 'auto',
                        filter: 'drop-shadow(0 0 28px rgba(236,72,153,0.6)) drop-shadow(0 6px 18px rgba(0,0,0,0.55))',
                        animation: 'qqIntroEurovisionPop 0.7s cubic-bezier(0.34, 1.56, 0.64, 1) 2.6s both',
                        opacity: 0,
                      }}
                    />
                  </span>
                )}
              </>
            )}
          </div>

          {/* Goldlinie UNTEN — symmetrisch zur oberen, gleiches expand */}
          <div style={{
            width: 'clamp(380px, 50vw, 760px)', height: 2, borderRadius: 999,
            background: `linear-gradient(90deg, transparent 0%, rgba(${accentRgb},0.6) 25%, ${accentHex} 50%, rgba(${accentRgb},0.6) 75%, transparent 100%)`,
            backgroundSize: '200% 100%',
            boxShadow: `0 0 14px rgba(${accentRgb},0.55)`,
            transformOrigin: 'center',
            animation: 'qqIntroLineExpand 0.7s cubic-bezier(0.16, 1, 0.3, 1) 0.95s both, qqIntroAccentShimmer 3.5s linear 2.6s infinite',
            opacity: 0,
          }} />

          {/* 2026-05-07 v13: Eurovision-Logo-Block unter dem Title entfernt —
              ist jetzt INSIDE des Title als Teil des CozyQuiz × Eurovision
              Stingers (siehe oben). Fallback fuer den Fall, dass logoUrl
              fehlt: kompakte Text-Pille auch im Stinger-Stil rendern. */}
          {eurovisionMode && !logoUrl && (
            <div style={{
              marginTop: 'clamp(8px, 1.4vh, 20px)',
              padding: '8px 28px', borderRadius: 999,
              background: 'linear-gradient(135deg, rgba(236,72,153,0.32), rgba(168,85,247,0.24))',
              border: '2px solid rgba(236,72,153,0.65)',
              fontSize: 'clamp(16px, 1.7vw, 24px)', fontWeight: 900,
              color: '#fde68a', letterSpacing: '0.22em', textTransform: 'uppercase',
              boxShadow: '0 0 30px rgba(236,72,153,0.45), 0 4px 14px rgba(0,0,0,0.4)',
              animation: 'qqIntroEurovisionPop 0.7s cubic-bezier(0.34, 1.56, 0.64, 1) 2.6s both',
              opacity: 0,
            }}>
              🎤 Eurovision Edition
            </div>
          )}
        </div>
        </div>{/* /Welcome-App-Card */}

        {/* Wolf + Sprechblase — kommen erst NACH dem Title-Pop rein.
            2026-05-08 (Wolf 'wirkt eher öde'): Wolf+Sprechblase früher (2.6s
            statt 3.4s) damit kein langer Stillstand vor dem Auftritt. Greeting
            wird zusätzlich Word-Stagger animiert (qqWordFadeUp pro Wort) statt
            statisch — wirkt lebendig wie der Wolf wirklich spricht. */}
        <div style={{
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          gap: 'clamp(14px, 1.8vw, 28px)',
          marginTop: 'clamp(20px, 2.6vh, 36px)',
          animation: 'qqIntroWolfStack 0.95s cubic-bezier(0.2, 1, 0.3, 1) 2.6s both',
          opacity: 0,
        }}>
          <AnimatedCozyWolf
            widthCss="clamp(130px, 15vw, 220px)"
            mode={eurovisionMode ? 'flagge' : undefined}
            speaking={visible}
          />

          <div style={{
            position: 'relative',
            padding: 'clamp(14px, 1.8vh, 24px) clamp(22px, 2.6vw, 38px)',
            borderRadius: 24,
            background: 'linear-gradient(180deg, rgba(15,23,42,0.78) 0%, rgba(11,16,28,0.78) 100%)',
            backdropFilter: 'blur(8px)',
            WebkitBackdropFilter: 'blur(8px)',
            border: `2px solid rgba(${accentRgb},0.55)`,
            boxShadow: `0 10px 32px rgba(0,0,0,0.5), 0 0 0 3px rgba(${accentRgb},0.12), inset 0 1px 0 rgba(255,255,255,0.06)`,
            color: '#f1f5f9',
            fontSize: 'clamp(18px, 2vw, 30px)', fontWeight: 900,
            maxWidth: '60vw',
            lineHeight: 1.28,
            animation: 'qqIntroBubbleBob 5s ease-in-out 4s infinite',
          }}>
            {/* Tail */}
            <div style={{
              position: 'absolute', left: -13, top: '50%',
              width: 0, height: 0, transform: 'translateY(-50%)',
              borderTop: '11px solid transparent', borderBottom: '11px solid transparent',
              borderRight: `14px solid rgba(${accentRgb},0.55)`,
            }} />
            <div style={{
              position: 'absolute', left: -10, top: '50%',
              width: 0, height: 0, transform: 'translateY(-50%)',
              borderTop: '9px solid transparent', borderBottom: '9px solid transparent',
              borderRight: '12px solid rgba(15,23,42,0.85)',
            }} />
            {greeting.split(' ').map((word, i) => (
              <span key={i} style={{
                display: 'inline-block',
                opacity: 0,
                animation: `qqWordFadeUp 0.5s cubic-bezier(0.16, 1, 0.3, 1) ${3.2 + i * 0.08}s both`,
                marginRight: 6,
              }}>{word}</span>
            ))}
          </div>
        </div>
      </div>
      <style>{`
        @keyframes qqIntroAmbientPulse {
          0%, 100% { opacity: 0.65; transform: translate(-50%, -50%) scale(1); }
          50%      { opacity: 1.0;  transform: translate(-50%, -50%) scale(1.10); }
        }
        @keyframes qqIntroFocusIn {
          0%   { backdrop-filter: blur(14px); -webkit-backdrop-filter: blur(14px); opacity: 0.6; }
          60%  { opacity: 1; }
          100% { backdrop-filter: blur(0); -webkit-backdrop-filter: blur(0); opacity: 1; }
        }
        @keyframes qqIntroEntrySweep {
          0%   { transform: translateX(0); opacity: 0; }
          25%  { opacity: 1; }
          100% { transform: translateX(280%); opacity: 0; }
        }
        @keyframes qqIntroLightFlash {
          0%   { opacity: 0; }
          25%  { opacity: 1; }
          100% { opacity: 0; }
        }
        /* 2026-05-06: cozier Sonnenaufgang statt Lichtblitz. Langsamer, weicher,
           radial-pulse von Center. */
        @keyframes qqIntroSunrise {
          0%   { opacity: 0;   transform: scale(0.85); }
          40%  { opacity: 0.7; transform: scale(1.05); }
          100% { opacity: 0;   transform: scale(1.25); }
        }
        /* Lichter-Schwarm-Burst — einmal hell aufblitzen, dann fade-out. */
        @keyframes qqIntroFireflyBurst {
          0%   { opacity: 0;   transform: translate(-50%, -50%) scale(0.6); }
          30%  { opacity: 1;   transform: translate(-50%, -50%) scale(1.6); }
          100% { opacity: 0;   transform: translate(-50%, -50%) scale(2.2); }
        }
        @keyframes qqIntroFireflyDrift {
          0%, 100% { opacity: 0.35; transform: translate(0, 0) scale(0.9); }
          25%      { opacity: 1;    transform: translate(8px, -10px) scale(1.1); }
          50%      { opacity: 0.6;  transform: translate(-6px, -18px) scale(1); }
          75%      { opacity: 0.9;  transform: translate(10px, -8px) scale(1.05); }
        }
        @keyframes qqIntroSubLetter {
          0%   { opacity: 0; transform: translateY(-12px); letter-spacing: 0.8em; filter: blur(8px); }
          100% { opacity: 0.92; transform: translateY(0); letter-spacing: 0; filter: blur(0); }
        }
        /* 2026-05-09 (Wolf-Wunsch 'CozyQuiz in App-Card prominent'): Card poppt
           rein nach Sunrise-Light. Subtle scale+blur fuer Stage-Entry. */
        @keyframes qqIntroWelcomeCard {
          0%   { opacity: 0; transform: translateY(20px) scale(0.92); filter: blur(8px); }
          60%  { opacity: 1; transform: translateY(-3px) scale(1.02); filter: blur(0); }
          100% { opacity: 1; transform: translateY(0) scale(1); filter: blur(0); }
        }
        @keyframes qqIntroLineExpand {
          0%   { opacity: 0; transform: scaleX(0); }
          100% { opacity: 0.85; transform: scaleX(1); }
        }
        @keyframes qqIntroEurovisionPop {
          0%   { opacity: 0; transform: translateY(8px) scale(0.85); }
          70%  { opacity: 1; transform: translateY(-2px) scale(1.06); }
          100% { opacity: 1; transform: translateY(0) scale(1); }
        }
        /* 2026-05-07 v17 (Wolf 'nicer als nur blinken — schau dir mal das gif
           auf dem desktop an'): mehrstufige Animation mit Tilt + Multi-Layer-
           Glow-Pulse + leichter Color-Shift Rosa→Weiss. Cycle 3.5s. */
        @keyframes qqStingerXShine {
          0%, 100% {
            transform: scale(1) rotate(0deg);
            color: #fde6f0;
            text-shadow: 0 2px 10px rgba(0,0,0,0.5);
          }
          25% {
            transform: scale(1.10) rotate(8deg);
            color: #fff;
            text-shadow: 0 2px 10px rgba(0,0,0,0.5),
                         0 0 14px rgba(255,255,255,0.85),
                         0 0 28px rgba(255,45,123,0.55);
          }
          50% {
            transform: scale(1.22) rotate(0deg);
            color: #fff;
            text-shadow: 0 2px 10px rgba(0,0,0,0.5),
                         0 0 28px rgba(255,255,255,0.95),
                         0 0 56px rgba(255,45,123,0.75),
                         0 0 96px rgba(168,85,247,0.45);
          }
          75% {
            transform: scale(1.10) rotate(-8deg);
            color: #fff;
            text-shadow: 0 2px 10px rgba(0,0,0,0.5),
                         0 0 14px rgba(255,255,255,0.85),
                         0 0 28px rgba(255,45,123,0.55);
          }
        }
        /* Backwards-compat alias falls noch wo verwendet. */
        @keyframes qqStingerXShimmer {
          0%, 100% { transform: scale(1);    text-shadow: 0 2px 10px rgba(0,0,0,0.5); }
          50%      { transform: scale(1.18); text-shadow: 0 2px 10px rgba(0,0,0,0.5), 0 0 24px rgba(255,255,255,0.85); }
        }
        /* Subtle vertical hover-float fuer Stinger-Logos. */
        @keyframes qqStingerHover {
          0%, 100% { transform: translateY(0); }
          50%      { transform: translateY(-6px); }
        }
        @keyframes qqIntroAccentShimmer {
          0%   { background-position: -200% 0; }
          100% { background-position:  200% 0; }
        }
        @keyframes qqIntroTitleLetter {
          0%   { opacity: 0; transform: translateY(40px) scale(0.4); filter: blur(14px); }
          55%  { opacity: 1; transform: translateY(-6px) scale(1.08); filter: blur(0); }
          80%  { transform: translateY(2px) scale(0.98); }
          100% { opacity: 1; transform: translateY(0) scale(1); filter: blur(0); }
        }
        @keyframes qqIntroTitleSettle {
          0%, 100% { transform: scale(1); }
          50%      { transform: scale(1.015); }
        }
        @keyframes qqIntroTitleShimmer {
          0%   { background-position: -120% 0; opacity: 0; }
          15%  { opacity: 1; }
          85%  { opacity: 1; }
          100% { background-position:  120% 0; opacity: 0; }
        }
        @keyframes qqIntroWolfStack {
          0%   { opacity: 0; transform: translateY(36px); filter: blur(8px); }
          60%  { opacity: 1; filter: blur(0); }
          100% { opacity: 1; transform: translateY(0); filter: blur(0); }
        }
        @keyframes qqIntroBubbleBob {
          0%, 100% { transform: translateY(0); }
          50%      { transform: translateY(-6px); }
        }
        /* 2026-05-08 (Welcome-Polish): Word-Stagger fuer Sprechblasen-Greeting.
           Macht den Wolf-Auftritt lebendig — wie wenn er wirklich spricht. */
        @keyframes qqWordFadeUp {
          0%   { opacity: 0; transform: translateY(10px); filter: blur(3px); }
          100% { opacity: 1; transform: translateY(0);    filter: blur(0); }
        }
      `}</style>
      </>
      )}
    </BeamerOverlay>
  );
}

// ─── RulesIntroOverlay ──────────────────────────────────────────────────────
// Zwischen-Folie: "Jetzt kommen die Regeln — gut aufpassen!"
// Aktiv bei rulesSlideIndex === -1. Crossfade vom Willkommen rein, in die
// erste Regel-Folie raus. Kühlere Palette (blau/violett) als Kontrast zum
// warmen Welcome, damit der Übergang auch farblich spürbar ist.
function RulesIntroOverlay({ language, visible, eurovisionMode }: {
  language: QQLanguage; visible: boolean; eurovisionMode?: boolean;
}) {
  const lang = useLangFlip(language);
  const headline = lang === 'en' ? 'Now the rules' : 'Jetzt kommen die Regeln';
  const sub = lang === 'en' ? 'Pay close attention!' : 'Gut aufpassen!';
  // 2026-05-10 (Audit-P0 Eurovision-Konsistenz): accent themed via getBrandColors.
  const accent = getBrandColors(eurovisionMode).accentHex;
  return (
    <BeamerOverlay
      visible={visible}
      zIndex={9988}
      hiddenScale={0.98}
      background="radial-gradient(ellipse at center, rgba(31,26,46,0.96) 0%, rgba(20,16,31,0.98) 55%, rgba(10,8,20,1) 100%)"
    >
      {/* Hintergrund-Glow — Brand-Pink (Eurovision: ESC-Pink) */}
      <div style={{
        position: 'absolute', left: '50%', top: '50%',
        width: '140vmin', height: '140vmin',
        transform: 'translate(-50%, -50%)',
        background: `radial-gradient(circle, rgba(${getBrandColors(eurovisionMode).accentRgb},0.22) 0%, rgba(162,18,71,0.12) 40%, transparent 65%)`,
        filter: 'blur(10px)',
        animation: visible ? 'qqRulesIntroGlow 3.6s ease-out both' : 'none',
        pointerEvents: 'none',
      }} />
      {/* Card — gleiche Struktur wie Rules-Slides (RulesView) */}
      <div style={{
        position: 'relative', zIndex: 5,
        maxWidth: 1200, width: '94%',
        background: 'rgba(15,12,9,0.85)',
        border: `2px solid ${accent}44`,
        borderRadius: 24,
        padding: 'clamp(40px, 6vh, 80px) clamp(40px, 6vw, 96px)',
        boxShadow: `0 0 120px ${accent}22, 0 16px 48px rgba(0,0,0,0.6)`,
        backdropFilter: 'blur(10px)',
        display: 'flex', flexDirection: 'column', alignItems: 'center',
        gap: 'clamp(14px, 2vh, 24px)', textAlign: 'center',
      }}>
        {/* 2026-05-05 v2 (Wolf 'Buch bouncen, sync zum Title-Wave'):
            Entry-Animation + continuous qqCatNameWave. */}
        <div style={{
          fontSize: 'clamp(64px, 9vw, 110px)', lineHeight: 1,
          display: 'inline-block',
          animation: visible
            ? 'qqRulesIntroIcon 1.1s cubic-bezier(0.2,0.9,0.3,1.3) 0.2s both, qqCatNameWave 2.4s ease-in-out 1.3s infinite'
            : 'none',
          filter: `drop-shadow(0 6px 24px ${accent}66)`,
        }}>📖</div>
        {/* Eyebrow — analog Rules-Slides "Spielregeln" */}
        <div style={{
          fontSize: 'clamp(13px,1.4vw,18px)', fontWeight: 900, letterSpacing: '0.1em',
          textTransform: 'uppercase', color: `${accent}88`,
        }}>
          {lang === 'de' ? 'Vorbereitung' : 'Get Ready'}
        </div>
        {/* Title — Letter-Cascade analog Rules-Slides */}
        <div
          aria-label={headline}
          style={{
            display: 'inline-flex',
            fontSize: 'clamp(44px, 7vw, 88px)', fontWeight: 900,
            lineHeight: 1.05, letterSpacing: '-0.01em',
            color: accent,
            textShadow: `0 0 60px ${accent}44`,
          }}
        >
          {Array.from(headline).map((char, i) => (
            <span key={i} style={{
              display: 'inline-block',
              opacity: 0,
              animation: visible
                ? `qqRulesTitleLetter 0.7s cubic-bezier(0.16, 1.2, 0.3, 1) ${0.3 + i * 0.05}s both, qqCatNameWave 2.4s ease-in-out ${1.4 + i * 0.08}s infinite`
                : 'none',
              whiteSpace: 'pre',
            }}>{char === ' ' ? ' ' : char}</span>
          ))}
        </div>
        {/* Divider — gleicher Style wie Rules-Slides */}
        <div style={{
          width: '100%', height: 3, borderRadius: 2,
          background: `linear-gradient(90deg, transparent, ${accent}cc 50%, transparent)`,
          backgroundSize: '200% 100%',
          animation: visible ? 'lineShimmer 3s linear 1.4s infinite' : 'none',
          boxShadow: `0 0 18px ${accent}44`,
        }} />
        {/* Subtitle */}
        <div style={{
          fontSize: 'clamp(22px,3vw,40px)', fontWeight: 700,
          letterSpacing: '0.05em',
          color: '#e2e8f0',
          textShadow: '0 2px 12px rgba(0,0,0,0.4)',
          animation: visible ? 'qqRulesIntroSub 0.8s cubic-bezier(0.2,0.8,0.4,1) 0.95s both' : 'none',
        }}>{sub}</div>
      </div>
      <style>{`
        @keyframes qqRulesIntroGlow {
          0% { opacity: 0; transform: translate(-50%, -50%) scale(0.5); }
          60% { opacity: 1; transform: translate(-50%, -50%) scale(1.0); }
          100% { opacity: 0.7; transform: translate(-50%, -50%) scale(1.08); }
        }
        @keyframes qqRulesIntroIcon {
          0% { opacity: 0; transform: translateY(18px) scale(0.6) rotate(-8deg); }
          65% { transform: translateY(-4px) scale(1.08) rotate(3deg); }
          100% { opacity: 1; transform: translateY(0) scale(1) rotate(0deg); }
        }
        @keyframes qqRulesIntroHeadline {
          0% { opacity: 0; transform: translateY(24px) scale(0.92); filter: blur(8px); }
          55% { filter: blur(0); }
          100% { opacity: 1; transform: translateY(0) scale(1); filter: blur(0); }
        }
        @keyframes qqRulesIntroSub {
          0% { opacity: 0; transform: translateY(10px); letter-spacing: 0.22em; }
          100% { opacity: 1; transform: translateY(0); letter-spacing: 0.08em; }
        }
      `}</style>
    </BeamerOverlay>
  );
}

export function RulesView({ state: s }: { state: QQStateUpdate }) {
  const lang = useLangFlip(s.language);
  // Wolf 2026-05-05: triggert Re-Render wenn Wolf im Rules-Editor speichert.
  useRuleOverridesVersion();
  const totalPhases = (s.totalPhases ?? 4) as 3 | 4;
  const allSlides = lang === 'en' ? buildRulesSlidesEn(totalPhases) : buildRulesSlidesDe(totalPhases);
  // 2026-05-09 (Wolf): Slides mit requiresConnections (z.B. 4×4-Finale) nur
  // zeigen wenn der Mod das Connections-Feature aktiviert hat. Comeback bleibt.
  const slides = s.connectionsEnabled === false
    ? allSlides.filter(sl => !sl.requiresConnections)
    : allSlides;
  const totalSlides = slides.length;
  const rawIdx = s.rulesSlideIndex ?? 0;
  // idx<0 = Overlay-Phase (Willkommen/Regel-Intro). Nichts rendern, damit der
  // Crossfade der Overlays nicht die erste Regel-Folie im Hintergrund zeigt.
  if (rawIdx < 0) return null;
  const idx = Math.max(0, Math.min(rawIdx, totalSlides - 1));
  const slide = slides[idx];
  const fontFam = s.theme?.fontFamily ? `'${s.theme.fontFamily}', 'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif` : "'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif";
  const isLast = idx === totalSlides - 1;
  const hasGrid = !!slide.grid;

  // 2026-05-08 (Wolf-Wunsch 'regelslides mit /animations Slot-1 animieren'):
  // Direction-Tracking — bei Slide N→N+1 slidet die neue Card von rechts rein
  // (forward), bei N→N-1 von links (backward). Vorher: phasePop-Mount (subtle
  // scale 0.94→1). Pragma-Variante ohne Dual-Render — alte Slide unmountet
  // via React-key-Wechsel sofort, neue Slide kommt dramatisch rein.
  const prevIdxRef = useRef(idx);
  const direction = idx > prevIdxRef.current ? 'forward'
                  : idx < prevIdxRef.current ? 'backward'
                  : 'forward';
  useEffect(() => { prevIdxRef.current = idx; }, [idx]);
  const slideInAnim = direction === 'forward' ? 'qqStageSlideInRight' : 'qqStageSlideInLeft';

  return (
    <div style={{
      flex: 1, display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center',
      position: 'relative', overflow: 'hidden', fontFamily: fontFam,
    }}>
      <Fireflies />

      {/* Main card — full-width for beamer readability.
          2026-05-08 (Wolf-Wunsch /animations Slot-1): Slide-In statt phasePop.
          Forward = von rechts, Backward = von links. Spring-Easing für sanftes
          Settle-Overshoot. */}
      <div key={idx} style={{
        position: 'relative', zIndex: 5,
        maxWidth: 1200, width: '94%', maxHeight: '92vh', overflow: 'hidden',
        background: 'rgba(15,12,9,0.85)',
        border: `2px solid ${slide.color}44`,
        borderRadius: 24,
        padding: `clamp(24px, 4vh, ${hasGrid ? 52 : 60}px) clamp(32px, 5vw, ${hasGrid ? 64 : 72}px)`,
        boxShadow: `0 0 120px ${slide.color}22, 0 16px 48px rgba(0,0,0,0.6)`,
        animation: `${slideInAnim} 0.55s cubic-bezier(0.34, 1.30, 0.64, 1) both`,
        backdropFilter: 'blur(10px)',
        willChange: 'transform, opacity',
      }}>
        {/* Icon + title — beides zentriert, Icon über Titel. Klassischer
            Stage-Look statt links-rechts-Layout. */}
        <div style={{
          display: 'flex', flexDirection: 'column', alignItems: 'center',
          gap: 'clamp(8px, 1vh, 14px)', marginBottom: 'clamp(16px, 2.5vh, 28px)',
          textAlign: 'center',
        }}>
          {/* 2026-05-05 (Wolf 'alle Emojis in Regeln bouncen, sync zum Wave'):
              continuous qqCatNameWave wie Title-Buchstaben. Delay 1.3s = Title-
              Wave-Init (1.0s) + halbe Cascade (~0.3s) → Emoji peakt synchron
              mit mittlerem Buchstaben statt asynchron dagegen zu wirken.
              2026-05-09 (Wolf-Wunsch 'Joker-PNGs prominent auf Joker-Slide'):
              Bei heroJokers ein Pärchen Joker-PNGs (Boy+Girl) als Hero, mit
              Wiggle-Animation in Counter-Phase für lebendige Doppel-Pose. */}
          {slide.heroJokers ? (
            <div style={{
              display: 'inline-flex', alignItems: 'flex-end', gap: 'clamp(8px, 1vw, 18px)',
              filter: 'drop-shadow(0 4px 16px rgba(0,0,0,0.5))',
              animation: 'qqCatNameWave 2.4s ease-in-out 1.3s infinite',
            }}>
              <JokerIcon i={0} size={'clamp(72px, 10vw, 130px)'} eurovisionMode={!!s.theme?.eurovisionMode}
                style={{ animation: 'qqJokerWiggle 2.4s ease-in-out 0.5s infinite' }} />
              <JokerIcon i={1} size={'clamp(72px, 10vw, 130px)'} eurovisionMode={!!s.theme?.eurovisionMode}
                style={{ animation: 'qqJokerWiggle 2.4s ease-in-out 1.7s infinite' }} />
            </div>
          ) : (
            <span style={{
              display: 'inline-block',
              fontSize: 'clamp(64px,9vw,110px)', lineHeight: 1,
              filter: 'drop-shadow(0 4px 16px rgba(0,0,0,0.5))',
              animation: 'qqCatNameWave 2.4s ease-in-out 1.3s infinite',
            }}><QQEmojiIcon emoji={slide.icon}/></span>
          )}
          <div style={{
            fontSize: 'clamp(13px,1.4vw,18px)', fontWeight: 900, letterSpacing: '0.1em',
            textTransform: 'uppercase', color: `${slide.color}88`,
          }}>
            {getRuleText('rules.header', lang, lang === 'de' ? 'Spielregeln' : 'Game Rules')}
          </div>
          <div style={{
            fontSize: 'clamp(44px,7vw,88px)', fontWeight: 900, lineHeight: 1.05,
            color: slide.color,
            textShadow: `0 0 60px ${slide.color}44`,
          }}>
            {/* 2026-05-05 (Wolf): Wave-Animation pro Buchstabe — gleiche
                Bewegungs-Sprache wie Cat-Intro-Headline. Stagger 0.08s.
                Spaces als &nbsp; damit Word-Spacing erhalten bleibt. */}
            {slide.title.split('').map((char, i) => (
              <span key={`${idx}-${i}`} style={{
                display: 'inline-block',
                opacity: 0,
                // 2026-05-05 v2 (Wolf 'jetzt kommen die regeln auch wave?'):
                // Entry-Letter-Cascade (scaleIn + blur-clear, stagger 0.05s —
                // gleiche Sprache wie Welcome-Title), DANN continuous
                // qqCatNameWave als sanftes Wiegen.
                animation: `qqRulesTitleLetter 0.7s cubic-bezier(0.16, 1.2, 0.3, 1) ${0.15 + i * 0.05}s both, qqCatNameWave 2.4s ease-in-out ${1.0 + i * 0.08}s infinite`,
                whiteSpace: 'pre',
              }}>{char === ' ' ? ' ' : char}</span>
            ))}
          </div>
        </div>

        {/* Divider — symmetrischer Gradient + continuous shimmer (analog Round-Intro-Bar
            und Welcome-Linie, damit die drei Marken-Folien dieselbe Bewegungs-Sprache
            sprechen). */}
        <div style={{
          width: '100%', height: 3, borderRadius: 2,
          background: `linear-gradient(90deg, transparent, ${slide.color}cc 50%, transparent)`,
          backgroundSize: '200% 100%',
          marginBottom: 'clamp(16px, 2.5vh, 32px)',
          animation: 'lineShimmer 3s linear infinite',
          boxShadow: `0 0 18px ${slide.color}44`,
        }} />

        {/* Content: text left, grid right (if grid exists) */}
        <div style={{
          display: 'flex', gap: 'clamp(24px, 3vw, 48px)',
          alignItems: (slide.showTree || slide.treeShowcase) ? 'stretch' : 'center',
          flexDirection: (slide.showTree || slide.treeShowcase) ? 'column' : (hasGrid ? 'row' : 'column'),
        }}>
          {/* Fortschrittsbaum (Inline-Variante in Abilities-Slide) */}
          {slide.showTree && (
            <div style={{ display: 'flex', justifyContent: 'center', animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.05s both' }}>
              <QQProgressTree state={s} variant="inline" />
            </div>
          )}

          {/* TREE SHOWCASE — eigene Slide, Tree groß + Phasen-Sweep */}
          {slide.treeShowcase && (
            <div style={{
              display: 'flex', flexDirection: 'column', alignItems: 'center',
              gap: 'clamp(20px, 3vh, 40px)',
              animation: 'contentReveal 0.6s var(--qq-ease-pop-fast) 0.1s both',
              padding: 'clamp(8px, 1.5vh, 24px) 0',
            }}>
              <QQProgressTree state={s} variant="showcase" showcaseMode showcaseStepMs={2800} />
              <div style={{
                display: 'inline-flex', alignItems: 'center', gap: 12,
                fontSize: 'clamp(18px, 2vw, 28px)', fontWeight: 700,
                color: '#a8a395', letterSpacing: '0.04em',
                animation: 'contentReveal 0.6s var(--qq-ease-pop-fast) 0.5s both',
              }}>
                <span style={{
                  display: 'inline-block', width: 8, height: 8, borderRadius: '50%',
                  background: '#EC4899', boxShadow: '0 0 12px rgba(236,72,153,0.65)',
                  animation: 'qqShowcaseHintPulse 1.6s ease-in-out infinite',
                }} />
                {getRuleText('rules.slide3.hint', lang, lang === 'de'
                  ? '5 Kategorien pro Runde — jede mit eigenem Twist'
                  : '5 categories per round — each with its own twist')}
              </div>
              <style>{`
                @keyframes qqShowcaseHintPulse {
                  0%, 100% { opacity: 0.5; transform: scale(0.85); }
                  50% { opacity: 1; transform: scale(1.15); }
                }
              `}</style>
            </div>
          )}

          {/* Text lines — zentriert für Quiz-Event-Look (kein Bullet-Liste-
              Eindruck, klare Stage-Präsentation). */}
          <div style={{
            display: 'flex', flexDirection: 'column',
            gap: 'clamp(10px, 1.5vh, 20px)', flex: 1,
            alignItems: 'center', textAlign: 'center',
          }}>
            {slide.lines.map((line, i) => (
              <div key={i} style={{
                animation: `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.1 + i * 0.12}s both`,
                maxWidth: 920,
              }}>
                <span style={{
                  fontSize: 'clamp(22px,3vw,40px)', fontWeight: 700,
                  color: '#e2e8f0', lineHeight: 1.3,
                }}>{line}</span>
              </div>
            ))}
            {/* Ability-Badges (Bann, Schild, Tauschen, …) als Icon-Strip */}
            {slide.abilities && slide.abilities.length > 0 && (
              <div style={{
                display: 'flex', flexWrap: 'wrap', justifyContent: 'center',
                gap: 'clamp(10px, 1.4vw, 20px)', marginTop: 'clamp(10px, 1.6vh, 22px)',
              }}>
                {slide.abilities.map((b, i) => (
                  <div key={`${b.label}-${i}`} style={{
                    display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6,
                    padding: 'clamp(10px, 1.2vh, 16px) clamp(14px, 1.6vw, 22px)', borderRadius: 16,
                    background: `${b.accent}1a`, border: `2px solid ${b.accent}55`,
                    boxShadow: `0 0 18px ${b.accent}33`, minWidth: 'clamp(96px, 11vw, 140px)',
                    animation: `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.4 + i * 0.08}s both`,
                  }}>
                    {b.slug
                      ? <QQIcon slug={b.slug} size={'clamp(40px, 5.5vw, 72px)'} alt={b.label} />
                      : <span style={{ fontSize: 'clamp(36px, 5vw, 64px)', lineHeight: 1 }}><QQEmojiIcon emoji={b.emoji}/></span>}
                    <div style={{
                      fontSize: 'clamp(14px, 1.6vw, 22px)', fontWeight: 900,
                      color: b.accent, letterSpacing: '0.04em',
                    }}>{b.label}</div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Mini grid example */}
          {slide.grid && <RulesMiniGrid grid={slide.grid} slideColor={slide.color} eurovisionMode={!!s.theme?.eurovisionMode} />}
        </div>

        {/* Extra callout — zentriert */}
        {slide.extra && (
          <div style={{
            marginTop: 'clamp(16px, 2.5vh, 32px)', padding: 'clamp(12px, 1.8vh, 20px) clamp(18px, 2.2vw, 28px)', borderRadius: 16,
            background: `${slide.color}15`, border: `2px solid ${slide.color}33`,
            fontSize: 'clamp(18px,2.4vw,34px)', fontWeight: 900,
            color: slide.color,
            animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.4s both',
            textShadow: `0 0 24px ${slide.color}33`,
            textAlign: 'center',
          }}>
            {slide.extra}
          </div>
        )}

        {/* Last slide hint */}
        {isLast && (
          <div style={{
            marginTop: 'clamp(16px, 2.5vh, 32px)', textAlign: 'center',
            fontSize: 'clamp(20px,2.8vw,36px)', fontWeight: 900,
            color: slide.color,
            animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.6s both',
            textShadow: `0 0 24px ${slide.color}33`,
          }}>
            {getRuleText('rules.lastSlideHint', lang, lang === 'de' ? '🎬 Los geht\'s!' : '🎬 Let\'s go!')}
          </div>
        )}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// LOBBY
// ═══════════════════════════════════════════════════════════════════════════════

// WolfLobbyGreeter — kleiner Wolf top-right in der Lobby, winkt hereinkommende
// Teams herein. Idle: 'QR-Code scannen!' / 'Genau den da!' / etc. Wenn Parent
// `welcomedTeamName` setzt (kommt von welcomeTeamId in LobbyView, ~3.2s aktiv
// nach Team-Join), uebernimmt 'Hallo {teamName}!' bis zum Timeout, dann zurueck
// zur Idle-Rotation.
function WolfLobbyGreeter({ lang, welcomedTeamName, eurovisionMode }: {
  lang: 'de' | 'en';
  welcomedTeamName: string | null;
  /** 2026-05-07 (Wolf-ESC): wenn true, Wolf haelt EU-Flagge statt Daumen hoch. */
  eurovisionMode?: boolean;
}) {
  // 2026-05-07 v8 (Wolf 'gib dem wolf ein paar eurovision sprueche'): im
  // ESC-Mode Slogan-Pool gegen Eurovision-Phrasen tauschen — Bonsoir-Vibe,
  // ESC-Insider, "12 points"-Witz. Mund-Counts ungefaehr nach Silben gesetzt
  // damit der Mund-Flap-Loop synchron mit dem Speak-Timing laeuft.
  const idleSlogans: Slogan[] = eurovisionMode
    ? (lang === 'de'
        ? [
            { text: 'Bonsoir Europe!', mouths: 4 },
            // 2026-05-07 v9 (Wolf 'griechen, polen, russen sind dabei'):
            // multilinguale Begruessungen als Easter-Egg im Idle-Pool.
            { text: 'Γεια σας!', mouths: 3 },        // EL: 'Hallo zusammen'
            { text: 'Witajcie!', mouths: 3 },        // PL: 'Willkommen'
            { text: 'Добро пожаловать!', mouths: 5 }, // RU: 'Willkommen'
            { text: 'Mit dem Handy joinen', mouths: 4 },
            { text: 'Welches Land seid ihr?', mouths: 5 },
            { text: 'Wer holt heute 12 Punkte?', mouths: 6 },
            { text: 'Lasst die Show beginnen!', mouths: 5 },
          ]
        : [
            { text: 'Good evening Europe!', mouths: 5 },
            { text: 'Γεια σας!', mouths: 3 },        // EL
            { text: 'Witajcie!', mouths: 3 },        // PL
            { text: 'Добро пожаловать!', mouths: 5 }, // RU
            { text: 'Phone out, scan, join!', mouths: 4 },
            { text: 'Which country are you?', mouths: 5 },
            { text: 'Who scores douze points?', mouths: 5 },
            { text: 'Let the show begin!', mouths: 4 },
          ])
    : (lang === 'de'
        ? [
            { text: 'QR-Code scannen!', mouths: 4 },
            { text: 'Genau den da!', mouths: 3 },
            { text: 'Bereit zu joinen?', mouths: 4 },
            { text: 'Mit dem Handy joinen', mouths: 4 },
            { text: 'Jeder kann mitspielen', mouths: 5 },
          ]
        : [
            { text: 'Scan the QR!', mouths: 3 },
            { text: 'That one over there!', mouths: 4 },
            { text: 'Ready to join?', mouths: 3 },
            { text: 'Phone out, scan, go!', mouths: 4 },
            { text: 'Anyone can play', mouths: 4 },
          ]);

  const [idleIdx, setIdleIdx] = useState(0);

  // 2026-05-07 v9 (Wolf 'wir haben griechen polen russen, wolf soll auf den
  // sprachen begruessen'): im ESC-Mode rotiert das Team-Join-Welcome
  // zufaellig durch DE/EN/EL/PL/RU. useMemo auf welcomedTeamName, damit
  // dasselbe Team beim selben Join nicht zwischen Sprachen flippt.
  const ESC_GREETINGS = useMemo<Array<(name: string) => string>>(() => [
    (n) => `Hallo ${n}!`,        // DE
    (n) => `Hello ${n}!`,        // EN
    (n) => `Γεια ${n}!`,         // EL — Griechisch
    (n) => `Cześć ${n}!`,        // PL — Polnisch
    (n) => `Привет ${n}!`,       // RU — Russisch
  ], []);
  const escWelcomeText = useMemo(() => {
    if (!welcomedTeamName || !eurovisionMode) return null;
    const fn = ESC_GREETINGS[Math.floor(Math.random() * ESC_GREETINGS.length)];
    return fn(welcomedTeamName);
  }, [welcomedTeamName, eurovisionMode, ESC_GREETINGS]);

  // Welcome-Slogan ueberschreibt idle wenn ein neues Team joint
  const welcomeSlogan: Slogan | null = welcomedTeamName
    ? {
        text: escWelcomeText
          ?? (lang === 'de' ? `Hallo ${welcomedTeamName}!` : `Hello ${welcomedTeamName}!`),
        mouths: Math.min(7, Math.max(3, Math.ceil(welcomedTeamName.length / 3) + 1)),
      }
    : null;

  const isWelcoming = welcomeSlogan !== null;
  // 2026-05-07 v14 (Bug-Fix Mod-Page-Crash 'Cannot read mouths'): Wenn der
  // Slogan-Pool zwischen ESC (8) und Cozy (5) wechselt, kann idleIdx fuer
  // den neuen Pool out-of-bounds sein → undefined → .mouths-Crash. Safe-Index
  // mit Modulo + Fallback auf Index 0.
  const slogan = welcomeSlogan
    ?? idleSlogans[idleIdx % Math.max(1, idleSlogans.length)]
    ?? idleSlogans[0]
    ?? { text: '', mouths: 2 };

  const speakMs = Math.min(4500, Math.max(1300, slogan.mouths * 440));
  const enterMs = 200;
  const exitMs = 400;
  const gapMs = 600;
  const totalMs = enterMs + speakMs + exitMs + gapMs;

  // Idle-Cycle nur wenn nicht im Welcome-Modus (Welcome bleibt bis Parent
  // welcomedTeamName auf null setzt — ~3.2s nach Join)
  useEffect(() => {
    if (isWelcoming) return;
    const id = window.setTimeout(() => {
      setIdleIdx(p => (p + 1) % idleSlogans.length);
    }, totalMs);
    return () => window.clearTimeout(id);
  }, [idleIdx, totalMs, idleSlogans.length, isWelcoming]);

  // Bubble-Key fuer Re-Mount + Mund-Sync. Bei Welcome team-name-basiert,
  // sonst idx-basiert.
  const bubbleKey = isWelcoming ? `welcome-${welcomedTeamName}` : `idle-${idleIdx}`;

  // Speaking-Gate fuer Wolf-Mund-Flap
  const [speakingNow, setSpeakingNow] = useState(false);
  useEffect(() => {
    setSpeakingNow(false);
    const t1 = window.setTimeout(() => setSpeakingNow(true), enterMs);
    const t2 = window.setTimeout(() => setSpeakingNow(false), enterMs + speakMs);
    return () => { window.clearTimeout(t1); window.clearTimeout(t2); };
  }, [bubbleKey, enterMs, speakMs]);

  return (
    // 2026-05-07 v20 (Wolf 'pack ihn wieder rechts hoch ... achte darauf
    // dass der wolf nicht springt wenn er was neues sagt'): top-right
    // anchor (Aufrufer). Anti-Jumping via fixe min-Hoehe am Bubble-
    // Container + alignItems:flex-end — Bubble pinned an die Unterkante
    // des 130px-Slots, Hoehe variabel innerhalb des Slots. Wolf darunter
    // sitzt damit auf konstanter Hoehe egal wie lang der Slogan ist.
    // Sehr lange Slogans (>130px) wuerden den Slot ueberschreiten und
    // Wolf einmalig schieben — kommt aber bei den aktuellen Idle/Welcome-
    // Slogans nicht vor (max ~110px gemessen).
    <div style={{
      display: 'flex', flexDirection: 'column', alignItems: 'flex-end',
      gap: 14, pointerEvents: 'none',
    }}>
      <div style={{
        minHeight: 130,
        display: 'flex',
        alignItems: 'flex-end',
        justifyContent: 'flex-end',
      }}>
        <SpeechBubble
          text={slogan.text}
          bubbleKey={bubbleKey}
          enterMs={enterMs}
          speakMs={speakMs}
          exitMs={exitMs}
          tailSide="left"
          eurovisionMode={eurovisionMode}
          size="lg"
        />
      </div>
      <AnimatedCozyWolf
        widthCss="clamp(140px, 13vw, 200px)"
        mode={eurovisionMode ? 'flagge' : 'daumen'}
        speaking={speakingNow}
        wink={!eurovisionMode && isWelcoming}
        mirror
      />
    </div>
  );
}

export function LobbyView({ state: s }: { state: QQStateUpdate }) {
  const cardBg = s.theme?.cardBg ?? COZY_CARD_BG;
  const fontFam = s.theme?.fontFamily ? `'${s.theme.fontFamily}', 'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif` : "'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif";
  const joinUrl = `${window.location.origin}/team`;
  // 2026-05-07 (Wolf-Bug 'trotz only GB englisch im moderator werden einige
  // texte in der lobby nicht uebersetzt'): vorher lokaler de-State mit 8s-
  // Auto-Toggle der s.language komplett ignoriert hat. Jetzt useLangFlip
  // wie ueberall sonst — sticky bei DE/EN, flippt nur in 'both' (12s).
  const lang = useLangFlip(s.language);
  const de = lang === 'de';

  // F1 Team-Join-Wave: tracke frisch dazugekommene Teams, Card bekommt
  // zusaetzlich zur Entry-Animation einen Wink-Shake + Glow-Burst.
  const prevTeamIdsRef = useRef<Set<string>>(new Set());
  // „seen" = schon mal in dieser Lobby-Session gemountet. Verhindert dass
  // beim Wave-Ende die teamCardIn-Animation erneut feuert (sonst flackert
  // die Karte: einblenden → kurz weg → wieder da).
  const seenTeamIdsRef = useRef<Set<string>>(new Set());
  const [waveIds, setWaveIds] = useState<Set<string>>(new Set());
  // Welcome-Banner: zeigt 'Willkommen, {Team}!' kurz prominent in der Mitte
  // wenn ein neues Team joint (User-Wunsch 2026-04-28). Banner overlayt — Lobby
  // bleibt im Hintergrund sichtbar.
  const [welcomeTeamId, setWelcomeTeamId] = useState<string | null>(null);
  const welcomeTimerRef = useRef<number | null>(null);
  useEffect(() => {
    const curIds = new Set(s.teams.map(t => t.id));
    const prev = prevTeamIdsRef.current;
    const newJoins: string[] = [];
    for (const id of curIds) if (!prev.has(id)) newJoins.push(id);
    prevTeamIdsRef.current = curIds;
    if (newJoins.length > 0 && prev.size > 0) {
      // Nur als „wave" markieren wenn Lobby schon bestand (sonst sind alle
      // initialen Teams „neu" und der Glow-Burst waere ueberfluessig).
      setWaveIds(new Set(newJoins));
      setTimeout(() => setWaveIds(new Set()), 1400);
      // Welcome-Banner für den letzten neuen Join (bei Mehrfach-Join nur einer
      // sichtbar, sonst stapelt sich's). Re-trigger durch clearTimeout möglich.
      const lastJoin = newJoins[newJoins.length - 1];
      setWelcomeTeamId(lastJoin);
      if (welcomeTimerRef.current) window.clearTimeout(welcomeTimerRef.current);
      welcomeTimerRef.current = window.setTimeout(() => setWelcomeTeamId(null), 3200);
    }
  }, [s.teams]);
  useEffect(() => () => { if (welcomeTimerRef.current) window.clearTimeout(welcomeTimerRef.current); }, []);
  const welcomedTeam = welcomeTeamId ? s.teams.find(t => t.id === welcomeTeamId) : null;
  // Nach jedem Render alle aktuellen Teams als „seen" markieren — fortan
  // bekommen sie KEIN teamCardIn mehr (würde sonst beim Wave-End-Re-Render
  // erneut feuern).
  useEffect(() => {
    for (const t of s.teams) seenTeamIdsRef.current.add(t.id);
  }, [s.teams]);

  // Dynamic status text
  const teamCount = s.teams.length;
  const connectedCount = s.teams.filter(t => t.connected).length;

  // QR size responsive to viewport height (avoid clipping on laptops)
  const qrSize = 'min(44vh, 420px)';

  // 2026-05-07 (Wolf-Sidequest): pro-Draft optionales Lobby-BG-Bild — wird
  // hinter den Standard-Glow-Layer gelegt, damit das Bild dezent durchscheint
  // ohne dass die UI darunter unlesbar wird. Kein BG-URL = Standard bleibt.
  const lobbyBgUrl = s.theme?.lobbyBackgroundUrl;

  return (
    <div style={{
      flex: 1, display: 'flex', flexDirection: 'column',
      padding: 'clamp(16px, 2.5vh, 32px) clamp(24px, 3vw, 56px)',
      position: 'relative', overflow: 'hidden',
      gap: 'clamp(10px, 1.5vh, 20px)',
      // Cozy-warmer Hintergrund (User-Wunsch 2026-04-28: nicht so schwarz, an
      // Setup-Look angleichen). Doppelter Radial-Gradient: oben-mitte amber-Glow,
      // unten-rechts indigo-Glow auf #0A0814-Base — exakt wie QQModeratorPage.
      background:
        'radial-gradient(ellipse at 50% -10%, rgba(236,72,153,0.10), transparent 55%), ' +
        'radial-gradient(ellipse at 85% 110%, rgba(99,102,241,0.08), transparent 55%), ' +
        'radial-gradient(ellipse at 15% 80%, rgba(244,114,182,0.05), transparent 50%), ' +
        '#0A0814',
    }}>
      {lobbyBgUrl && (
        <div
          aria-hidden
          style={{
            position: 'absolute', inset: 0,
            backgroundImage: `url(${lobbyBgUrl})`,
            backgroundSize: 'cover',
            backgroundPosition: 'center',
            backgroundRepeat: 'no-repeat',
            // 2026-05-07 (Wolf 'sehe BG nicht'): mixBlendMode screen + 0.55
            // hat ESC-Buehnenbild fast komplett geschluckt (Screen-Mode laesst
            // nur helle Pixel durch). Switch auf normal-Blend mit 0.7 — BG
            // wird klar sichtbar, Content sitzt mit eigenem Card-BG drueber.
            opacity: 0.7,
            pointerEvents: 'none',
            zIndex: 0,
          }}
        />
      )}
      <Fireflies />
      {s.theme?.eurovisionMode && <EurovisionHearts />}

      {/* Wolf-Lobby-Greeter top-right — winkt + reagiert auf Team-Joins
          mit 'Hallo {teamName}!'. Idle: 'QR-Code scannen!' / etc.
          2026-05-07 (Wolf 'Wolf mit dem daumen hoch oben rechts, wenn ein
          team sich einloggt sowas wie oh hallo team x').
          2026-05-07 v20 (Wolf 'pack ihn wieder rechts hoch, mach cozyquiz
          auf lobby kleiner und verschieb cozyquiz x und eurovision mehr in
          die mitte'): zurueck zu top-right. Anti-Jumping geloest via
          absolute-positionierter Bubble innerhalb des Greeters (siehe
          WolfLobbyGreeter return) — Bubble waechst nach oben weg vom Wolf
          ohne den Wolf zu verschieben. */}
      <div style={{
        position: 'absolute',
        right: 'clamp(20px, 2.5vw, 48px)',
        top: 'clamp(16px, 2.5vh, 32px)',
        zIndex: 7,
        pointerEvents: 'none',
        animation: 'panelSlideIn 0.7s var(--qq-ease-bounce) 0.5s both',
      }}>
        <WolfLobbyGreeter
          lang={de ? 'de' : 'en'}
          welcomedTeamName={welcomedTeam?.name ?? null}
          eurovisionMode={s.theme?.eurovisionMode}
        />
      </div>

      {/* Welcome-Team-Banner — overlayt zentral wenn neues Team joint.
          B8 (2026-04-29): User-Wunsch 'noch groesser, mittig'. top:50%,
          Avatar + Title-Schrift deutlich vergroessert. */}
      {welcomedTeam && (
        <div style={{
          position: 'absolute', top: '50%', left: '50%',
          transform: 'translate(-50%, -50%)',
          zIndex: 50,
          padding: 'clamp(32px, 4vh, 60px) clamp(56px, 7vw, 120px)',
          borderRadius: 24,
          background: 'linear-gradient(180deg, rgba(26,19,12,0.96), rgba(15,12,9,0.98))',
          border: `4px solid ${welcomedTeam.color}`,
          boxShadow: `0 0 80px ${welcomedTeam.color}aa, 0 18px 60px rgba(0,0,0,0.7)`,
          animation: 'qqWelcomeBanner 3.2s var(--qq-ease-out-cubic) both',
          pointerEvents: 'none',
          display: 'flex', alignItems: 'center', gap: 'clamp(24px, 3vw, 44px)',
          maxWidth: '90vw',
        }}>
          <QQTeamAvatar avatarId={welcomedTeam.avatarId} teamEmoji={welcomedTeam.emoji} size={'clamp(120px, 14vw, 200px)'} style={{
            boxShadow: `0 0 32px ${welcomedTeam.color}aa`,
            flexShrink: 0,
          }} />
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8, minWidth: 0 }}>
            <div style={{
              fontSize: 'clamp(18px, 1.8vw, 26px)', fontWeight: 900,
              color: welcomedTeam.color, letterSpacing: '0.22em', textTransform: 'uppercase',
              textShadow: `0 0 18px ${welcomedTeam.color}88`,
            }}>
              {de ? '✨ Willkommen' : '✨ Welcome'}
            </div>
            <div style={{
              fontFamily: fontFam,
              fontSize: 'clamp(56px, 7vw, 120px)', fontWeight: 900,
              color: '#FFEFC9', lineHeight: 1.02,
              letterSpacing: '-0.005em',
              whiteSpace: 'nowrap',
              overflow: 'hidden', textOverflow: 'ellipsis',
              maxWidth: '70vw',
              textShadow: `0 0 36px ${welcomedTeam.color}88`,
            }}>
              {welcomedTeam.name}!
            </div>
          </div>
        </div>
      )}

      {/* ── Top: CozyQuiz-Wordmark als prominenter Page-Titel.
          2026-05-06 (Wolf 'bisschen glow weg, wave-effekt rein, sah nicht
          aus wie sonst texte in der app'): Multi-Layer-Goldglow (4 Schichten
          + Breath-Drop-Shadow auf outer wrapper) reduziert auf eine subtile
          Layer + Depth-Shadow — Sprache jetzt analog Rules-/Cat-Title.
          Continuous qqCatNameWave (-10px translateY) per Buchstabe mit
          Stagger 80ms, startet nach der Entry-Cascade (delay 0.95s + i*0.08). */}
      {/* 2026-05-07 v3 (Wolf 'der Effekt ist rechteckig, sieht abgehakt aus'):
          Wrapper hatte 2 parallel laufende Animationen (phasePop + Entry),
          beide haben das rechteckige Wordmark-Bbox skaliert → der text-shadow-
          Halo skalierte mit, was als rechteckiger 'Showlight' wahrnehmbar war.
          phasePop raus, nur qqLobbyWordmarkEntry mit reinem Fade. Plus
          radialer Glow-BG hinter dem Wort fuer Atmosphaere ohne rechteckige
          Form-Sichtbarkeit. */}
      <div style={{
        textAlign: 'center', position: 'relative', zIndex: 5, flexShrink: 0,
        animation: 'qqLobbyWordmarkEntry 0.85s cubic-bezier(0.16, 1, 0.3, 1) 0.15s both',
        paddingTop: 'clamp(6px, 1vh, 14px)',
      }}>
        {/* Radialer Glow-Backdrop hinter dem Wordmark — runde Form, kein
            rechteckiges Halo. Atmend-langsam pulsierend. */}
        <div aria-hidden style={{
          position: 'absolute',
          left: '50%', top: '50%',
          transform: 'translate(-50%, -50%)',
          width: 'clamp(420px, 60vw, 900px)',
          height: 'clamp(180px, 26vh, 320px)',
          // 2026-05-07 v17 (Wolf 'das gleiche hier in die lobby cozyquiz x
          // eurovision'): Backdrop-Tint folgt dem Theme — Pink in ESC-Mode,
          // Gold sonst. Standard-CozyQuiz-Mode unveraendert.
          background: s.theme?.eurovisionMode
            ? 'radial-gradient(ellipse at center, rgba(255,45,123,0.18) 0%, rgba(255,45,123,0.06) 45%, transparent 70%)'
            : 'radial-gradient(ellipse at center, rgba(236,72,153,0.18) 0%, rgba(236,72,153,0.06) 45%, transparent 70%)',
          filter: 'blur(20px)',
          pointerEvents: 'none',
          zIndex: -1,
          animation: 'qqLobbyTitleGlow 6s ease-in-out infinite',
        }} />
        <style>{`
          .cq-wordmark {
            font-weight: 900;
            line-height: 1;
            letter-spacing: -0.02em;
            color: #EC4899;
            display: inline-block;
            position: relative;
          }
          .cq-wordmark > span {
            display: inline-block;
            will-change: transform, opacity;
          }
          @keyframes qqLobbyWordmarkEntry {
            0%   { opacity: 0; transform: translateY(8px); }
            100% { opacity: 1; transform: translateY(0); }
          }
          @keyframes qqLobbyTitleGlow {
            0%, 100% { opacity: 0.55; transform: translate(-50%, -50%) scale(0.96); }
            50%      { opacity: 0.85; transform: translate(-50%, -50%) scale(1.04); }
          }
        `}</style>
        {/* 2026-05-07 (Wolf-Sidequest): Pro-Draft Welcome-Text-Override.
            Wenn theme.welcomeText gesetzt ist, ersetzt es 'CozyQuiz' im Wordmark.
            ESC-Quiz nutzt das fuer 'Bonsoir Europe' o.ae. */}
        {(() => {
          const customWelcome = de
            ? (s.theme?.welcomeText?.de ?? '')
            : (s.theme?.welcomeText?.en ?? '');

          // 2026-05-07 v17 (Wolf 'das gleiche hier oben hin wie auf der setup
          // page, schoen das genau gleiche hier in die lobby COZYQUIZ x
          // Eurovision'): Im ESC-Mode mit Logo IMMER den Stinger rendern —
          // [COZYQUIZ Stinger Fit] × [Eurovision-Logo] mit X-Shine + Hover-
          // Float, identisch zu Welcome/PreGame.
          // 2026-05-07 v18 (Wolf-Bug 'sprachwechsel laesst die Seite huepfen,
          // französisch etc'): customWelcome-Guard entfernt. Vorher hat das
          // Theme-welcomeText ('Bonsoir Europe' DE / 'Good evening Europe' EN)
          // die Stinger-Renderung blockiert und das Wordmark zwischen
          // unterschiedlich langen Texten (14 vs 19 Zeichen) flippen lassen —
          // bei jedem Lang-Flip ein vertikaler Layout-Hop weil fontSize-Tier
          // wechselt. Stinger hat fixe Width unabhaengig von Sprache.
          // Standard-CozyQuiz-Mode bleibt komplett unangetastet.
          if (s.theme?.eurovisionMode && s.theme?.logoUrl) {
            return (
              <div style={{
                display: 'inline-flex',
                alignItems: 'center',
                gap: 'clamp(18px, 2.2vw, 40px)',
              }}>
                {/* CozyQuiz-Wordmark im Stinger-Fit-Font, hover-floatend.
                    2026-05-07 v20 (Wolf 'mach cozyquiz auf lobby kleiner und
                    verschieb cozyquiz x und eurovision mehr in die mitte'):
                    7vw/108 -> 5.2vw/82 (-24 %). Schmalerer Stinger sitzt
                    entspannt im viewport-Center ohne dem Top-Right-Wolf in
                    die Quere zu kommen — und wirkt visuell mittiger. */}
                <span style={{
                  fontFamily: "'Stinger Fit', 'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif",
                  fontSize: 'clamp(38px, 5.2vw, 82px)',
                  fontWeight: 400,
                  letterSpacing: '0.04em',
                  color: '#FF2D7B',
                  textShadow: '0 2px 14px rgba(0,0,0,0.65), 0 0 28px rgba(255,45,123,0.55)',
                  lineHeight: 0.96,
                  animation: 'qqStingerHover 4.2s ease-in-out 0.6s infinite',
                }}>COZYQUIZ</span>
                {/* X mit qqStingerXShine (Tilt + Multi-Layer-Glow). height:1em
                    fixiert die vertikale Mittellage.
                    2026-05-07 v19 (Wolf 'jetzt ist das x doch noch weniger
                    mittig'): top:-0.08em von v18 wieder raus, stattdessen
                    COZYQUIZ + Logo geshrinkt (siehe oben) — dadurch wirkt X
                    proportional dominanter + natuerlicher mittig. */}
                {/* 2026-05-07 v20: matched zu COZYQUIZ-Shrink (-24 %). */}
                <span aria-hidden style={{
                  display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                  fontFamily: "'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif",
                  fontWeight: 900,
                  fontSize: 'clamp(28px, 4vw, 62px)',
                  lineHeight: 1,
                  height: '1em',
                  color: '#fde6f0',
                  textShadow: '0 2px 10px rgba(0,0,0,0.5)',
                  animation: 'qqStingerXShine 3.5s ease-in-out 0.6s infinite',
                }}>×</span>
                {/* Eurovision-Logo — Hoehe so dimensioniert dass die sichtbaren
                    'Eurovision Song Contest'-Letters optisch ungefaehr gleich
                    gross sind wie das CozyQuiz-Wordmark. */}
                <span style={{
                  display: 'inline-flex', alignItems: 'center',
                  animation: 'qqStingerHover 4.2s ease-in-out 0.6s infinite',
                }}>
                  <img
                    src={s.theme.logoUrl}
                    alt="Eurovision Song Contest"
                    draggable={false}
                    style={{
                      // 2026-05-07 v20: matched zu COZYQUIZ-Shrink (-24 %),
                      // 11vh/166 -> 8.5vh/126.
                      height: 'clamp(60px, 8.5vh, 126px)',
                      width: 'auto',
                      filter: 'drop-shadow(0 0 24px rgba(236,72,153,0.6)) drop-shadow(0 4px 12px rgba(0,0,0,0.55))',
                    }}
                  />
                </span>
              </div>
            );
          }

          const wordmark = customWelcome.length > 0 ? customWelcome : 'CozyQuiz';
          // Stagger reduziert sich proportional bei langen Texten damit Wave
          // nicht ueber 4s laeuft.
          const stagger = Math.max(0.03, 0.07 * (8 / Math.max(wordmark.length, 8)));
          return (
            <div
              className="cq-wordmark"
              style={{
                // 2026-05-08 (Wolf-Wunsch 'logo text in standard wie eurovision'):
                // Stinger Fit als Wordmark-Font auch fuer Standard-Drafts.
                // Eurovision behaelt Hot-Pink (#FF2D7B), Standard nutzt Brand-
                // Pink (#EC4899). Wave-Animation pro Buchstabe bleibt erhalten.
                fontFamily: "'Stinger Fit', 'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif",
                fontWeight: 400,
                letterSpacing: '0.04em',
                fontSize: wordmark.length > 14 ? 'clamp(40px, 6.5vw, 100px)' : 'clamp(56px, 9vw, 140px)',
                color: s.theme?.eurovisionMode ? '#FF2D7B' : '#EC4899',
                textShadow: s.theme?.eurovisionMode
                  ? '0 3px 18px rgba(0,0,0,0.65), 0 0 32px rgba(255,45,123,0.35)'
                  : '0 3px 18px rgba(0,0,0,0.65), 0 0 32px rgba(236,72,153,0.40)',
              }}
              aria-label={wordmark}
            >
              {Array.from(wordmark).map((ch, i) => (
                <span
                  key={i}
                  style={{
                    animation: `qqCatNameWave 2.6s ease-in-out ${0.85 + i * stagger}s infinite`,
                    whiteSpace: ch === ' ' ? 'pre' : undefined,
                  }}
                >{ch}</span>
              ))}
            </div>
          );
        })()}
      </div>

      {/* ── Center: 2-column layout — QR left, Teams right.
          Symmetrische Ränder: QR bündig links, Teams-Grid bündig rechts,
          gleicher Abstand zum Viewport-Rand auf beiden Seiten. ── */}
      <div style={{
        flex: 1, display: 'grid',
        gridTemplateColumns: 'auto 1fr',
        alignItems: 'center',
        columnGap: 'clamp(24px, 3vw, 48px)',
        position: 'relative', zIndex: 5,
        width: '100%',
        padding: '0 clamp(24px, 4vw, 80px)',
        minHeight: 0,
      }}>
        {/* Left: QR Code */}
        <div style={{
          display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 'clamp(10px, 1.5vh, 18px)',
          flexShrink: 0, justifySelf: 'start',
          animation: 'phasePop 0.6s var(--qq-ease-bounce) 0.3s both',
        }}>
          <div style={{
            background: '#ffffff', borderRadius: 24, padding: 'clamp(14px, 2vh, 24px)',
            // C5 „Scan-me"-Breath: sanftes gruenes Box-Shadow-Puls signalisiert Interaktivitaet.
            animation: 'qrScanBreath 3s ease-in-out infinite, qrGlow 3s ease-in-out infinite',
            boxShadow: '0 16px 64px rgba(0,0,0,0.5), 0 0 50px rgba(255,255,255,0.1)',
            width: qrSize, height: qrSize, display: 'flex', alignItems: 'center', justifyContent: 'center',
          }}>
            <QRCodeSVG value={joinUrl} size={256} bgColor="#ffffff" fgColor="#0A0814" level="M"
              style={{ width: '100%', height: '100%' }} />
          </div>
          <div style={{ textAlign: 'center' }}>
            <div style={{
              fontSize: 'clamp(18px, 2vw, 28px)', color: '#e2e8f0', fontWeight: 900, marginBottom: 4,
            }}>
              {de ? 'Scannen & mitspielen!' : 'Scan & join!'}
            </div>
            <div style={{
              fontSize: 'clamp(13px, 1.4vw, 18px)', color: '#94a3b8', fontFamily: 'monospace',
              background: cardBg, padding: '6px 16px', borderRadius: 8,
              border: '1px solid rgba(255,255,255,0.1)',
              display: 'inline-block',
            }}>
              {joinUrl.replace('https://', '').replace('http://', '')}
            </div>
          </div>
          {/* CozyWolf Branding — prominent unterhalb des QR-Codes */}
          <div style={{
            display: 'flex', alignItems: 'center', gap: 10,
            padding: '8px 18px', borderRadius: 999,
            background: 'linear-gradient(135deg, rgba(236,72,153,0.16), rgba(236,72,153,0.10))',
            border: '1.5px solid rgba(236,72,153,0.35)',
            boxShadow: '0 4px 18px rgba(0,0,0,0.35), 0 0 18px rgba(236,72,153,0.12)',
          }}>
            <img
              src="/logo.png"
              alt=""
              style={{ width: 28, height: 28, objectFit: 'contain', filter: 'drop-shadow(0 1px 2px rgba(0,0,0,0.6))' }}
            />
            <span style={{
              fontSize: 'clamp(12px, 1.1vw, 15px)', fontWeight: 900,
              color: '#cbd5e1', letterSpacing: '0.04em',
            }}>
              {de ? 'präsentiert von' : 'presented by'}
            </span>
            <span style={{
              fontSize: 'clamp(14px, 1.4vw, 18px)', fontWeight: 900,
              color: '#EC4899', letterSpacing: '0.04em',
              textShadow: '0 1px 2px rgba(0,0,0,0.6)',
            }}>
              CozyWolf
            </span>
          </div>
        </div>

        {/* Right: Teams + status — nimmt verfügbare Breite voll aus */}
        <div style={{
          minWidth: 0, width: '100%',
          display: 'flex', flexDirection: 'column', gap: 'clamp(10px, 1.5vh, 18px)',
          alignItems: 'stretch', justifyContent: 'center',
        }}>
          <div style={{
            fontSize: 'clamp(14px, 1.5vw, 20px)', fontWeight: 900,
            color: '#94a3b8', letterSpacing: '0.1em', textTransform: 'uppercase',
            textAlign: 'center', opacity: 0.7,
          }}>
            {de ? 'Angemeldete Teams' : 'Joined Teams'} · {teamCount}
          </div>

          {teamCount === 0 ? (
            // Empty-State: prominenter Hinweis mit wackelndem Pfeil zum QR-Code links.
            // Loest 'Beamer-Lobby zeigt bei 0 Teams nichts Auffaelliges' aus dem
            // UI-Polish-Audit (C1). Pfeil ist Marken-Gold, damit er als Akzent zwischen
            // QR (links) und kommendem Team-Grid (rechts) ueber dem Slate-Hintergrund
            // klar liest.
            <div style={{
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              gap: 'clamp(14px, 2vw, 26px)',
              padding: 'clamp(28px, 4vh, 56px) clamp(20px, 3vw, 40px)',
              border: '2px dashed rgba(236,72,153,0.4)', borderRadius: 16,
              background: 'linear-gradient(135deg, rgba(236,72,153,0.06), rgba(236,72,153,0.04))',
              boxShadow: '0 0 40px rgba(236,72,153,0.12)',
            }}>
              <span style={{
                fontSize: 'clamp(36px, 5vw, 64px)', lineHeight: 1,
                animation: 'qqEmptyArrowNudge 1.6s ease-in-out infinite',
                display: 'inline-block', flexShrink: 0,
              }} aria-hidden>👈</span>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 6, textAlign: 'center' }}>
                <span style={{
                  fontSize: 'clamp(20px, 2.4vw, 32px)', fontWeight: 900,
                  color: '#EC4899', letterSpacing: '0.02em',
                  textShadow: '0 2px 12px rgba(236,72,153,0.3)',
                  animation: 'lobbyPulse 2.5s ease-in-out infinite',
                }}>
                  {de ? 'Scannt den QR-Code!' : 'Scan the QR code!'}
                </span>
                <span style={{
                  fontSize: 'clamp(14px, 1.5vw, 20px)', fontWeight: 700,
                  color: '#94a3b8', letterSpacing: '0.06em',
                }}>
                  {de ? 'Eure Teams erscheinen hier.' : 'Teams appear here.'}
                </span>
              </div>
            </div>
          ) : (
            <div style={{
              display: 'grid',
              // Immer 2-spaltig: 1-2 Teams = 2 Spalten (eine Zeile), 3-4 = 2×2,
              // 5-8 = 2×3 / 2×4. Hält Karten schön breit statt quetschig-schmal.
              gridTemplateColumns: 'repeat(2, minmax(0, 1fr))',
              // 2026-05-10 (Spacing-Audit P2): Compact-Gap von 6 auf 10 bumpt —
              // bei 7-8 Teams verschmolzen die Cards auf 8 m Beamer-Distanz
              // optisch zu einem Block. 10 px hält sichtbare Atmung ohne dass
              // die Cards merklich schmaler werden.
              gap: teamCount > 6 ? 10 : 'clamp(8px, 1.2vw, 14px)',
            }}>
              {s.teams.map((t, i) => {
                const compact = teamCount > 6;
                const isFreshJoin = waveIds.has(t.id);
                // Schon mal gerendert? Dann KEINE Entry-Animation mehr feuern,
                // sonst flackert die Karte beim Wave-End (Animation-Property
                // wechselt von teamJoinWave → teamCardIn → opacity:0-Frame).
                const wasSeen = seenTeamIdsRef.current.has(t.id);
                return (
                  <div key={t.id} style={{
                    padding: compact
                      ? 'clamp(16px, 2vh, 24px) clamp(20px, 2.2vw, 28px)'
                      : 'clamp(18px, 2.2vh, 26px) clamp(22px, 2.4vw, 30px)',
                    borderRadius: compact ? 18 : 22,
                    background: cardBg,
                    border: `2px solid ${isFreshJoin ? t.color : t.color + '55'}`,
                    boxShadow: isFreshJoin
                      ? `0 8px 28px rgba(0,0,0,0.4), 0 0 60px ${t.color}99, 0 0 30px ${t.color}55`
                      : `0 8px 28px rgba(0,0,0,0.4), 0 0 24px ${t.color}22`,
                    display: 'flex', alignItems: 'center',
                    gap: compact ? 'clamp(14px, 1.5vw, 20px)' : 'clamp(14px, 1.6vw, 20px)',
                    // F1: frisch joinende Teams kriegen wink-Shake + Glow-Burst.
                    // Bereits gesehene Teams (wasSeen) bekommen KEINE Animation
                    // mehr — sonst spielt teamCardIn nach Wave-Ende erneut und
                    // die Karte flackert (out → in).
                    animation: isFreshJoin
                      ? 'teamJoinWave 1.2s var(--qq-ease-bounce) both'
                      : wasSeen
                        ? undefined
                        : `teamCardIn 0.5s var(--qq-ease-bounce) ${0.4 + i * 0.06}s both`,
                    transition: 'box-shadow 0.6s ease, border-color 0.6s ease',
                    minWidth: 0,
                    position: 'relative',
                  }}>
                    <QQTeamAvatar avatarId={t.avatarId} teamEmoji={t.emoji} size={compact ? 'clamp(56px, 5.4vw, 76px)' : 'clamp(64px, 6vw, 88px)'} style={{ flexShrink: 0 }} />
                    {isFreshJoin && (
                      <span aria-hidden style={{
                        position: 'absolute', top: -16, right: -10,
                        fontSize: 30, lineHeight: 1,
                        animation: 'teamJoinHi 1.1s cubic-bezier(0.34,1.5,0.64,1) both',
                        filter: `drop-shadow(0 0 8px ${t.color}cc)`,
                      }}>👋</span>
                    )}
                    <div style={{ minWidth: 0, flex: 1 }}>
                      <div style={{
                        fontWeight: 900,
                        // 2026-05-04: Bei langen Namen automatisch kleiner +
                        // 2-Zeilen-Wrap statt harte 12-Zeichen-Truncation,
                        // damit Witznamen wie "Schon Wieder Falsch" nicht
                        // auf "Schon Wiede..." verstuemmelt werden.
                        fontSize: t.name.length > 16
                          ? (compact ? 'clamp(15px, 1.55vw, 21px)' : 'clamp(16px, 1.7vw, 24px)')
                          : (compact ? 'clamp(18px, 1.9vw, 26px)' : 'clamp(20px, 2.1vw, 30px)'),
                        color: t.color,
                        lineHeight: 1.1,
                        display: '-webkit-box',
                        WebkitLineClamp: 2,
                        WebkitBoxOrient: 'vertical',
                        overflow: 'hidden',
                        wordBreak: 'break-word',
                      }} title={t.name}>
                        {t.name}
                      </div>
                      <div style={{
                        fontSize: compact ? 'clamp(13px, 1.2vw, 16px)' : 'clamp(13px, 1.25vw, 17px)',
                        fontWeight: 700, color: t.connected ? '#22C55E' : '#94a3b866',
                        marginTop: 4,
                      }}>
                        {t.connected ? (de ? '● bereit' : '● ready') : '○ offline'}
                      </div>
                      {/* 2026-05-06 (Wolf 'in der Lobby anzeigen wenn Team mit
                          Code eingeloggt ist zum X. Mal dabei, willkommen
                          zurueck'): Stamm-Code-Returner-Hint. gamesPlayed wird
                          von Backend async via getQQRegularTeam populiert
                          nach qq:joinTeam. */}
                      {(t.gamesPlayed ?? 0) > 0 && (
                        <div style={{
                          marginTop: 4,
                          display: 'inline-flex', alignItems: 'center', gap: 6,
                          padding: '3px 10px', borderRadius: 999,
                          background: `${t.color}1c`,
                          border: `1px solid ${t.color}55`,
                          fontSize: compact ? 'clamp(11px, 1vw, 14px)' : 'clamp(12px, 1.1vw, 16px)',
                          fontWeight: 800,
                          color: t.color,
                          maxWidth: '100%',
                          animation: 'qqPauseEyebrowFloat 4s ease-in-out infinite',
                        }} title={de
                          ? `${t.gamesPlayed} Spiele · ${t.wins ?? 0} Siege`
                          : `${t.gamesPlayed} games · ${t.wins ?? 0} wins`}>
                          <span aria-hidden>👋</span>
                          {de
                            ? `Willkommen zurück — ${t.gamesPlayed}. Mal dabei`
                            : `Welcome back — visit #${t.gamesPlayed}`}
                        </div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {/* Dynamic status */}
          <div style={{
            fontSize: 'clamp(16px, 1.8vw, 24px)', fontWeight: 900, textAlign: 'center',
            color: teamCount < 2 ? '#EC4899' : '#22C55E',
            animation: teamCount >= 2 ? 'lobbyPulse 2.5s ease-in-out infinite' : undefined,
          }}>
            {teamCount === 0
              ? (de ? '📱 Scannt den Code um beizutreten' : '📱 Scan to join')
              : teamCount < 2
                ? (de ? '⏳ Noch 1 Team fehlt!' : '⏳ 1 more team needed!')
                : teamCount >= 5
                  ? (de ? `🔥 ${teamCount} Teams sind dabei!` : `🔥 ${teamCount} teams are in!`)
                  : connectedCount === teamCount
                    ? (de ? `🚀 Gleich geht's los!` : `🚀 Let's go!`)
                    : (de ? `${connectedCount}/${teamCount} verbunden` : `${connectedCount}/${teamCount} connected`)}
          </div>
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// TEAMS REVEAL — einmalige epische Team-Vorstellung nach Rules, vor Phase 1
// ═══════════════════════════════════════════════════════════════════════════════

export function TeamsRevealView({ state: s }: { state: QQStateUpdate }) {
  const lang = useLangFlip(s.language);
  const fontFam = s.theme?.fontFamily ? `'${s.theme.fontFamily}', 'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif` : "'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif";
  const teams = s.teams.filter(t => t.connected).length > 0
    ? s.teams.filter(t => t.connected)
    : s.teams;
  // Animation start anchor — fallback auf "jetzt" falls Backend-Feld fehlt
  const anchor = s.teamsRevealStartedAt ?? Date.now();
  const [tick, setTick] = useState(0);
  useEffect(() => {
    const id = setInterval(() => setTick(t => t + 1), 250);
    return () => clearInterval(id);
  }, []);
  void tick;
  const elapsed = Date.now() - anchor;

  // 2026-05-09 v3: WELCOME-Hero + Subtitle + Teams-Parallel.
  // 2026-05-11 (Wolf-Bug 'kurzer Herzlich-Willkommen-Flash vor Heute spielen
  // weg'): WELCOME-Hero komplett deaktiviert — startet jetzt direkt mit
  // „Heute spielen…" + Team-Cascade. Welcome-Moment bleibt im Pre-Rules-
  // QuizIntroOverlay (rulesSlideIndex === -2), an dieser Stelle war's doppelt.
  const titleDelay = 0;
  const titleDur = 800;
  const WELCOME_DUR = 0;               // war 1400 — deaktiviert
  const WELCOME_FADE = 0;              // war 400 — deaktiviert
  const TITLE_HOLD = 0;                // Teams starten sofort (vorher = 1800)
  const SLAM_DUR = 1400;
  const SETTLE = 300;                  // Settle gekürzt 500→300 (mehr Energie)
  const FLIP_DUR = 900;                // Flip gekürzt 1000→900
  const TEAM_STAGGER = 280;            // Team-zu-Team-Stagger (parallel, nicht sequentiell)
  const PER_TEAM_TOTAL = SLAM_DUR + SETTLE + FLIP_DUR; // 2600 für ein Team
  const teamStart = (i: number) => TITLE_HOLD + i * TEAM_STAGGER;
  const flipStartFor = (i: number) => teamStart(i) + SLAM_DUR + SETTLE;
  const holdEndFor = (i: number) => flipStartFor(i) + FLIP_DUR;
  const goodLuckDelay = TITLE_HOLD + (teams.length - 1) * TEAM_STAGGER + PER_TEAM_TOTAL + 400;
  const showGoodLuck = elapsed >= goodLuckDelay;
  const showWelcome = elapsed < WELCOME_DUR + WELCOME_FADE;
  const showSubtitle = elapsed >= WELCOME_DUR;
  // revealedCount obsolet — pro Team direkt berechnet. Compat-Stub falls abgegriffen.
  const revealedCount = Math.max(0, Math.min(teams.length,
    elapsed < TITLE_HOLD ? 0 : Math.floor((elapsed - TITLE_HOLD) / TEAM_STAGGER) + 1));

  // 2026-04-30 v3 round 6 (User-Bug 'sound trifft avatar-erscheinen nicht'):
  // Statt per 250ms-Tick auf revealedCount zu pollen (= Sound bis zu 250ms
  // verspaetet), pre-scheduln wir alle Sounds via setTimeout am EXAKTEN
  // ms-Anchor. So feuert der Cascade-Ton synchron zum Slam-Down.
  // Nur 1× pro mount: wenn anchor neu gesetzt wird, Timer-Cleanup.
  // v3 round 9 (User-Bug 'konstanter ton stoert hinter der cascade'):
  // playTeamReveal (Slam-Sound, gleiche Pitch pro Team) entfernt — nur noch
  // die aufsteigende Pentatonik-Cascade. Sauberer, kein Doppel-Layer mehr.
  useEffect(() => {
    if (s.sfxMuted) return;
    const cascadeTotal = teams.length + 1;
    const timers: number[] = [];
    for (let i = 0; i < teams.length; i++) {
      // 2026-05-09 (Game-Show-Reveal): Cascade-Note feuert jetzt beim
      // FLIP-Start (= Avatar wird sichtbar) statt beim Slam-Start. Sync zum
      // visuellen Reveal-Moment, nicht zum „Mystery-Card-fällt-rein".
      const fireAt = anchor + flipStartFor(i);
      const delay = Math.max(0, fireAt - Date.now());
      timers.push(window.setTimeout(() => {
        try { playAvatarCascadeNote(i, cascadeTotal); } catch {}
      }, delay));
    }
    // VIEL GLUECK: eigener Sound-Slot + Fallback-Fanfare
    const goodLuckFireAt = anchor + goodLuckDelay;
    const goodLuckMs = Math.max(0, goodLuckFireAt - Date.now());
    timers.push(window.setTimeout(() => {
      try { playGoodLuckFanfare(); } catch {}
      try { playFanfare(); } catch {}
    }, goodLuckMs));
    return () => { timers.forEach(t => window.clearTimeout(t)); };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [anchor, teams.length, s.sfxMuted]);

  // 2026-05-07 v18 (Wolf 'die seite wo die teams vorgestellt werden, darf
  // auch mehr nach eurovision aussehen, also bg von eurovision und vlt text
  // in eurovision farben'): ESC-Adaption — BG-Image (5.png Vienna-Stripe-Pink
  // wie Lobby) statt Slate, Title + Good-Luck in Pink, EurovisionHearts statt
  // Fireflies, optionaler ESC-Logo-Anker oben (kleiner als Lobby-Stinger,
  // damit Big-Title dominiert). Standard-CozyQuiz-Mode unangetastet.
  const isEsc = !!s.theme?.eurovisionMode;
  const escBgUrl = isEsc ? s.theme?.lobbyBackgroundUrl : null;
  const escLogoUrl = isEsc ? s.theme?.logoUrl : null;
  const titleColor = isEsc ? '#FF2D7B' : '#f8fafc';
  const titleShadow = isEsc
    ? '0 3px 18px rgba(0,0,0,0.6), 0 0 28px rgba(255,45,123,0.45)'
    : '0 4px 20px rgba(236,72,153,0.25)';
  const goodLuckColor = isEsc ? '#FF2D7B' : '#EC4899';
  const goodLuckShadow = isEsc
    ? '0 3px 18px rgba(0,0,0,0.6), 0 0 24px rgba(255,45,123,0.55)'
    : '0 4px 24px rgba(236,72,153,0.5)';
  return (
    <div style={{
      width: '100%', height: '100%', position: 'relative',
      background: isEsc
        ? 'radial-gradient(ellipse at center, #2d1644 0%, #1f0f3d 55%, #0d0820 100%)'
        : 'radial-gradient(ellipse at center, #1e293b 0%, #0f172a 55%, #020617 100%)',
      display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
      fontFamily: fontFam, overflow: 'hidden',
    }}>
      {escBgUrl && (
        <div aria-hidden style={{
          position: 'absolute', inset: 0,
          backgroundImage: `url(${escBgUrl})`,
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          backgroundRepeat: 'no-repeat',
          opacity: 0.55,
          pointerEvents: 'none',
          zIndex: 0,
        }} />
      )}
      {isEsc ? <EurovisionHearts /> : <Fireflies />}
      <style>{`
        @keyframes qqTrTitle {
          0%   { opacity: 0; transform: translateY(-30px) scale(0.8); letter-spacing: 0.5em; }
          100% { opacity: 1; transform: translateY(0)     scale(1);   letter-spacing: 0.12em; }
        }
        /* 2026-05-08 (Wolf-Wunsch 'heute spielen wirkt eher öde'): Letters
           cascaden einzeln rein (1.2em → 0.1em letter-spacing pro Buchstabe),
           dann subtle Wave nach Settle. Underline-Reveal expandiert von center
           als Pink-Gradient. */
        @keyframes qqTrTitleLetter {
          0%   { opacity: 0; transform: translateY(-32px) scale(0.6); filter: blur(8px); }
          70%  { opacity: 1; transform: translateY(4px)   scale(1.06); filter: blur(0); }
          100% { opacity: 1; transform: translateY(0)     scale(1);   filter: blur(0); }
        }
        @keyframes qqTrTitleWave {
          0%, 100% { transform: translateY(0); }
          50%      { transform: translateY(-3px); }
        }
        @keyframes qqTrUnderline {
          0%   { opacity: 0; transform: scaleX(0); }
          60%  { opacity: 1; transform: scaleX(1.05); }
          100% { opacity: 1; transform: scaleX(1); }
        }
        @keyframes qqTrUnderlineShimmer {
          0%   { background-position: -100% 0; }
          100% { background-position: 200% 0; }
        }
        @keyframes qqTrSlam {
          0%   { opacity: 0; transform: translateY(-80vh) scale(2) rotate(-18deg); filter: blur(6px); }
          55%  { opacity: 1; transform: translateY(8%)    scale(1.15) rotate(3deg); filter: blur(0); }
          75%  { transform: translateY(-2%) scale(0.96) rotate(-1deg); }
          100% { transform: translateY(0)    scale(1) rotate(0deg); }
        }
        /* 2026-05-09 (Game-Show-Reveal Slot M): Slam für Cards (3:4 box)
           mit etwas heftiger overshoot (1.18 statt 1.15). Identisch zu Slot M. */
        @keyframes qqGsTeamSlam {
          0%   { opacity: 0; transform: translateY(-90vh) scale(2)    rotate(-18deg); filter: blur(7px); }
          55%  { opacity: 1; transform: translateY(8%)    scale(1.18) rotate(3deg);   filter: blur(0); }
          75%  {            transform: translateY(-2%)    scale(0.96) rotate(-1deg); }
          100% { opacity: 1; transform: translateY(0)     scale(1)    rotate(0);     filter: blur(0); }
        }
        @keyframes qqTrFlash {
          0%   { opacity: 0; }
          10%  { opacity: 0.9; }
          100% { opacity: 0; }
        }
        @keyframes qqTrGood {
          0%   { opacity: 0; transform: scale(0.7); }
          60%  { opacity: 1; transform: scale(1.1); }
          100% { opacity: 1; transform: scale(1); }
        }
        @keyframes qqTrPulse {
          0%,100% { transform: scale(1); }
          50%     { transform: scale(1.04); }
        }
        @keyframes qqTrEscLogo {
          0%   { opacity: 0; transform: translateY(-12px) scale(0.92); }
          100% { opacity: 1; transform: translateY(0) scale(1); }
        }
      `}</style>

      {/* Backdrop spotlight — Pink in ESC, Gold sonst */}
      <div style={{
        position: 'absolute', inset: 0,
        background: isEsc
          ? 'radial-gradient(circle at 50% 40%, rgba(255,45,123,0.16) 0%, transparent 55%)'
          : 'radial-gradient(circle at 50% 40%, rgba(236,72,153,0.12) 0%, transparent 55%)',
        pointerEvents: 'none',
        zIndex: 1,
      }} />

      {/* ESC-Logo-Anker oben — nur Logo (ohne COZYQUIZ-Wordmark) damit der
          Big-Title 'Heute spielen…' dominiert. Brueckenbau zu Lobby/Welcome. */}
      {escLogoUrl && (
        <div style={{
          position: 'relative', zIndex: 2,
          marginBottom: 'clamp(14px, 1.6vw, 24px)',
          animation: 'qqTrEscLogo 700ms cubic-bezier(0.2, 0.8, 0.2, 1) 100ms both',
        }}>
          <img
            src={escLogoUrl}
            alt="Eurovision Song Contest"
            draggable={false}
            style={{
              height: 'clamp(48px, 6vh, 92px)',
              width: 'auto',
              filter: 'drop-shadow(0 0 18px rgba(236,72,153,0.55)) drop-shadow(0 4px 10px rgba(0,0,0,0.5))',
              animation: 'qqStingerHover 4.2s ease-in-out 1.2s infinite',
            }}
          />
        </div>
      )}

      {/* 2026-05-11 (Wolf-Bug): WELCOME-Hero entfernt — Welcome-Moment lebt
          im Pre-Rules-QuizIntroOverlay. TeamsRevealView startet jetzt direkt
          mit dem „Heute spielen…"-Subtitle + Team-Cascade. */}

      {/* Subtitle Title — startet sofort beim Mount (kein Welcome-Wait mehr).
          Letters cascaden einzeln rein, dann sanftes Wave-Loop. Pink-Underline
          expandiert drunter mit Shimmer-Loop. */}
      <div style={{
        position: 'relative', zIndex: 2,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        flexDirection: 'column', gap: 'clamp(8px, 1vh, 14px)',
        marginBottom: 'clamp(24px, 3vw, 48px)',
        opacity: showSubtitle ? 1 : 0,
        transform: showSubtitle ? 'translateY(0)' : 'translateY(-12px)',
        transition: 'opacity 0.5s ease, transform 0.5s cubic-bezier(0.2, 0.8, 0.2, 1)',
      }}>
      <div style={{
        position: 'relative', zIndex: 2,
        fontSize: 'clamp(36px, 5.2vw, 82px)', fontWeight: 900, color: titleColor,
        textTransform: 'uppercase', letterSpacing: '0.1em',
        textShadow: titleShadow,
        display: 'inline-flex', flexWrap: 'nowrap',
      }}>
        {(() => {
          const titleText = lang === 'en' ? '🎬 Tonight\u2019s teams\u2026' : '🎬 Heute spielen\u2026';
          const letters = Array.from(titleText);
          const letterStagger = 0.05;
          const baseSec = titleDelay / 1000;
          return letters.map((ch, i) => (
            <span key={i} style={{
              display: 'inline-block',
              opacity: 0,
              whiteSpace: 'pre',
              animation:
                `qqTrTitleLetter 0.7s cubic-bezier(0.16, 1.2, 0.3, 1) ${baseSec + i * letterStagger}s both, ` +
                `qqTrTitleWave 2.6s ease-in-out ${baseSec + 1.2 + i * 0.06}s infinite`,
            }}>{ch}</span>
          ));
        })()}
      </div>
      {/* Pink-Underline — expandiert von center, dann shimmer-loop */}
      {(() => {
        const titleText = lang === 'en' ? '🎬 Tonights teams' : '🎬 Heute spielen';
        const letterCount = Array.from(titleText).length;
        const baseSec = titleDelay / 1000;
        const underlineDelay = baseSec + letterCount * 0.05 + 0.1;
        return (
          <div style={{
            width: 'clamp(220px, 35vw, 480px)', height: 3, borderRadius: 999,
            background: isEsc
              ? 'linear-gradient(90deg, transparent 0%, rgba(255,45,123,0.7) 25%, #FF2D7B 50%, rgba(255,45,123,0.7) 75%, transparent 100%)'
              : 'linear-gradient(90deg, transparent 0%, rgba(236,72,153,0.7) 25%, #EC4899 50%, rgba(236,72,153,0.7) 75%, transparent 100%)',
            backgroundSize: '200% 100%',
            boxShadow: isEsc
              ? '0 0 14px rgba(255,45,123,0.55)'
              : '0 0 14px rgba(236,72,153,0.55)',
            transformOrigin: 'center',
            opacity: 0,
            animation:
              `qqTrUnderline 0.8s cubic-bezier(0.16, 1, 0.3, 1) ${underlineDelay}s both, ` +
              `qqTrUnderlineShimmer 3.5s linear ${underlineDelay + 0.8}s infinite`,
          }} />
        );
      })()}
      </div>

      {/* Teams grid — Game-Show-Card-Reveal (sequenziell). Pro Team:
          Card slammt face-down rein → settled → flippt zur Vorderseite →
          Spotlight-Hold für Mod-Anmoderation → nächstes Team. */}
      {(() => {
        const n = teams.length;
        const rowSizes: number[] =
          n <= 6 ? [n]
          : n === 7 ? [4, 3]
          : n === 8 ? [4, 4]
          : n === 9 ? [5, 4]
          : n === 10 ? [5, 5]
          : (() => {
              const rows = Math.ceil(n / 4);
              const base = Math.floor(n / rows);
              const extra = n - base * rows;
              return Array.from({ length: rows }, (_, i) => base + (i < extra ? 1 : 0));
            })();
        const many = n > 5;
        const multiRow = rowSizes.length > 1;
        // Card-Width — Avatar ist ~55% der Card-Width
        const cardWidth = multiRow
          ? 'clamp(140px, 13vw, 220px)'
          : many ? 'clamp(160px, 15vw, 240px)' : 'clamp(190px, 18vw, 280px)';
        const avatarSize = multiRow
          ? 'clamp(82px, 8vw, 130px)'
          : many ? 'clamp(96px, 9.5vw, 160px)' : 'clamp(118px, 12vw, 196px)';
        const nameFont = multiRow ? 'clamp(16px, 1.7vw, 24px)' : 'clamp(18px, 1.9vw, 28px)';
        let cursor = 0;
        return (
          <div style={{
            display: 'flex', flexDirection: 'column',
            gap: 'clamp(18px, 2.4vw, 36px)',
            alignItems: 'center', maxWidth: '92vw',
            position: 'relative', zIndex: 2,
          }}>
            {rowSizes.map((size, rIdx) => {
              const slice = teams.slice(cursor, cursor + size);
              const startI = cursor;
              cursor += size;
              return (
                <div key={rIdx} style={{
                  display: 'flex', gap: 'clamp(14px, 2vw, 32px)',
                  justifyContent: 'center', flexWrap: 'nowrap',
                }}>
                  {slice.map((t, j) => {
                    const i = startI + j;
                    const startMs = teamStart(i);
                    const flipMs = flipStartFor(i);
                    const holdEndMs = holdEndFor(i);
                    const isVisible = elapsed >= startMs;
                    const isFlipped = elapsed >= flipMs;
                    const isInSpotlight = elapsed >= flipMs && elapsed < holdEndMs;
                    return (
                      <div key={t.id} style={{
                        width: cardWidth,
                        aspectRatio: '3 / 4',
                        perspective: '1200px',
                        opacity: isVisible ? 1 : 0,
                        animation: isVisible
                          ? `qqGsTeamSlam ${SLAM_DUR}ms cubic-bezier(0.34, 1.46, 0.64, 1) both`
                          : 'none',
                        filter: isInSpotlight ? `drop-shadow(0 0 38px ${t.color}cc)` : 'none',
                        transition: 'filter 0.6s ease',
                      }}>
                        <div style={{
                          position: 'relative', width: '100%', height: '100%',
                          transformStyle: 'preserve-3d',
                          transition: `transform ${FLIP_DUR}ms cubic-bezier(0.34, 1.46, 0.64, 1)`,
                          transform: isFlipped ? 'rotateY(180deg)' : 'rotateY(0deg)',
                        }}>
                          {/* Rückseite — generischer CozyQuiz-Card-Back */}
                          <div style={{
                            position: 'absolute', inset: 0,
                            backfaceVisibility: 'hidden',
                            WebkitBackfaceVisibility: 'hidden',
                            borderRadius: 'clamp(14px, 1.4vw, 22px)',
                            background:
                              'radial-gradient(ellipse at 50% 30%, rgba(236,72,153,0.32) 0%, transparent 60%),' +
                              'radial-gradient(ellipse at 50% 80%, rgba(162,18,71,0.28) 0%, transparent 55%),' +
                              'linear-gradient(135deg, #1F1A2E 0%, #14101F 60%, #0F0817 100%)',
                            border: '2px solid rgba(236,72,153,0.55)',
                            boxShadow: '0 8px 28px rgba(0,0,0,0.55), inset 0 0 36px rgba(236,72,153,0.18)',
                            display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
                            gap: 12, padding: 'clamp(14px, 1.6vw, 22px)',
                            overflow: 'hidden',
                          }}>
                            <div aria-hidden style={{
                              position: 'absolute', inset: 0,
                              backgroundImage:
                                'repeating-linear-gradient(45deg, rgba(236,72,153,0.06) 0 2px, transparent 2px 22px),' +
                                'repeating-linear-gradient(-45deg, rgba(236,72,153,0.04) 0 2px, transparent 2px 22px)',
                              pointerEvents: 'none',
                            }} />
                            {/* 2026-05-09 (Wolf-Wunsch): Pink-Wolf-PNG (transparent)
                                ersetzt idle.svg auf der Card-Back. Platzierung
                                identisch zur Vorderseite (color-circle + 54%
                                Avatar-Inner-Size). */}
                            <div style={{
                              width: avatarSize, height: avatarSize, borderRadius: '50%',
                              background: 'rgba(236,72,153,0.33)',
                              border: '2.5px solid #EC4899',
                              boxShadow: '0 0 28px rgba(236,72,153,0.99)',
                              display: 'flex', alignItems: 'center', justifyContent: 'center',
                              flexShrink: 0,
                              overflow: 'hidden',
                              position: 'relative',
                            }}>
                              <img
                                src="/avatars/cozywolf/pink.png"
                                alt=""
                                draggable={false}
                                style={{
                                  width: '90%', height: '90%', objectFit: 'contain',
                                  filter: 'drop-shadow(0 1px 2px rgba(0,0,0,0.55)) drop-shadow(0 0 1px rgba(0,0,0,0.5))',
                                }}
                              />
                            </div>
                            {/* CozyQuiz-Wordmark in Stinger Fit, Brand-Pink */}
                            <div style={{
                              fontFamily: "'Stinger Fit', 'Bricolage Grotesque', 'Inter', system-ui, sans-serif",
                              fontSize: multiRow ? 'clamp(20px, 2.2vw, 32px)' : 'clamp(24px, 2.6vw, 40px)',
                              fontWeight: 900,
                              color: '#FBCFE8',
                              letterSpacing: '0.02em',
                              textShadow: '0 0 14px rgba(236,72,153,0.7), 0 0 4px rgba(236,72,153,0.4)',
                              lineHeight: 1,
                              position: 'relative',
                            }}>CozyQuiz</div>
                          </div>
                          {/* Vorderseite — Avatar im Color-Glow-Kreis + Name
                              als Text in Team-Color (matcht Slot M Showreel) */}
                          <div style={{
                            position: 'absolute', inset: 0,
                            backfaceVisibility: 'hidden',
                            WebkitBackfaceVisibility: 'hidden',
                            transform: 'rotateY(180deg)',
                            borderRadius: 'clamp(14px, 1.4vw, 22px)',
                            background: `linear-gradient(180deg, ${t.color}22, ${t.color}10)`,
                            border: `2px solid ${t.color}`,
                            boxShadow: `0 14px 36px rgba(0,0,0,0.55), inset 0 0 44px ${t.color}33, 0 0 28px ${t.color}66`,
                            display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
                            gap: 'clamp(10px, 1.2vw, 18px)', padding: 'clamp(16px, 1.8vw, 26px)',
                          }}>
                            {/* Avatar — 1:1 wie Slot M Showreel: Color-Tinted-
                                Circle mit großem Emoji DIREKT (nicht via
                                QQTeamAvatar). emoji-fontSize ~54% des Wrappers,
                                damit's wie im Showreel kraftvoll wirkt. */}
                            <div style={{
                              width: avatarSize, height: avatarSize,
                              borderRadius: '50%',
                              background: `${t.color}33`,
                              border: `2.5px solid ${t.color}`,
                              boxShadow: `0 0 28px ${t.color}99`,
                              display: 'flex', alignItems: 'center', justifyContent: 'center',
                              flexShrink: 0,
                              overflow: 'hidden',
                              animation: isInSpotlight ? 'qqTrPulse 2.2s ease-in-out infinite' : 'none',
                            }}>
                              {t.emoji ? (
                                // Emoji-Avatar (Standard-Set): Emoji direkt als
                                // großer Text — wie Slot M Showreel.
                                // 2026-05-10 (Wolf 'Eurovision-Flaggen inkonsistent —
                                // bei heute spielen DE/GR als Text'): CountryFlagOrEmoji
                                // rendert Country-Flag-Codepoints als Twemoji-Image
                                // statt nativem Glyph (Windows Edge zeigt sonst nur
                                // Regional-Indicator-Letters DE/GR etc).
                                <CountryFlagOrEmoji
                                  emoji={t.emoji}
                                  fontSize={`calc(${typeof avatarSize === 'string' ? avatarSize : `${avatarSize}px`} * 0.54)`}
                                />
                              ) : (
                                // PNG-Avatar (cozyCast Set): über QQTeamAvatar rendern
                                <QQTeamAvatar avatarId={t.avatarId} teamEmoji={undefined} size="86%" />
                              )}
                            </div>
                            {/* Name als Text in Team-Color — Showreel-style */}
                            <TeamNameLabel
                              name={t.name}
                              maxLines={2}
                              shrinkAfter={14}
                              color={t.color}
                              fontWeight={900}
                              fontSize={nameFont}
                              style={{
                                textAlign: 'center',
                                letterSpacing: '-0.01em',
                                textShadow: `0 0 8px ${t.color}55`,
                                maxWidth: '95%',
                              }}
                            />
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              );
            })}
          </div>
        );
      })()}

      {/* "Viel Glück!" — reserve space from the start to prevent layout jump when it fades in */}
      <div style={{
        marginTop: 'clamp(32px, 4vw, 64px)',
        height: 'clamp(38px, 5.2vw, 80px)',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
      }}>
        <div style={{
          fontSize: 'clamp(28px, 4vw, 64px)', fontWeight: 900,
          color: goodLuckColor,
          textTransform: 'uppercase', letterSpacing: '0.15em',
          textShadow: goodLuckShadow,
          opacity: showGoodLuck ? 1 : 0,
          transform: showGoodLuck ? 'scale(1)' : 'scale(0.7)',
          animation: showGoodLuck ? 'qqTrGood 900ms cubic-bezier(.2,.8,.2,1) both' : 'none',
        }}>
          <QQEmojiIcon emoji="✨"/> {lang === 'en' ? 'Good luck!' : 'Viel Glück!'} <QQEmojiIcon emoji="✨"/>
        </div>
      </div>

    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// ROUND MINI TREE — 5 Kategorie-Dots der aktuellen Runde, Wolf auf aktuellem Dot.
// Bei Fragewechsel gleitet der Wolf durch CSS-transition zum neuen Dot.
// ═══════════════════════════════════════════════════════════════════════════════

function RoundMiniTree({ state: s, catColor }: { state: QQStateUpdate; catColor: string }) {
  const schedule = s.schedule ?? [];
  const phase = s.gamePhaseIndex;
  const firstIdx = schedule.findIndex(e => e.phase === phase);
  const phaseEntries = schedule.filter(e => e.phase === phase);

  const currentInPhase = phaseEntries.length === 0 || firstIdx < 0
    ? 0
    : Math.max(0, Math.min(s.questionIndex - firstIdx, phaseEntries.length - 1));

  // Wolf startet auf Vorgänger-Dot, springt nach Seiten-Entrance (~1s) zum aktuellen Dot.
  const [displayIdx, setDisplayIdx] = useState(Math.max(0, currentInPhase - 1));
  const [hopping, setHopping] = useState(false);

  useEffect(() => {
    if (currentInPhase === 0) {
      setDisplayIdx(0);
      setHopping(false);
      return;
    }
    setDisplayIdx(Math.max(0, currentInPhase - 1));
    setHopping(false);
    const t1 = setTimeout(() => {
      setDisplayIdx(currentInPhase);
      setHopping(true);
    }, 1000);
    const t2 = setTimeout(() => setHopping(false), 1000 + 560);
    return () => { clearTimeout(t1); clearTimeout(t2); };
  }, [currentInPhase]);

  if (phaseEntries.length === 0 || firstIdx < 0) return null;

  // User-Wunsch 2026-04-28: Mini-Tree unter „Runde N" darf größer sein.
  // 60→84 ergibt ~40% größere Dots, der Wolf wandert ebenfalls größer mit.
  const DOT = 84;
  const GAP = 32;
  const WOLF = DOT + 14;
  const totalWidth = phaseEntries.length * DOT + (phaseEntries.length - 1) * GAP;
  const wolfLeft = displayIdx * (DOT + GAP) + DOT / 2;
  const progressWidth = displayIdx === 0 ? 0 : displayIdx * (DOT + GAP);

  return (
    <div style={{
      position: 'relative', width: totalWidth, height: WOLF + 4,
      display: 'flex', alignItems: 'center',
    }}>
      {/* Track (grau) + Progress (amber) — auf Dot-Mittelhöhe */}
      <div style={{
        position: 'absolute', top: '50%', left: DOT / 2,
        width: totalWidth - DOT, height: 3,
        background: 'rgba(148,163,184,0.28)',
        transform: 'translateY(-50%)', borderRadius: 2,
      }} />
      {progressWidth > 0 && (
        <div style={{
          position: 'absolute', top: '50%', left: DOT / 2,
          width: progressWidth, height: 3,
          // 2026-05-04 (Wolf): Strich nimmt aktuelle Kategorie-Farbe (catColor)
          // statt immer Gold. Auf Cat-Seiten matcht er damit den Wolf-Avatar.
          background: `linear-gradient(90deg, ${catColor}, ${catColor})`,
          transform: 'translateY(-50%)', borderRadius: 2,
          boxShadow: `0 0 10px ${catColor}99`,
          transition: 'width 540ms var(--qq-ease-smooth), background 400ms ease, box-shadow 400ms ease',
        }} />
      )}

      {/* Dots — bei current bleibt der Dot leer, der Wolf sitzt drauf */}
      {phaseEntries.map((e, i) => {
        const label = QQ_CATEGORY_LABELS[e.category];
        const subSlug = e.bunteTueteKind ? qqSubSlug(e.bunteTueteKind) : null;
        const catSlug = qqCatSlug(e.category);
        // 2026-05-11 (Wolf-Bug 'onlyConnect zeigt 🎁 statt 🧩'): bei Bunte-
        // Tüte-Subs OHNE eigenes PNG (onlyConnect, bluff, oneOfEight) NICHT
        // auf cat-bunte-tuete (= 🎁) fallback. Stattdessen Sub-Emoji nehmen
        // (passend zum Badge: 🧩 / 🎭 / 🕵️). Nur Quiz-Kategorien ohne Sub
        // dürfen catSlug nutzen.
        const iconSlug = e.bunteTueteKind ? subSlug : catSlug;
        const emojiFallback = e.bunteTueteKind ? QQ_BUNTE_TUETE_LABELS[e.bunteTueteKind].emoji : label.emoji;
        const isPast = i < displayIdx;
        const isCurrent = i === displayIdx;
        const dotLeft = i * (DOT + GAP);
        const iconSize = Math.round(DOT * 0.78);
        return (
          <div key={i} style={{
            position: 'absolute', top: '50%', left: dotLeft,
            width: DOT, height: DOT, borderRadius: '50%',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: Math.round(DOT * 0.55),
            background: isPast ? 'rgba(148,163,184,0.18)'
              : isCurrent ? 'transparent'
              : 'rgba(30,41,59,0.55)',
            border: isCurrent ? 'none' : '1.5px solid rgba(148,163,184,0.35)',
            filter: isPast ? 'grayscale(1)' : 'none',
            opacity: isPast ? 0.55 : isCurrent ? 0 : 1,
            transform: 'translateY(-50%)',
            transition: 'opacity 320ms ease, filter 320ms ease, background 320ms ease',
            zIndex: 1,
          }}>
            {iconSlug
              ? <QQIcon slug={iconSlug} size={iconSize} alt={label.de} />
              : emojiFallback}
          </div>
        );
      })}

      {/* Wolf-Avatar — sitzt fix auf der Linie, slidet horizontal zum nächsten
          Dot. 2026-05-09 v2 (Wolf 'kreis darf nicht bouncen, linie ist fix'):
          outer-Bounce/Hop entfernt; KOPF (innen) wackelt subtil. */}
      <div style={{
        position: 'absolute', top: '50%', left: wolfLeft,
        width: WOLF, height: WOLF, borderRadius: '50%',
        background: 'transparent',
        border: `3px solid ${catColor}`,
        boxShadow: `0 0 0 4px ${catColor}40, 0 6px 14px ${catColor}55`,
        transform: 'translate(-50%, -50%)',
        transition: 'left 560ms cubic-bezier(0.34, 1.25, 0.64, 1), border-color 400ms ease, box-shadow 400ms ease',
        zIndex: 2,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        overflow: 'hidden',
      }}>
        <img
          src="/avatars/cozywolf/pink.png"
          alt=""
          draggable={false}
          style={{
            width: '94%', height: '94%', objectFit: 'contain',
            filter: 'drop-shadow(0 1px 2px rgba(0,0,0,0.55))',
            animation: 'qqWolfHeadBob 1.6s ease-in-out infinite',
          }}
        />
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// PHASE INTRO
// ═══════════════════════════════════════════════════════════════════════════════

// 2026-05-09 (Wolf-Vision): 3D-Card-Reveal für neue Aktionen pro Runde —
// Klauen (R2) und Stapeln (R3) werden mit derselben Slam+Flip-Choreo wie
// TeamsRevealView (Slot M) aufgedeckt. Card-Back zeigt Pink-Hatch-Pattern
// + „NEU"-Wordmark; Vorderseite ist die normale Action-Card.
function ActionCardReveal({
  cardData: c, iconNode, iconSize, cardCount, lang, startDelayMs,
}: {
  cardData: { count: number; label: string; limit?: string; accent: string; emoji?: string };
  iconNode: React.ReactNode;
  iconSize: string;
  cardCount: number;
  lang: 'de' | 'en';
  startDelayMs: number;
}) {
  const SLAM_DUR = 1400;
  const SETTLE = 500;
  const FLIP_DUR = 1000;
  const [phase, setPhase] = useState<'hidden' | 'slamming' | 'flipping' | 'done'>('hidden');
  useEffect(() => {
    const t1 = window.setTimeout(() => setPhase('slamming'), startDelayMs);
    const t2 = window.setTimeout(() => setPhase('flipping'), startDelayMs + SLAM_DUR + SETTLE);
    const t3 = window.setTimeout(() => setPhase('done'), startDelayMs + SLAM_DUR + SETTLE + FLIP_DUR);
    return () => { window.clearTimeout(t1); window.clearTimeout(t2); window.clearTimeout(t3); };
  }, [startDelayMs]);
  const isFlipped = phase === 'flipping' || phase === 'done';
  const isVisible = phase !== 'hidden';
  return (
    <div style={{
      flex: cardCount === 1 ? '0 1 auto' : '1 1 0',
      minWidth: cardCount === 1 ? 280 : 200,
      maxWidth: cardCount === 1 ? 480 : 480,
      // 2026-05-10 (Wolf-Live-Test L7 'rechte Card kleiner als linke'):
      // `height: 360` matched non-isNew Card exakt. `alignSelf: stretch` raus
      // (zog Outer auf parent-row-Höhe — Inner blieb bei 360 und wirkte dann
      // kleiner). Plus boxSizing für saubere Box-Berechnung.
      // 2026-05-10 (Spacing-Audit P1 #9): height → minHeight. Zusammen mit
      // Inner perspective height: '100%' unten und alignItems:stretch im
      // Parent (PhaseIntroView Z. 7341) wachsen jetzt isNew + non-isNew
      // Cards SYNCHRON zur natürlichen Maximum-Höhe der Row. Bei langen
      // DE-Labels wird die ganze Row höher, alle Cards bleiben gleich groß.
      minHeight: 360,
      boxSizing: 'border-box',
      perspective: '1400px',
      opacity: isVisible ? 1 : 0,
      animation: isVisible ? `qqGsTeamSlam ${SLAM_DUR}ms cubic-bezier(0.34, 1.46, 0.64, 1) both` : 'none',
      filter: isVisible ? `drop-shadow(0 0 28px ${c.accent}88)` : 'none',
      transition: 'filter 0.6s ease',
      display: 'flex',
    }}>
      <div style={{
        // 2026-05-09 v3 (Wolf 'stack card nicht gleich groß wie steal/place'):
        // FIXED height statt minHeight — non-isNew Cards können bei mehr
        // Inhalt höher werden und stretchten via alignItems:stretch über 360,
        // isNew Card mit absolute-positionierten Front/Back blieb auf 360
        // gepinnt → Größen-Drift. Jetzt alle hart auf 360.
        // 2026-05-10 (Spacing-Audit P1 #9): height: 360 → '100%'. Outer
        // ActionCardReveal hat jetzt minHeight:360, Parent-Row stretcht via
        // alignItems:stretch. Inner perspective-Wrapper nimmt 100% der Outer-
        // Höhe → Front/Back (inset:0) füllen automatisch mit. Bei wachsenden
        // Sibling-Cards bleiben Outer + Inner + Front/Back synchron.
        position: 'relative', width: '100%', height: '100%',
        transformStyle: 'preserve-3d',
        transition: `transform ${FLIP_DUR}ms cubic-bezier(0.34, 1.46, 0.64, 1)`,
        transform: isFlipped ? 'rotateY(180deg)' : 'rotateY(0deg)',
      }}>
        {/* Card-Back — Cross-Hatch + großes „NEU".
            2026-05-09 v2 (Wolf): Pink-Glow-Halo (0 0 40px accent44) hinzu —
            matcht Card-Front, sodass beim Flip kein "Größen-Shift" wahrnehmbar
            ist. Vorher hatte nur die Vorderseite den Halo. */}
        <div style={{
          position: 'absolute', inset: 0,
          backfaceVisibility: 'hidden',
          WebkitBackfaceVisibility: 'hidden',
          borderRadius: 24,
          background:
            'radial-gradient(ellipse at 50% 30%, rgba(236,72,153,0.32) 0%, transparent 60%),' +
            'radial-gradient(ellipse at 50% 80%, rgba(162,18,71,0.28) 0%, transparent 55%),' +
            'linear-gradient(135deg, #1F1A2E 0%, #14101F 60%, #0F0817 100%)',
          border: '3px solid rgba(236,72,153,0.65)',
          boxShadow: '0 0 40px rgba(236,72,153,0.27), 0 8px 28px rgba(0,0,0,0.55), inset 0 0 36px rgba(236,72,153,0.18)',
          display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
          gap: 14,
          overflow: 'hidden',
        }}>
          <div aria-hidden style={{
            position: 'absolute', inset: 0,
            backgroundImage:
              'repeating-linear-gradient(45deg, rgba(236,72,153,0.06) 0 2px, transparent 2px 22px),' +
              'repeating-linear-gradient(-45deg, rgba(236,72,153,0.04) 0 2px, transparent 2px 22px)',
            pointerEvents: 'none',
          }} />
          <div style={{
            fontSize: 'clamp(32px, 3.6vw, 56px)', fontWeight: 900,
            color: '#FBCFE8', letterSpacing: '0.18em',
            textShadow: '0 0 24px rgba(236,72,153,0.7)',
            position: 'relative',
          }}>{lang === 'en' ? 'NEW' : 'NEU'}</div>
          <div style={{
            fontSize: 'clamp(56px, 6.5vw, 96px)', lineHeight: 1,
            filter: 'drop-shadow(0 0 18px rgba(236,72,153,0.55))',
            position: 'relative',
          }}>✨</div>
        </div>
        {/* Vorderseite — die normale Action-Card.
            2026-05-11 (Wolf 'Cards einheitlich groß UND breit, deckungsgleich'):
            Layout-Refactor zu 3-Reihen-Grid (Top-Spacer, Hauptinhalt-Block,
            Limit-Slot-mit-Fixed-Höhe). Der Limit-Slot wird IMMER gerendert,
            auch ohne Pill — als unsichtbarer Spacer mit identischer Höhe.
            Damit sitzt der zentrale Inhalt (Icon + Count+Label + Sub-Line) bei
            allen Cards auf exakt der gleichen vertikalen Position, unabhängig
            davon ob Pill da ist oder nicht. */}
        <div style={{
          position: 'absolute', inset: 0,
          backfaceVisibility: 'hidden',
          WebkitBackfaceVisibility: 'hidden',
          transform: 'rotateY(180deg)',
          borderRadius: 24,
          background: `linear-gradient(180deg, ${c.accent}28, ${c.accent}10)`,
          border: `3px solid ${c.accent}aa`,
          boxShadow: `0 0 40px ${c.accent}44, 0 8px 28px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.08)`,
          display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'space-between',
          padding: 'clamp(20px, 2.4vh, 36px) clamp(20px, 2vw, 32px)',
          boxSizing: 'border-box',
        }}>
          {/* Hauptinhalt-Block — zentriert sich vertikal via flex:1 */}
          <div style={{
            flex: 1, display: 'flex', flexDirection: 'column',
            alignItems: 'center', justifyContent: 'center',
            gap: 'clamp(8px, 1.2vh, 16px)', width: '100%',
          }}>
            <div style={{
              fontSize: iconSize, lineHeight: 1,
              filter: `drop-shadow(0 6px 18px ${c.accent}55)`,
            }}>{iconNode}</div>
            <div style={{
              display: 'flex', alignItems: 'baseline',
              gap: 'clamp(6px, 0.8vw, 12px)',
              fontWeight: 900, lineHeight: 1,
              flexWrap: 'wrap', justifyContent: 'center',
            }}>
              <span style={{
                fontSize: 'clamp(36px, 4.2vw, 64px)',
                color: c.accent, fontVariantNumeric: 'tabular-nums',
                textShadow: `0 0 22px ${c.accent}88`,
              }}>{c.count}x</span>
              <span style={{
                fontSize: 'clamp(28px, 3.2vw, 48px)',
                color: '#F1F5F9', letterSpacing: '0.01em',
              }}>{c.label}</span>
            </div>
            <div style={{
              fontSize: 'clamp(13px, 1.4vw, 19px)',
              fontWeight: 700, color: '#cbd5e1',
              textAlign: 'center', lineHeight: 1.25, opacity: 0.85,
            }}>{lang === 'en' ? 'per correct answer' : 'pro richtige Antwort'}</div>
          </div>
          {/* Limit-Slot — fixed Höhe, immer gerendert (auch ohne Inhalt).
              Damit sitzen Cards mit/ohne Pill auf identischer Achse. */}
          <div style={{
            flex: '0 0 auto', minHeight: 'clamp(28px, 2.6vh, 36px)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            marginTop: 4,
          }}>
            {c.limit && (
              <div style={{
                padding: '5px 14px', borderRadius: 999,
                background: 'rgba(15,23,42,0.6)',
                border: `1.5px solid ${c.accent}55`,
                fontSize: 'clamp(11px, 1.15vw, 15px)',
                fontWeight: 900, color: '#e2e8f0',
                whiteSpace: 'nowrap',
                boxShadow: `0 2px 8px ${c.accent}22`,
              }}>{c.limit}</div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export function PhaseIntroView({ state: s }: { state: QQStateUpdate }) {
  useRuleOverridesVersion();
  const lang = useLangFlip(s.language);
  const fontFam = s.theme?.fontFamily ? `'${s.theme.fontFamily}', 'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif` : "'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif";
  // 2026-05-07 (Wolf 'mehr Pink+Blau im ESC, Set B+F'): im eurovisionMode
  // alle PhaseIntro-Akzente (Title-Glow, Round-Pille, Phasen-Linie, Wolf-
  // Drop-Shadow, Fireflies) auf ESC-Pink ziehen statt der Phase-Standardfarbe
  // (gold/lila/grün rotierend). Dadurch wirkt 'Halbfinale 1/2/Finale'
  // konsistent in der ESC-Identitaet.
  const isEsc = !!s.theme?.eurovisionMode;
  const color = isEsc ? '#FF2D7B' : getRoundColor(s.gamePhaseIndex, s.totalPhases ?? 4);
  // 2026-05-07 (Wolf-Sidequest): Pro-Draft Phase-Namen Override.
  // Wenn theme.phaseNames gesetzt: ersetzen die Standard-Namen ('Runde 1' etc.).
  // ESC-Quiz nutzt 'Halbfinale 1', 'Halbfinale 2', 'Finale'.
  // Override-Array startet bei index 1 (Phase 1 = Index 1, Phase 0 ist
  // ungenutzt im bt.phase.names — ['', 'Runde 1', 'Runde 2', ...]).
  const phaseNamesDefault = bt.phase.names[lang];
  const phaseNamesOverride = lang === 'en'
    ? s.theme?.phaseNames?.en
    : s.theme?.phaseNames?.de;
  const phaseNamesRaw: string[] = phaseNamesOverride && phaseNamesOverride.length > 0
    ? ['', ...phaseNamesOverride, ...phaseNamesDefault.slice(phaseNamesOverride.length + 1)]
    : phaseNamesDefault;
  const phaseDescsRaw = bt.phase.descs[lang];
  // „Finale" ist seit Connections-Einführung das 4×4-Mini-Game, NICHT mehr die
  // letzte Quiz-Runde. Quiz-Runden werden immer als „Runde N" angezeigt — auch
  // die letzte. Falls Connections deaktiviert ist und die letzte Quiz-Runde
  // gleichzeitig das Spielende ist, behält sie trotzdem ihren „Runde N"-Titel
  // (das echte Finale-Drama liegt bei der Connections-Phase).
  const phaseName = phaseNamesRaw[s.gamePhaseIndex];
  const phaseDesc = phaseDescsRaw[s.gamePhaseIndex];

  const questionInPhase = (s.questionIndex % 5) + 1;
  const isFirstOfRound = questionInPhase === 1;

  // Category info for upcoming question
  const cat = s.currentQuestion?.category as QQCategory | undefined;
  const catInfo = cat ? QQ_CATEGORY_LABELS[cat] : undefined;
  const CAT_COLORS: Record<string, string> = {
    SCHAETZCHEN: '#EAB308', MUCHO: '#3B82F6', BUNTE_TUETE: '#EF4444',
    ZEHN_VON_ZEHN: '#10B981', CHEESE: '#8B5CF6',
  };
  const catColor = (cat && CAT_COLORS[cat]) || color;

  // Wolf 2026-05-05: Texte sind editierbar im /rules-editor.
  // Defaults bleiben hier als Fallback erhalten.
  const CAT_EXPLAIN: Record<string, { de: string; en: string }> = {
    SCHAETZCHEN:   { de: getRuleText('cat.SCHAETZCHEN.explain', 'de', 'Wer schätzt am nächsten dran?'),
                     en: getRuleText('cat.SCHAETZCHEN.explain', 'en', 'Who can guess the closest?') },
    MUCHO:         { de: getRuleText('cat.MUCHO.explain', 'de', 'Wählt die richtige Antwort'),
                     en: getRuleText('cat.MUCHO.explain', 'en', 'Pick the right answer') },
    BUNTE_TUETE:   { de: getRuleText('cat.BUNTE_TUETE.explain', 'de', 'Überraschungs-Mechanik — seid bereit!'),
                     en: getRuleText('cat.BUNTE_TUETE.explain', 'en', 'Surprise mechanic — be ready!') },
    ZEHN_VON_ZEHN: { de: getRuleText('cat.ZEHN_VON_ZEHN.explain', 'de', '3 Antworten, 10 Punkte vergeben'),
                     en: getRuleText('cat.ZEHN_VON_ZEHN.explain', 'en', '3 answers, distribute 10 points') },
    CHEESE:        { de: getRuleText('cat.CHEESE.explain', 'de', 'Was ist das?'),
                     en: getRuleText('cat.CHEESE.explain', 'en', 'What is this?') },
  };

  // BUNTE_TUETE: pro Sub-Mechanik eigene Vorstellung (Name, Emoji, 1-Zeiler).
  // Texte editierbar via /rules-editor — Defaults hier als Fallback.
  const BUNTE_SUB_INTRO: Record<string, { de: { name: string; explain: string }; en: { name: string; explain: string }; emoji: string }> = {
    onlyConnect: {
      emoji: '🧩',
      de: { name:    getRuleText('bunte.onlyConnect.name',    'de', '4 gewinnt'),
            explain: getRuleText('bunte.onlyConnect.explain', 'de', '4 Begriffe — was verbindet sie? Ein Tipp pro Team, schnellste richtige Antwort gewinnt zuerst.') },
      en: { name:    getRuleText('bunte.onlyConnect.name',    'en', 'Only Connect'),
            explain: getRuleText('bunte.onlyConnect.explain', 'en', '4 terms — what connects them? One guess per team, fastest correct answer wins first.') },
    },
    bluff: {
      emoji: '🎭',
      de: { name:    getRuleText('bunte.bluff.name',    'de', 'Bluff'),
            explain: getRuleText('bunte.bluff.explain', 'de', 'Erfindet plausible Falsch-Antworten und ratet die echte.') },
      en: { name:    getRuleText('bunte.bluff.name',    'en', 'Bluff'),
            explain: getRuleText('bunte.bluff.explain', 'en', 'Make up plausible fake answers and find the real one.') },
    },
    hotPotato: {
      emoji: '🔥',
      de: { name:    getRuleText('bunte.hotPotato.name',    'de', 'Heiße Kartoffel'),
            explain: getRuleText('bunte.hotPotato.explain', 'de', 'Reihum antworten — keine Antwort vor Zeitende = raus.') },
      en: { name:    getRuleText('bunte.hotPotato.name',    'en', 'Hot Potato'),
            explain: getRuleText('bunte.hotPotato.explain', 'en', 'Take turns — no answer before time runs out = out.') },
    },
    top5: {
      emoji: '🏆',
      de: { name:    getRuleText('bunte.top5.name',    'de', 'Top 5'),
            explain: getRuleText('bunte.top5.explain', 'de', 'Nennt die häufigsten Antworten — je oben, desto mehr Punkte.') },
      en: { name:    getRuleText('bunte.top5.name',    'en', 'Top 5'),
            explain: getRuleText('bunte.top5.explain', 'en', 'Guess the most common answers — higher rank, more points.') },
    },
    oneOfEight: {
      emoji: '🕵️',
      de: { name:    getRuleText('bunte.oneOfEight.name',    'de', 'Imposter'),
            explain: getRuleText('bunte.oneOfEight.explain', 'de', 'Findet die EINE falsche Aussage zwischen 7 wahren.') },
      en: { name:    getRuleText('bunte.oneOfEight.name',    'en', 'Imposter'),
            explain: getRuleText('bunte.oneOfEight.explain', 'en', 'Spot the ONE false statement among 7 true ones.') },
    },
    order: {
      emoji: '📋',
      de: { name:    getRuleText('bunte.order.name',    'de', 'Reihenfolge'),
            explain: getRuleText('bunte.order.explain', 'de', 'Sortiert in der richtigen Reihenfolge.') },
      en: { name:    getRuleText('bunte.order.name',    'en', 'Order'),
            explain: getRuleText('bunte.order.explain', 'en', 'Sort in the correct order.') },
    },
    map: {
      emoji: '🗺️',
      de: { name:    getRuleText('bunte.map.name',    'de', 'CozyGuessr'),
            explain: getRuleText('bunte.map.explain', 'de', 'Errate den Ort auf der Karte — nächstes Team gewinnt.') },
      en: { name:    getRuleText('bunte.map.name',    'en', 'CozyGuessr'),
            explain: getRuleText('bunte.map.explain', 'en', 'Guess the location on the map — closest team wins.') },
    },
  };
  const bunteKind = cat === 'BUNTE_TUETE'
    ? (s.currentQuestion?.bunteTuete?.kind as keyof typeof BUNTE_SUB_INTRO | undefined)
    : undefined;
  const bunteSub = bunteKind ? BUNTE_SUB_INTRO[bunteKind] : undefined;

  const catLabel = bunteSub
    ? bunteSub[lang].name
    : (catInfo ? catInfo[lang] : '');
  const catEmoji = bunteSub
    ? bunteSub.emoji
    : (catInfo?.emoji ?? '');
  const catExplain = bunteSub
    ? bunteSub[lang].explain
    : (cat ? (CAT_EXPLAIN[cat]?.[lang] ?? '') : '');

  // ── Rule reminders per round ──
  // Subtitle ueber den Action-Cards. Beschreibt knapp wie die Wahl funktioniert,
  // die exakte Anzahl pro Aktion steht direkt auf den Cards (× N).
  // Wolf 2026-05-05: Texte editierbar via /rules-editor — Defaults als Fallback.
  const ROUND_RULES: Record<number, { de: string[]; en: string[]; emoji: string }> = {
    1: {
      emoji: '🏁',
      de: [getRuleText('round.1.line1', 'de', 'Eure Aktion diese Runde:'),
           getRuleText('round.1.line2', 'de', 'Sichert euch eure ersten Felder!')],
      en: [getRuleText('round.1.line1', 'en', 'Your action this round:'),
           getRuleText('round.1.line2', 'en', 'Claim your first cells!')],
    },
    2: {
      emoji: '⚔️',
      de: [getRuleText('round.2.line1', 'de', 'Pro richtige Antwort wählt eine Aktion:'),
           getRuleText('round.2.line2', 'de', 'Klauen jetzt möglich!')],
      en: [getRuleText('round.2.line1', 'en', 'Per correct answer choose one action:'),
           getRuleText('round.2.line2', 'en', 'Stealing now possible!')],
    },
    3: {
      emoji: '🏯',
      de: [getRuleText('round.3.line1', 'de', 'Pro richtige Antwort wählt eine Aktion:'),
           getRuleText('round.3.line2', 'de', 'Stapeln freigeschaltet — Felder dauerhaft sichern + 1 Punkt extra!')],
      en: [getRuleText('round.3.line1', 'en', 'Per correct answer choose one action:'),
           getRuleText('round.3.line2', 'en', 'Stack unlocked — lock your tile + 1 extra point!')],
    },
    4: {
      emoji: '🏯',
      de: s.connectionsEnabled !== false
        ? [getRuleText('round.4.line1', 'de', 'Pro richtige Antwort wählt eine Aktion:'),
           getRuleText('round.4.line2_finale', 'de', 'Quiz-Buddy-Punkte sammeln — danach Stapel-Bonus im Finale!')]
        : [getRuleText('round.4.line1', 'de', 'Pro richtige Antwort wählt eine Aktion:'),
           getRuleText('round.4.line2_nofin', 'de', 'Quiz-Buddy-Punkte — alles bleibt verfügbar!')],
      en: s.connectionsEnabled !== false
        ? [getRuleText('round.4.line1', 'en', 'Per correct answer choose one action:'),
           getRuleText('round.4.line2_finale', 'en', 'Collect quiz buddy points — stack-bonus finale follows!')]
        : [getRuleText('round.4.line1', 'en', 'Per correct answer choose one action:'),
           getRuleText('round.4.line2_nofin', 'en', 'Quiz buddy points — everything stays available!')],
    },
  };
  const roundRules = ROUND_RULES[s.gamePhaseIndex] ?? ROUND_RULES[3];

  // ── Round Self-Transition ──
  // Beim Mount der Slide (ab Runde 2) zeigen wir kurz den Look der vorherigen
  // Runde, dann faden wir Farben, Label & Tree auf die neue Runde. Der
  // Ziffer-Flip im Titel ist die zentrale Geste.
  const hasRoundTransition = isFirstOfRound && s.introStep === 0 && s.gamePhaseIndex > 1;
  const [transitioning, setTransitioning] = useState(hasRoundTransition);
  // Choreografie: Wolf hüpft ZUERST, danach rollt die Ziffer.
  // - treeShowsPrev: hält den Tree kurz auf Runde N-1, swappt nach 220ms auf
  //   Runde N → QQProgressTree triggert internen Hop (220ms Delay + 620ms Anim).
  // - Wolf landet ca. bei 1100ms (220 + 220 + 620 + Puffer).
  // - colorTransitioning: 2026-05-04 v4 (Wolf 'Runde-Farbe weird beim Wechsel,
  //   blaue Runde + rote 3 + dann blaue 4'): jetzt synchron mit dem
  //   New-Digit-Roll (1650ms) statt mit dem Wolf-Hop (1100ms). Word "Runde"
  //   und neuer Digit haben jetzt IMMER dieselbe Farbe (vorher: Word
  //   sweepte ueber Grau, Outer-Span fadete separat → kurze Mismatch-Phase
  //   wo Word schon neue Farbe zeigte aber alter Digit noch alter Farbe).
  //   transition 820ms = sync mit roundDigitRoll-Dauer.
  // - Digit-Fall startet 1150ms, Roll 1650ms — alles NACH dem Hop.
  // - transitioning endet bei 2500ms.
  const [treeShowsPrev, setTreeShowsPrev] = useState(hasRoundTransition);
  const [colorTransitioning, setColorTransitioning] = useState(hasRoundTransition);
  useEffect(() => {
    if (!hasRoundTransition) {
      setTransitioning(false);
      setTreeShowsPrev(false);
      setColorTransitioning(false);
      return;
    }
    setTransitioning(true);
    setTreeShowsPrev(true);
    setColorTransitioning(true);
    const tTree  = setTimeout(() => setTreeShowsPrev(false), 220);
    // 2026-05-04 v4 (Wolf): 1100 → 1650 — Color-Flip synchron mit New-Digit-
    // Roll-In statt mit Wolf-Hop. Verhindert Mismatch-Phase „neue Wort-Farbe
    // + alter Digit-Farbe".
    const tColor = setTimeout(() => setColorTransitioning(false), 1650);
    const tEnd   = setTimeout(() => setTransitioning(false), 2500);
    return () => { clearTimeout(tTree); clearTimeout(tColor); clearTimeout(tEnd); };
  }, [s.gamePhaseIndex, hasRoundTransition]);

  const prevIdx = s.gamePhaseIndex - 1;
  // 2026-05-07: prevColor auch ESC-Pink, damit waehrend Round-Transition
  // kein Farbwechsel stattfindet (Phase-Color cycelt nicht im ESC-Mode).
  const prevColor = isEsc ? '#FF2D7B' : getRoundColor(Math.max(1, prevIdx), s.totalPhases ?? 4);
  const prevPhaseName = prevIdx < 1 ? phaseName : phaseNamesRaw[prevIdx];
  const prevPhaseDesc = prevIdx < 1 ? phaseDesc : phaseDescsRaw[prevIdx];

  const displayColor = transitioning ? prevColor : color;
  const displayPhaseDesc = transitioning ? prevPhaseDesc : phaseDesc;
  const displayGpi = transitioning ? prevIdx : s.gamePhaseIndex;

  // Ziffer-Flip: nur möglich wenn beide Titel "Runde N" / "Round N" sind
  const digitRe = /^(Runde|Round)\s+(\d+)$/;
  const prevTitleMatch = prevPhaseName.match(digitRe);
  const newTitleMatch = phaseName.match(digitRe);
  const canDigitFlip = hasRoundTransition && !!prevTitleMatch && !!newTitleMatch;
  const titleWord = newTitleMatch ? newTitleMatch[1] : (lang === 'de' ? 'Runde' : 'Round');
  const prevDigit = prevTitleMatch ? prevTitleMatch[2] : '';
  const newDigit  = newTitleMatch  ? newTitleMatch[2]  : '';

  // Finale-Roll-Animation deaktiviert seit „Finale" jetzt das 4×4-Connections-
  // Mini-Game ist und Quiz-Runden immer „Runde N" heißen. Variablen bleiben
  // als no-op für die Render-Pfade unten.
  const isFinaleTransition = false;
  const finaleWord = lang === 'de' ? 'FINALE' : 'FINAL';
  const prevRoundFull = prevTitleMatch ? `${prevTitleMatch[1]} ${prevTitleMatch[2]}` : '';

  // Tree-State zu Beginn der Transition: letzter Dot der vorherigen Phase
  // (Wolf sitzt dort). Sobald treeShowsPrev kippt, swappt der Tree auf die
  // neue Phase und der Wolf hüpft (gesteuert in QQProgressTree).
  const displayTreeState: QQStateUpdate = useMemo(() => {
    if (!treeShowsPrev || prevIdx < 1) return s;
    const sched = s.schedule ?? [];
    let lastIdx = -1;
    for (let i = 0; i < sched.length; i++) if (sched[i].phase === prevIdx) lastIdx = i;
    return { ...s, gamePhaseIndex: prevIdx as any, questionIndex: lastIdx >= 0 ? lastIdx : s.questionIndex };
  }, [treeShowsPrev, s, prevIdx]);

  // 2026-05-04 (Wolf): Watermark-Wolf unten in PhaseIntro entfernt — er hopt
  // schon oben auf dem Progress-Tree, ein zweiter Wolf war redundant.
  const showWolfMark = false;

  // 2026-05-07 (Wolf-ESC): Pro-Draft PhaseIntro-BG-Bild (z.B. Eurovision-
  // Logo-BG hinter 'Halbfinale 1'). Fallback: lobbyBackgroundUrl.
  const phaseIntroBgUrl = s.theme?.phaseIntroBackgroundUrl ?? s.theme?.lobbyBackgroundUrl;

  return (
    <div style={{
      flex: 1, display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center',
      position: 'relative', overflow: 'hidden',
    }}>
      {phaseIntroBgUrl && (
        <div
          aria-hidden
          style={{
            position: 'absolute', inset: 0,
            backgroundImage: `url(${phaseIntroBgUrl})`,
            backgroundSize: 'cover',
            backgroundPosition: 'center',
            backgroundRepeat: 'no-repeat',
            // 2026-05-07 (Wolf 'BG kaum sichtbar'): screen-Blend raus, 0.32 ->
            // 0.5. PhaseIntro hat groesseren Title drueber, BG darf etwas
            // dezenter bleiben als Lobby aber muss sichtbar sein.
            opacity: 0.5,
            pointerEvents: 'none',
            zIndex: 0,
          }}
        />
      )}
      <Fireflies color={isFirstOfRound && s.introStep <= 1 ? `${displayColor}88` : `${catColor ?? color}88`} />
      {s.theme?.eurovisionMode && <EurovisionHearts />}

      {showWolfMark && (
        <div style={{
          position: 'absolute',
          bottom: 'clamp(16px, 2.4vh, 36px)',
          left: '50%',
          transform: 'translateX(-50%)',
          width: 'clamp(54px, 6vw, 92px)',
          opacity: 0,
          animation: 'qqPhaseIntroWolfFade 1.4s ease-out 1.4s forwards, qqPhaseIntroWolfBob 4.6s ease-in-out 2.8s infinite',
          filter: `drop-shadow(0 0 18px ${catColor ?? color}55) drop-shadow(0 0 6px ${catColor ?? color}33)`,
          pointerEvents: 'none',
          zIndex: 4,
        }} aria-hidden>
          <AnimatedCozyWolf
            widthCss="100%"
            mode={s.theme?.eurovisionMode ? 'flagge' : undefined}
            speaking={false}
          />
        </div>
      )}
      <style>{`
        @keyframes qqPhaseIntroWolfFade {
          0%   { opacity: 0; transform: translate(-50%, 12px); }
          100% { opacity: 0.7; transform: translate(-50%, 0); }
        }
        @keyframes qqPhaseIntroWolfBob {
          0%, 100% { transform: translate(-50%, 0); }
          50%      { transform: translate(-50%, -6px); }
        }
      `}</style>

      {isFirstOfRound && s.introStep === 0 ? (
        /* ── Step 0: Round announcement (first question only) ── */
        <>
          {/* Round progress pill — Farbe + Text transitionen von prev auf new.
              2026-05-07 (Wolf 'mehr Pink+Blau, Set F'): im ESC-Mode Pille mit
              Pink→Blau-Gradient-BG + zweifarbiger Border statt monochrom. */}
          <div style={{
            padding: '8px 24px', borderRadius: 999,
            background: isEsc
              ? 'linear-gradient(135deg, rgba(255,45,123,0.20) 0%, rgba(59,130,246,0.20) 100%)'
              : `${displayColor}18`,
            border: isEsc
              ? '2px solid rgba(255,45,123,0.55)'
              : `2px solid ${displayColor}44`,
            fontSize: 'clamp(16px, 1.8vw, 24px)', fontWeight: 900,
            color: isEsc ? '#fde6f0' : `${displayColor}cc`,
            letterSpacing: '0.1em',
            marginBottom: 28,
            animation: hasRoundTransition ? undefined : 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.1s both',
            transition: 'background 500ms ease, border-color 500ms ease, color 500ms ease',
            position: 'relative', zIndex: 5,
            boxShadow: isEsc ? '0 0 18px rgba(255,45,123,0.25)' : 'none',
          }}>
            {lang === 'de'
              ? `Runde ${displayGpi} von ${s.totalPhases}`
              : `Round ${displayGpi} of ${s.totalPhases}`}
          </div>

          {/* Shockwave burst behind title — laeuft jetzt auch waehrend
              Round-Transition (Wolf 2026-05-04): in Runde 1 sah man eine
              animierte Welle unter dem Titel, in Runde 2/3/4 fehlte sie.
              Bei aktiver Transition: spaeteres Delay damit's nicht mit dem
              Digit-Flip kollidiert. */}
          <div style={{ position: 'relative', zIndex: 5 }}>
            <div style={{
              position: 'absolute', top: '50%', left: '50%',
              width: 200, height: 200, marginLeft: -100, marginTop: -100,
              borderRadius: '50%',
              border: `3px solid ${displayColor}55`,
              animation: hasRoundTransition
                ? 'roundShockwave 0.8s cubic-bezier(0,0,0.2,1) 2.4s both'
                : 'roundShockwave 0.8s cubic-bezier(0,0,0.2,1) 0.2s both',
              pointerEvents: 'none',
            }} />
            {/* Round name — Ziffer-Flip / Finale-Wort-Roll / BAM.
                overflow:hidden nur waehrend der Transition, sonst bleibt
                ein sichtbares Clip-Rechteck um das FINALE-Wort stehen. */}
            {isFinaleTransition ? (
              <div style={{
                fontFamily: fontFam,
                fontSize: 'clamp(80px, 14vw, 200px)', fontWeight: 900, lineHeight: 1,
                textAlign: 'center',
                position: 'relative', display: 'inline-block',
                overflow: transitioning ? 'hidden' : 'visible',
                // Padding-x fängt Drop-Shadow + letterSpacing-Breite des FINALE-Worts ab,
                // sonst wird das letzte 'E' rechts abgeschnitten.
                padding: '0 0.18em 0.18em',
                animation: 'roundBreathe 4s ease-in-out 2s infinite',
              }}>
                {/* Sizer (unsichtbar) – trägt Breite/Baseline des FINALE-Worts.
                    MUSS dasselbe letterSpacing wie der animierte Span haben, sonst
                    kollabiert der Container. */}
                <span style={{ visibility: 'hidden', letterSpacing: '0.04em' }}>{finaleWord}</span>
                {/* Alte "Runde N" fällt – synchron zur Subtitle-Fall-Animation */}
                <span style={{
                  position: 'absolute', left: 0, top: 0, right: 0, textAlign: 'center',
                  color: prevColor,
                  textShadow: `0 0 120px ${prevColor}33`,
                  animation: 'roundDigitFall 760ms var(--qq-ease-smooth-out) 1150ms both',
                }}>{prevRoundFull}</span>
                {/* FINALE rollt von oben – mit Gold-Gradient */}
                <span style={{
                  position: 'absolute', left: 0, top: 0, right: 0, textAlign: 'center',
                  backgroundImage: 'linear-gradient(180deg, #FBCFE8 0%, #EC4899 45%, #D97706 100%)',
                  WebkitBackgroundClip: 'text',
                  backgroundClip: 'text',
                  WebkitTextFillColor: 'transparent',
                  color: 'transparent',
                  letterSpacing: '0.04em',
                  textShadow: `0 0 80px #EC489955`,
                  filter: 'drop-shadow(0 12px 0 rgba(180,83,9,0.35))',
                  animation: 'roundDigitRoll 820ms cubic-bezier(0.16, 1, 0.3, 1) 1650ms both',
                }}>{finaleWord}</span>
              </div>
            ) : canDigitFlip ? (
              <div style={{
                fontFamily: fontFam,
                fontSize: 'clamp(100px, 18vw, 260px)', fontWeight: 900, lineHeight: 1,
                textShadow: `0 0 120px ${color}33`,
                textAlign: 'center',
                display: 'inline-flex', alignItems: 'baseline', justifyContent: 'center',
                gap: '0.18em',
                animation: 'roundBreathe 4s ease-in-out 2s infinite',
              }}>
                {/* Wort "Runde": 2026-05-04 v4 (Wolf-Bug) — Vorher Gradient-Sweep
                    von Grau→Color, ergab Mismatch-Phase wo Wort schon neue Farbe
                    hatte waehrend Digit noch alte Farbe zeigte. Jetzt: gleiche
                    Color-Logik wie Outer-Digit-Span (prevColor → color) mit 820ms
                    transition. Wort + Neuer Digit fluten IMMER synchron. */}
                <span style={{
                  display: 'inline-block',
                  color: colorTransitioning ? prevColor : color,
                  transition: 'color 820ms ease',
                }}>{titleWord}</span>
                {/* Ziffern-Flip-Container — startet NACH dem Wolf-Hop (Hop landet ~1100ms).
                    overflow:hidden nur waehrend der Transition — sonst bleibt ein
                    sichtbares Clip-Rechteck um die Ziffer stehen. */}
                <span style={{
                  position: 'relative', display: 'inline-block',
                  overflow: transitioning ? 'hidden' : 'visible',
                  paddingBottom: '0.15em',
                  lineHeight: 1,
                  // 2026-05-04 v4 (Wolf): Outer-Span color synchron mit New-Digit-
                  // Roll-In (1650-2470ms). colorTransitioning endet jetzt bei
                  // 1650ms, danach 820ms transition → bei 2470ms voll in neuer
                  // Farbe. Gleiches Timing wie Word "Runde" → kein Mismatch.
                  color: colorTransitioning ? prevColor : color,
                  transition: 'color 820ms ease',
                }}>
                  {/* Unsichtbarer Sizer — trägt die Baseline + Breite des neuen Digits */}
                  <span style={{ visibility: 'hidden' }}>{newDigit}</span>
                  {/* Alte Ziffer fällt — startet, sobald der Wolf gelandet ist */}
                  <span style={{
                    position: 'absolute', left: 0, top: 0, right: 0, textAlign: 'center',
                    color: prevColor,
                    animation: 'roundDigitFall 760ms var(--qq-ease-smooth-out) 1150ms both',
                  }}>{prevDigit}</span>
                  {/* Neue Ziffer rollt von oben */}
                  <span style={{
                    position: 'absolute', left: 0, top: 0, right: 0, textAlign: 'center',
                    animation: 'roundDigitRoll 820ms cubic-bezier(0.16, 1, 0.3, 1) 1650ms both',
                  }}>{newDigit}</span>
                </span>
              </div>
            ) : (
              <div style={{
                fontFamily: fontFam,
                fontSize: 'clamp(100px, 18vw, 260px)', fontWeight: 900, lineHeight: 0.9,
                color,
                // 2026-05-07 v12 (Wolf 'kontrast unleserlich'): bei ESC-Pink-
                // Title auf Pink/Lila/Heart-BG dunkler Halo dazu fuer Lesbarkeit.
                textShadow: isEsc
                  ? `0 4px 22px rgba(0,0,0,0.7), 0 0 120px ${color}44`
                  : `0 0 120px ${color}44`,
                textAlign: 'center',
                animation: 'roundBam 0.65s var(--qq-ease-out-cubic) 0.15s both, roundBreathe 4s ease-in-out 1.2s infinite',
              }}>
                {phaseName}
              </div>
            )}
          </div>

          {/* Divider line with glow + shimmer.
              2026-05-04 v4 (Wolf-Bug 'shimmer fehlt auch in Runde 3+4'):
              Vorher 3s Cycle + 1.0s Delay → bei schnellem Mod-Clicken durch
              Step-0 verpasste Wolf den Shimmer-Pass. Jetzt zwei-Layer-Ansatz:
              - Base-Layer: farbiger Bar (immer sichtbar, kein Shimmer)
              - Overlay-Layer (eigenes div): heller weisser Shimmer-Sweep, 1.8s
                Cycle, no delay → mind. 1 Pass schon waehrend der 2.5s Round-
                Transition garantiert sichtbar. */}
          <div style={{
            width: 'clamp(240px, 35vw, 500px)', height: 5, borderRadius: 3,
            background: `linear-gradient(90deg, transparent, ${displayColor}, transparent)`,
            marginTop: 28, marginBottom: 28,
            transformOrigin: 'center',
            animation: 'roundLineGlow 0.7s var(--qq-ease-bounce) 0.5s both',
            boxShadow: `0 0 20px ${displayColor}55, 0 0 40px ${displayColor}22`,
            transition: 'box-shadow 500ms ease',
            position: 'relative', zIndex: 5,
            overflow: 'hidden',
          }}>
            {/* Heller White-Shimmer-Sweep — laeuft kontinuierlich von links
                nach rechts, garantiert sichtbar in allen Runden. */}
            <div style={{
              position: 'absolute', inset: 0,
              background: 'linear-gradient(90deg, transparent 0%, transparent 30%, rgba(255,255,255,0.85) 50%, transparent 70%, transparent 100%)',
              backgroundSize: '200% 100%',
              animation: 'lineShimmer 1.8s linear 0.6s infinite',
              pointerEvents: 'none',
            }} />
          </div>

          {/* Mission subtitle — bei Round-Transition rollt der alte Text raus und der neue rein (synchron zur Ziffer).
              overflow:hidden nur waehrend der Transition, sonst bleibt ein
              Clip-Rechteck um den Subtitle stehen. */}
          {hasRoundTransition ? (
            <div style={{
              fontFamily: fontFam,
              fontSize: 'clamp(36px, 5vw, 68px)', fontWeight: 900,
              textShadow: `0 0 30px ${color}33`,
              position: 'relative', zIndex: 5,
              textAlign: 'center',
              display: 'inline-block',
              overflow: transitioning ? 'hidden' : 'visible',
              paddingBottom: '0.2em',
            }}>
              {/* Sizer (unsichtbar) — trägt die Baseline + Breite des neuen Subtitle */}
              <span style={{ visibility: 'hidden' }}>{phaseDesc}</span>
              {/* Alter Subtitle fällt — synchron zur alten Ziffer */}
              <span style={{
                position: 'absolute', left: 0, right: 0, top: 0, textAlign: 'center',
                color: `${prevColor}dd`,
                animation: 'roundDigitFall 760ms var(--qq-ease-smooth-out) 1150ms both',
              }}>{prevPhaseDesc}</span>
              {/* Neuer Subtitle rollt von oben — synchron zur neuen Ziffer.
                  Farbe folgt dem Wolf-Avatar (colorTransitioning), genau wie
                  der Outer-Digit-Span. */}
              <span style={{
                position: 'absolute', left: 0, right: 0, top: 0, textAlign: 'center',
                color: colorTransitioning ? `${prevColor}dd` : `${color}dd`,
                transition: 'color 600ms ease',
                animation: 'roundDigitRoll 820ms cubic-bezier(0.16, 1, 0.3, 1) 1650ms both',
              }}>{phaseDesc}</span>
            </div>
          ) : (
            <div style={{
              fontFamily: fontFam,
              fontSize: 'clamp(36px, 5vw, 68px)', fontWeight: 900,
              color: `${displayColor}dd`,
              textShadow: `0 0 30px ${displayColor}33`,
              animation: 'subtitleSlide 0.55s var(--qq-ease-bounce) 0.7s both',
              transition: 'color 500ms ease, text-shadow 500ms ease',
              position: 'relative', zIndex: 5,
              textAlign: 'center',
            }}>
              {displayPhaseDesc}
            </div>
          )}

          {/* Fortschrittsbaum — während Transition zeigt er den letzten Dot der
              vorherigen Runde, nach ~450ms swappt er auf die neue Runde →
              Amber-Linie wächst smooth zum ersten Dot rüber. */}
          <div style={{
            marginTop: 36,
            animation: hasRoundTransition ? undefined : 'contentReveal 0.6s var(--qq-ease-pop-fast) 1.0s both',
            position: 'relative', zIndex: 5,
          }}>
            <QQProgressTree state={displayTreeState} variant="inline" />
          </div>
        </>
      ) : isFirstOfRound && s.introStep === 1 ? (
        /* ── Step 1: Rule reminder (what's new this round) ── */
        <>
          {/* Round pill — smaller context */}
          <div style={{
            padding: '6px 20px', borderRadius: 999,
            background: `${color}15`, border: `1.5px solid ${color}33`,
            fontSize: 'clamp(14px, 1.5vw, 20px)', fontWeight: 900,
            color: `${color}aa`, letterSpacing: '0.04em',
            marginBottom: 24,
            animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.1s both',
            position: 'relative', zIndex: 5,
          }}>
            {phaseName}
          </div>

          {/* Big emoji — R3+R4 zeigen Stapel-Pin als Highlight (Trinity-Mechanik) */}
          <div style={{
            fontSize: 'clamp(72px, 12vw, 140px)',
            animation: 'phasePop 0.6s var(--qq-ease-bounce) 0.15s both, cfloat 4s ease-in-out 1s infinite',
            position: 'relative', zIndex: 5,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
          }}>
            {(s.gamePhaseIndex === 3 || s.gamePhaseIndex === 4) ? (
              <QQEmojiIcon emoji="🏯" />
            ) : (
              roundRules.emoji
            )}
          </div>

          {/* "NEU" badge (skip for round 1) */}
          {s.gamePhaseIndex > 1 && (
            <div style={{
              display: 'inline-flex', alignItems: 'center', gap: 8,
              padding: '6px 22px', borderRadius: 999,
              background: `${color}25`, border: `2px solid ${color}55`,
              fontSize: 'clamp(18px, 2vw, 28px)', fontWeight: 900,
              color, letterSpacing: '0.1em', textTransform: 'uppercase',
              marginTop: 20, marginBottom: 8,
              animation: 'phasePop 0.5s var(--qq-ease-bounce) 0.3s both',
              position: 'relative', zIndex: 5,
            }}>
              {lang === 'de' ? '✨ NEU' : '✨ NEW'}
            </div>
          )}

          {/* Aktionen-Bereich — kleiner Header, dann Karten als Hauptinhalt.
              Vorher: zwei dicke Textzeilen mit redundanter Wiederholung der
              Action-Card-Subtexte. Jetzt: Cards sprechen fuer sich. */}
          <div style={{
            display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 12,
            marginTop: s.gamePhaseIndex === 1 ? 24 : 12,
            position: 'relative', zIndex: 5,
          }}>
            {/* Schlankes Label statt riesiger Regel-Texte */}
            <div style={{
              fontSize: 'clamp(13px, 1.4vw, 20px)', fontWeight: 900,
              color: `${color}cc`, letterSpacing: '0.1em', textTransform: 'uppercase',
              textAlign: 'center',
              animation: 'phasePop 0.5s var(--qq-ease-bounce) 0.4s both',
            }}>
              {(() => {
                // Erste Regel-Zeile als Untertitel — sie beschreibt das Was kompakt.
                const lead = (lang === 'en' ? roundRules.en : roundRules.de)[0];
                return lead;
              })()}
            </div>
            {/* Action-Cards mit explizitem Counter (×N) pro Aktion. Cards werden je
                nach Runde dynamisch zusammengestellt — eine Wahl pro richtige
                Antwort. Limits (max X pro Runde / Spiel) als Footer-Pill je Card. */}
            {(() => {
              type ActionCardData = {
                count: number;
                emoji?: string;
                slug?: 'marker-sanduhr' | 'marker-shield' | 'marker-swap';
                label: string;
                limit?: string;
                accent: string;
                /** 2026-05-09 (Wolf): in dieser Runde NEU verfügbar — kriegt
                 *  einen 3D-Card-Reveal (Slam face-down → Flip), damit der
                 *  Moment „neue Fähigkeit ist da" episch wirkt. */
                isNew?: boolean;
              };
              const ph = s.gamePhaseIndex;
              // 2026-04-28 (User-Wunsch): 'Platzieren'-Card nur anzeigen wenn
              // noch freie Felder im Grid existieren (sonst irreführend in
              // Runde 3/4 wenn Brett voll ist).
              const hasFreeCells = s.grid.some(row => row.some(c => !c.ownerId));
              const placeCard: ActionCardData | null = hasFreeCells
                ? (ph === 1
                    // 2026-05-09 (Wolf): Place ist in R1 brandneu für die Spieler →
                    // soll auch flippen wie die NEW-Cards in R2/R3.
                    ? { count: 1, emoji: '📍', label: lang === 'en' ? 'Place' : 'Platzieren', accent: color, isNew: true }
                    : ph === 2
                    ? { count: 2, emoji: '📍', label: lang === 'en' ? 'Place' : 'Platzieren', accent: color }
                    : { count: 2, emoji: '📍', label: lang === 'en' ? 'Place' : 'Platzieren',
                        limit: lang === 'en' ? 'while free cells' : 'wenn Feld frei',
                        accent: color })
                : null;
              const cards: ActionCardData[] = ph === 1
                ? (placeCard ? [placeCard] : [])
                : ph === 2
                ? [
                    ...(placeCard ? [placeCard] : []),
                    { count: 1, emoji: '⚡', label: lang === 'en' ? 'Steal' : 'Klauen',
                      limit: lang === 'en' ? 'max 2x per round' : 'max 2x pro Runde',
                      accent: '#EF4444', isNew: true },
                  ]
                : ph === 3
                ? [
                    ...(placeCard ? [placeCard] : []),
                    { count: 1, emoji: '⚡', label: lang === 'en' ? 'Steal' : 'Klauen', accent: '#EF4444' },
                    { count: 1, emoji: '🏯', label: lang === 'en' ? 'Stack' : 'Stapeln',
                      limit: lang === 'en' ? '+1 pt · max 3 per game' : '+1 Pkt · max 3 pro Spiel',
                      accent: '#06B6D4', isNew: true },
                  ]
                : ph === 4
                ? [
                    ...(placeCard ? [placeCard] : []),
                    { count: 1, emoji: '⚡', label: lang === 'en' ? 'Steal' : 'Klauen', accent: '#EF4444' },
                    { count: 1, emoji: '🏯', label: lang === 'en' ? 'Stack' : 'Stapeln',
                      limit: lang === 'en' ? '+1 pt · max 3 per game' : '+1 Pkt · max 3 pro Spiel',
                      accent: '#06B6D4' },
                  ]
                : [];
              // Cards alle gleich gross + mittig + prominent. Statt 'compact-Modus'
              // bei vielen Cards behalten wir EINE Groesse und lassen flex die Breite
              // gleich verteilen. align-items: stretch sorgt fuer gleiche Hoehen.
              const oder = lang === 'en' ? 'or' : 'oder';
              const cardCount = cards.length;
              // Single-Card → zentriert mit max-Breite, multi → flex evenly
              // 2026-04-30 v3 round 8 (User-Wunsch 'cards aufploppen nacheinander
              // damit ich moderieren kann'): pro Card gestaffelter Delay 1.5s,
              // erste Card bei 0.85s. „oder"-Separator pop'pt 100ms vor naechster
              // Card. Sound (playActionMenuReveal) pro Card synchron im
              // separaten useEffect (siehe oben am Beginn der Komponente).
              const cardStaggerMs = 1500;
              const cardBaseMs = 850;
              return (
                <div style={{
                  flex: 1, minHeight: 0,
                  marginTop: 'clamp(20px, 3vh, 40px)',
                  display: 'flex', flexDirection: 'row', flexWrap: 'wrap',
                  alignItems: 'stretch', justifyContent: 'center',
                  gap: 'clamp(10px, 1.6vw, 24px)',
                  width: '100%', maxWidth: 1700,
                }}>
                  {cards.map((c, i) => {
                    const iconSize = 'clamp(72px, 8.5vw, 132px)';
                    const iconNode = c.slug
                      ? <QQIcon slug={c.slug} size={iconSize} alt={c.label} />
                      : <QQEmojiIcon emoji={c.emoji ?? '?'} />;
                    // Bei isNew: längerer Delay für die epische 3D-Slam+Flip
                    // Choreo. Sonst Standard-Stagger.
                    const cardDelayMs = c.isNew
                      ? cardBaseMs + i * cardStaggerMs + 600  // extra Build-up
                      : cardBaseMs + i * cardStaggerMs;
                    const sepDelayMs = cardDelayMs - 100; // separator kurz vor card
                    // Card-Inhalt (Front-Side bei isNew, sonst direkter Render)
                    const cardInner = (
                      <div style={{
                        width: '100%', height: '100%',
                        display: 'flex', flexDirection: 'column', alignItems: 'center',
                        justifyContent: 'center',
                        gap: 'clamp(8px, 1.2vh, 16px)',
                        padding: 'clamp(20px, 2.4vh, 36px) clamp(20px, 2vw, 32px)',
                        borderRadius: 24,
                        background: `linear-gradient(180deg, ${c.accent}28, ${c.accent}10)`,
                        border: `3px solid ${c.accent}aa`,
                        boxShadow: `0 0 40px ${c.accent}44, 0 8px 28px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.08)`,
                        boxSizing: 'border-box',
                      }}>
                        {/* Card-Inhalt — wird gleich unten als Children eingefügt */}
                      </div>
                    );
                    void cardInner;

                    return (
                      <Fragment key={i}>
                        {i > 0 && (
                          <div style={{
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            fontSize: 'clamp(15px, 1.6vw, 22px)',
                            fontWeight: 900, color: '#94a3b8',
                            letterSpacing: '0.1em', textTransform: 'uppercase',
                            flex: '0 0 auto',
                            animation: `phasePop 0.4s var(--qq-ease-bounce) ${sepDelayMs / 1000}s both`,
                          }}>{oder}</div>
                        )}
                        {c.isNew ? (
                          // 2026-05-09 (Wolf-Vision): NEUE Aktion mit 3D-Slam+Flip-
                          // Reveal — Card slammt face-down rein (Card-Back mit Cross-
                          // Hatch + NEU-Pattern), settled, flippt zur Vorderseite.
                          // Dieselbe Choreo wie TeamsRevealView (Slot M).
                          <ActionCardReveal
                            cardData={c}
                            iconNode={iconNode}
                            iconSize={iconSize}
                            cardCount={cardCount}
                            lang={lang}
                            startDelayMs={cardDelayMs}
                          />
                        ) : (
                        <div style={{
                          // 2026-05-11 (Wolf 'Cards einheitlich groß UND breit,
                          // deckungsgleich'): Outer-Props matchen ActionCard-
                          // Reveal exakt. minWidth bei multi-card auf 200 lassen
                          // (Cards können dann gleichmäßig schmaler werden bei
                          // 3-Card-Layouts), maxWidth 480.
                          flex: cardCount === 1 ? '0 1 auto' : '1 1 0',
                          minWidth: cardCount === 1 ? 280 : 200,
                          maxWidth: cardCount === 1 ? 480 : 480,
                          minHeight: 360,
                          boxSizing: 'border-box',
                          // 2026-05-11: justifyContent center → space-between.
                          // Plus 3-Reihen-Grid mit Limit-Slot-Spacer wie
                          // ActionCardReveal-Front. Stellt sicher: Hauptinhalt
                          // sitzt bei Cards mit und ohne Pill auf gleicher
                          // vertikaler Achse, Pill (falls vorhanden) am Boden.
                          display: 'flex', flexDirection: 'column', alignItems: 'center',
                          justifyContent: 'space-between',
                          padding: 'clamp(20px, 2.4vh, 36px) clamp(20px, 2vw, 32px)',
                          borderRadius: 24,
                          background: `linear-gradient(180deg, ${c.accent}28, ${c.accent}10)`,
                          border: `3px solid ${c.accent}aa`,
                          boxShadow: `0 0 40px ${c.accent}44, 0 8px 28px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.08)`,
                          animation: `phasePop 0.6s var(--qq-ease-bounce) ${cardDelayMs / 1000}s both`,
                          overflow: 'hidden',
                        }}>
                          {/* Hauptinhalt-Block — zentriert sich vertikal */}
                          <div style={{
                            flex: 1, display: 'flex', flexDirection: 'column',
                            alignItems: 'center', justifyContent: 'center',
                            gap: 'clamp(8px, 1.2vh, 16px)', width: '100%',
                          }}>
                            {/* Icon — gross + drop-shadow als Fokus-Element */}
                            <div style={{
                              fontSize: iconSize,
                              lineHeight: 1,
                              filter: `drop-shadow(0 6px 18px ${c.accent}55)`,
                            }}>{iconNode}</div>
                            {/* Counter + Label kombiniert — das Hauptinfo-Token */}
                            <div style={{
                              display: 'flex', alignItems: 'baseline',
                              gap: 'clamp(6px, 0.8vw, 12px)',
                              fontWeight: 900, lineHeight: 1,
                              flexWrap: 'wrap', justifyContent: 'center',
                            }}>
                              <span style={{
                                fontSize: 'clamp(36px, 4.2vw, 64px)',
                                color: c.accent,
                                fontVariantNumeric: 'tabular-nums',
                                textShadow: `0 0 22px ${c.accent}88`,
                              }}>{c.count}x</span>
                              <span style={{
                                fontSize: 'clamp(28px, 3.2vw, 48px)',
                                color: '#F1F5F9',
                                letterSpacing: '0.01em',
                              }}>{c.label}</span>
                            </div>
                            {/* Sub-Zeile */}
                            <div style={{
                              fontSize: 'clamp(13px, 1.4vw, 19px)',
                              fontWeight: 700, color: '#cbd5e1',
                              textAlign: 'center', lineHeight: 1.25,
                              opacity: 0.85,
                            }}>
                              {lang === 'en' ? 'per correct answer' : 'pro richtige Antwort'}
                            </div>
                          </div>
                          {/* Limit-Slot — fixed Höhe, immer gerendert (auch
                              ohne Inhalt). Stellt sicher dass Cards mit/ohne
                              Pill exakt gleich aussehen. */}
                          <div style={{
                            flex: '0 0 auto', minHeight: 'clamp(28px, 2.6vh, 36px)',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            marginTop: 4,
                          }}>
                            {c.limit && (
                              <div style={{
                                padding: '5px 14px', borderRadius: 999,
                                background: 'rgba(15,23,42,0.6)',
                                border: `1.5px solid ${c.accent}55`,
                                fontSize: 'clamp(11px, 1.15vw, 15px)',
                                fontWeight: 900, color: '#e2e8f0',
                                whiteSpace: 'nowrap',
                                boxShadow: `0 2px 8px ${c.accent}22`,
                              }}>
                                {c.limit}
                              </div>
                            )}
                          </div>
                        </div>
                        )}
                      </Fragment>
                    );
                  })}
                </div>
              );
            })()}
            {/* (per-Runde Card-Bloecke entfernt — werden durch unified IIFE oben generiert) */}
          </div>
        </>
      ) : s.categoryIsNew ? (
        /* ── Category explanation (first time this category/mechanic appears) ── */
        (() => {
          // Detailed explanations per category (and BUNTE_TUETE sub-kinds)
          const btKind = s.currentQuestion?.bunteTuete?.kind;
          const CAT_INTRO: Record<string, { emoji: string; title: { de: string; en: string }; lines: { de: string[]; en: string[] } }> = {
            SCHAETZCHEN: {
              emoji: catEmoji, title: { de: 'Schätzchen', en: 'Close Call' },
              lines: {
                de: ['Wer am nächsten dran liegt, gewinnt — knapp dran zählt auch.'],
                en: ['Closest guess wins — near misses also count.'],
              },
            },
            MUCHO: {
              emoji: catEmoji, title: { de: 'Mu-Cho', en: 'Mu-Cho' },
              lines: {
                de: ['4 Antworten, 1 richtige. Speed entscheidet.'],
                en: ['4 options, 1 right. Speed decides.'],
              },
            },
            ZEHN_VON_ZEHN: {
              emoji: catEmoji, title: { de: '10 von 10', en: 'All In' },
              lines: {
                de: ['Verteilt 10 Punkte auf 3 Antworten.'],
                en: ['Spread 10 points across 3 answers.'],
              },
            },
            CHEESE: {
              emoji: catEmoji, title: { de: 'Schau mal!', en: 'Picture This' },
              lines: {
                de: ['Erkennt das Bild — tippt die Antwort ins Handy.'],
                en: ['Spot the image — type your answer.'],
              },
            },
            // BUNTE_TUETE sub-mechanics
            'BUNTE_TUETE:top5': {
              emoji: '🏆', title: { de: 'Top 5', en: 'Top 5' },
              lines: {
                de: ['Bis zu 5 Antworten — meiste Treffer gewinnt.'],
                en: ['Up to 5 answers — most hits wins.'],
              },
            },
            'BUNTE_TUETE:oneOfEight': {
              emoji: '🕵️', title: { de: 'Imposter', en: 'Imposter' },
              lines: {
                de: ['Unter 8 Aussagen ist eine falsch. Findet sie.'],
                en: ['One of 8 statements is false. Find it.'],
              },
            },
            'BUNTE_TUETE:order': {
              emoji: '📊', title: { de: 'Reihenfolge', en: 'Order' },
              lines: {
                de: ['Sortiert richtig — meiste Treffer gewinnt.'],
                en: ['Sort correctly — most hits wins.'],
              },
            },
            'BUNTE_TUETE:map': {
              emoji: '🗺️', title: { de: 'CozyGuessr', en: 'CozyGuessr' },
              lines: {
                de: ['Tippt den Ort auf der Karte — nächstes Team gewinnt.'],
                en: ['Pin the spot on the map — closest team wins.'],
              },
            },
            'BUNTE_TUETE:hotPotato': {
              emoji: '🥔', title: { de: 'Heiße Kartoffel', en: 'Hot Potato' },
              lines: {
                de: ['Reihum antworten — keine Antwort vor Zeitende = raus'],
                en: ['Take turns — no answer before time runs out = out'],
              },
            },
            'BUNTE_TUETE:onlyConnect': {
              emoji: '🧩', title: { de: '4 gewinnt', en: 'Only Connect' },
              lines: {
                de: ['4 Begriffe — was verbindet sie? Ein Tipp pro Team, schnellste richtige Antwort gewinnt zuerst.'],
                en: ['4 terms — what connects them? One guess per team, fastest correct answer wins first.'],
              },
            },
            'BUNTE_TUETE:bluff': {
              emoji: '🎭', title: { de: 'Bluff', en: 'Bluff' },
              lines: {
                de: ['Erfindet plausible Falsch-Antworten und ratet die echte.'],
                en: ['Invent plausible fake answers — then spot the real one.'],
              },
            },
          };

          const key = cat === 'BUNTE_TUETE' && btKind ? `BUNTE_TUETE:${btKind}` : (cat ?? '');
          const info = CAT_INTRO[key] ?? CAT_INTRO[cat ?? ''];
          if (!info) return null;

          return (
            <>
              {/* Category pill — zwei Zeilen: Runde + Fragen-Fortschritt */}
              <div style={{
                display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 4,
                padding: '8px 22px', borderRadius: 16,
                background: `${catColor}15`, border: `1.5px solid ${catColor}33`,
                color: `${catColor}aa`, letterSpacing: '0.04em',
                marginBottom: 16,
                animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.1s both',
                position: 'relative', zIndex: 5,
              }}>
                <div style={{
                  fontSize: 'clamp(11px, 1.2vw, 16px)', fontWeight: 900,
                  opacity: 0.8, textTransform: 'uppercase',
                }}>
                  {lang === 'de' ? `Runde ${s.gamePhaseIndex}` : `Round ${s.gamePhaseIndex}`}
                </div>
                <div style={{
                  fontSize: 'clamp(14px, 1.5vw, 20px)', fontWeight: 900,
                }}>
                  {lang === 'de' ? `Frage ${questionInPhase} von 5` : `Question ${questionInPhase} of 5`}
                </div>
              </div>

              {/* Runden-Mini-Tree mit Wolf-Hop — zeigt Position innerhalb der aktuellen Runde */}
              <div style={{
                marginBottom: 20,
                animation: 'phasePop 0.5s var(--qq-ease-bounce) 0.12s both',
                position: 'relative', zIndex: 5,
              }}>
                <RoundMiniTree state={s} catColor={catColor} />
              </div>

              {/* Big emoji/icon — bevorzugt PNG, sonst Emoji-Fallback */}
              <div style={{
                fontSize: 'clamp(72px, 12vw, 140px)', lineHeight: 1,
                animation: 'phasePop 0.6s var(--qq-ease-bounce) 0.15s both, qqCatNameWave 2.8s ease-in-out 1.4s infinite',
                position: 'relative', zIndex: 5,
              }}>
                {(() => {
                  const subSlug = btKind ? qqSubSlug(btKind) : null;
                  const catSlug = cat ? qqCatSlug(cat as string) : null;
                  // 2026-05-11 (Wolf): bei Bunte-Tüte-Subs ohne PNG NICHT auf
                  // cat-bunte-tuete-PNG fallback (wäre 🎁), sondern Sub-Emoji
                  // aus info.emoji rendern.
                  const slug = btKind ? subSlug : catSlug;
                  return slug
                    ? <QQIcon slug={slug} size={'clamp(110px, 16vw, 200px)'} alt={info.title.de} />
                    : info.emoji;
                })()}
              </div>

              {/* Category/mechanic name — 3D-Stack-Look + smoothe per-Buchstabe
                  Wave (Wolf-Wunsch 2026-05-04). Wave statt qqCatTitleBreathe-
                  scale: einzelne Buchstaben in Span-Wrappern, 0.07s Stagger
                  ergibt die klassische Ocean-Wave-Geste. */}
              <div style={{
                fontFamily: fontFam,
                fontSize: 'clamp(56px, 10vw, 160px)', fontWeight: 900, lineHeight: 1,
                color: catColor,
                textShadow:
                  `0 0 14px ${catColor}99, ` +
                  `0 0 40px ${catColor}55, ` +
                  `0 0 96px ${catColor}33, ` +
                  `0 5px 0 rgba(0,0,0,0.45), ` +
                  `0 14px 28px rgba(0,0,0,0.55)`,
                marginTop: 12,
                animation: 'phasePop 0.7s var(--qq-ease-bounce) 0.3s both',
                position: 'relative', zIndex: 5,
                textAlign: 'center',
                letterSpacing: '-0.005em',
                willChange: 'text-shadow',
              }}>
                {Array.from(info.title[lang]).map((ch, i) => (
                  <span
                    key={i}
                    style={{
                      display: 'inline-block',
                      whiteSpace: ch === ' ' ? 'pre' : undefined,
                      // Wave startet erst NACH der Entry-Pop-Animation (~1.2s),
                      // damit phasePop-scale und Wave-translate sich nicht in
                      // die Quere kommen. Stagger pro Buchstabe von dort.
                      animation: 'qqCatNameWave 2.8s ease-in-out infinite',
                      animationDelay: `${1.2 + i * 0.07}s`,
                    }}
                  >{ch}</span>
                ))}
              </div>

              {/* Explanation lines */}
              <div style={{
                display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 10,
                marginTop: 24, position: 'relative', zIndex: 5,
              }}>
                {info.lines[lang].map((line, i) => (
                  <div key={i} style={{
                    fontSize: i === 0 ? 'clamp(26px, 3.5vw, 48px)' : 'clamp(20px, 2.5vw, 36px)',
                    fontWeight: i === 0 ? 800 : 600,
                    color: i === 0 ? '#F1F5F9' : `${catColor}99`,
                    textAlign: 'center',
                    animation: `phasePop 0.6s var(--qq-ease-bounce) ${0.5 + i * 0.15}s both`,
                  }}>
                    {line}
                  </div>
                ))}
              </div>

              {/* User-Wunsch 2026-04-28: 'Antwort auf dem Handy' Hint überall
                  raus — auf dem Beamer redundant, auf dem Handy doppelt. */}
            </>
          );
        })()
      ) : (
        /* ── Category reveal (no explanation needed — already seen) ── */
        <>
          {/* Question progress: "Frage 2 von 5" + Runden-Mini-Tree mit Wolf */}
          <div style={{
            display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 14,
            marginBottom: 28,
            animation: 'phasePop 0.5s var(--qq-ease-bounce) 0.1s both',
            position: 'relative', zIndex: 5,
          }}>
            <div style={{
              display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 2,
            }}>
              <div style={{
                fontSize: 'clamp(13px, 1.6vw, 20px)', fontWeight: 900,
                color: `${catColor}99`, letterSpacing: '0.1em', textTransform: 'uppercase',
              }}>
                {lang === 'de' ? `Runde ${s.gamePhaseIndex}` : `Round ${s.gamePhaseIndex}`}
              </div>
              <div style={{
                fontSize: 'clamp(22px, 2.8vw, 36px)', fontWeight: 900,
                color: catColor, letterSpacing: '0.1em',
              }}>
                {lang === 'de' ? `Frage ${questionInPhase} von 5` : `Question ${questionInPhase} of 5`}
              </div>
            </div>
            <RoundMiniTree state={s} catColor={catColor} />
          </div>

          {cat && (
            <>
              {/* Emoji/Icon — float idle. Bei BUNTE_TUETE: Sub-Mechanik-Icon
                  (sonst sähen 4 gewinnt, Bluff, Hot Potato … alle gleich aus). */}
              {/* 2026-05-05 (Wolf 'Bounce sync zum Wave'): cfloat 4s → qqCatNameWave
                  2.8s mit Delay 1.4s = Mitte der Title-Wave-Cascade. */}
              <div style={{
                fontSize: 'clamp(80px, 14vw, 180px)', lineHeight: 1,
                animation: 'phasePop 0.7s var(--qq-ease-bounce) 0.25s both, qqCatNameWave 2.8s ease-in-out 1.4s infinite',
                position: 'relative', zIndex: 5,
              }}>
                {(() => {
                  const subSlug = bunteKind ? qqSubSlug(bunteKind) : null;
                  // 2026-05-11 (Wolf): bei Bunte-Tüte-Subs ohne PNG NICHT auf
                  // cat-bunte-tuete-PNG fallback. catEmoji ist hier bereits
                  // korrekt das Sub-Emoji (🧩/🎭/🕵️) via bunteSub.emoji.
                  const slug = bunteKind ? subSlug : qqCatSlug(cat as string);
                  if (slug) return <QQIcon slug={slug} size={'clamp(120px, 18vw, 240px)'} alt={catLabel} />;
                  return catEmoji;
                })()}
              </div>

              {/* Category name — per-Buchstabe Wave (Wolf-Wunsch 2026-05-04:
                  Wave bei ALLEN Cat-Branches, nicht nur cat-intro). */}
              <div style={{
                fontFamily: fontFam,
                fontSize: 'clamp(68px, 13vw, 200px)', fontWeight: 900, lineHeight: 1,
                color: catColor,
                textShadow: `0 0 80px ${catColor}44`,
                marginTop: 12,
                animation: 'phasePop 0.7s var(--qq-ease-bounce) 0.4s both',
                position: 'relative', zIndex: 5,
                textAlign: 'center',
              }}>
                {Array.from(catLabel).map((ch, i) => (
                  <span
                    key={i}
                    style={{
                      display: 'inline-block',
                      whiteSpace: ch === ' ' ? 'pre' : undefined,
                      animation: 'qqCatNameWave 2.8s ease-in-out infinite',
                      animationDelay: `${1.3 + i * 0.07}s`,
                    }}
                  >{ch}</span>
                ))}
              </div>

              {/* Category explanation — 1 line.
                  2026-05-05 (Wolf 'Schriftart komisch, an restl. App anpassen'):
                  Caveat-Cursive raus → inherit (Nunito) für Konsistenz mit
                  Rest der App. Size/Weight angepasst auf Standard-Sub-Headline. */}
              {catExplain && (
                <div style={{
                  fontSize: 'clamp(22px, 2.6vw, 36px)', fontWeight: 700,
                  color: `${catColor}cc`,
                  letterSpacing: '0.02em',
                  marginTop: 14,
                  animation: 'phasePop 0.6s var(--qq-ease-bounce) 0.65s both',
                  position: 'relative', zIndex: 5,
                  textAlign: 'center',
                }}>
                  {catExplain}
                </div>
              )}
            </>
          )}
        </>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// TEAM ANSWER REVEAL — shared block rendered in right panel
// ═══════════════════════════════════════════════════════════════════════════════
function TeamAnswerReveal({ s, q, lang, cardBg, accent }: {
  s: QQStateUpdate; q: NonNullable<QQStateUpdate['currentQuestion']>;
  lang: 'de' | 'en'; cardBg: string; accent: string;
}) {
  if (!s.answers.length) return null;
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
      {/* Schätzchen — target banner + estimates with delta bars */}
      {q.category === 'SCHAETZCHEN' && (() => {
        const scored = [...s.answers].map(a => {
          const num = Number(a.text.replace(/[^0-9.,\-]/g, '').replace(',', '.'));
          const team = s.teams.find(t => t.id === a.teamId);
          const distance = Number.isNaN(num) || q.targetValue == null ? Infinity : Math.abs(num - q.targetValue);
          return { ...a, num, distance, team };
        }).sort((a, b) => a.distance - b.distance);
        const maxDistance = Math.max(1, ...scored.filter(s => Number.isFinite(s.distance)).map(s => s.distance));
        // 2026-05-10 (Wolf-Bug 'EN-Spiel zeigt DE-unit'): EN-Fallback ergänzt.
        const unitStr = (lang === 'en' && (q as any).unitEn ? (q as any).unitEn : (q as any).unit) ?? '';
        // Jahreszahlen ohne Tausenderpunkt — sonst sieht 1500 wie 1,5 aus.
        // Auto-Detection: int zwischen 1000-2100 sieht aus wie eine Jahreszahl.
        // (User-Bug 2026-04-28: '1.914' erschien weil unit nicht 'Jahr' war.)
        const looksLikeYear = (n: number) => Number.isInteger(n) && n >= 1000 && n <= 2100;
        // 2026-05-07 (Wolf): explizites isYearAnswer-Flag aus Builder hat
        // Vorrang vor unit-String-Heuristik. Auto-Detection bleibt als
        // Fallback fuer aeltere Drafts ohne Flag.
        const isYearUnit = !!q.isYearAnswer || /jahr|year/i.test(unitStr) || (q.targetValue != null && looksLikeYear(q.targetValue));
        const targetStr = q.targetValue != null
          ? (isYearUnit ? String(Math.round(q.targetValue)) : q.targetValue.toLocaleString('de-DE'))
          : '—';
        return (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10, animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.1s both' }}>
            {/* Target banner */}
            <div style={{
              padding: '14px 20px', borderRadius: 16,
              background: 'linear-gradient(135deg, rgba(236,72,153,0.22), rgba(236,72,153,0.10))',
              border: '2px solid rgba(236,72,153,0.55)',
              boxShadow: '0 0 0 3px rgba(236,72,153,0.12), 0 8px 24px rgba(0,0,0,0.3)',
              display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 14,
              animation: 'revealAnswerBam 0.55s var(--qq-ease-out-cubic) both',
            }}>
              <span style={{ fontSize: 'clamp(22px, 2.6vw, 34px)' }}><QQEmojiIcon emoji="🎯"/></span>
              <span style={{
                fontSize: 'clamp(14px, 1.4vw, 18px)', fontWeight: 900,
                color: '#FBCFE8', letterSpacing: '0.1em', textTransform: 'uppercase',
              }}>{lang === 'en' ? 'Target' : 'Lösung'}</span>
              <span style={{
                fontSize: 'clamp(30px, 4vw, 56px)', fontWeight: 900,
                color: '#EC4899',
                textShadow: '0 2px 12px rgba(236,72,153,0.45)',
              }}>
                {targetStr}{unitStr ? ` ${unitStr}` : ''}
              </span>
            </div>

            {/* Estimates list with delta bars */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
              {scored.map((a, i) => {
                const isWinner = i === 0;
                const pct = Number.isFinite(a.distance) ? (a.distance / maxDistance) * 100 : 100;
                const distStr = Number.isFinite(a.distance)
                  ? `Δ ${isYearUnit ? String(Math.round(a.distance)) : a.distance.toLocaleString('de-DE')}${unitStr ? ` ${unitStr}` : ''}`
                  : '—';
                return (
                  <div key={a.teamId} style={{
                    position: 'relative', overflow: 'hidden',
                    padding: '10px 14px', borderRadius: 16,
                    background: isWinner
                      ? 'linear-gradient(135deg, rgba(34,197,94,0.14), rgba(22,163,74,0.06))'
                      : 'rgba(255,255,255,0.035)',
                    border: isWinner ? '2px solid rgba(34,197,94,0.55)' : '1.5px solid rgba(255,255,255,0.08)',
                    boxShadow: isWinner ? '0 0 0 3px rgba(34,197,94,0.12)' : 'none',
                    animation: `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.2 + i * 0.08}s both`,
                  }}>
                    {/* Distance bar (background) */}
                    {Number.isFinite(a.distance) && (
                      <div style={{
                        position: 'absolute', left: 0, top: 0, bottom: 0,
                        width: `${100 - pct}%`,
                        background: isWinner
                          ? 'linear-gradient(90deg, rgba(34,197,94,0.22), rgba(34,197,94,0.04))'
                          : `linear-gradient(90deg, ${a.team?.color ?? '#64748b'}30, transparent)`,
                        transition: 'width 0.8s var(--qq-ease-out-cubic)',
                      }} />
                    )}
                    <div style={{ position: 'relative', display: 'flex', alignItems: 'center', gap: 12 }}>
                      <span style={{
                        width: 'clamp(26px, 2.8vw, 34px)', height: 'clamp(26px, 2.8vw, 34px)',
                        borderRadius: 8,
                        background: isWinner ? 'linear-gradient(135deg,#EC4899,#EC4899)' : 'rgba(100,116,139,0.25)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        fontSize: 'clamp(12px, 1.3vw, 16px)', fontWeight: 900, color: '#fff',
                        flexShrink: 0,
                      }}>
                        {isWinner ? <QQEmojiIcon emoji="🥇"/> : `#${i + 1}`}
                      </span>
                      {a.team && (
                        <QQTeamAvatar avatarId={a.team.avatarId} teamEmoji={a.team.emoji} size={'clamp(28px, 3vw, 38px)'} style={{ flexShrink: 0 }} />
                      )}
                      <span style={{
                        fontWeight: 900, fontSize: 'clamp(14px, 1.5vw, 20px)',
                        color: a.team?.color ?? '#e2e8f0', flex: '0 1 auto',
                      }}>{a.team?.name ?? a.teamId}</span>
                      <span style={{
                        flex: 1, textAlign: 'right',
                        fontSize: 'clamp(18px, 2.2vw, 30px)', fontWeight: 900,
                        color: isWinner ? '#4ade80' : '#e2e8f0',
                      }}>
                        {a.text}{unitStr ? ` ${unitStr}` : ''}
                      </span>
                      <span style={{
                        minWidth: 'clamp(64px, 8vw, 110px)', textAlign: 'right',
                        fontFamily: "'Caveat', cursive",
                        fontSize: 'clamp(14px, 1.5vw, 20px)',
                        color: isWinner ? '#86efac' : '#64748b', fontWeight: 700,
                      }}>
                        {distStr}
                      </span>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        );
      })()}

      {/* MUCHO: who chose which option */}
      {q.category === 'MUCHO' && q.options && (() => {
        const correctVoters = q.correctOptionIndex != null
          ? s.answers
              .filter(a => a.text === String(q.correctOptionIndex))
              .sort((a, b) => a.submittedAt - b.submittedAt)
          : [];
        const showSpeedRank = correctVoters.length > 1;
        const speedRank: Record<string, number> = {};
        correctVoters.forEach((a, i) => { speedRank[a.teamId] = i + 1; });
        const t0 = s.timerEndsAt ? s.timerEndsAt - (s.timerDurationSec * 1000) : (correctVoters[0]?.submittedAt ?? 0);
        const MUCHO_COLORS = ['#3B82F6', '#EF4444', '#EC4899', '#22C55E'];

        return (
          <div style={{ animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.1s both', display: 'flex', flexDirection: 'column', gap: 8 }}>
            {q.options!.map((optText, optIdx) => {
              const voters = s.answers
                .filter(a => a.text === String(optIdx))
                .sort((a, b) => a.submittedAt - b.submittedAt)
                .map(a => ({ team: s.teams.find(t => t.id === a.teamId), answer: a }))
                .filter((v): v is { team: NonNullable<typeof v.team>; answer: typeof v.answer } => !!v.team);
              const isCorrect = optIdx === q.correctOptionIndex;
              const optColor = MUCHO_COLORS[optIdx] ?? '#475569';
              return (
                <div key={optIdx} style={{
                  display: 'flex', alignItems: 'stretch', gap: 0,
                  borderRadius: 16, overflow: 'hidden',
                  background: isCorrect ? 'rgba(34,197,94,0.12)' : 'rgba(255,255,255,0.035)',
                  border: isCorrect ? '2px solid rgba(34,197,94,0.55)' : '1.5px solid rgba(255,255,255,0.08)',
                  boxShadow: isCorrect ? '0 0 0 3px rgba(34,197,94,0.12)' : 'none',
                  animation: `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.1 + optIdx * 0.07}s both`,
                  minHeight: 54,
                }}>
                  <div style={{
                    width: 'clamp(44px, 5vw, 64px)', background: optColor,
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: 'clamp(18px, 2.2vw, 28px)', fontWeight: 900, color: '#fff',
                    flexShrink: 0,
                  }}>
                    {['A','B','C','D'][optIdx] ?? optIdx + 1}
                  </div>
                  <div style={{
                    flex: 1, padding: '8px 14px',
                    display: 'flex', alignItems: 'center', gap: 14, flexWrap: 'wrap',
                  }}>
                    <span style={{
                      fontSize: 'clamp(14px, 1.6vw, 20px)', fontWeight: 900,
                      color: isCorrect ? '#86efac' : '#cbd5e1',
                      minWidth: 0, flex: '0 1 auto',
                    }}>
                      {optText}
                    </span>
                    {voters.length > 0 && (
                      <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap', marginLeft: 'auto' }}>
                        {voters.map(({ team: tm }, vi) => (
                          <div key={tm.id} style={{
                            display: 'flex', alignItems: 'center', gap: 6,
                            padding: '4px 10px 4px 4px', borderRadius: 999,
                            background: 'rgba(0,0,0,0.28)',
                            border: `1.5px solid ${tm.color}`,
                            animation: `contentReveal 0.3s var(--qq-ease-pop-fast) ${vi * 0.08}s both`,
                          }}>
                            <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(26px, 3vw, 36px)'} />
                            <span style={{ fontSize: 'clamp(12px, 1.3vw, 16px)', fontWeight: 900, color: tm.color }}>{tm.name}</span>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              );
            })}

            {/* Speed ranking row for correct voters (ties) */}
            {showSpeedRank && (
              <div style={{
                marginTop: 6, padding: '10px 14px', borderRadius: 16,
                background: 'linear-gradient(135deg, rgba(236,72,153,0.12), rgba(234,179,8,0.06))',
                border: '1.5px solid rgba(236,72,153,0.35)',
                display: 'flex', alignItems: 'center', gap: 12, flexWrap: 'wrap',
                animation: `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.1 + q.options!.length * 0.07 + 0.1}s both`,
              }}>
                <span style={{
                  fontSize: 'clamp(12px, 1.2vw, 15px)', fontWeight: 900,
                  color: '#EC4899', letterSpacing: '0.04em', textTransform: 'uppercase',
                }}><QQEmojiIcon emoji="⚡"/> Schnellster zuerst</span>
                {correctVoters.map((a, i) => {
                  const tm = s.teams.find(t => t.id === a.teamId);
                  if (!tm) return null;
                  const timeSec = t0 ? ((a.submittedAt - t0) / 1000).toFixed(1) : null;
                  const rank = i + 1;
                  return (
                    <div key={tm.id} style={{
                      display: 'flex', alignItems: 'center', gap: 6,
                      padding: '4px 10px', borderRadius: 999,
                      background: rank === 1 ? 'rgba(236,72,153,0.22)' : 'rgba(0,0,0,0.28)',
                      border: rank === 1 ? '1.5px solid rgba(236,72,153,0.6)' : `1.5px solid ${tm.color}`,
                    }}>
                      <span style={{
                        fontSize: 'clamp(12px, 1.2vw, 15px)', fontWeight: 900,
                        color: rank === 1 ? '#EC4899' : '#cbd5e1',
                      }}>#{rank}</span>
                      <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(16px, 1.9vw, 22px)'} />
                      <span style={{ fontSize: 'clamp(12px, 1.3vw, 16px)', fontWeight: 900, color: tm.color }}>{tm.name}</span>
                      {timeSec && (
                        <span style={{ fontSize: 'clamp(11px, 1.1vw, 14px)', fontWeight: 700, color: '#94a3b8' }}>{timeSec}s</span>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        );
      })()}

      {/* ZEHN_VON_ZEHN (All-In): stacked bar per option — who put how many points */}
      {q.category === 'ZEHN_VON_ZEHN' && q.options && (() => {
        const ALLIN_COLORS = ['#3B82F6','#22C55E','#EF4444'];
        // Parse each answer to per-option point arrays
        const parsed = s.answers.map(a => {
          const pts = String(a.text ?? '').split(',').map(x => parseInt(x.trim(), 10));
          return { teamId: a.teamId, pts, submittedAt: a.submittedAt };
        }).filter(p => p.pts.length === q.options!.length && !p.pts.some(Number.isNaN));
        // Total points per option across all teams
        const totalsPerOption = q.options!.map((_, i) => parsed.reduce((sum, p) => sum + (p.pts[i] ?? 0), 0));
        const globalMax = Math.max(1, ...totalsPerOption);

        // Gewinner-Bestimmung: höchster Einsatz auf der korrekten Option, bei Tie → schnellste Einreichung gewinnt.
        const correctIdx = q.correctOptionIndex;
        let winner: { team: (typeof s.teams)[number]; pts: number; submittedAt: number; hasTie: boolean; correctOptText: string } | null = null;
        if (correctIdx != null) {
          const onCorrect = parsed
            .map(p => ({ team: s.teams.find(t => t.id === p.teamId), pts: p.pts[correctIdx] ?? 0, submittedAt: p.submittedAt }))
            .filter((x): x is { team: (typeof s.teams)[number]; pts: number; submittedAt: number } => !!x.team && x.pts > 0);
          if (onCorrect.length > 0) {
            const maxPts = Math.max(...onCorrect.map(x => x.pts));
            const topPts = onCorrect.filter(x => x.pts === maxPts);
            topPts.sort((a, b) => a.submittedAt - b.submittedAt);
            winner = {
              team: topPts[0].team,
              pts: topPts[0].pts,
              submittedAt: topPts[0].submittedAt,
              hasTie: topPts.length > 1,
              correctOptText: q.options![correctIdx] ?? '',
            };
          }
        }

        return (
          <div style={{ animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.1s both', display: 'flex', flexDirection: 'column', gap: 10 }}>
            {winner && (
              <div style={{
                display: 'flex', alignItems: 'center', gap: 14,
                padding: 'clamp(10px, 1.2vh, 16px) clamp(14px, 1.6vw, 22px)',
                borderRadius: 16,
                background: `linear-gradient(135deg, ${winner.team.color}22, rgba(34,197,94,0.18))`,
                border: `2px solid ${winner.team.color}55`,
                boxShadow: `0 0 0 3px ${winner.team.color}22`,
                animation: 'revealWinnerIn 0.6s var(--qq-ease-bounce) both',
              }}>
                <QQTeamAvatar avatarId={winner.team.avatarId} teamEmoji={winner.team.emoji} size={'clamp(44px, 4.5vw, 60px)'} style={{ flexShrink: 0, boxShadow: `0 0 20px ${winner.team.color}55` }} />
                <div style={{ flex: 1, minWidth: 0, display: 'flex', flexDirection: 'column', gap: 2 }}>
                  <div style={{
                    fontSize: 'clamp(11px, 1vw, 14px)', fontWeight: 900, color: '#94a3b8',
                    letterSpacing: '0.1em', textTransform: 'uppercase',
                  }}>
                    <QQEmojiIcon emoji="🏆"/> {lang === 'en' ? 'Round winner' : 'Rundensieger'}
                  </div>
                  <div style={{
                    fontSize: 'clamp(16px, 1.9vw, 26px)', fontWeight: 900,
                    color: '#F1F5F9', lineHeight: 1.2,
                  }}>
                    <span style={{ color: winner.team.color }}>{winner.team.name}</span>{' '}
                    {winner.hasTie
                      ? (lang === 'en'
                          ? <>has the most points on <b>{winner.correctOptText}</b> <span style={{ color: '#4ade80' }}>(+{winner.pts})</span> and was fastest.</>
                          : <>hat die meisten Punkte auf <b>{winner.correctOptText}</b> <span style={{ color: '#4ade80' }}>(+{winner.pts})</span> und war am schnellsten.</>)
                      : (lang === 'en'
                          ? <>has the most points on <b>{winner.correctOptText}</b> <span style={{ color: '#4ade80' }}>(+{winner.pts})</span>.</>
                          : <>hat die meisten Punkte auf <b>{winner.correctOptText}</b> <span style={{ color: '#4ade80' }}>(+{winner.pts})</span>.</>)}
                  </div>
                </div>
              </div>
            )}
            {q.options!.map((optText, optIdx) => {
              const isCorrectLocked = optIdx === q.correctOptionIndex;
              const isHunterHere = false;
              const showGreen = isCorrectLocked || isHunterHere;
              const color = showGreen ? '#22C55E' : (ALLIN_COLORS[optIdx] ?? '#64748b');
              const highestTeamIds = new Set<string>();
              const highestHidden = false;
              // Team contributions on this option (only teams with >0 pts), sorted desc
              const contribs = parsed
                .map(p => ({ team: s.teams.find(t => t.id === p.teamId), pts: p.pts[optIdx] ?? 0 }))
                .filter((c): c is { team: NonNullable<typeof c.team>; pts: number } => !!c.team && c.pts > 0)
                .sort((a, b) => b.pts - a.pts);
              const totalPts = totalsPerOption[optIdx];
              // Visible contribs (vor Cascade: höchste Bets sind noch versteckt)
              const visibleContribs = highestHidden
                ? contribs.filter(c => !highestTeamIds.has(c.team.id))
                : contribs;
              const visibleTotal = visibleContribs.reduce((s, c) => s + c.pts, 0);
              const displayTotal = highestHidden ? visibleTotal : totalPts;
              const barPct = (displayTotal / globalMax) * 100;
              return (
                <div key={optIdx} style={{
                  borderRadius: 16, overflow: 'hidden',
                  background: isCorrectLocked ? 'rgba(34,197,94,0.22)'
                    : isHunterHere ? 'rgba(34,197,94,0.14)'
                    : 'rgba(255,255,255,0.035)',
                  border: showGreen ? '2px solid #22C55E' : '1.5px solid rgba(255,255,255,0.08)',
                  boxShadow: isCorrectLocked ? '0 0 44px rgba(34,197,94,0.48), 0 0 90px rgba(34,197,94,0.18)'
                    : isHunterHere ? '0 0 28px rgba(34,197,94,0.45)'
                    : 'none',
                  transform: isHunterHere ? 'scale(1.015)' : 'scale(1)',
                  transition: 'background 0.25s ease, border-color 0.25s ease, box-shadow 0.25s ease, transform 0.25s ease',
                  animation: isCorrectLocked
                    ? 'revealCorrectPop 0.6s var(--qq-ease-bounce) both'
                    : `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.1 + optIdx * 0.08}s both`,
                }}>
                  {/* Row 1: label + total */}
                  <div style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '10px 14px' }}>
                    <span style={{
                      width: 'clamp(36px, 4vw, 52px)', height: 'clamp(36px, 4vw, 52px)',
                      borderRadius: 8, background: color,
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      fontSize: 'clamp(16px, 1.9vw, 24px)', fontWeight: 900, color: '#fff',
                      flexShrink: 0,
                      boxShadow: showGreen ? '0 0 16px rgba(34,197,94,0.6)' : 'none',
                      transition: 'background 0.3s ease, box-shadow 0.3s ease',
                    }}>
                      {optIdx + 1}
                    </span>
                    <span style={{
                      flex: 1,
                      fontSize: 'clamp(15px, 1.7vw, 22px)', fontWeight: 900,
                      color: isCorrectLocked ? '#86efac' : '#e2e8f0',
                    }}>
                      {optText}
                    </span>
                    <span style={{
                      fontSize: 'clamp(18px, 2.2vw, 30px)', fontWeight: 900,
                      color: isCorrectLocked ? '#4ade80' : color,
                      minWidth: 56, textAlign: 'right',
                      transition: 'color 0.3s ease',
                    }}>
                      💰 {displayTotal}
                    </span>
                  </div>
                  {/* Row 2: stacked bar — each segment = one team's contribution */}
                  <div style={{
                    height: 28, position: 'relative', margin: '0 14px 10px',
                    borderRadius: 8, overflow: 'hidden',
                    background: 'rgba(0,0,0,0.35)',
                    width: `${barPct}%`,
                    transition: 'width 0.7s var(--qq-ease-out-cubic)',
                    display: 'flex',
                  }}>
                    {contribs.map((c, ci) => {
                      const isHighest = highestTeamIds.has(c.team.id);
                      const hidden = highestHidden && isHighest;
                      const segPct = displayTotal > 0 ? (c.pts / displayTotal) * 100 : 0;
                      if (hidden) return null;
                      const justRevealed = isHighest;
                      return (
                        <div key={c.team.id} style={{
                          width: `${segPct}%`,
                          background: c.team.color,
                          borderRight: ci < contribs.length - 1 ? '2px solid rgba(0,0,0,0.4)' : 'none',
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                          gap: 4, minWidth: 0, overflow: 'hidden',
                          fontSize: 'clamp(11px, 1.1vw, 14px)', fontWeight: 900, color: '#fff',
                          textShadow: '0 1px 2px rgba(0,0,0,0.6)',
                          animation: justRevealed
                            ? 'muchoVoterDrop 0.55s cubic-bezier(0.34,1.5,0.64,1) both'
                            : `contentReveal 0.5s var(--qq-ease-pop-fast) ${0.2 + optIdx * 0.08 + ci * 0.05}s both`,
                        }}>
                          <QQTeamAvatar avatarId={c.team.avatarId} teamEmoji={c.team.emoji} size={'clamp(14px, 1.5vw, 18px)'} />
                          <span>{c.pts}</span>
                        </div>
                      );
                    })}
                  </div>
                </div>
              );
            })}

            {/* Legend: teams */}
            {parsed.length > 0 && (
              <div style={{
                marginTop: 2, padding: '8px 14px', borderRadius: 8,
                background: 'rgba(255,255,255,0.03)',
                border: '1px solid rgba(255,255,255,0.06)',
                display: 'flex', alignItems: 'center', gap: 12, flexWrap: 'wrap',
                animation: `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.1 + q.options!.length * 0.08 + 0.1}s both`,
              }}>
                <span style={{
                  fontSize: 'clamp(11px, 1vw, 13px)', fontWeight: 900, color: '#64748b',
                  letterSpacing: '0.04em', textTransform: 'uppercase',
                }}>Teams</span>
                {s.teams.map(tm => {
                  const p = parsed.find(x => x.teamId === tm.id);
                  const earned = p && q.correctOptionIndex != null ? (p.pts[q.correctOptionIndex] ?? 0) : 0;
                  return (
                    <div key={tm.id} style={{
                      display: 'flex', alignItems: 'center', gap: 6,
                      padding: '3px 10px', borderRadius: 999,
                      background: 'rgba(0,0,0,0.28)',
                      border: `1.5px solid ${tm.color}`,
                    }}>
                      <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={22} />
                      <span style={{ fontSize: 'clamp(11px, 1.1vw, 14px)', fontWeight: 900, color: tm.color }}>{tm.name}</span>
                      <span style={{
                        fontSize: 'clamp(11px, 1.1vw, 14px)', fontWeight: 900,
                        color: earned > 0 ? '#4ade80' : '#64748b',
                      }}>+{earned}</span>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        );
      })()}

      {/* CHEESE: typed answers with speed for ties — step-based reveal */}
      {/* 2026-05-02 (Phone-Beamer-Audit): isWinner via currentQuestionWinners
          (Backend-Truth) - sonst kriegen Schreibfehler-akzeptierte Teams kein
          gruenes Highlight in der Step-Liste. */}
      {q.category === 'CHEESE' && (() => {
        const sorted = [...s.answers].sort((a, b) => a.submittedAt - b.submittedAt);
        const t0 = s.timerEndsAt ? s.timerEndsAt - (s.timerDurationSec * 1000) : (sorted[0]?.submittedAt ?? 0);
        const winnerSet = new Set(s.currentQuestionWinners ?? (s.correctTeamId ? [s.correctTeamId] : []));
        const hasTie = winnerSet.size > 1;
        // 2026-05-06 (Wolf 'reveal slow→fast Winner, Sync mit Sound-Cascade'):
        // Winner-Avatare droppen mit 850ms Stagger in der Reihenfolge slowest→
        // fastest (= submittedAt DESC). Schnellster Winner zuletzt = Climax-
        // Moment, synchron zum playRevealHighlight-Sound. Non-Winner-Avatare
        // droppen sofort am Anfang (nicht Teil der Cascade).
        const winnerSlowToFast = [...s.answers]
          .filter(a => winnerSet.has(a.teamId))
          .sort((a, b) => b.submittedAt - a.submittedAt)
          .map(a => a.teamId);
        return (
          <div style={{ animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.1s both', display: 'flex', flexDirection: 'column', gap: 8 }}>
            {sorted.map((a, i) => {
              const team = s.teams.find(t => t.id === a.teamId);
              const isWinner = winnerSet.has(a.teamId);
              const timeSec = t0 ? ((a.submittedAt - t0) / 1000).toFixed(1) : null;
              if (!team) return null;
              const greenOn = isWinner;
              const avatarsOn = true;
              const winnerCascadeIdx = isWinner ? winnerSlowToFast.indexOf(a.teamId) : -1;
              // 850ms Stagger fuer Winner (sync zur Sound-Cascade), 0s fuer
              // Non-Winner (sind sofort sichtbar). 0.85 statt 0.16 frueher.
              const avatarDelay = avatarsOn
                ? (isWinner ? winnerCascadeIdx * 0.85 : 0)
                : 0;
              return (
                <div key={a.teamId} style={{
                  display: 'flex', alignItems: 'stretch', gap: 0,
                  borderRadius: 16, overflow: 'hidden',
                  background: greenOn ? 'rgba(34,197,94,0.14)' : 'rgba(255,255,255,0.035)',
                  border: greenOn ? '2px solid rgba(34,197,94,0.55)' : '1.5px solid rgba(255,255,255,0.08)',
                  boxShadow: greenOn ? '0 0 0 3px rgba(34,197,94,0.12)' : 'none',
                  animation: `contentReveal 0.45s var(--qq-ease-pop-fast) ${0.1 + i * 0.08}s both`,
                  minHeight: 60,
                  transition: 'background 0.35s ease, border-color 0.35s ease, box-shadow 0.35s ease',
                  position: 'relative',
                }}>
                  {/* Shimmer overlay bei Grün-Enthüllung */}
                  {greenOn && (
                    <div aria-hidden style={{
                      position: 'absolute', inset: 0, pointerEvents: 'none',
                      background: 'linear-gradient(90deg, transparent 0%, rgba(255,255,255,0.28) 50%, transparent 100%)',
                      animation: 'revealShimmer 1s ease 0.05s 1 both',
                    }} />
                  )}
                  <div style={{
                    width: 'clamp(60px, 6.5vw, 90px)',
                    background: greenOn ? 'linear-gradient(135deg,#22C55E,#16A34A)' : `${team.color}30`,
                    borderRight: `2px solid ${greenOn ? 'rgba(34,197,94,0.5)' : team.color + '50'}`,
                    display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
                    flexShrink: 0, gap: 2,
                    transition: 'background 0.35s ease, border-color 0.35s ease',
                  }}>
                    {avatarsOn
                      ? (
                        <div style={{ animation: `muchoVoterDrop 0.55s cubic-bezier(0.34,1.5,0.64,1) ${avatarDelay}s both` }}>
                          <QQTeamAvatar avatarId={team.avatarId} teamEmoji={team.emoji} size={'clamp(22px, 2.6vw, 34px)'} />
                        </div>
                      )
                      : (
                        <span style={{
                          width: 'clamp(22px, 2.6vw, 34px)', height: 'clamp(22px, 2.6vw, 34px)',
                          borderRadius: '50%',
                          background: 'rgba(255,255,255,0.08)',
                          border: '1.5px dashed rgba(255,255,255,0.22)',
                        }} />
                      )
                    }
                    <span style={{ fontSize: 'clamp(10px, 1vw, 13px)', fontWeight: 900, color: greenOn ? '#fff' : team.color, letterSpacing: 0.3 }}>
                      {team.name}
                    </span>
                  </div>
                  <div style={{
                    flex: 1, padding: '10px 16px',
                    display: 'flex', alignItems: 'center', gap: 12,
                    position: 'relative',
                  }}>
                    <span style={{
                      flex: 1,
                      fontSize: 'clamp(18px, 2.4vw, 32px)', fontWeight: 900,
                      color: greenOn ? '#86efac' : '#e2e8f0',
                      lineHeight: 1.2,
                      transition: 'color 0.35s ease',
                    }}>
                      {a.text || '—'}
                    </span>
                    {hasTie && timeSec && avatarsOn && (
                      <span style={{
                        padding: '4px 10px', borderRadius: 999,
                        background: i === 0 && isWinner ? 'rgba(236,72,153,0.22)' : 'rgba(0,0,0,0.28)',
                        border: i === 0 && isWinner ? '1.5px solid rgba(236,72,153,0.6)' : '1px solid rgba(255,255,255,0.1)',
                        fontSize: 'clamp(11px, 1.1vw, 14px)', fontWeight: 900,
                        color: i === 0 && isWinner ? '#EC4899' : '#94a3b8',
                        whiteSpace: 'nowrap',
                        animation: `contentReveal 0.3s var(--qq-ease-pop-fast) ${avatarDelay + 0.2}s both`,
                      }}>
                        {i === 0 && isWinner ? '⚡ ' : ''}{timeSec}s
                      </span>
                    )}
                    {greenOn && (
                      <span style={{
                        fontSize: 'clamp(20px, 2.4vw, 30px)', color: '#4ade80', fontWeight: 900,
                        animation: 'revealCorrectPop 0.45s var(--qq-ease-bounce) both',
                      }}>✓</span>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        );
      })()}

      {/* BUNTE TÜTE top5 — answer-centric: list correct answers, pin teams who had each */}
      {q.category === 'BUNTE_TUETE' && (q.bunteTuete as any)?.kind === 'top5' && (() => {
        const btt = q.bunteTuete as any;
        const correctListDE: string[] = (btt.answers ?? []).map((s: string) => s.trim()).filter(Boolean);
        const correctListEN: string[] = (btt.answersEn ?? []).map((s: string) => s.trim()).filter(Boolean);
        const correctList = lang === 'en' && correctListEN.length ? correctListEN : correctListDE;
        // 2026-05-02: Backend-Truth via top5HitsByTeam. Backend matched DE+EN
        // concat (correctAll = correctDE.concat(correctEN)), Indizes 0..N-1 in DE,
        // N..2N-1 in EN. Frontend mappt zurueck auf Display-Sprache.
        const hitsByTeam = s.top5HitsByTeam ?? {};
        // Map: für jede DE-Antwort i, welche Teams haben Index i ODER i+correctListDE.length getroffen?
        const perAnswer = correctList.map((correct, ci) => {
          const deIdx = ci;
          const enIdx = ci + correctListDE.length; // EN-Indizes liegen hinter DE
          const hitters = s.answers
            .filter(a => {
              const teamHits = hitsByTeam[a.teamId] ?? [];
              return teamHits.includes(deIdx) || teamHits.includes(enIdx);
            })
            .map(a => s.teams.find(t => t.id === a.teamId))
            .filter((t): t is NonNullable<typeof t> => !!t);
          return { correct, hitters };
        });
        // Hit-count + ranking summary per team
        const teamScore = s.answers.map(a => ({
          teamId: a.teamId,
          hits: (hitsByTeam[a.teamId] ?? []).length,
        })).sort((a, b) => b.hits - a.hits);

        return (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10, animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.1s both' }}>
            {/* The 5 correct answers */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
              {perAnswer.map(({ correct, hitters }, i) => (
                <div key={i} style={{
                  display: 'flex', alignItems: 'center', gap: 12,
                  padding: '10px 14px', borderRadius: 16,
                  background: hitters.length > 0
                    ? 'linear-gradient(135deg, rgba(34,197,94,0.12), rgba(22,163,74,0.06))'
                    : 'rgba(255,255,255,0.035)',
                  border: hitters.length > 0 ? '1.5px solid rgba(34,197,94,0.4)' : '1.5px solid rgba(255,255,255,0.08)',
                  animation: `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.1 + i * 0.08}s both`,
                }}>
                  <span style={{
                    width: 'clamp(32px, 3.5vw, 44px)', height: 'clamp(32px, 3.5vw, 44px)',
                    borderRadius: 8,
                    background: hitters.length > 0 ? 'linear-gradient(135deg,#EC4899,#EC4899)' : 'rgba(100,116,139,0.3)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: 'clamp(15px, 1.6vw, 20px)', fontWeight: 900, color: '#fff',
                    flexShrink: 0,
                  }}>
                    #{i + 1}
                  </span>
                  <span style={{
                    flex: 1,
                    fontSize: 'clamp(16px, 1.9vw, 26px)', fontWeight: 900,
                    color: '#F1F5F9',
                  }}>
                    {correct}
                  </span>
                  {hitters.length > 0 ? (
                    <div style={{ display: 'flex', alignItems: 'center', gap: 6, flexWrap: 'wrap' }}>
                      {hitters.map((tm, hi) => (
                        <div key={tm.id} style={{
                          display: 'flex', alignItems: 'center', gap: 5,
                          padding: '3px 10px 3px 3px', borderRadius: 999,
                          background: 'rgba(0,0,0,0.28)',
                          border: `1.5px solid ${tm.color}`,
                          animation: `contentReveal 0.3s var(--qq-ease-pop-fast) ${0.2 + i * 0.08 + hi * 0.05}s both`,
                        }}>
                          <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(24px, 2.8vw, 32px)'} />
                          <span style={{ fontSize: 'clamp(11px, 1.2vw, 14px)', fontWeight: 900, color: tm.color }}>{tm.name}</span>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <span style={{ fontSize: 'clamp(12px, 1.2vw, 15px)', fontWeight: 700, color: '#64748b', fontStyle: 'italic' }}>
                      {lang === 'en' ? 'nobody' : 'niemand'}
                    </span>
                  )}
                </div>
              ))}
            </div>

            {/* Team score summary */}
            <div style={{
              marginTop: 4, padding: '8px 14px', borderRadius: 8,
              background: 'rgba(255,255,255,0.03)',
              border: '1px solid rgba(255,255,255,0.06)',
              display: 'flex', alignItems: 'center', gap: 10, flexWrap: 'wrap',
              animation: `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.1 + correctList.length * 0.08 + 0.1}s both`,
            }}>
              <span style={{
                fontSize: 'clamp(11px, 1vw, 13px)', fontWeight: 900, color: '#64748b',
                letterSpacing: '0.04em', textTransform: 'uppercase',
              }}><QQEmojiIcon emoji="🏆"/> Treffer</span>
              {teamScore.map(ts => {
                const tm = s.teams.find(t => t.id === ts.teamId);
                if (!tm) return null;
                const isWinner = ts.teamId === s.correctTeamId;
                return (
                  <div key={tm.id} style={{
                    display: 'flex', alignItems: 'center', gap: 6,
                    padding: '3px 10px', borderRadius: 999,
                    background: isWinner ? 'rgba(34,197,94,0.18)' : 'rgba(0,0,0,0.28)',
                    border: isWinner ? '1.5px solid rgba(34,197,94,0.6)' : `1.5px solid ${tm.color}`,
                  }}>
                    <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(14px, 1.5vw, 18px)'} />
                    <span style={{ fontSize: 'clamp(11px, 1.1vw, 14px)', fontWeight: 900, color: tm.color }}>{tm.name}</span>
                    <span style={{
                      fontSize: 'clamp(12px, 1.2vw, 15px)', fontWeight: 900,
                      color: isWinner ? '#4ade80' : '#cbd5e1',
                    }}>{ts.hits}/{correctList.length}</span>
                  </div>
                );
              })}
            </div>
          </div>
        );
      })()}

      {/* BUNTE TÜTE order — correct sequence big, per-position stats + team summary */}
      {/* 2026-05-02: Backend-Truth via orderHitsByTeam (per-team boolean[] per position). */}
      {q.category === 'BUNTE_TUETE' && (q.bunteTuete as any)?.kind === 'order' && (() => {
        const btt = q.bunteTuete as any;
        const items: string[] = btt.items ?? [];
        const correctOrder: number[] = btt.correctOrder ?? items.map((_: any, i: number) => i);
        const correctSeq = correctOrder.map((idx: number) => (items[idx] ?? '').trim());
        const orderHits = s.orderHitsByTeam ?? {};
        // Per-position: how many teams got this right
        const perPositionHits = correctSeq.map((_, posIdx) => {
          const hitters = s.answers
            .filter(a => (orderHits[a.teamId] ?? [])[posIdx] === true)
            .map(a => s.teams.find(t => t.id === a.teamId))
            .filter((t): t is NonNullable<typeof t> => !!t);
          return { hitters, total: s.answers.length };
        });
        // Per-team: how many positions correct
        const teamScores = s.answers.map(a => ({
          teamId: a.teamId,
          score: (orderHits[a.teamId] ?? []).filter(Boolean).length,
        })).sort((a, b) => b.score - a.score);

        return (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10, animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.1s both' }}>
            {/* Correct sequence as numbered chain */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
              {correctSeq.map((item, pi) => {
                const { hitters, total } = perPositionHits[pi];
                const allRight = hitters.length === total && total > 0;
                const noneRight = hitters.length === 0;
                return (
                  <div key={pi} style={{
                    display: 'flex', alignItems: 'center', gap: 12,
                    padding: '10px 14px', borderRadius: 16,
                    background: allRight
                      ? 'linear-gradient(135deg, rgba(34,197,94,0.18), rgba(22,163,74,0.08))'
                      : noneRight ? 'rgba(239,68,68,0.08)' : 'rgba(255,255,255,0.04)',
                    border: allRight
                      ? '1.5px solid rgba(34,197,94,0.55)'
                      : noneRight ? '1.5px solid rgba(239,68,68,0.3)' : '1.5px solid rgba(255,255,255,0.08)',
                    animation: `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.1 + pi * 0.08}s both`,
                  }}>
                    <span style={{
                      width: 'clamp(32px, 3.5vw, 44px)', height: 'clamp(32px, 3.5vw, 44px)',
                      borderRadius: 8,
                      background: 'linear-gradient(135deg,#EC4899,#EA580C)',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      fontSize: 'clamp(15px, 1.6vw, 20px)', fontWeight: 900, color: '#fff',
                      flexShrink: 0,
                    }}>
                      {pi + 1}
                    </span>
                    <span style={{
                      flex: 1,
                      fontSize: 'clamp(16px, 1.9vw, 26px)', fontWeight: 900,
                      color: '#F1F5F9',
                    }}>
                      {item}
                    </span>
                    {/* Team avatars who got this position right */}
                    {hitters.length > 0 && (
                      <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                        {hitters.map((tm, hi) => (
                          <QQTeamAvatar key={tm.id} avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(24px, 2.6vw, 32px)'} title={tm.name} style={{
                            marginLeft: hi > 0 ? -6 : 0,
                            boxShadow: '0 2px 6px rgba(0,0,0,0.4)',
                            animation: `contentReveal 0.3s var(--qq-ease-pop-fast) ${0.2 + pi * 0.08 + hi * 0.04}s both`,
                          }} />
                        ))}
                      </div>
                    )}
                    <span style={{
                      minWidth: 44, textAlign: 'right',
                      fontSize: 'clamp(13px, 1.4vw, 17px)', fontWeight: 900,
                      color: allRight ? '#4ade80' : noneRight ? '#f87171' : '#94a3b8',
                    }}>
                      {hitters.length}/{total}
                    </span>
                  </div>
                );
              })}
            </div>

            {/* Team summary bar */}
            <div style={{
              marginTop: 4, padding: '8px 14px', borderRadius: 8,
              background: 'rgba(255,255,255,0.03)',
              border: '1px solid rgba(255,255,255,0.06)',
              display: 'flex', alignItems: 'center', gap: 10, flexWrap: 'wrap',
              animation: `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.1 + correctSeq.length * 0.08 + 0.1}s both`,
            }}>
              <span style={{
                fontSize: 'clamp(11px, 1vw, 13px)', fontWeight: 900, color: '#64748b',
                letterSpacing: '0.04em', textTransform: 'uppercase',
              }}><QQEmojiIcon emoji="🎯"/> Richtige Positionen</span>
              {teamScores.map(ts => {
                const tm = s.teams.find(t => t.id === ts.teamId);
                if (!tm) return null;
                const isWinner = ts.teamId === s.correctTeamId;
                return (
                  <div key={tm.id} style={{
                    display: 'flex', alignItems: 'center', gap: 6,
                    padding: '3px 10px', borderRadius: 999,
                    background: isWinner ? 'rgba(34,197,94,0.18)' : 'rgba(0,0,0,0.28)',
                    border: isWinner ? '1.5px solid rgba(34,197,94,0.6)' : `1.5px solid ${tm.color}`,
                  }}>
                    <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(14px, 1.5vw, 18px)'} />
                    <span style={{ fontSize: 'clamp(11px, 1.1vw, 14px)', fontWeight: 900, color: tm.color }}>{tm.name}</span>
                    <span style={{
                      fontSize: 'clamp(12px, 1.2vw, 15px)', fontWeight: 900,
                      color: isWinner ? '#4ade80' : '#cbd5e1',
                    }}>{ts.score}/{correctSeq.length}</span>
                  </div>
                );
              })}
            </div>
          </div>
        );
      })()}

      {/* BUNTE TÜTE map */}
      {q.category === 'BUNTE_TUETE' && (q.bunteTuete as any)?.kind === 'map' && (() => {
        const btt = q.bunteTuete as any;
        const tLat: number = btt.lat; const tLng: number = btt.lng;
        const scored = [...s.answers].map(a => {
          const parts = a.text.split(',');
          const lat = parseFloat(parts[0]); const lng = parseFloat(parts[1]);
          if (Number.isNaN(lat) || Number.isNaN(lng)) return { ...a, distKm: null };
          const R = 6371;
          const dLat = (lat - tLat) * Math.PI / 180;
          const dLng = (lng - tLng) * Math.PI / 180;
          const aa = Math.sin(dLat / 2) ** 2 + Math.cos(tLat * Math.PI / 180) * Math.cos(lat * Math.PI / 180) * Math.sin(dLng / 2) ** 2;
          return { ...a, distKm: R * 2 * Math.atan2(Math.sqrt(aa), Math.sqrt(1 - aa)) };
        }).sort((a, b) => (a.distKm === null ? 1 : b.distKm === null ? -1 : a.distKm - b.distKm));
        return scored.map((a, i) => {
          const team = s.teams.find(t => t.id === a.teamId);
          const isWinner = a.teamId === s.correctTeamId;
          const distStr = a.distKm === null ? '—' : a.distKm < 1 ? `${Math.round(a.distKm * 1000)} m` : `${a.distKm.toFixed(1)} km`;
          return (
            <div key={a.teamId} style={{
              display: 'flex', alignItems: 'center', gap: 10,
              padding: '7px 12px', borderRadius: 8, marginBottom: 4,
              background: isWinner ? 'rgba(34,197,94,0.08)' : 'rgba(255,255,255,0.03)',
              border: isWinner ? '1px solid rgba(34,197,94,0.2)' : '1px solid rgba(255,255,255,0.05)',
              animation: `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.1 + i * 0.08}s both`,
            }}>
              <span style={{ fontSize: 12, fontWeight: 900, color: i === 0 ? '#60A5FA' : '#475569', width: 20 }}>#{i + 1}</span>
              {team && <QQTeamAvatar avatarId={team.avatarId} teamEmoji={team.emoji} size={18} />}
              <span style={{ fontWeight: 900, color: team?.color ?? '#e2e8f0', flex: 1, fontSize: 13 }}>{team?.name}</span>
              <span style={{ fontFamily: "'Caveat', cursive", fontSize: 15, color: isWinner ? '#4ade80' : '#64748b' }}><QQEmojiIcon emoji="📍"/> {distStr}</span>
            </div>
          );
        });
      })()}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// CozyGuessr Reveal — progressive map reveal (moderator steuert step-by-step)
// ═══════════════════════════════════════════════════════════════════════════════

const QQFitBoundsOnTrigger: React.FC<{ bounds: L.LatLngBounds; trigger: number }> = ({ bounds, trigger }) => {
  const map = useMap();
  useEffect(() => {
    if (bounds.isValid()) {
      // flyToBounds = smoother Cinematic-Zoom (vs. fitBounds = harter Sprung).
      // padding etwas grosszuegiger + duration 1.4s damit die Bewegung als
      // bewusster Move zum Ziel erkennbar ist (Geoguessr-style).
      map.flyToBounds(bounds, { padding: [100, 100], maxZoom: 8, duration: 1.4 });
    }
  }, [trigger]); // eslint-disable-line react-hooks/exhaustive-deps
  return null;
};

// Slow-Zoom-Intro: beim ersten Reveal-Step (showTarget) auf den Zielbereich
// zoomen — startet typischerweise von einem weiten Default-Zoom und gleitet
// rein, wie GeoGuessr-Round-End. Nur einmal beim Mount.
const QQInitialTargetZoom: React.FC<{ lat: number; lng: number }> = ({ lat, lng }) => {
  const map = useMap();
  useEffect(() => {
    const t = window.setTimeout(() => {
      map.flyTo([lat, lng] as any, 6, { duration: 2.0 });
    }, 200);
    return () => window.clearTimeout(t);
  }, []); // eslint-disable-line react-hooks/exhaustive-deps
  return null;
};

const QQMapResizer: React.FC<{ trigger: boolean }> = ({ trigger }) => {
  const map = useMap();
  useEffect(() => {
    const t = window.setTimeout(() => map.invalidateSize(), 60);
    return () => window.clearTimeout(t);
  }, [trigger]); // eslint-disable-line react-hooks/exhaustive-deps
  return null;
};

/**
 * 4 gewinnt / Only Connect — Beamer-Layout für active + reveal.
 *
 * Active:
 *   - Frage oben (z.B. „Was verbindet diese Begriffe?")
 *   - 4 Hint-Slots: aufgedeckte Hinweise farblich, kommende verschleiert
 *   - Aktuell sichtbarer Hint pulsiert leicht
 *   - Team-Status-Reihe unten (✓ wenn correct, ✕ wenn locked, sonst dim)
 *
 * Reveal:
 *   - Antwort prominent in Gold
 *   - Winner-Team mit Avatar + atHintIdx-Badge
 *   - Alle 4 Hints sichtbar
 */
/**
 * Bluff — Beamer-Layout für die 3 Phasen + Reveal.
 *  write:  Frage + „Teams schreiben Bluffs" + Submission-Counter + Avatare ✓
 *  review: Frage + Bluffs in einer Liste + ✕-Buttons (Moderator filtert)
 *  vote:   Frage + Optionen mit Vote-Counter pro Option
 *  reveal: Echte Antwort hervorgehoben + per-Option Avatare die gewählt haben
 *          + per-Bluff-Box wer den Bluff geschrieben hat + Punktevergabe
 */
function BluffBeamerView({ state: s, lang, revealed }: {
  state: QQStateUpdate; lang: 'de' | 'en'; revealed: boolean;
}) {
  const q = s.currentQuestion!;
  const bt = q.bunteTuete as import('../../../shared/quarterQuizTypes').QQBunteTueteBluff;
  const phase = s.bluffPhase;
  const accent = '#F472B6'; // pink
  // realText 2026-05-05 entfernt — die Echte-Antwort wird in der neuen
  // Bluff-Tabelle als gruene Real-Card mit ✓ echt-Pille gezeigt, separate
  // Hero-Card war redundant.

  const submitCount = Object.keys(s.bluffSubmissions ?? {}).filter(id => s.bluffSubmissions[id]?.trim()).length;
  const totalActive = s.teams.filter(t => t.connected).length;
  const voteCount = Object.keys(s.bluffVotes ?? {}).length;

  return (
    <div style={{
      flex: 1, display: 'flex', flexDirection: 'column',
      gap: 'clamp(14px, 2vh, 24px)',
      padding: 'clamp(20px, 2.5vh, 36px) clamp(24px, 3vw, 48px) clamp(16px, 2vh, 28px)',
      position: 'relative',
      // 2026-05-09 (Wolf 'gewinnercard bei bluff unten abgeschnitten'): outer
      // braucht min-height: 0 + overflow: hidden, sonst expandiert das innere
      // BluffVoteScreen-grid über die verfügbare Höhe und drückt die Sieger-
      // Card raus aus dem Beamer-Viewport.
      minHeight: 0, overflow: 'hidden',
    }}>
      <Fireflies color={`${accent}55`} />

      {/* Header */}
      <div style={{
        display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between',
        gap: 16, position: 'relative', zIndex: 5,
      }}>
        <div style={{
          display: 'inline-flex', alignItems: 'center', gap: 10,
          padding: '8px 22px', borderRadius: 999,
          background: `${accent}22`, border: `2px solid ${accent}44`,
          backdropFilter: 'blur(8px)', WebkitBackdropFilter: 'blur(8px)',
          animation: 'contentReveal 0.35s var(--qq-ease-pop-fast) both',
        }}>
          <span style={{ fontSize: 'clamp(20px, 2.2vw, 30px)', lineHeight: 1 }}>🎭</span>
          <span style={{
            fontSize: 'clamp(14px, 1.5vw, 20px)', fontWeight: 900,
            color: accent, letterSpacing: '0.1em', textTransform: 'uppercase',
          }}>{lang === 'de' ? 'Bluff' : 'Bluff'}</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          {!revealed && phase && (
            <div style={{
              padding: '8px 16px', borderRadius: 999,
              background: 'rgba(255,255,255,0.05)', border: '1.5px solid rgba(255,255,255,0.12)',
              fontSize: 'clamp(13px, 1.4vw, 18px)', fontWeight: 900, color: '#cbd5e1',
            }}>
              {/* 2026-05-05 (Wolf 'emojis vom style nicht passend, schwarz-weiss'):
                  📝 → ✍️ (bunte writing hand), 🗳 → 🎯 (bullseye, „triff
                  die echte"), 👮 → 🕵️ (Detective, passt thematisch zum
                  Bluff-Detection besser als Polizei-Emoji). */}
              {phase === 'write' && (lang === 'de' ? `✍️ Bluffs schreiben (${submitCount}/${totalActive})` : `✍️ Writing (${submitCount}/${totalActive})`)}
              {phase === 'review' && (lang === 'de' ? `🕵️ Moderator-Check` : `🕵️ Moderator check`)}
              {phase === 'vote' && (lang === 'de' ? `🎯 Abstimmen (${voteCount}/${totalActive})` : `🎯 Voting (${voteCount}/${totalActive})`)}
              {phase === 'reveal' && (lang === 'de' ? `🎉 Auflösung` : `🎉 Reveal`)}
            </div>
          )}
          {phase === 'write' && s.bluffWriteEndsAt && <BluffTimer endsAt={s.bluffWriteEndsAt} accent={accent} />}
          {phase === 'vote' && s.bluffVoteEndsAt && <BluffTimer endsAt={s.bluffVoteEndsAt} accent={accent} />}
        </div>
      </div>

      {/* Frage — 2026-05-09 (Wolf-Konzept-D): kleiner als zuvor, damit Real-Card-
          Hero in der Mitte mehr Platz bekommt. Pre-Reveal bleibt sie groß
          (Frage ist da das Hauptelement), Reveal scaled sie down. */}
      <div style={{
        textAlign: 'center', position: 'relative', zIndex: 5,
        animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.1s both',
      }}>
        <div style={{
          fontSize: phase === 'reveal'
            ? 'clamp(22px, 2.4vw, 38px)'
            : 'clamp(34px, 4vw, 64px)',
          fontWeight: 900,
          color: '#F1F5F9', lineHeight: 1.2, maxWidth: 1100, margin: '0 auto',
          transition: 'font-size 0.5s ease',
        }}>
          {lang === 'en' && q.textEn ? q.textEn : q.text}
        </div>
      </div>

      {/* Phase-spezifischer Inhalt — bei reveal stapeln wir vorher die
          Reveal-Header-Cards (Echte Antwort + Sieger-Pille) damit sie OBEN
          sichtbar sind und das Options-Grid den Rest fuellt. */}
      {phase === 'write' && <BluffWriteScreen state={s} accent={accent} lang={lang} />}
      {phase === 'review' && <BluffReviewScreen state={s} accent={accent} lang={lang} />}
      {phase === 'vote' && <BluffVoteWaitingScreen state={s} accent={accent} lang={lang} />}

      {/* 2026-05-09 (Konzept-D Refactor): Reveal-Layout neu:
          1) Hero-Real-Card mittig (RIESIG, dominantes Element)
          2) Sieger-Banner direkt drunter (compact, eine Reihe)
          3) Mini-Bluff-Pills horizontal unten
          Alles in einer einzigen `BluffRevealHero`-Komponente. */}
      {phase === 'reveal' && <BluffRevealHero state={s} lang={lang} />}

    </div>
  );
}

// 2026-05-09 (Wolf-Konzept-D): Bluff-Reveal komplett neues Layout.
// - Hero-Real-Card riesig in der Mitte (echte Antwort als Star)
// - Sieger-Banner direkt drunter (Avatar + Name + Reinfälle-Pillen, kompakt)
// - Bluffs als horizontale Mini-Pills ganz unten (Author-Avatar + Bluff-Text + Voter-Dots)
function BluffRevealHero({ state: s, lang }: { state: QQStateUpdate; lang: 'de' | 'en' }) {
  const opts = s.bluffOptions ?? [];
  const realOpt = opts.find(o => o.source === 'real');
  const bluffOpts = opts.filter(o => o.source !== 'real');

  // Voters je Option für die Mini-Pills
  const votersByOption: Record<string, string[]> = {};
  for (const [teamId, optId] of Object.entries(s.bluffVotes ?? {})) {
    if (!votersByOption[optId]) votersByOption[optId] = [];
    votersByOption[optId].push(teamId);
  }

  // Sieger-Daten
  const winners = s.currentQuestionWinners ?? [];
  const winnerTeams = winners
    .map(id => s.teams.find(t => t.id === id))
    .filter(Boolean) as typeof s.teams;
  const winnerTeam = winnerTeams[0] ?? null;
  const isCoTie = winnerTeams.length > 1;
  const points = s.bluffPoints ?? {};
  const wPts = winnerTeam ? points[winnerTeam.id] : null;
  const breakdown: Array<{ icon: string; n: number; label: { de: string; en: string }; bg: string }> = [];
  if ((wPts?.foundReal ?? 0) > 0) breakdown.push({ icon: '✅', n: wPts!.foundReal, label: { de: 'echt', en: 'real' }, bg: 'rgba(34,197,94,0.20)' });
  if ((wPts?.blufferBonus ?? 0) > 0) breakdown.push({ icon: '🎭', n: wPts!.blufferBonus, label: { de: 'Reinfälle', en: 'fooled' }, bg: 'rgba(244,114,182,0.20)' });
  if ((wPts?.truthAccident ?? 0) > 0) breakdown.push({ icon: '✨', n: wPts!.truthAccident, label: { de: 'Glück', en: 'lucky' }, bg: 'rgba(236,72,153,0.22)' });

  return (
    <div style={{
      flex: 1, display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center',
      gap: 'clamp(16px, 2vh, 28px)',
      width: '100%', position: 'relative', zIndex: 5,
      padding: '0 clamp(8px, 1.5vw, 24px)',
    }}>
      {/* HERO: Real-Card mittig — riesig, grün, dominantes Element */}
      {realOpt && (
        <div style={{
          maxWidth: 'min(1300px, 92vw)', width: '100%',
          padding: 'clamp(28px, 4vh, 56px) clamp(36px, 4.5vw, 72px)',
          borderRadius: 32,
          background: 'linear-gradient(135deg, rgba(34,197,94,0.28) 0%, rgba(34,197,94,0.08) 100%)',
          border: '3px solid rgba(34,197,94,0.85)',
          boxShadow: '0 0 80px rgba(34,197,94,0.45), 0 14px 40px rgba(0,0,0,0.5)',
          display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 'clamp(10px, 1.4vh, 18px)',
          animation: 'revealAnswerBam 0.7s var(--qq-ease-out-cubic) 0.15s both',
        }}>
          <div style={{
            display: 'inline-flex', alignItems: 'center', gap: 8,
            padding: '5px 16px', borderRadius: 999,
            background: 'rgba(34,197,94,0.35)', border: '1.5px solid #22C55E',
            fontSize: 'clamp(13px, 1.4vw, 18px)', fontWeight: 900,
            color: '#86EFAC', letterSpacing: '0.12em', textTransform: 'uppercase',
          }}>
            ✓ {lang === 'de' ? 'Echte Antwort' : 'Real answer'}
          </div>
          <div style={{
            fontSize: 'clamp(36px, 5.6vw, 88px)', fontWeight: 900,
            color: '#86EFAC', textAlign: 'center', lineHeight: 1.12,
            textShadow: '0 0 32px rgba(34,197,94,0.55)',
            letterSpacing: '-0.01em', maxWidth: '100%', wordBreak: 'break-word',
          }}>
            {realOpt.text}
          </div>
        </div>
      )}

      {/* SIEGER-BANNER direkt unter Hero — kompakt, eine Reihe */}
      {winnerTeam && (
        <div style={{
          maxWidth: 'min(1100px, 90vw)',
          display: 'flex', alignItems: 'center', gap: 'clamp(14px, 1.8vw, 24px)',
          padding: 'clamp(10px, 1.4vh, 18px) clamp(20px, 2.4vw, 36px)',
          borderRadius: 999,
          background: `linear-gradient(135deg, ${winnerTeam.color}33, ${winnerTeam.color}0d)`,
          border: `2.5px solid ${winnerTeam.color}cc`,
          boxShadow: `0 0 36px ${winnerTeam.color}66, 0 6px 18px rgba(0,0,0,0.5)`,
          animation: 'revealWinnerIn 0.55s var(--qq-ease-bounce) 0.5s both',
          flexWrap: 'wrap', justifyContent: 'center',
        }}>
          <span style={{
            padding: '4px 12px', borderRadius: 999,
            background: `linear-gradient(135deg, ${winnerTeam.color}, ${winnerTeam.color}dd)`,
            fontSize: 'clamp(11px, 1.2vw, 15px)', fontWeight: 900,
            color: '#0a1f0d', letterSpacing: '0.12em', textTransform: 'uppercase',
            whiteSpace: 'nowrap',
          }}>
            🎉 {lang === 'de' ? 'Sieger' : 'Winner'}
          </span>
          <div style={{ display: 'flex', alignItems: 'center', gap: 0 }}>
            {winnerTeams.map((tm, idx) => (
              <QQTeamAvatar
                key={tm.id}
                avatarId={tm.avatarId}
                teamEmoji={tm.emoji}
                size={'clamp(44px, 4.6vw, 64px)'}
                style={{
                  boxShadow: `0 0 16px ${tm.color}88, 0 0 0 2px rgba(15,23,42,0.6)`,
                  marginLeft: idx === 0 ? 0 : 'clamp(-10px, -1vw, -6px)',
                  zIndex: winnerTeams.length - idx,
                }}
              />
            ))}
          </div>
          <div style={{ minWidth: 0 }}>
            {isCoTie ? (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
                {winnerTeams.map(tm => (
                  <TeamNameLabel
                    key={tm.id}
                    name={tm.name}
                    maxLines={1}
                    shrinkAfter={18}
                    color={tm.color}
                    fontWeight={900}
                    fontSize="clamp(15px, 1.6vw, 22px)"
                    style={{ lineHeight: 1.15 }}
                  />
                ))}
              </div>
            ) : (
              <TeamNameLabel
                name={winnerTeam.name}
                maxLines={1}
                shrinkAfter={18}
                color={winnerTeam.color}
                fontWeight={900}
                fontSize="clamp(20px, 2.2vw, 30px)"
                style={{ lineHeight: 1.1 }}
              />
            )}
          </div>
          {breakdown.length > 0 && (
            <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
              {breakdown.map((b, i) => (
                <span key={i} title={`${b.n} × ${b.label[lang]}`} style={{
                  padding: '4px 10px', borderRadius: 999,
                  background: b.bg,
                  fontSize: 'clamp(13px, 1.4vw, 17px)', fontWeight: 900, color: '#f1f5f9',
                  whiteSpace: 'nowrap',
                }}>
                  {b.icon} {b.n}
                </span>
              ))}
            </div>
          )}
        </div>
      )}

      {/* MINI-BLUFF-PILLS horizontal — Author-Avatar + Bluff-Text + Voter-Dots */}
      {bluffOpts.length > 0 && (
        <div style={{
          width: '100%', maxWidth: 'min(1500px, 96vw)',
          display: 'flex', flexDirection: 'column',
          alignItems: 'center', gap: 8,
        }}>
          <div style={{
            fontSize: 'clamp(11px, 1.1vw, 14px)', fontWeight: 900,
            color: '#94a3b8', letterSpacing: '0.14em', textTransform: 'uppercase',
            opacity: 0.75,
          }}>
            🎭 {lang === 'de' ? 'Die Bluffs' : 'The bluffs'}
          </div>
          <div style={{
            display: 'flex', flexWrap: 'wrap', justifyContent: 'center',
            gap: 'clamp(8px, 1vw, 14px)',
            width: '100%',
          }}>
            {bluffOpts.map((opt, i) => {
              const contribIds = opt.source === 'team' ? opt.contributors : [];
              const authorTeam = contribIds[0] ? s.teams.find(t => t.id === contribIds[0]) : null;
              const extraAuthors = contribIds.length > 1 ? contribIds.length - 1 : 0;
              const voters = votersByOption[opt.id] ?? [];
              const cardColor = authorTeam?.color ?? '#64748b';
              return (
                <div key={opt.id} style={{
                  display: 'inline-flex', alignItems: 'center',
                  gap: 'clamp(8px, 1vw, 14px)',
                  padding: '8px 16px 8px 10px',
                  borderRadius: 999,
                  background: `${cardColor}1a`,
                  border: `1.5px solid ${cardColor}66`,
                  boxShadow: `0 4px 12px rgba(0,0,0,0.35), 0 0 12px ${cardColor}22`,
                  animation: `contentReveal 0.5s var(--qq-ease-out-cubic) ${0.7 + i * 0.08}s both`,
                  maxWidth: 'min(440px, 90vw)',
                }}>
                  {/* Author-Avatar */}
                  {authorTeam && (
                    <div style={{
                      display: 'inline-flex', alignItems: 'center', flexShrink: 0,
                      position: 'relative',
                    }}>
                      <QQTeamAvatar
                        avatarId={authorTeam.avatarId} teamEmoji={authorTeam.emoji}
                        size={'clamp(28px, 2.8vw, 38px)'}
                        style={{
                          boxShadow: `0 0 8px ${authorTeam.color}77, 0 0 0 2px rgba(15,23,42,0.55)`,
                        }}
                      />
                      {extraAuthors > 0 && (
                        <span style={{
                          position: 'absolute', right: -6, bottom: -4,
                          background: '#0A0814', border: `1.5px solid ${authorTeam.color}`,
                          borderRadius: 999, padding: '1px 5px',
                          fontSize: 9, fontWeight: 900, color: authorTeam.color,
                          lineHeight: 1.1,
                        }}>+{extraAuthors}</span>
                      )}
                    </div>
                  )}
                  {/* Bluff-Text */}
                  <span style={{
                    fontSize: 'clamp(13px, 1.4vw, 18px)', fontWeight: 800,
                    color: '#F1F5F9', overflow: 'hidden',
                    textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                    minWidth: 0, flex: 1,
                  }}>{opt.text}</span>
                  {/* Voter-Dots — kleine Avatare derer die für DIESEN Bluff gestimmt haben */}
                  {voters.length > 0 && (
                    <div style={{
                      display: 'inline-flex', alignItems: 'center', gap: 0,
                      paddingLeft: 8, marginLeft: 4,
                      borderLeft: `1px dashed ${cardColor}55`,
                      flexShrink: 0,
                    }}>
                      {voters.slice(0, 4).map((vid, vi) => {
                        const tm = s.teams.find(t => t.id === vid);
                        if (!tm) return null;
                        return (
                          <QQTeamAvatar
                            key={vid}
                            avatarId={tm.avatarId} teamEmoji={tm.emoji}
                            size={'clamp(20px, 2vw, 28px)'}
                            title={tm.name}
                            style={{
                              boxShadow: `0 0 0 1.5px ${tm.color}, 0 0 0 3px rgba(10,8,20,0.85)`,
                              marginLeft: vi === 0 ? 0 : -8,
                              zIndex: voters.length - vi,
                            }}
                          />
                        );
                      })}
                      {voters.length > 4 && (
                        <span style={{
                          marginLeft: 4,
                          fontSize: 11, fontWeight: 900, color: '#cbd5e1',
                        }}>+{voters.length - 4}</span>
                      )}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

function BluffTimer({ endsAt, accent }: { endsAt: number; accent: string }) {
  const [remaining, setRemaining] = useState(() => Math.max(0, (endsAt - Date.now()) / 1000));
  useEffect(() => {
    const iv = setInterval(() => setRemaining(Math.max(0, (endsAt - Date.now()) / 1000)), 250);
    return () => clearInterval(iv);
  }, [endsAt]);
  const sec = Math.ceil(remaining);
  const urgent = sec <= 10;
  return (
    <div style={{
      padding: '8px 18px', borderRadius: 999,
      background: urgent ? 'rgba(239,68,68,0.22)' : `${accent}22`,
      border: `2px solid ${urgent ? '#EF4444' : `${accent}55`}`,
      fontSize: 'clamp(18px, 2vw, 26px)', fontWeight: 900,
      color: urgent ? '#FCA5A5' : '#F8FAFC', fontVariantNumeric: 'tabular-nums',
      animation: urgent ? 'pulse 0.8s ease-in-out infinite alternate' : undefined,
    }}>
      ⏱ {sec}s
    </div>
  );
}

function BluffWriteScreen({ state: s, accent, lang }: {
  state: QQStateUpdate; accent: string; lang: 'de' | 'en';
}) {
  return (
    <div style={{
      flex: 1, display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center', gap: 24,
      position: 'relative', zIndex: 5,
    }}>
      <div style={{
        fontSize: 'clamp(60px, 8vw, 110px)',
        animation: 'cfloat 4s ease-in-out infinite',
      }}>✍️</div>
      <div style={{
        fontSize: 'clamp(22px, 2.4vw, 34px)', fontWeight: 900,
        color: '#fde68a', textAlign: 'center', lineHeight: 1.3, maxWidth: 1000,
      }}>
        {lang === 'de'
          ? 'Erfindet eine plausible Falsch-Antwort auf eurem Handy!'
          : 'Make up a plausible wrong answer on your phone!'}
      </div>
      {/* Avatar-Reihe — wer hat schon submitted? */}
      <div style={{
        display: 'flex', gap: 'clamp(12px, 1.6vw, 22px)', flexWrap: 'wrap',
        justifyContent: 'center', marginTop: 12,
      }}>
        {s.teams.map(tm => {
          const submitted = !!(s.bluffSubmissions ?? {})[tm.id]?.trim();
          return (
            <div key={tm.id} title={tm.name} style={{
              position: 'relative',
              display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
              opacity: submitted ? 1 : 0.55,
              // 2026-05-05 (Wolf 'in der ganzen App konsistent gruener Glow,
              // nicht ✓-Haekchen' fuer Submit-Status): drop-shadow gruen
              // wenn submitted, sonst grayscale.
              filter: submitted
                ? 'drop-shadow(0 0 10px rgba(34,197,94,0.55)) drop-shadow(0 0 3px rgba(34,197,94,0.4))'
                : 'grayscale(0.4)',
              transition: 'opacity 0.4s ease, filter 0.4s ease',
            }}>
              <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(56px, 6vw, 84px)'} style={{
                background: '#0A0814',
                boxShadow: submitted
                  ? `0 0 0 3px #22C55E, 0 4px 10px rgba(0,0,0,0.55)`
                  : `0 0 0 2px ${tm.color}55, 0 4px 10px rgba(0,0,0,0.55)`,
                transition: 'box-shadow 0.45s ease',
              }} />
            </div>
          );
        })}
      </div>
    </div>
  );
}

function BluffReviewScreen({ state: s, accent, lang }: {
  state: QQStateUpdate; accent: string; lang: 'de' | 'en';
}) {
  void accent;
  const submissions = Object.entries(s.bluffSubmissions ?? {}).filter(([, t]) => t?.trim());
  return (
    <div style={{
      flex: 1, display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center', gap: 14,
      position: 'relative', zIndex: 5,
      padding: 'clamp(16px, 2vh, 28px)',
    }}>
      <div style={{
        fontSize: 'clamp(18px, 2vw, 26px)', fontWeight: 900,
        color: '#94a3b8', textAlign: 'center',
      }}>
        {lang === 'de'
          ? '🕵️ Moderator prüft die Bluffs… Bluffs werden für die Spieler nicht angezeigt.'
          : '🕵️ Moderator reviewing bluffs… not visible to players.'}
      </div>
      <div style={{
        display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
        gap: 10, width: '100%', maxWidth: 1100,
      }}>
        {submissions.map(([teamId, text]) => {
          const tm = s.teams.find(t => t.id === teamId);
          const rejected = (s.bluffRejected ?? []).includes(teamId);
          return (
            <div key={teamId} style={{
              padding: '10px 14px', borderRadius: 16,
              background: rejected ? 'rgba(239,68,68,0.10)' : 'rgba(255,255,255,0.04)',
              border: `1.5px solid ${rejected ? 'rgba(239,68,68,0.4)' : 'rgba(255,255,255,0.08)'}`,
              opacity: rejected ? 0.6 : 1,
              display: 'flex', flexDirection: 'column', gap: 6,
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                {tm && <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={20} />}
                <span style={{
                  fontSize: 11, fontWeight: 900, color: tm?.color ?? '#94a3b8',
                  letterSpacing: '0.04em', textTransform: 'uppercase',
                }}>{tm?.name ?? teamId}</span>
                {rejected && (
                  <span style={{ marginLeft: 'auto', fontSize: 10, color: '#FCA5A5', fontWeight: 900 }}>
                    {lang === 'de' ? 'abgelehnt' : 'rejected'}
                  </span>
                )}
              </div>
              <div style={{
                fontSize: 14, fontWeight: 700,
                color: rejected ? '#FCA5A5' : '#F1F5F9',
                textDecoration: rejected ? 'line-through' : undefined,
                wordBreak: 'break-word',
              }}>{text}</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

/**
 * Vote-Phase auf dem Beamer: KEINE Optionen anzeigen (jedes Team sieht ein
 * eigenes Random-4-Subset auf seinem Phone). Stattdessen großes Voting-
 * Spannungs-Banner + Avatare mit ✓-Status pro Submit.
 */
function BluffVoteWaitingScreen({ state: s, accent, lang }: {
  state: QQStateUpdate; accent: string; lang: 'de' | 'en';
}) {
  const totalActive = s.teams.filter(t => t.connected).length;
  const voted = Object.keys(s.bluffVotes ?? {}).length;
  return (
    <div style={{
      flex: 1, display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center', gap: 24,
      position: 'relative', zIndex: 5,
    }}>
      <div style={{
        fontSize: 'clamp(60px, 8vw, 110px)',
        animation: 'cfloat 4s ease-in-out infinite',
      }}>🎯</div>
      <div style={{
        fontSize: 'clamp(22px, 2.4vw, 34px)', fontWeight: 900,
        color: '#fde68a', textAlign: 'center', lineHeight: 1.3, maxWidth: 1000,
      }}>
        {lang === 'de'
          ? 'Welche Antwort ist die echte? Tippt auf eurem Handy!'
          : 'Which answer is real? Tap on your phone!'}
      </div>
      <div style={{
        padding: '8px 22px', borderRadius: 999,
        background: `${accent}22`, border: `2px solid ${accent}55`,
        fontSize: 'clamp(14px, 1.5vw, 20px)', fontWeight: 900, color: '#fbcfe8',
      }}>
        {lang === 'de' ? `${voted} / ${totalActive} Teams haben gewählt` : `${voted} / ${totalActive} teams voted`}
      </div>
      {/* Avatar-Reihe — wer hat schon gewählt? */}
      <div style={{
        display: 'flex', gap: 'clamp(12px, 1.6vw, 22px)', flexWrap: 'wrap',
        justifyContent: 'center', marginTop: 12,
      }}>
        {s.teams.map(tm => {
          const voted = !!(s.bluffVotes ?? {})[tm.id];
          return (
            <div key={tm.id} title={tm.name} style={{
              position: 'relative',
              display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
              opacity: voted ? 1 : 0.55,
              // 2026-05-05 (Wolf): green-glow statt ✓-Badge fuer Submit-Status.
              filter: voted
                ? 'drop-shadow(0 0 10px rgba(34,197,94,0.55)) drop-shadow(0 0 3px rgba(34,197,94,0.4))'
                : 'grayscale(0.4)',
              transition: 'opacity 0.4s ease, filter 0.4s ease',
            }}>
              <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(56px, 6vw, 84px)'} style={{
                background: '#0A0814',
                boxShadow: voted
                  ? `0 0 0 3px #22C55E, 0 4px 10px rgba(0,0,0,0.55)`
                  : `0 0 0 2px ${tm.color}55, 0 4px 10px rgba(0,0,0,0.55)`,
                transition: 'box-shadow 0.45s ease',
              }} />
            </div>
          );
        })}
      </div>
      <div style={{
        fontSize: 'clamp(11px, 1vw, 13px)', fontWeight: 700,
        color: '#94a3b8', textAlign: 'center', marginTop: 8, opacity: 0.8,
        maxWidth: 700, lineHeight: 1.5,
      }}>
        {lang === 'de'
          ? 'Jedes Team sieht 4 zufällige Antworten — auch die echte. Kein Spickeln vom Beamer!'
          : 'Each team sees 4 random answers — including the real one. No peeking!'}
      </div>
    </div>
  );
}

function BluffVoteScreen({ state: s, accent, lang, revealed }: {
  state: QQStateUpdate; accent: string; lang: 'de' | 'en'; revealed: boolean;
}) {
  void accent;
  const opts = s.bluffOptions ?? [];
  // pro Option: welche Teams haben gewählt?
  const votersByOption: Record<string, string[]> = {};
  for (const [teamId, optId] of Object.entries(s.bluffVotes ?? {})) {
    if (!votersByOption[optId]) votersByOption[optId] = [];
    votersByOption[optId].push(teamId);
  }

  // 2026-05-05 v2 (Wolf-Konzept): Reveal-Layout = GRID mit den neuen Card-Stilen.
  // - 1/2/3 Spalten je nach Antwort-Anzahl
  // - Card-BG = Team-Farbe des Bluff-Authors (Real-Card = grün)
  // - Author-Avatar als halbtransparenter Watermark im BG
  // - Pro Card vertikal: [Letter+Antwort+Pille] obere Reihe, [Voter-Avatare] untere Reihe
  // - Sieger-Card kommt im Parent UNTER der Grid (siehe BluffBeamerView)
  if (revealed) {
    const cols = opts.length >= 6 ? 3 : opts.length >= 4 ? 2 : 1;
    return (
      <div style={{
        // 2026-05-09 (Wolf 'gewinnercard bluff abgeschnitten'): flex 1 1 0 +
        // min-height: 0 + overflow: hidden, damit das Grid bei wenig Platz
        // schrumpft und Sieger-Card unten sichtbar bleibt.
        flex: '1 1 0', minHeight: 0, overflow: 'hidden',
        display: 'grid',
        gridTemplateColumns: `repeat(${cols}, 1fr)`,
        gap: 'clamp(10px, 1.4vh, 18px)',
        maxWidth: cols === 3 ? 1500 : cols === 2 ? 1200 : 900,
        width: '100%', margin: '0 auto',
        position: 'relative', zIndex: 5,
        animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.15s both',
      }}>
        {opts.map((opt, i) => {
          const isReal = opt.source === 'real';
          const voters = votersByOption[opt.id] ?? [];
          const contribIds = opt.source === 'team' ? opt.contributors : [];
          const authorTeam = !isReal && contribIds[0]
            ? s.teams.find(t => t.id === contribIds[0])
            : null;
          const extraAuthors = !isReal && contribIds.length > 1
            ? contribIds.length - 1
            : 0;
          const cardColor = isReal ? '#22C55E' : (authorTeam?.color ?? '#64748b');
          return (
            <div key={opt.id} style={{
              position: 'relative',
              overflow: 'hidden',
              padding: 'clamp(12px, 1.6vh, 22px) clamp(16px, 2vw, 28px)',
              borderRadius: 18,
              background: isReal
                ? `linear-gradient(135deg, ${cardColor}33 0%, ${cardColor}10 100%)`
                : `linear-gradient(135deg, ${cardColor}3a 0%, ${cardColor}10 100%)`,
              border: `2px solid ${cardColor}${isReal ? 'cc' : '99'}`,
              boxShadow: isReal
                ? `0 0 28px ${cardColor}33, 0 6px 16px rgba(0,0,0,0.4)`
                : `0 0 18px ${cardColor}28, 0 6px 14px rgba(0,0,0,0.4)`,
              display: 'flex', flexDirection: 'column', gap: 'clamp(6px, 0.8vh, 10px)',
              // 2026-05-05 (Wolf): minHeight reduziert (110-170 → 90-130) damit
              // leere Cards nicht so viel toten Platz unten haben — gewonnener
              // Raum geht an die Sieger-Card unten.
              minHeight: 'clamp(90px, 11vh, 130px)',
              // 2026-05-07 (Audit P2): phasePop (scale-bounce) skalierte den
              // Watermark-Avatar mit, der schon halbtransparent ist und den
              // doppelten Bounce sichtbar machte. contentReveal (sanftes Slide+
              // Fade) ist jetzt quizweit konsistent (siehe OnlyConnect-Hints,
              // Wolf-Entscheidung 2026-05-06).
              animation: `contentReveal 0.55s var(--qq-ease-out-cubic) ${0.3 + i * 0.08}s both`,
            }}>
              {/* Author-Avatar als BG-Watermark — gross, halbtransparent, hinter
                  dem ganzen Card-Inhalt. Gibt das „Owner-Stempel"-Feeling. */}
              {!isReal && authorTeam && (
                // 2026-05-05 (Wolf-Polish 'emoji groesse + transparenz anpassen'):
                // 14vw → 17vw (groesser), opacity 0.18 → 0.14 (dezenter), blur
                // 1.5 → 0.5 (klarer aber durch opacity weiter im BG).
                <div aria-hidden style={{
                  position: 'absolute',
                  right: 'clamp(-16px, -2vw, -36px)',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  width: 'clamp(150px, 17vw, 240px)',
                  height: 'clamp(150px, 17vw, 240px)',
                  opacity: 0.14,
                  filter: 'blur(0.5px)',
                  pointerEvents: 'none',
                  zIndex: 1,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                }}>
                  <QQTeamAvatar avatarId={authorTeam.avatarId} teamEmoji={authorTeam.emoji} size="100%" flat />
                </div>
              )}

              {/* Top-Row: Letter + Antwort + Pille */}
              <div style={{
                display: 'flex', alignItems: 'center', gap: 'clamp(10px, 1.2vw, 16px)',
                position: 'relative', zIndex: 2,
              }}>
                <span style={{
                  width: 'clamp(28px, 3vw, 38px)', height: 'clamp(28px, 3vw, 38px)',
                  borderRadius: '50%',
                  background: cardColor,
                  color: '#0a1f0d',
                  fontSize: 'clamp(13px, 1.4vw, 18px)', fontWeight: 900,
                  display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                  flexShrink: 0,
                  boxShadow: '0 2px 6px rgba(0,0,0,0.4)',
                }}>{String.fromCharCode(65 + i)}</span>

                <span style={{
                  flex: 1, minWidth: 0,
                  fontSize: 'clamp(20px, 2.2vw, 32px)', fontWeight: 900,
                  color: isReal ? '#86efac' : '#F8FAFC',
                  wordBreak: 'break-word', lineHeight: 1.18,
                  textShadow: isReal
                    ? '0 0 14px rgba(34,197,94,0.4)'
                    : '0 1px 3px rgba(0,0,0,0.5)',
                }}>{opt.text}</span>

                {isReal ? (
                  <span style={{
                    padding: '4px 12px', borderRadius: 999,
                    background: 'rgba(34,197,94,0.3)', border: '1.5px solid #22C55E',
                    fontSize: 'clamp(11px, 1.1vw, 14px)', fontWeight: 900, color: '#86EFAC',
                    whiteSpace: 'nowrap', flexShrink: 0,
                  }}>
                    ✓ {lang === 'de' ? 'echt' : 'real'}
                  </span>
                ) : authorTeam ? (
                  <span style={{
                    padding: '4px 12px', borderRadius: 999,
                    background: `${authorTeam.color}28`, border: `1.5px solid ${authorTeam.color}aa`,
                    fontSize: 'clamp(10px, 1.05vw, 13px)', fontWeight: 900, color: authorTeam.color,
                    whiteSpace: 'nowrap', flexShrink: 0,
                    display: 'inline-flex', alignItems: 'center', gap: 5,
                    maxWidth: '60%',
                  }}>
                    <QQEmojiIcon emoji="🎭"/>
                    <span style={{ overflow: 'hidden', textOverflow: 'ellipsis' }}>
                      {authorTeam.name}{extraAuthors > 0 ? ` +${extraAuthors}` : ''}
                    </span>
                  </span>
                ) : null}
              </div>

              {/* Bottom-Row: Voter-Avatare die diese Antwort gewählt haben.
                  Reservierte Höhe damit Cards ohne Voters genauso hoch sind.
                  2026-05-06 v3 (Wolf 'avatare immernoch mini'): minHeight an
                  70-110px Avatar-Groesse angepasst. */}
              <div style={{
                display: 'flex', alignItems: 'center', gap: 'clamp(10px, 1.1vw, 18px)',
                flexWrap: 'wrap',
                position: 'relative', zIndex: 2,
                paddingTop: voters.length > 0 ? 'clamp(6px, 0.8vh, 10px)' : 0,
                borderTop: voters.length > 0 ? '1px dashed rgba(255,255,255,0.16)' : 'none',
                minHeight: 'clamp(76px, 7.5vw, 116px)',
              }}>
                {voters.length > 0 ? (
                  <>
                    <span style={{
                      // 2026-05-05 (Wolf 'Wählten/keine Stimmen etwas groesser'):
                      // 10-12px → 14-19px. Aus Pub-Distanz lesbar.
                      fontSize: 'clamp(14px, 1.4vw, 19px)', fontWeight: 900,
                      color: '#cbd5e1', letterSpacing: '0.08em', textTransform: 'uppercase',
                      marginRight: 6,
                    }}>
                      {lang === 'de' ? 'Wählten' : 'Voted'}
                    </span>
                    {voters.map((vid, vIdx) => {
                      const tm = s.teams.find(t => t.id === vid);
                      if (!tm) return null;
                      return (
                        <div key={vid} title={tm.name} style={{
                          position: 'relative',
                          animation: `phasePop 0.5s var(--qq-ease-bounce) ${0.45 + i * 0.08 + vIdx * 0.06}s both`,
                        }}>
                          {/* 2026-05-06 v3 (Wolf 'avatare auf den cards sind
                              immernoch mini auch nach 3 Bugfixes'): nochmal
                              deutlich groesser auf 70-110px. flex-wrap im
                              Parent erlaubt 2-Reihen-Layout bei vielen Voters. */}
                          <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(70px, 7vw, 110px)'} style={{
                            boxShadow: isReal
                              ? `0 0 0 3px #22C55E, 0 0 22px rgba(34,197,94,0.6)`
                              : `0 0 0 2.5px ${tm.color}, 0 0 18px ${tm.color}77`,
                            opacity: 0.95,
                          }} />
                          {isReal && (
                            <span aria-hidden style={{
                              position: 'absolute', top: -5, right: -5,
                              width: 18, height: 18, borderRadius: '50%',
                              background: '#22C55E', border: '2px solid #0A0814',
                              display: 'flex', alignItems: 'center', justifyContent: 'center',
                              fontSize: 10, fontWeight: 900, color: '#fff', lineHeight: 1,
                            }}>✓</span>
                          )}
                        </div>
                      );
                    })}
                  </>
                ) : (
                  <span style={{
                    // 2026-05-05 (Wolf): 10-12px → 14-18px.
                    fontSize: 'clamp(14px, 1.3vw, 18px)', fontWeight: 700,
                    color: 'rgba(148,163,184,0.55)', letterSpacing: '0.06em',
                    fontStyle: 'italic',
                  }}>
                    {lang === 'de' ? 'keine Stimmen' : 'no votes'}
                  </span>
                )}
              </div>
            </div>
          );
        })}
      </div>
    );
  }

  // Vote-Phase (nicht-revealed): bleibt beim alten Grid-Layout.
  const cols = opts.length >= 6 ? 3 : opts.length >= 4 ? 2 : 1;
  return (
    <div style={{
      flex: 1, display: 'grid',
      gridTemplateColumns: `repeat(${cols}, 1fr)`,
      gap: 'clamp(8px, 1vw, 14px)',
      maxWidth: cols === 3 ? 1400 : 1100, width: '100%', margin: '0 auto',
      position: 'relative', zIndex: 5,
      animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.15s both',
    }}>
      {opts.map((opt, i) => {
        const voters = votersByOption[opt.id] ?? [];
        return (
          <div key={opt.id} style={{
            padding: 'clamp(12px, 1.4vh, 18px) clamp(14px, 1.6vw, 22px)',
            borderRadius: 16,
            background: 'rgba(255,255,255,0.04)',
            border: '1.5px solid rgba(255,255,255,0.10)',
            display: 'flex', flexDirection: 'column', gap: 8,
          }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
              <span style={{
                width: 28, height: 28, borderRadius: '50%',
                background: 'rgba(255,255,255,0.08)',
                color: '#94a3b8',
                fontSize: 13, fontWeight: 900,
                display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                flexShrink: 0,
              }}>{String.fromCharCode(65 + i)}</span>
              <span style={{
                flex: 1, fontSize: 'clamp(18px, 2vw, 28px)', fontWeight: 900,
                color: '#F1F5F9', wordBreak: 'break-word',
              }}>{opt.text}</span>
            </div>
            {voters.length > 0 && (
              <div style={{
                fontSize: 11, fontWeight: 900, color: '#94a3b8',
                letterSpacing: '0.04em',
              }}>
                {voters.length} {lang === 'de' ? 'Stimme(n)' : 'vote(s)'}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

// 2026-05-09 v2 (Wolf-Reform): Connect 4 — alle 4 Hints sofort sichtbar,
// 1 Tipp pro Team, Reveal mit Lösung + Winner-Card wie CHEESE.
function OnlyConnectBeamerView({ state: s, lang, revealed }: {
  state: QQStateUpdate; lang: 'de' | 'en'; revealed: boolean;
}) {
  const q = s.currentQuestion!;
  const bt = q.bunteTuete as import('../../../shared/quarterQuizTypes').QQBunteTueteOnlyConnect;
  const hintsAll = (lang === 'en' && bt.hintsEn?.length === 4 ? bt.hintsEn : bt.hints) ?? [];
  const answer = formatRevealedAnswer(lang, bt.answer, bt.answerEn);
  const lockedSet = new Set(s.onlyConnectLockedTeams ?? []);
  const accent = '#F87171';
  // 2026-05-09 v2: alle Hints sofort sichtbar; correctSorted nach submittedAt
  // (= Speed) — Reihenfolge der Action-Vergabe analog Standard-Mechaniken.
  const correctSorted = (s.onlyConnectGuesses ?? [])
    .filter(g => g.correct)
    .slice()
    .sort((a, b) => a.submittedAt - b.submittedAt);
  const winnerSet = new Set(s.currentQuestionWinners ?? []);

  // 2026-05-09 v2: Reveal-Choreo CHEESE-style — Lösung-Card slammt zuerst (0.4s),
  // dann Winner-Cards gestaffelt (0.85s + 0.18s pro Team). Sound entsprechend.
  const SOLUTION_DELAY = 0.4;
  const WINNER_BASE = 0.85;
  const WINNER_STEP = 0.18;
  useEffect(() => {
    if (!revealed || s.sfxMuted) return;
    const handles: number[] = [];
    const cascadeTotal = Math.max(2, correctSorted.length + 1);
    handles.push(window.setTimeout(() => {
      try { playRevealHighlight(); } catch {}
    }, Math.max(0, SOLUTION_DELAY * 1000 - 60)));
    correctSorted.forEach((_g, idx) => {
      const delayMs = (WINNER_BASE + idx * WINNER_STEP) * 1000 - 60;
      handles.push(window.setTimeout(() => {
        try { playAvatarCascadeNote(idx + 1, cascadeTotal); } catch {}
      }, Math.max(0, delayMs)));
    });
    return () => handles.forEach(h => window.clearTimeout(h));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [revealed, correctSorted.length, s.sfxMuted]);

  return (
    <div style={{
      flex: 1, display: 'flex', flexDirection: 'column',
      gap: 'clamp(14px, 2vh, 24px)',
      padding: 'clamp(20px, 2.5vh, 36px) clamp(24px, 3vw, 48px) clamp(16px, 2vh, 28px)',
      position: 'relative',
    }}>
      <Fireflies color={`${accent}55`} />

      {/* Header — Pille links, Timer rechts (Wolf 2026-05-04: Hinweis-Counter
          umgezogen ueber die Frage, Timer war vorher gar nicht sichtbar). */}
      <div style={{
        display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between',
        gap: 16, position: 'relative', zIndex: 5,
      }}>
        <div style={{
          display: 'inline-flex', alignItems: 'center', gap: 10,
          padding: '8px 22px', borderRadius: 999,
          background: `${accent}22`, border: `2px solid ${accent}44`,
          backdropFilter: 'blur(8px)', WebkitBackdropFilter: 'blur(8px)',
          animation: 'contentReveal 0.35s var(--qq-ease-pop-fast) both',
        }}>
          <span style={{ fontSize: 'clamp(20px, 2.2vw, 30px)', lineHeight: 1 }}>🧩</span>
          <span style={{
            fontSize: 'clamp(14px, 1.5vw, 20px)', fontWeight: 900,
            color: accent, letterSpacing: '0.1em', textTransform: 'uppercase',
          }}>{lang === 'de' ? '4 gewinnt' : 'Connect 4'}</span>
        </div>
        {/* 2026-05-06 (Konsistenz-Audit S2#4): 'Auflösung'-Pille entfernt —
            keine andere Standard-Kategorie zeigt sie, der Reveal-Modus
            ist eh durch Avatar-Cascade + Lösung-Card visuell klar. */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          {!revealed && s.timerEndsAt && (
            <BeamerTimer endsAt={s.timerEndsAt} durationSec={s.timerDurationSec} accent={accent} />
          )}
        </div>
      </div>

      {/* Frage oben mittig */}
      <div style={{
        textAlign: 'center', position: 'relative', zIndex: 5,
        animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.1s both',
      }}>
        <div style={{
          fontSize: 'clamp(26px, 3vw, 44px)', fontWeight: 900,
          color: '#F1F5F9', lineHeight: 1.2, maxWidth: 1400, margin: '0 auto',
        }}>
          {lang === 'en' && q.textEn ? q.textEn : (q.text || (lang === 'de' ? 'Was verbindet diese Hinweise?' : 'What connects these clues?'))}
        </div>
      </div>

      {/* 2026-05-09 v2 (Wolf-Reform): 2×2 Hint-Grid mittig zentriert. Alle 4
          Hints sofort sichtbar (kein progressives Reveal, keine Avatare auf
          Hints). Im Reveal-Modus stays the grid sichtbar als Kontext, Lösung
          + Winner-Card kommen darunter. */}
      <div style={{
        flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center',
        position: 'relative', zIndex: 5,
      }}>
        <div style={{
          display: 'grid', gridTemplateColumns: 'repeat(2, minmax(280px, 1fr))',
          gap: 'clamp(14px, 1.8vw, 28px)',
          maxWidth: 1100, width: '100%',
        }}>
          {[0, 1, 2, 3].map(i => {
            const hintText = hintsAll[i] ?? `Hinweis ${i + 1}`;
            const hintColor = i === 0 ? '#EC4899' : i === 1 ? '#22C55E' : i === 2 ? '#60A5FA' : '#A78BFA';
            return (
              <div key={i} style={{
                display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
                padding: 'clamp(20px, 3vh, 36px) clamp(20px, 2vw, 32px)',
                borderRadius: 18,
                background: `linear-gradient(180deg, ${hintColor}28, ${hintColor}10)`,
                border: `2px solid ${hintColor}88`,
                boxShadow: `0 0 18px ${hintColor}33`,
                minHeight: 'clamp(120px, 16vh, 180px)',
                textAlign: 'center', gap: 10,
                animation: `contentReveal 0.5s var(--qq-ease-out-cubic) ${0.15 + i * 0.10}s both`,
              }}>
                <div style={{
                  fontSize: 'clamp(11px, 1.1vw, 14px)', fontWeight: 900,
                  color: hintColor,
                  letterSpacing: '0.1em', textTransform: 'uppercase',
                }}>{lang === 'de' ? `Hinweis ${i + 1}` : `Clue ${i + 1}`}</div>
                <div style={{
                  fontSize: 'clamp(24px, 2.8vw, 44px)', fontWeight: 900,
                  color: '#F1F5F9', lineHeight: 1.15,
                }}>{hintText}</div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Reveal: ZWEI getrennte Cards nebeneinander.
          2026-05-06 (Wolf 'lösungscard und gewinnercard trennen — lösungscard
          grün umrandet wie sonst auch, gewinnercard in der Farbe des Gewinners
          → vollständig konsistent mit Rest der App'):
          Vorher 1× zusammengelegte Gold-Card (Lösung+Sieger). Jetzt:
          - Lösungs-Card: grün umrandet + grüner Glow (analog MUCHO/ZvZ-
            Lock-Step-Highlight wo die korrekte Option grün wird).
          - Sieger-Card: in der Farbe des Gewinner-Teams.
          Beide Cards bleiben im Question-Mode mit visibility:hidden gerendert,
          damit der Layout-Space reserviert ist (kein Sprung beim Reveal). */}
      {(() => {
        // 2026-05-09 v2: Winner-Order = correctSorted (= submitted-time-order),
        // gefiltert auf winnerSet (Backend-Truth). Speed = Reihenfolge.
        const orderedWinnerIds = correctSorted
          .map(g => g.teamId)
          .filter(id => winnerSet.has(id));
        const winnerTeams = revealed
          ? orderedWinnerIds
              .map(id => s.teams.find(t => t.id === id))
              .filter((t): t is NonNullable<typeof t> => !!t)
          : [];
        const primaryWinner = winnerTeams[0] ?? null;
        const winnerColor = primaryWinner?.color ?? '#EC4899';
        return (
          <div style={{
            display: 'grid',
            gridTemplateColumns: winnerTeams.length > 0 ? '1fr 1fr' : '1fr',
            gap: 'clamp(12px, 1.6vw, 22px)',
            position: 'relative', zIndex: 5,
            alignItems: 'stretch',
            visibility: revealed ? 'visible' : 'hidden',
            opacity: revealed ? 1 : 0,
            transition: 'opacity 0.5s ease 0.15s',
          }}>
            {/* Lösungs-Card — grün umrandet (analog Lock-Step-Highlight in
                MUCHO/ZvZ wo die korrekte Option grün wird). */}
            <div style={{
              display: 'flex', flexDirection: 'column', alignItems: 'center',
              justifyContent: 'center',
              padding: 'clamp(16px, 2vh, 28px)',
              borderRadius: 24,
              minHeight: 'clamp(140px, 18vh, 220px)',
              background: 'linear-gradient(135deg, rgba(34,197,94,0.18), rgba(34,197,94,0.05))',
              border: '2.5px solid rgba(34,197,94,0.55)',
              boxShadow: '0 0 40px rgba(34,197,94,0.25), inset 0 1px 0 rgba(255,255,255,0.05)',
              animation: revealed ? `revealAnswerBam 0.6s var(--qq-ease-out-cubic) ${SOLUTION_DELAY}s both` : undefined,
            }}>
              <div style={{
                fontSize: 'clamp(36px, 4.4vw, 72px)', fontWeight: 900,
                color: '#86efac', textShadow: '0 0 30px rgba(34,197,94,0.45)',
                textAlign: 'center', lineHeight: 1.1,
              }}>
                {answer}
              </div>
            </div>

            {/* Sieger-Card — kompakter Stil analog CHEESE/MUCHO/ZvZ:
                nur Avatare nebeneinander mit Zeit-Pill darunter, KEINE Team-
                Namen. Schnellster bekommt Pink-Gold-Ring.
                2026-05-09 v3 (Wolf-Bug 'connect 4 winnercard viiiel zu groß +
                unten abgeschnitten'): vorher Avatar+Team-Name horizontal mit
                flexWrap auf mehrere Zeilen → Card konnte höher als Container
                wachsen. Jetzt fix kompakte Höhe wie Lösung-Card. */}
            {winnerTeams.length > 0 && (() => {
              // t0 = Question-Start, berechnet aus timer (oder Fallback erste Submission)
              const t0 = s.timerEndsAt && s.timerDurationSec
                ? s.timerEndsAt - s.timerDurationSec * 1000
                : correctSorted[0]?.submittedAt ?? null;
              const guessByTeam = new Map(correctSorted.map(g => [g.teamId, g]));
              return (
                <div style={{
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  gap: 'clamp(14px, 1.8vw, 28px)', flexWrap: 'wrap',
                  padding: 'clamp(16px, 2vh, 28px)',
                  borderRadius: 24,
                  minHeight: 'clamp(140px, 18vh, 220px)',
                  background: `linear-gradient(135deg, ${winnerColor}26, ${winnerColor}08)`,
                  border: `2.5px solid ${winnerColor}aa`,
                  boxShadow: `0 0 40px ${winnerColor}55, inset 0 1px 0 rgba(255,255,255,0.05)`,
                  animation: revealed ? `revealAnswerBam 0.6s var(--qq-ease-out-cubic) ${SOLUTION_DELAY + 0.15}s both` : undefined,
                }}>
                  {winnerTeams.map((tm, idx) => {
                    const guess = guessByTeam.get(tm.id);
                    const timeSec = t0 != null && guess
                      ? Math.max(0, (guess.submittedAt - t0) / 1000)
                      : null;
                    const isFastest = idx === 0;
                    const avatarSize = isFastest
                      ? 'clamp(72px, 7.5vw, 104px)'
                      : 'clamp(60px, 6.4vw, 88px)';
                    return (
                      <div key={tm.id} style={{
                        position: 'relative',
                        display: 'flex', flexDirection: 'column', alignItems: 'center',
                        animation: `phasePop 0.5s var(--qq-ease-bounce) ${WINNER_BASE + idx * WINNER_STEP}s both`,
                      }}>
                        <QQTeamAvatar
                          avatarId={tm.avatarId} teamEmoji={tm.emoji}
                          size={avatarSize}
                          style={{
                            border: isFastest ? '4px solid #EC4899' : 'none',
                            boxShadow: isFastest
                              ? `0 0 0 3px ${tm.color}, 0 0 22px rgba(236,72,153,0.6), 0 6px 14px rgba(0,0,0,0.55)`
                              : `0 0 0 3px ${tm.color}, 0 0 14px ${tm.color}88, 0 6px 14px rgba(0,0,0,0.55)`,
                            background: '#0A0814',
                            flexShrink: 0,
                          }}
                        />
                        {timeSec != null && (
                          <span style={{
                            position: 'absolute',
                            left: '50%', bottom: -8,
                            transform: 'translate(-50%, 50%)',
                            padding: '3px 11px', borderRadius: 999,
                            background: isFastest ? 'rgba(236,72,153,0.95)' : 'rgba(15,23,42,0.95)',
                            border: isFastest ? '1.5px solid rgba(236,72,153,1)' : `1.5px solid ${tm.color}`,
                            color: isFastest ? '#0A0814' : '#e2e8f0',
                            fontWeight: 900,
                            fontSize: 'clamp(12px, 1.3vw, 17px)',
                            whiteSpace: 'nowrap',
                            boxShadow: '0 4px 10px rgba(0,0,0,0.5)',
                            lineHeight: 1.1,
                          }}>
                            {timeSec.toFixed(1)}s
                          </span>
                        )}
                      </div>
                    );
                  })}
                </div>
              );
            })()}
          </div>
        );
      })()}

      {/* Team-Status-Reihe (analog CHEESE/4×4) — NUR im Active-Pfad zeigen.
          Wolf 2026-05-05: beim Reveal ausgeblendet, da locked/X-Teams öffentlich
          ausgestellt wurden (Anti-Public-Shaming). Sieger sind im Reveal-Card
          oben rechts; auf welchem Hinweis sie es hatten siehst du an den
          Hint-Cards mit Gold-Ring. */}
      {/* 2026-05-09 v2 (Wolf-Reform): Submit-Status-Reihe — pre-reveal pro Team
          Avatar mit ✓ wenn submitted (richtig) oder ✕ wenn locked. Anti-Spoiler:
          ✓ und ✕ sehen identisch aus von außen, nur Team weiß ob's richtig war. */}
      {!revealed && (
      <div style={{
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        gap: 'clamp(10px, 1.6vw, 22px)', flexWrap: 'wrap',
        position: 'relative', zIndex: 5,
        animation: 'contentReveal 0.45s var(--qq-ease-pop-fast) 0.2s both',
      }}>
        {s.teams.map((tm) => {
          const isLocked = lockedSet.has(tm.id);
          const isWinner = winnerSet.has(tm.id);
          const hasSubmitted = isLocked || isWinner;
          return (
            <div key={tm.id} title={tm.name} style={{
              position: 'relative',
              display: 'inline-flex', flexDirection: 'column', alignItems: 'center', gap: 4,
              flexShrink: 0,
              opacity: hasSubmitted ? 1 : 0.55,
              filter: hasSubmitted ? 'none' : 'grayscale(0.4)',
              transition: 'opacity 0.4s ease, filter 0.4s ease',
            }}>
              <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(48px, 5vw, 72px)'} style={{
                background: '#0A0814',
                boxShadow: hasSubmitted
                  ? `0 0 0 2px ${tm.color}, 0 0 14px ${tm.color}88, 0 4px 10px rgba(0,0,0,0.55)`
                  : `0 0 0 2px ${tm.color}55, 0 4px 10px rgba(0,0,0,0.55)`,
              }} />
              {hasSubmitted && (
                <div style={{
                  position: 'absolute', bottom: -4, right: -4,
                  width: 22, height: 22, borderRadius: '50%',
                  background: '#0A0814', border: `2px solid ${tm.color}`,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 12, lineHeight: 1, color: tm.color, fontWeight: 900,
                  animation: 'bAnswerCheck 0.4s var(--qq-ease-bounce) both',
                }}>✓</div>
              )}
            </div>
          );
        })}
      </div>
      )}
    </div>
  );
}

/**
 * Top-5 Reveal: zweispaltige Show-Seite.
 * Links: Frage + Gewinner-Block. Rechts: Top-5-Liste die sequentiell 5→1 aufdeckt.
 * Nach jeder Antwort erscheinen Avatare (oder X-Kreis wenn niemand) mit Pop-Animation.
 */
function Top5Reveal({ state: s, lang }: { state: QQStateUpdate; lang: 'de' | 'en' }) {
  const q = s.currentQuestion!;
  const btt = q.bunteTuete as any;
  const correctListDE: string[] = (btt.answers ?? []).map((x: string) => x.trim()).filter(Boolean);
  const correctListEN: string[] = (btt.answersEn ?? []).map((x: string) => x.trim()).filter(Boolean);
  const correctList = lang === 'en' && correctListEN.length ? correctListEN : correctListDE;
  const n = correctList.length;

  // 2026-05-02: Backend-Truth via top5HitsByTeam. Backend matched mit
  // similarityScore>=0.8 (fuzzy). Frontend hat jetzt nur noch Anzeige-Logik,
  // keine eigene Match-Logik mehr. Backend's correctAll = correctDE.concat(correctEN);
  // Index ci -> DE-Slot, ci+correctDE.length -> EN-Slot.
  const hitsByTeam = s.top5HitsByTeam ?? {};

  // perAnswer in Original-Reihenfolge (Platz 1 = Index 0).
  const perAnswer = useMemo(() => {
    return correctList.map((correct, ci) => {
      const deIdx = ci;
      const enIdx = ci + correctListDE.length;
      const hitters = s.answers
        .filter(a => {
          const teamHits = hitsByTeam[a.teamId] ?? [];
          return teamHits.includes(deIdx) || teamHits.includes(enIdx);
        })
        .map(a => s.teams.find(t => t.id === a.teamId))
        .filter((t): t is NonNullable<typeof t> => !!t);
      return { correct, hitters };
    });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [s.answers, s.teams, correctList, correctListDE.length, JSON.stringify(hitsByTeam)]);

  // Treffer pro Team — für Winner-Block. Aus Backend-Hits.
  const teamScore = useMemo(() => {
    return s.answers.map(a => ({
      teamId: a.teamId,
      hits: (hitsByTeam[a.teamId] ?? []).length,
    })).sort((x, y) => y.hits - x.hits);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [s.answers, JSON.stringify(hitsByTeam)]);

  const topHits = teamScore[0]?.hits ?? 0;
  const winners = teamScore.filter(t => t.hits === topHits && topHits > 0);

  // Sequentielles Reveal: Start mit -1 (noch nichts), dann 5, 4, 3, 2, 1 (Indizes: n-1 … 0).
  // 2026-05-03 (Wolf-Bug 'Cascade-Sound aber alle Avatare gleichzeitig'):
  // Race-Condition fix — siehe Schaetzchen. cascadeStartedRef verhindert
  // Re-Run bei n-Aenderung waehrend laufender Cascade.
  const [revealedMinIdx, setRevealedMinIdx] = useState<number>(n);
  const cascadeStartedRef = useRef(false);
  const STEP_MS = 2400;
  const INITIAL_DELAY_MS = 600;

  useEffect(() => {
    if (cascadeStartedRef.current || n === 0) return;
    cascadeStartedRef.current = true;
    setRevealedMinIdx(n);
    const timers: ReturnType<typeof setTimeout>[] = [];
    const cascadeTotal = n + 1;
    for (let i = 0; i < n; i++) {
      const targetIdx = n - 1 - i;
      const isTopRow = i === n - 1;
      const t = setTimeout(() => {
        setRevealedMinIdx(targetIdx);
        if (!s.sfxMuted) {
          try { playAvatarCascadeNote(i, cascadeTotal); } catch {}
          if (isTopRow) {
            try { playRevealHighlight(); } catch {}
          }
        }
      }, INITIAL_DELAY_MS + i * STEP_MS);
      timers.push(t);
    }
    return () => { timers.forEach(clearTimeout); };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [n]);

  const qText = (lang === 'en' && q.textEn ? q.textEn : q.text) ?? '';

  return (
    <div style={{
      flex: 1, display: 'flex', flexDirection: 'column',
      gap: 'clamp(14px, 1.8vh, 22px)',
      padding: 'clamp(16px, 2vh, 28px) clamp(20px, 3vw, 48px) clamp(54px, 7vh, 80px)',
      animation: 'contentReveal 0.45s var(--qq-ease-pop-fast) both',
      minHeight: 0,
    }}>
      {/* ── Top row: Full-width question card ─────────────────── */}
      <div style={{
        background: 'rgba(255,255,255,0.04)',
        border: '2px solid rgba(255,255,255,0.08)',
        borderRadius: 24,
        padding: 'clamp(16px, 2vh, 26px) clamp(24px, 2.8vw, 42px)',
        boxShadow: '0 8px 32px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.05)',
        animation: 'bQuestionIn 0.5s var(--qq-ease-bounce) both',
        flexShrink: 0,
      }}>
        <div style={{
          fontSize: 'clamp(11px, 1vw, 14px)', fontWeight: 900, color: '#EC4899',
          letterSpacing: '0.1em', textTransform: 'uppercase', marginBottom: 8,
        }}>
          🎁 {lang === 'en' ? 'Top 5 — Reveal' : 'Top 5 — Auflösung'}
        </div>
        <div key={lang} style={{
          fontSize: qText.length > 120 ? 'clamp(26px, 2.7vw, 40px)' : 'clamp(30px, 3.2vw, 52px)',
          fontWeight: 900, lineHeight: 1.18, color: '#F1F5F9',
          animation: 'langFadeIn 0.4s ease both',
        }}>
          {qText}
        </div>
      </div>

      {/* ── Bottom row: Winners (left) + Top-5 list (right) ───── */}
      <div style={{
        flex: 1, display: 'grid',
        gridTemplateColumns: 'minmax(0, 5fr) minmax(0, 7fr)',
        gap: 'clamp(16px, 2.5vw, 36px)',
        minHeight: 0,
      }}>
        {/* Winner card — Team-Farben-Frame bei Einzelsieger, Gold bei mehreren. */}
        {(() => {
          const singleColor = winners.length === 1
            ? s.teams.find(t => t.id === winners[0].teamId)?.color ?? null
            : null;
          const cardBgGrad = winners.length === 0
            ? 'transparent'
            : singleColor
              ? `linear-gradient(135deg, ${singleColor}1f, ${singleColor}07)`
              : 'linear-gradient(135deg, rgba(236,72,153,0.14), rgba(236,72,153,0.04))';
          const cardBorder = winners.length === 0
            ? 'none'
            : singleColor
              ? `3px solid ${singleColor}88`
              : '3px solid rgba(236,72,153,0.55)';
          const cardShadow = winners.length === 0
            ? 'none'
            : singleColor
              ? `0 0 48px ${singleColor}33, 0 8px 24px rgba(0,0,0,0.4)`
              : '0 0 48px rgba(236,72,153,0.22), 0 8px 24px rgba(0,0,0,0.4)';
          return (
        <div style={{
          height: '100%',
          background: cardBgGrad,
          border: cardBorder,
          borderRadius: 24,
          padding: 'clamp(18px, 2.4vh, 32px) clamp(14px, 1.8vw, 28px)',
          boxShadow: cardShadow,
          display: 'flex', flexDirection: 'column', justifyContent: 'center',
          gap: 14, minHeight: 0,
          opacity: revealedMinIdx === 0 ? 1 : 0.12,
          filter: revealedMinIdx === 0 ? 'none' : 'blur(18px) saturate(0.4)',
          transition: 'opacity 0.7s ease, filter 0.7s ease',
        }}>
          <div style={{
            fontSize: 'clamp(11px, 1vw, 14px)', fontWeight: 900, color: '#94a3b8',
            letterSpacing: '0.1em', textTransform: 'uppercase',
          }}>
            <QQEmojiIcon emoji="🏆"/> {winners.length > 1
              ? (lang === 'en' ? 'Round winners' : 'Rundensieger')
              : (lang === 'en' ? 'Round winner' : 'Rundensieger')}
          </div>
          {winners.length === 0 ? (
            <div style={{ fontSize: 'clamp(20px, 2.2vw, 32px)', fontWeight: 900, color: '#f87171' }}>
              {lang === 'en' ? 'Nobody scored.' : 'Niemand hat getroffen.'}
            </div>
          ) : (() => {
            // Skaliere Größen je nach Anzahl Sieger — wenig Sieger = deutlich größer.
            const wn = winners.length;
            // Ab 5 Siegern 2 Spalten (4-4 bei 8) damit unten nichts abgeschnitten wird
            const twoCol = wn >= 5;
            const avatarSize =
              wn === 1 ? 'clamp(130px, 14vw, 210px)'
              : wn === 2 ? 'clamp(112px, 11.5vw, 172px)'
              : wn === 3 ? 'clamp(96px, 9.8vw, 144px)'
              : wn === 4 ? 'clamp(84px, 8.6vw, 124px)'
              : wn <= 6 ? 'clamp(70px, 6.4vw, 100px)'
              : 'clamp(64px, 5.8vw, 92px)';
            const nameSize =
              wn === 1 ? 'clamp(40px, 4.6vw, 76px)'
              : wn === 2 ? 'clamp(34px, 3.8vw, 60px)'
              : wn === 3 ? 'clamp(30px, 3.4vw, 52px)'
              : wn === 4 ? 'clamp(26px, 3vw, 44px)'
              : wn <= 6 ? 'clamp(20px, 2.1vw, 30px)'
              : 'clamp(18px, 1.95vw, 28px)';
            const subSize =
              wn === 1 ? 'clamp(18px, 1.9vw, 30px)'
              : wn === 2 ? 'clamp(16px, 1.7vw, 26px)'
              : wn === 3 ? 'clamp(15px, 1.6vw, 24px)'
              : wn === 4 ? 'clamp(14px, 1.5vw, 22px)'
              : 'clamp(12px, 1.3vw, 18px)';
            const rowGap = wn <= 2 ? 18 : wn === 3 ? 14 : wn === 4 ? 12 : 10;
            const itemGap = wn <= 2 ? 20 : wn === 3 ? 18 : wn === 4 ? 16 : twoCol ? 10 : 14;
            return (
              <div style={{
                display: 'grid',
                gridTemplateColumns: twoCol ? '1fr 1fr' : '1fr',
                gap: twoCol ? `${rowGap}px 18px` : `${rowGap}px`,
                minHeight: 0, overflow: 'hidden',
              }}>
                {winners.map(w => {
                  const tm = s.teams.find(t => t.id === w.teamId);
                  if (!tm) return null;
                  return (
                    <div key={tm.id} style={{
                      display: 'flex', alignItems: 'center', gap: itemGap, minWidth: 0,
                      animation: revealedMinIdx === 0 ? 'revealWinnerIn 0.6s var(--qq-ease-bounce) 0.2s both' : 'none',
                    }}>
                      <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={avatarSize} style={{
                        flexShrink: 0,
                        animation: revealedMinIdx === 0 ? 'celebShake 0.6s ease 0.6s both' : 'none',
                      }} />
                      <div style={{ minWidth: 0, flex: 1, overflow: 'hidden' }}>
                        <TeamNameLabel
                          name={tm.name}
                          maxLines={2}
                          shrinkAfter={14}
                          fontSize={nameSize}
                          color={tm.color}
                          fontWeight={900}
                          style={{ lineHeight: 1.1 }}
                        />
                        <div style={{
                          fontSize: subSize, fontWeight: 900, color: '#cbd5e1', marginTop: 2,
                        }}>
                          {w.hits}/{n} {lang === 'en' ? 'correct' : 'richtig'}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            );
          })()}
        </div>
          );
        })()}

      {/* ── Right column: Top-5 List (bottom-up reveal, fills column) ─────── */}
      <div style={{
        display: 'flex', flexDirection: 'column', gap: 'clamp(8px, 1.2vh, 14px)',
        justifyContent: 'space-between',
        minHeight: 0, height: '100%',
      }}>
        {perAnswer.map(({ correct, hitters }, idx) => {
          const rank = idx + 1;
          const isVisible = idx >= revealedMinIdx;
          const hasHits = hitters.length > 0;
          // 2026-05-07 (Audit P1): Pro Reihe Stagger-Delay, damit bei schnellem
          // Mod-Klick (mehrere Reihen flippen synchron isVisible=true) die
          // Reihen kaskadieren statt synchron zu poppen. Bottom-up Reveal:
          // hoechster Index (rank 5) zuerst, niedrigster Index (rank 1) zuletzt.
          const rowDelay = (perAnswer.length - 1 - idx) * 0.18;
          const rankGradient = rank === 1
            ? 'linear-gradient(135deg,#EC4899,#EC4899)'
            : rank === 2
              ? 'linear-gradient(135deg,#E2E8F0,#94A3B8)'
              : rank === 3
                ? 'linear-gradient(135deg,#F97316,#B45309)'
                : 'linear-gradient(135deg,#475569,#334155)';
          return (
            <div
              key={idx}
              style={{
                display: 'grid',
                gridTemplateColumns: 'auto 1fr auto',
                alignItems: 'center',
                gap: 'clamp(10px, 1.2vw, 18px)',
                padding: 'clamp(10px, 1.4vh, 18px) clamp(14px, 1.6vw, 22px)',
                borderRadius: 16,
                background: hasHits
                  ? 'linear-gradient(135deg, rgba(34,197,94,0.14), rgba(22,163,74,0.06))'
                  : 'rgba(148,163,184,0.06)',
                border: hasHits
                  ? '2px solid rgba(34,197,94,0.4)'
                  : '2px solid rgba(148,163,184,0.15)',
                visibility: isVisible ? 'visible' : 'hidden',
                animation: isVisible
                  ? `top5RowSlideIn 0.55s var(--qq-ease-out-cubic) ${rowDelay}s both, top5RowGlow 1.2s ease ${0.3 + rowDelay}s both`
                  : 'none',
                flex: 1,
                minHeight: 'clamp(64px, 8vh, 92px)',
              }}
            >
              {/* Rank badge */}
              <div style={{
                width: 'clamp(52px, 5vw, 72px)', height: 'clamp(52px, 5vw, 72px)',
                borderRadius: 16,
                background: rankGradient,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 'clamp(24px, 2.8vw, 40px)', fontWeight: 900, color: '#fff',
                flexShrink: 0,
                textShadow: '0 2px 4px rgba(0,0,0,0.3)',
                animation: isVisible ? `top5RankPop 0.55s var(--qq-ease-bounce) ${0.1 + rowDelay}s both` : 'none',
                boxShadow: rank === 1 ? '0 0 20px rgba(236,72,153,0.5)' : 'none',
              }}>
                #{rank}
              </div>

              {/* Answer text */}
              <div style={{
                fontSize: 'clamp(20px, 2.3vw, 34px)', fontWeight: 900,
                color: hasHits ? '#86efac' : '#cbd5e1',
                lineHeight: 1.2,
                minWidth: 0, wordBreak: 'break-word',
              }}>
                {hasHits ? '✓ ' : ''}{correct}
              </div>

              {/* Hitters / No-hit X */}
              <div style={{
                display: 'flex', alignItems: 'center', gap: 6,
                flexShrink: 0,
              }}>
                {hasHits ? (
                  hitters.map((tm, hi) => (
                    <QQTeamAvatar
                      key={tm.id}
                      avatarId={tm.avatarId} teamEmoji={tm.emoji}
                      size={'clamp(52px, 5.4vw, 78px)'}
                      title={tm.name}
                      style={{
                        boxShadow: `0 0 16px ${tm.color}55`,
                        animation: isVisible
                          ? `top5AvatarPop 0.5s cubic-bezier(0.34,1.6,0.64,1) ${0.35 + hi * 0.09 + rowDelay}s both`
                          : 'none',
                      }}
                    />
                  ))
                ) : (
                  <div style={{
                    width: 'clamp(52px, 5.4vw, 78px)', height: 'clamp(52px, 5.4vw, 78px)',
                    borderRadius: '50%',
                    background: 'rgba(148,163,184,0.15)',
                    border: '2px dashed rgba(148,163,184,0.4)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: 'clamp(20px, 2.2vw, 28px)', fontWeight: 900, color: '#94a3b8',
                    animation: isVisible
                      ? `top5AvatarPop 0.5s cubic-bezier(0.34,1.6,0.64,1) ${0.35 + rowDelay}s both`
                      : 'none',
                  }}>
                    ✕
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// OrderReveal — Bunte-Tüte "order" reveal, Top5-Style mit 2-Spalten-Layout
// ═══════════════════════════════════════════════════════════════════════════════
function OrderReveal({ state: s, lang }: { state: QQStateUpdate; lang: 'de' | 'en' }) {
  const q = s.currentQuestion!;
  const btt = q.bunteTuete as any;
  const itemsDE: string[] = (btt.items ?? []) as string[];
  const itemsEN: string[] = (btt.itemsEn ?? []) as string[];
  const itemValues: string[] = (btt.itemValues ?? []) as string[];
  const correctOrder: number[] = (btt.correctOrder ?? []) as number[];
  const items = lang === 'en' && itemsEN.length ? itemsEN : itemsDE;
  const n = correctOrder.length;

  const criteriaTxt = lang === 'en' && btt.criteriaEn ? btt.criteriaEn : btt.criteria;

  // 2026-05-02: Backend-Truth via orderHitsByTeam (per-team boolean[] per
  // Position, similarityScore>=0.8 fuzzy matched). Frontend nutzt das direkt;
  // parseAnswers wird nur noch fuer den Item-Display benoetigt.
  const orderHits = s.orderHitsByTeam ?? {};
  const parsedAnswers = useMemo(() => {
    const deLc = itemsDE.map(s => (s ?? '').trim().toLowerCase());
    const enLc = itemsEN.map(s => (s ?? '').trim().toLowerCase());
    return s.answers.map(a => {
      const parts = String(a.text ?? '').split('|').map(p => p.trim()).filter(Boolean);
      const order: number[] = parts.map(p => {
        const asNum = Number(p);
        if (Number.isFinite(asNum) && asNum >= 0 && asNum < itemsDE.length) return asNum;
        const pLc = p.toLowerCase();
        const di = deLc.indexOf(pLc);
        if (di >= 0) return di;
        const ei = enLc.indexOf(pLc);
        if (ei >= 0) return ei;
        return -1;
      });
      return { teamId: a.teamId, order };
    });
  }, [s.answers, itemsDE, itemsEN]);

  // Pro Position: welche Teams haben hier richtig (Backend-Truth)?
  const perPosition = useMemo(() => {
    return correctOrder.map((correctIdx, posIdx) => {
      const hitters = s.answers
        .filter(a => (orderHits[a.teamId] ?? [])[posIdx] === true)
        .map(a => s.teams.find(t => t.id === a.teamId))
        .filter((t): t is NonNullable<typeof t> => !!t);
      return { correctIdx, hitters };
    });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [s.answers, correctOrder, s.teams, JSON.stringify(orderHits)]);

  // Treffer pro Team (Anzahl korrekter Positionen, Backend-Truth).
  const teamScore = useMemo(() => {
    return s.answers.map(a => ({
      teamId: a.teamId,
      hits: (orderHits[a.teamId] ?? []).filter(Boolean).length,
    })).sort((x, y) => y.hits - x.hits);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [s.answers, JSON.stringify(orderHits)]);

  const topHits = teamScore[0]?.hits ?? 0;
  const winners = teamScore.filter(t => t.hits === topHits && topHits > 0);

  // 2026-05-03 (Wolf-Bug Cascade-Race): siehe Schaetzchen. Race-Fix.
  const [revealedMinIdx, setRevealedMinIdx] = useState<number>(n);
  const cascadeStartedRef = useRef(false);
  const STEP_MS = 2000;
  const INITIAL_DELAY_MS = 500;

  useEffect(() => {
    if (cascadeStartedRef.current || n === 0) return;
    cascadeStartedRef.current = true;
    setRevealedMinIdx(n);
    const timers: ReturnType<typeof setTimeout>[] = [];
    const cascadeTotal = n + 1;
    for (let i = 0; i < n; i++) {
      const targetIdx = n - 1 - i;
      const isTopRow = i === n - 1;
      const t = setTimeout(() => {
        setRevealedMinIdx(targetIdx);
        if (!s.sfxMuted) {
          try { playAvatarCascadeNote(i, cascadeTotal); } catch {}
          if (isTopRow) {
            try { playRevealHighlight(); } catch {}
          }
        }
      }, INITIAL_DELAY_MS + i * STEP_MS);
      timers.push(t);
    }
    return () => { timers.forEach(clearTimeout); };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [n]);

  const qText = (lang === 'en' && q.textEn ? q.textEn : q.text) ?? '';

  return (
    <div style={{
      flex: 1, display: 'flex', flexDirection: 'column',
      gap: 'clamp(14px, 1.8vh, 22px)',
      padding: 'clamp(16px, 2vh, 28px) clamp(20px, 3vw, 48px) clamp(54px, 7vh, 80px)',
      animation: 'contentReveal 0.45s var(--qq-ease-pop-fast) both',
      minHeight: 0,
    }}>
      {/* ── Top: Frage ─────────────────────────────────────────── */}
      <div style={{
        background: 'rgba(255,255,255,0.04)',
        border: '2px solid rgba(255,255,255,0.08)',
        borderRadius: 24,
        padding: 'clamp(16px, 2vh, 26px) clamp(24px, 2.8vw, 42px)',
        boxShadow: '0 8px 32px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.05)',
        animation: 'bQuestionIn 0.5s var(--qq-ease-bounce) both',
        flexShrink: 0,
      }}>
        <div style={{
          fontSize: 'clamp(11px, 1vw, 14px)', fontWeight: 900, color: '#EC4899',
          letterSpacing: '0.1em', textTransform: 'uppercase', marginBottom: 8,
        }}>
          🎁 {lang === 'en' ? 'Lucky Bag — Order' : 'Bunte Tüte — Reihenfolge'}
        </div>
        <div key={lang} style={{
          fontSize: qText.length > 120 ? 'clamp(26px, 2.7vw, 40px)' : 'clamp(30px, 3.2vw, 52px)',
          fontWeight: 900, lineHeight: 1.18, color: '#F1F5F9',
          animation: 'langFadeIn 0.4s ease both',
        }}>
          {qText}
        </div>
        {criteriaTxt && (
          <div style={{
            marginTop: 8, fontSize: 'clamp(14px, 1.4vw, 20px)', fontWeight: 700,
            color: '#FBCFE8', fontStyle: 'italic',
          }}>
            ↕ {criteriaTxt}
          </div>
        )}
      </div>

      {/* ── Mitte: Antwort-Liste full-width, von oben nach unten ── */}
      <div style={{
        flex: 1, display: 'flex', flexDirection: 'column',
        minHeight: 0,
      }}>
        {/* Antwort-Liste — bottom-up enthuellt */}
        <div style={{
          flex: 1,
          display: 'flex', flexDirection: 'column', gap: 'clamp(8px, 1.2vh, 14px)',
          justifyContent: 'space-between',
          minHeight: 0,
        }}>
          {perPosition.map(({ correctIdx, hitters }, idx) => {
            const rank = idx + 1;
            const isVisible = idx >= revealedMinIdx;
            const hasHits = hitters.length > 0;
            // 2026-05-07 (Audit P1): siehe Top5 — pro Reihe Stagger-Delay,
            // damit synchron-flippende Reihen kaskadieren statt synchron poppen.
            const rowDelay = (perPosition.length - 1 - idx) * 0.18;
            const rankGradient = rank === 1
              ? 'linear-gradient(135deg,#EC4899,#EC4899)'
              : rank === 2
                ? 'linear-gradient(135deg,#E2E8F0,#94A3B8)'
                : rank === 3
                  ? 'linear-gradient(135deg,#F97316,#B45309)'
                  : 'linear-gradient(135deg,#475569,#334155)';
            const itemText = items[correctIdx] ?? '';
            return (
              <div
                key={idx}
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'auto 1fr auto',
                  alignItems: 'center',
                  gap: 'clamp(10px, 1.2vw, 18px)',
                  padding: 'clamp(10px, 1.4vh, 18px) clamp(14px, 1.6vw, 22px)',
                  borderRadius: 16,
                  background: hasHits
                    ? 'linear-gradient(135deg, rgba(34,197,94,0.14), rgba(22,163,74,0.06))'
                    : 'rgba(148,163,184,0.06)',
                  border: hasHits
                    ? '2px solid rgba(34,197,94,0.4)'
                    : '2px solid rgba(148,163,184,0.15)',
                  visibility: isVisible ? 'visible' : 'hidden',
                  animation: isVisible
                    ? `top5RowSlideIn 0.55s var(--qq-ease-out-cubic) ${rowDelay}s both, top5RowGlow 1.2s ease ${0.3 + rowDelay}s both`
                    : 'none',
                  flex: 1,
                  minHeight: 'clamp(64px, 8vh, 92px)',
                }}
              >
                <div style={{
                  width: 'clamp(52px, 5vw, 72px)', height: 'clamp(52px, 5vw, 72px)',
                  borderRadius: 16,
                  background: rankGradient,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 'clamp(24px, 2.8vw, 40px)', fontWeight: 900, color: '#fff',
                  flexShrink: 0,
                  textShadow: '0 2px 4px rgba(0,0,0,0.3)',
                  animation: isVisible ? `top5RankPop 0.55s var(--qq-ease-bounce) ${0.1 + rowDelay}s both` : 'none',
                  boxShadow: rank === 1 ? '0 0 20px rgba(236,72,153,0.5)' : 'none',
                }}>
                  #{rank}
                </div>

                <div style={{
                  display: 'flex', alignItems: 'baseline', gap: 'clamp(8px, 1vw, 14px)',
                  flexWrap: 'wrap', minWidth: 0,
                }}>
                  <div style={{
                    fontSize: 'clamp(20px, 2.3vw, 34px)', fontWeight: 900,
                    color: hasHits ? '#86efac' : '#cbd5e1',
                    lineHeight: 1.2,
                    minWidth: 0, wordBreak: 'break-word',
                  }}>
                    {hasHits ? '✓ ' : ''}{itemText}
                  </div>
                  {itemValues[correctIdx] && (
                    <span style={{
                      display: 'inline-flex', alignItems: 'center',
                      padding: '3px 12px', borderRadius: 999,
                      background: hasHits ? 'rgba(34,197,94,0.22)' : 'rgba(148,163,184,0.16)',
                      border: hasHits ? '1.5px solid rgba(34,197,94,0.55)' : '1.5px solid rgba(148,163,184,0.3)',
                      color: hasHits ? '#86efac' : '#cbd5e1',
                      fontWeight: 900,
                      fontSize: 'clamp(14px, 1.5vw, 22px)',
                      whiteSpace: 'nowrap',
                      fontVariantNumeric: 'tabular-nums',
                    }}>
                      {itemValues[correctIdx]}
                    </span>
                  )}
                </div>

                <div style={{
                  display: 'flex', alignItems: 'center', gap: 6,
                  flexShrink: 0,
                }}>
                  {hasHits ? (
                    hitters.map((tm, hi) => (
                      <QQTeamAvatar
                        key={tm.id}
                        avatarId={tm.avatarId} teamEmoji={tm.emoji}
                        size={'clamp(36px, 3.8vw, 54px)'}
                        title={tm.name}
                        style={{
                          boxShadow: `0 0 14px ${tm.color}55`,
                          animation: isVisible
                            ? `top5AvatarPop 0.5s cubic-bezier(0.34,1.6,0.64,1) ${0.35 + hi * 0.09 + rowDelay}s both`
                            : 'none',
                        }}
                      />
                    ))
                  ) : (
                    <div style={{
                      width: 'clamp(36px, 3.8vw, 54px)', height: 'clamp(36px, 3.8vw, 54px)',
                      borderRadius: '50%',
                      background: 'rgba(148,163,184,0.15)',
                      border: '2px dashed rgba(148,163,184,0.4)',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      fontSize: 'clamp(20px, 2.2vw, 28px)', fontWeight: 900, color: '#94a3b8',
                      animation: isVisible
                        ? `top5AvatarPop 0.5s cubic-bezier(0.34,1.6,0.64,1) ${0.35 + rowDelay}s both`
                        : 'none',
                    }}>
                      ✕
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        {/* Sieger-Footer — horizontale Pill-Reihe, skaliert bis 8 Teams */}
        <div style={{
          marginTop: 'clamp(10px, 1.4vh, 18px)',
          padding: 'clamp(10px, 1.4vh, 16px) clamp(14px, 1.8vw, 24px)',
          borderRadius: 16,
          background: winners.length > 0
            ? 'linear-gradient(135deg, rgba(236,72,153,0.10), rgba(236,72,153,0.04))'
            : 'rgba(148,163,184,0.06)',
          border: winners.length > 0
            ? '2px solid rgba(236,72,153,0.35)'
            : '2px solid rgba(148,163,184,0.15)',
          display: 'flex', alignItems: 'center',
          gap: 'clamp(12px, 1.6vw, 22px)',
          flexShrink: 0, minHeight: 0,
          opacity: revealedMinIdx === 0 ? 1 : 0.18,
          filter: revealedMinIdx === 0 ? 'none' : 'blur(8px) saturate(0.4)',
          transition: 'opacity 0.6s ease, filter 0.6s ease',
        }}>
          <div style={{
            display: 'flex', flexDirection: 'column', gap: 2,
            flexShrink: 0, minWidth: 0,
            paddingRight: 'clamp(8px, 1vw, 16px)',
            borderRight: '2px solid rgba(255,255,255,0.08)',
          }}>
            <div style={{
              fontSize: 'clamp(11px, 1vw, 14px)', fontWeight: 900, color: '#EC4899',
              letterSpacing: '0.1em', textTransform: 'uppercase',
              whiteSpace: 'nowrap',
            }}>
              <QQEmojiIcon emoji="🏆"/> {winners.length > 1
                ? (lang === 'en' ? 'Round winners' : 'Rundensieger')
                : (lang === 'en' ? 'Round winner' : 'Rundensieger')}
            </div>
            {winners.length > 0 && (
              <div style={{
                fontSize: 'clamp(13px, 1.2vw, 18px)', fontWeight: 900, color: '#cbd5e1',
                whiteSpace: 'nowrap',
              }}>
                {winners[0].hits}/{n} {lang === 'en' ? 'correct' : 'richtig'}
              </div>
            )}
          </div>

          {winners.length === 0 ? (
            <div style={{
              fontSize: 'clamp(18px, 2vw, 28px)', fontWeight: 900, color: '#f87171',
            }}>
              {lang === 'en' ? 'Nobody scored.' : 'Niemand hat getroffen.'}
            </div>
          ) : (() => {
            const wn = winners.length;
            // Avatar + Name als Pill, skaliert je nach Anzahl Sieger
            const avatarSize = wn <= 2 ? 'clamp(54px, 5.6vw, 78px)'
              : wn <= 4 ? 'clamp(46px, 4.8vw, 66px)'
              : wn <= 6 ? 'clamp(40px, 4.2vw, 56px)'
              : 'clamp(36px, 3.8vw, 50px)';
            const nameSize = wn <= 2 ? 'clamp(20px, 2.2vw, 32px)'
              : wn <= 4 ? 'clamp(17px, 1.9vw, 26px)'
              : wn <= 6 ? 'clamp(15px, 1.7vw, 22px)'
              : 'clamp(14px, 1.5vw, 19px)';
            const pillGap = wn <= 4 ? 'clamp(10px, 1.2vw, 18px)' : 'clamp(8px, 0.9vw, 12px)';
            return (
              <div style={{
                display: 'flex', alignItems: 'center', flexWrap: 'wrap',
                gap: pillGap,
                flex: 1, minWidth: 0,
              }}>
                {winners.map((w, wi) => {
                  const tm = s.teams.find(t => t.id === w.teamId);
                  if (!tm) return null;
                  return (
                    <div key={tm.id} style={{
                      display: 'flex', alignItems: 'center', gap: 'clamp(6px, 0.8vw, 12px)',
                      padding: 'clamp(4px, 0.6vh, 8px) clamp(10px, 1.1vw, 16px) clamp(4px, 0.6vh, 8px) clamp(4px, 0.5vh, 6px)',
                      borderRadius: 999,
                      background: `linear-gradient(135deg, ${tm.color}26, ${tm.color}0a)`,
                      border: `2px solid ${tm.color}55`,
                      animation: revealedMinIdx === 0
                        ? `revealWinnerIn 0.55s var(--qq-ease-bounce) ${0.2 + wi * 0.08}s both`
                        : 'none',
                      minWidth: 0,
                    }}>
                      <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={avatarSize} style={{
                        flexShrink: 0,
                        boxShadow: `0 0 14px ${tm.color}55`,
                      }} />
                      <TeamNameLabel
                        name={tm.name}
                        maxLines={2}
                        shrinkAfter={14}
                        fontSize={nameSize}
                        color={tm.color}
                        fontWeight={900}
                        style={{ lineHeight: 1.1, minWidth: 0 }}
                      />
                    </div>
                  );
                })}
              </div>
            );
          })()}
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// SchaetzchenReveal — Top5-Style:
// oben Frage (volle Breite), darunter links Lösung+Gewinner, rechts Top 5 Teams
// (max 5, am nächsten dran). Bottom-up Enthüllung bis zum Gewinner.
// ═══════════════════════════════════════════════════════════════════════════════
function SchaetzchenReveal({ state: s, lang }: { state: QQStateUpdate; lang: 'de' | 'en' }) {
  const q = s.currentQuestion!;
  const target = q.targetValue as number;

  // Jahreszahlen (Unit enthaelt "Jahr"/"year" ODER Wert sieht wie Jahr aus)
  // OHNE Tausenderpunkt formatieren — sonst stehen Werte wie 1500 als '1.500'
  // da, was wie 1.5 aussieht und falsch ist.
  const unitStr = (lang === 'en' && q.unitEn ? q.unitEn : q.unit) ?? '';
  const looksLikeYear = (n: number) => Number.isInteger(n) && n >= 1000 && n <= 2100;
  // 2026-05-07: explizites isYearAnswer-Flag mit Vorrang.
  const isYearUnit = !!q.isYearAnswer || /jahr|year/i.test(unitStr) || (target != null && looksLikeYear(target));

  const fmt = (n: number) => {
    const abs = Math.abs(n);
    if (isYearUnit) return String(Math.round(n));
    if (abs >= 1000000) return (n / 1000000).toFixed(1).replace(/\.0$/, '') + 'M';
    if (abs >= 10000) return (n / 1000).toFixed(0) + 'k';
    if (abs >= 1000) return n.toLocaleString(lang === 'en' ? 'en-US' : 'de-DE');
    return n % 1 === 0 ? String(n) : n.toFixed(1);
  };

  // Parse + Distanz. Sort: bester (geringste |Δ|) zuerst, bei Delta-Tie → schnellste Einreichung gewinnt.
  const ranked = useMemo(() => {
    return s.answers
      .map(a => {
        const num = Number(String(a.text).replace(/[^0-9.,\-]/g, '').replace(',', '.'));
        const team = s.teams.find(t => t.id === a.teamId);
        if (!team || !Number.isFinite(num)) return null;
        return { teamId: a.teamId, num, team, delta: Math.abs(num - target), submittedAt: a.submittedAt };
      })
      .filter((x): x is { teamId: string; num: number; team: NonNullable<ReturnType<typeof s.teams.find>>; delta: number; submittedAt: number } => !!x)
      .sort((a, b) => a.delta - b.delta || a.submittedAt - b.submittedAt);
  }, [s.answers, s.teams, target]);

  // Max 5 Teams rechts; Bottom-up Enthüllung (#5 → #4 → … → #1).
  const top5 = ranked.slice(0, 5);
  const n = top5.length;
  const winner = ranked[0] ?? null;

  // 2026-05-03 (Wolf-Bug 'Schaetzchen Cascade-Sound aber alle Avatare gleichzeitig'):
  // Initial-State auf n-fest-init brach bei Race: wenn Component mountet bevor
  // Answers eintreffen → n=0 → revealedMinIdx=0 → alle Rows sofort sichtbar
  // (idx>=0 immer true). Sound wurde aber im setTimeout-Closure mit neuem n
  // korrekt cascadet → nur visuell defekt. Fix: useEffect-deps=[n] + StartedRef
  // damit Cascade einmalig startet sobald n erstmals >0 wird.
  const [revealedMinIdx, setRevealedMinIdx] = useState<number>(n);
  const cascadeStartedRef = useRef(false);
  const STEP_MS = 1600;
  const INITIAL_DELAY_MS = 500;

  useEffect(() => {
    if (cascadeStartedRef.current || n === 0) return;
    cascadeStartedRef.current = true;
    setRevealedMinIdx(n); // alle Rows initial verstecken
    const timers: ReturnType<typeof setTimeout>[] = [];
    const cascadeTotal = n + 1;
    for (let i = 0; i < n; i++) {
      const targetIdx = n - 1 - i;
      const isTopRow = i === n - 1;
      const t = setTimeout(() => {
        setRevealedMinIdx(targetIdx);
        if (!s.sfxMuted) {
          try { playAvatarCascadeNote(i, cascadeTotal); } catch {}
          if (isTopRow) {
            try { playRevealHighlight(); } catch {}
          }
        }
      }, INITIAL_DELAY_MS + i * STEP_MS);
      timers.push(t);
    }
    return () => { timers.forEach(clearTimeout); };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [n]);

  const qText = (lang === 'en' && q.textEn ? q.textEn : q.text) ?? '';

  return (
    <div style={{
      flex: 1, display: 'flex', flexDirection: 'column',
      gap: 'clamp(12px, 1.6vh, 20px)',
      padding: 'clamp(14px, 1.8vh, 24px) clamp(20px, 3vw, 48px)',
      animation: 'contentReveal 0.45s var(--qq-ease-pop-fast) both',
      minHeight: 0,
    }}>
      {/* ── Zeile 1: Frage über ganze Breite (Top-5-Style) ── */}
      <div style={{
        background: 'rgba(255,255,255,0.04)',
        border: '2px solid rgba(255,255,255,0.08)',
        borderRadius: 24,
        padding: 'clamp(14px, 1.8vh, 22px) clamp(22px, 2.6vw, 42px)',
        boxShadow: '0 8px 32px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.05)',
        animation: 'bQuestionIn 0.5s var(--qq-ease-bounce) both',
        display: 'flex', flexDirection: 'column', justifyContent: 'center',
        flexShrink: 0, overflow: 'hidden',
      }}>
        <div style={{
          fontSize: 'clamp(11px, 1vw, 14px)', fontWeight: 900, color: '#EAB308',
          letterSpacing: '0.1em', textTransform: 'uppercase', marginBottom: 6,
        }}>
          <QQEmojiIcon emoji="🎯"/> {lang === 'en' ? 'Guess It — Reveal' : 'Schätzchen — Auflösung'}
        </div>
        <div key={lang} style={{
          fontSize: qText.length > 120 ? 'clamp(26px, 2.6vw, 40px)' : 'clamp(30px, 3.2vw, 52px)',
          fontWeight: 900, lineHeight: 1.18, color: '#F1F5F9',
          textAlign: 'center', minWidth: 0,
          animation: 'langFadeIn 0.4s ease both',
        }}>
          {qText}
        </div>
      </div>

      {/* ── Zeile 2: Grid — links Lösung + Gewinner, rechts Top 5 ── */}
      <div style={{
        flex: 1, display: 'grid',
        gridTemplateColumns: 'minmax(0, 1fr) minmax(0, 1fr)',
        gap: 'clamp(16px, 2.4vw, 32px)',
        minHeight: 0,
      }}>
        {/* Linke Spalte: 2 separate Cards — Lösung (gruen umrandet) oben,
            Gewinner (in Teamfarbe umrandet) unten. War vorher eine unified
            Card mit nur grünem Rand und Winner als Footer — User wollte die
            Winner-Hälfte deutlich in Team-Farbe abgesetzt sehen. */}
        <div style={{
          display: 'flex', flexDirection: 'column',
          gap: 'clamp(10px, 1.4vh, 18px)',
          minHeight: 0, minWidth: 0,
        }}>
          {/* Loesung — obere Card, gruen umrandet */}
          <div style={{
            flex: '1 1 0', minHeight: 0,
            borderRadius: 24,
            background: 'radial-gradient(circle at 50% 35%, rgba(34,197,94,0.18), rgba(22,163,74,0.04) 70%)',
            border: '3px solid rgba(34,197,94,0.6)',
            boxShadow: '0 0 50px rgba(34,197,94,0.25), inset 0 0 26px rgba(34,197,94,0.08)',
            animation: 'revealAnswerBam 0.6s var(--qq-ease-out-cubic) 0.2s both',
            padding: 'clamp(14px, 1.8vh, 24px) clamp(18px, 2vw, 30px)',
            display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: 10,
            position: 'relative', overflow: 'hidden',
          }}>
            {/* Shimmer-Sweep */}
            <div style={{
              position: 'absolute', top: 0, width: '60%', height: '100%',
              background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.12), transparent)',
              animation: 'revealShimmer 0.9s ease 0.55s both',
              pointerEvents: 'none',
            }} />
            <div style={{
              fontSize: 'clamp(12px, 1.2vw, 18px)', fontWeight: 900, color: '#86efac',
              letterSpacing: '0.1em', textTransform: 'uppercase', opacity: 0.82,
              position: 'relative', zIndex: 1,
            }}>
              {lang === 'en' ? 'Answer' : 'Lösung'}
            </div>
            <div style={{
              fontSize: 'clamp(64px, 8vw, 140px)',
              fontWeight: 900, color: '#86efac', lineHeight: 1,
              fontVariantNumeric: 'tabular-nums',
              textShadow: '0 0 40px rgba(34,197,94,0.5)',
              position: 'relative', zIndex: 1,
            }}>
              {fmt(target)}
            </div>
          </div>

          {/* Winner — untere Card, in Teamfarbe umrandet */}
          {winner && (
            <div style={{
              flex: '1 1 0', minHeight: 0,
              borderRadius: 24,
              border: `3px solid ${winner.team.color}`,
              background: `linear-gradient(180deg, ${winner.team.color}26, ${winner.team.color}08)`,
              boxShadow: `0 0 44px ${winner.team.color}44, inset 0 0 26px ${winner.team.color}11`,
              padding: 'clamp(14px, 1.8vh, 24px) clamp(18px, 2.2vw, 32px)',
              display: 'flex', flexDirection: 'column',
              alignItems: 'center', justifyContent: 'center',
              gap: 'clamp(8px, 1.2vh, 16px)',
              minWidth: 0,
              opacity: revealedMinIdx === 0 ? 1 : 0.12,
              filter: revealedMinIdx === 0 ? 'none' : 'blur(18px) saturate(0.4)',
              transition: 'opacity 0.7s ease, filter 0.7s ease',
              position: 'relative',
            }}>
              {/* Trophy-Label oben, klein und mittig */}
              <span style={{
                fontSize: 'clamp(10px, 0.9vw, 13px)', fontWeight: 900,
                color: winner.team.color, letterSpacing: '0.1em', textTransform: 'uppercase',
                opacity: 0.92, whiteSpace: 'nowrap',
              }}>
                <QQEmojiIcon emoji="🏆"/> {lang === 'en' ? 'Closest' : 'Am nächsten dran'}
              </span>

              {/* Mega-Zahl — gleiche Groesse + zentriert wie Loesung darueber */}
              <div style={{
                fontSize: 'clamp(64px, 8vw, 140px)',
                fontWeight: 900, color: winner.team.color, lineHeight: 1,
                fontVariantNumeric: 'tabular-nums',
                textShadow: `0 0 40px ${winner.team.color}55`,
                animation: revealedMinIdx === 0 ? 'revealWinnerIn 0.6s var(--qq-ease-bounce) 0.3s both' : 'none',
              }}>
                {fmt(winner.num)}
              </div>

              {/* Team-Info-Reihe: Avatar | Name | Delta-Pill */}
              <div style={{
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                gap: 'clamp(10px, 1.2vw, 18px)',
                flexWrap: 'wrap', minWidth: 0,
              }}>
                <QQTeamAvatar avatarId={winner.team.avatarId} teamEmoji={winner.team.emoji} size={'clamp(48px, 5vw, 72px)'} style={{
                  flexShrink: 0,
                  boxShadow: `0 0 22px ${winner.team.color}88`,
                  animation: revealedMinIdx === 0 ? 'celebShake 0.6s ease 0.6s both' : 'none',
                }} />
                {/* Name als Pille (Rechteck mit Team-Color-Tint) — 2 Zeilen
                    erlaubt, damit lange Witznamen voll ausgeschrieben werden
                    (Wolf-Wunsch 2026-05-04: kein '...' am Namen). */}
                <div style={{
                  padding: 'clamp(6px, 0.9vh, 10px) clamp(14px, 1.8vw, 22px)',
                  borderRadius: 16,
                  background: `${winner.team.color}22`,
                  border: `2px solid ${winner.team.color}66`,
                  boxShadow: `0 0 18px ${winner.team.color}33`,
                  maxWidth: 'min(50vw, 480px)',
                  textShadow: `0 0 22px ${winner.team.color}55`,
                }}>
                  <TeamNameLabel
                    name={winner.team.name}
                    withTeamPrefix
                    maxLines={2}
                    shrinkAfter={18}
                    fontSize="clamp(20px, 2.2vw, 36px)"
                    color={winner.team.color}
                    fontWeight={900}
                    style={{ textAlign: 'center', lineHeight: 1.1 }}
                  />
                </div>
                <div style={{
                  display: 'inline-flex', alignItems: 'baseline', gap: 6,
                  padding: '6px 16px',
                  borderRadius: 999,
                  background: winner.delta === 0 ? 'rgba(34,197,94,0.22)' : `${winner.team.color}22`,
                  border: winner.delta === 0 ? '2px solid rgba(34,197,94,0.6)' : `2px solid ${winner.team.color}55`,
                  fontSize: 'clamp(16px, 1.7vw, 26px)', fontWeight: 900,
                  color: winner.delta === 0 ? '#86efac' : '#e2e8f0',
                  fontVariantNumeric: 'tabular-nums',
                  letterSpacing: '0.04em',
                }}>
                  {winner.delta === 0
                    ? (lang === 'en' ? '✨ exact!' : '✨ genau!')
                    : `Δ ${fmt(winner.delta)}`}
                </div>
              </div>
            </div>
          )}
          {!winner && (
            <div style={{
              flex: '1 1 0', minHeight: 0,
              borderRadius: 24,
              border: '2px solid rgba(239,68,68,0.4)',
              padding: 'clamp(14px, 1.8vh, 24px) clamp(18px, 2.2vw, 32px)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 'clamp(20px, 2.2vw, 32px)', fontWeight: 900, color: '#f87171',
            }}>
              {lang === 'en' ? 'No valid guesses.' : 'Keine gültigen Schätzungen.'}
            </div>
          )}
        </div>

        {/* Rechte Spalte: Top 5 Ranking (bottom-up enthüllt) */}
        <div style={{
          display: 'flex', flexDirection: 'column', gap: 'clamp(8px, 1.2vh, 14px)',
          minHeight: 0, minWidth: 0,
        }}>
          {top5.map((r, idx) => {
            const rank = idx + 1;
            const isVisible = idx >= revealedMinIdx;
            const isTop = rank === 1;
            // Cozy-Range: 2nd-Place ist Co-Winner wenn er in `currentQuestionWinners`
            // ist (Backend hat das beim eval bestimmt). Visuell als '+1 Feld'-Pille
            // markiert, damit klar ist 'der hat auch was bekommen'.
            const isInRangeWinner = !isTop && (s.currentQuestionWinners ?? []).includes(r.teamId);
            const rankGradient = rank === 1
              ? 'linear-gradient(135deg,#EC4899,#EC4899)'
              : rank === 2
                ? 'linear-gradient(135deg,#E2E8F0,#94A3B8)'
                : rank === 3
                  ? 'linear-gradient(135deg,#F97316,#B45309)'
                  : 'linear-gradient(135deg,#475569,#334155)';
            return (
              <div
                key={r.teamId}
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'auto auto 1fr auto',
                  alignItems: 'center',
                  gap: 'clamp(10px, 1.2vw, 18px)',
                  padding: 'clamp(10px, 1.4vh, 18px) clamp(14px, 1.6vw, 22px)',
                  borderRadius: 16,
                  background: isTop
                    ? `linear-gradient(135deg, ${r.team.color}22, ${r.team.color}08)`
                    : isInRangeWinner
                      ? `linear-gradient(135deg, ${r.team.color}1a, ${r.team.color}05)`
                      : 'rgba(148,163,184,0.06)',
                  border: isTop
                    ? `2px solid ${r.team.color}55`
                    : isInRangeWinner
                      ? `2px solid ${r.team.color}55`
                      : '2px solid rgba(148,163,184,0.15)',
                  visibility: isVisible ? 'visible' : 'hidden',
                  animation: isVisible
                    ? `top5RowSlideIn 0.55s var(--qq-ease-out-cubic) both, top5RowGlow 1.2s ease 0.3s both`
                    : 'none',
                  flex: 1,
                  minHeight: 'clamp(72px, 9vh, 110px)',
                  boxShadow: isTop
                    ? `0 0 28px ${r.team.color}33`
                    : isInRangeWinner ? `0 0 18px ${r.team.color}22` : 'none',
                }}
              >
                <div style={{
                  width: 'clamp(52px, 5vw, 72px)', height: 'clamp(52px, 5vw, 72px)',
                  borderRadius: 16,
                  background: rankGradient,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 'clamp(24px, 2.8vw, 40px)', fontWeight: 900, color: '#fff',
                  flexShrink: 0,
                  textShadow: '0 2px 4px rgba(0,0,0,0.3)',
                  animation: isVisible ? 'top5RankPop 0.55s var(--qq-ease-bounce) 0.1s both' : 'none',
                  boxShadow: rank === 1 ? '0 0 20px rgba(236,72,153,0.5)' : 'none',
                }}>
                  #{rank}
                </div>
                <QQTeamAvatar avatarId={r.team.avatarId} teamEmoji={r.team.emoji} size={'clamp(44px, 4.4vw, 62px)'} style={{
                  boxShadow: `0 0 14px ${r.team.color}55`,
                  flexShrink: 0,
                  animation: isVisible ? `top5AvatarPop 0.5s cubic-bezier(0.34,1.6,0.64,1) 0.35s both` : 'none',
                }} />
                <div style={{ minWidth: 0 }}>
                  <div style={{
                    display: 'flex', alignItems: 'center', gap: 8,
                  }}>
                    <span style={{
                      fontSize: 'clamp(16px, 1.7vw, 24px)', fontWeight: 900,
                      color: isTop || isInRangeWinner ? r.team.color : '#cbd5e1',
                      lineHeight: 1.1,
                      overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                    }}>{r.team.name}</span>
                    {isInRangeWinner && (
                      <span style={{
                        display: 'inline-flex', alignItems: 'center', gap: 4,
                        padding: '2px 8px', borderRadius: 999,
                        background: `${r.team.color}26`,
                        border: `1.5px solid ${r.team.color}55`,
                        fontSize: 'clamp(11px, 1.1vw, 15px)', fontWeight: 900,
                        color: r.team.color,
                        whiteSpace: 'nowrap',
                      }}>
                        🎯 {lang === 'en' ? 'in range · +1' : 'in Range · +1'}
                      </span>
                    )}
                  </div>
                  <div style={{
                    fontSize: 'clamp(24px, 2.6vw, 40px)', fontWeight: 900,
                    color: isTop ? '#FBCFE8' : '#f1f5f9', marginTop: 4,
                    lineHeight: 1,
                    fontVariantNumeric: 'tabular-nums',
                    textShadow: isTop ? '0 0 16px rgba(236,72,153,0.35)' : 'none',
                  }}>
                    {fmt(r.num)}
                  </div>
                </div>
                <div style={{
                  padding: '8px 18px', borderRadius: 999,
                  background: isTop ? 'rgba(250,204,21,0.22)' : 'rgba(15,23,42,0.7)',
                  border: isTop ? '2px solid rgba(250,204,21,0.55)' : '1.5px solid rgba(148,163,184,0.3)',
                  fontSize: 'clamp(18px, 1.9vw, 28px)', fontWeight: 900,
                  color: isTop ? '#FBCFE8' : '#e2e8f0',
                  fontVariantNumeric: 'tabular-nums',
                  flexShrink: 0,
                  animation: isVisible ? `top5AvatarPop 0.5s cubic-bezier(0.34,1.6,0.64,1) 0.45s both` : 'none',
                }}>
                  {r.delta === 0 ? '🎯 0' : `Δ ${fmt(r.delta)}`}
                </div>
              </div>
            );
          })}
          {top5.length === 0 && (
            <div style={{
              flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center',
              color: '#64748b', fontSize: 'clamp(18px, 2vw, 28px)', fontWeight: 700,
            }}>
              {lang === 'en' ? 'No valid guesses.' : 'Keine gültigen Schätzungen.'}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function CozyGuessrReveal({ state: s, lang }: { state: QQStateUpdate; lang: 'de' | 'en' }) {
  const q = s.currentQuestion!;
  const btt = (q.bunteTuete as any);
  const tLat: number = btt.lat;
  const tLng: number = btt.lng;
  const step = s.mapRevealStep ?? 0;

  // Distanzen + Sortierung worst→best (für dramatisches Aufdecken)
  const scored = useMemo(() => {
    return [...s.answers].map(a => {
      const parts = String(a.text ?? '').split(',');
      const lat = Number(parts[0]); const lng = Number(parts[1]);
      if (!Number.isFinite(lat) || !Number.isFinite(lng)) return { ...a, lat: null as any, lng: null as any, distKm: null as any };
      const R = 6371;
      const dLat = (lat - tLat) * Math.PI / 180;
      const dLng = (lng - tLng) * Math.PI / 180;
      const aa = Math.sin(dLat/2)**2 + Math.cos(tLat*Math.PI/180)*Math.cos(lat*Math.PI/180)*Math.sin(dLng/2)**2;
      return { ...a, lat, lng, distKm: R * 2 * Math.atan2(Math.sqrt(aa), Math.sqrt(1-aa)) };
    }).filter(a => a.distKm !== null);
  }, [s.answers, tLat, tLng]);

  const worstFirst = useMemo(() => [...scored].sort((a, b) => (b.distKm ?? 0) - (a.distKm ?? 0)), [scored]);
  const bestFirst  = useMemo(() => [...scored].sort((a, b) => (a.distKm ?? 0) - (b.distKm ?? 0)), [scored]);

  // Pins werden EXAKT an der eingereichten Position dargestellt — kein
  // Cluster-Spread mehr. (User-Wunsch 2026-04-28: 'pins müssen exakt gesetzt
  // werden, nicht rundherum um das ziel'. Geoguessr-Look — falls Pins
  // überlappen ist das die echte Information; bounds.fit zoomt automatisch
  // näher rein wenn alle Pins eng beieinander liegen.)
  const displayPos = useMemo(() => {
    const out = new Map<string, { lat: number; lng: number }>();
    for (const p of scored) {
      if (p.lat != null && p.lng != null) {
        out.set(p.teamId, { lat: p.lat, lng: p.lng });
      }
    }
    return out;
  }, [scored]);

  const showTarget  = step >= 1;
  const revealedCnt = Math.max(0, step - 1); // Step 2 = 1 Pin, Step 3 = 2 Pins, ...
  const revealedPins = worstFirst.slice(0, revealedCnt);
  const validCount = scored.length;
  const showRanking = step >= (1 + validCount + 1);

  // FitBounds bounds — aber Cap auf max. 2500km Pin-Distanz vom Ziel. Sehr
  // weit entfernte Pins (z.B. „Penguin-Team in Argentinien" bei einem
  // Hamburg-Quiz) wuerden sonst die Map auf Welt-Level rauszoomen, sodass
  // alle nahen Pins als Pixel verschmelzen. Diese „Off-Map"-Pins werden in
  // einer Leiste unter der Karte separat mit Distanz angezeigt.
  const FIT_MAX_KM = 2500;
  const onMapPins = useMemo(
    () => revealedPins.filter(p => (p.distKm ?? 0) <= FIT_MAX_KM),
    [revealedPins]
  );
  const offMapPins = useMemo(
    () => revealedPins.filter(p => (p.distKm ?? 0) > FIT_MAX_KM),
    [revealedPins]
  );
  const bounds = useMemo(() => {
    const b = L.latLngBounds([] as any);
    if (showTarget) b.extend([tLat, tLng]);
    for (const p of onMapPins) {
      const dp = displayPos.get(p.teamId);
      const lat = dp?.lat ?? p.lat;
      const lng = dp?.lng ?? p.lng;
      b.extend([lat, lng]);
    }
    if (!b.isValid()) b.extend([tLat, tLng]);
    return b;
  }, [showTarget, onMapPins, tLat, tLng, displayPos]);

  // v3 round 11 (User-Wunsch 'cozyguessr am ende um ziel rum zoomen, genau
  // zeigen wie knapp es zwischen teams war'): Geoguessr-Style. Wenn alle
  // Pins revealed sind und das Ranking sichtbar ist (showRanking), zoom auf
  // einen engen Bereich um Ziel + Top-3-naechste-Pins. Wir nutzen ein
  // separates Bounds + ein eigenes FitBounds-Trigger.
  const closeUpBounds = useMemo(() => {
    const b = L.latLngBounds([] as any);
    b.extend([tLat, tLng]);
    // Top 3 closest valid (on-map) pins um die enge Group-View zu zeigen
    const topClose = bestFirst.filter(p => (p.distKm ?? 0) <= FIT_MAX_KM).slice(0, 3);
    for (const p of topClose) {
      const dp = displayPos.get(p.teamId);
      const lat = dp?.lat ?? p.lat;
      const lng = dp?.lng ?? p.lng;
      if (lat != null && lng != null) b.extend([lat, lng]);
    }
    if (!b.isValid()) b.extend([tLat, tLng]);
    return b;
  }, [bestFirst, tLat, tLng, displayPos]);

  // 2026-04-30 v3 round 10 (User-Wunsch 'kannst du nicht den 📍-emote
  // nutzen' + 'auflösung etwas unpraktisch, ziel sieht man gar nicht'):
  // Target nutzt jetzt das 📍-Pin-Emoji XL mit Glow. Team-Markers haben
  // Avatar oben + 📍-Pin unten der die Tip-Position markiert.
  // iconAnchor sitzt am unteren Tip damit die Nadel exakt auf lat/lng landet.
  // Geoguessr-Style: Target deutlich groesser & dauerhaft pulsierend, plus
  // Distanz-Polylines vom Team-Pin zum Ziel (siehe Render unten).
  const targetIcon = useMemo(() => L.divIcon({
    className: 'qq-target-pin',
    html: `<div style="
      position: relative; width: 88px; height: 110px;
      animation: mapTargetDrop 0.75s var(--qq-ease-bounce) both, qqTargetPulse 2.1s ease-in-out 0.8s infinite;
      transform-origin: 50% 100%;
      filter: drop-shadow(0 0 18px rgba(236,72,153,0.95)) drop-shadow(0 8px 16px rgba(0,0,0,0.6));
    ">
      <span style="
        position: absolute; left: 50%; top: 0;
        transform: translateX(-50%);
        font-size: 96px; line-height: 1;
        color: #EC4899;
      ">📍</span>
      <!-- 2026-05-09 (Wolf): pulsierender pinker Glow-Dot entfernt — war
           redundant zum 📍 selbst, sah aus wie ein Bug. -->
    </div>`,
    iconSize: [88, 110] as any,
    iconAnchor: [44, 105] as any, // Pin-Tip an lat/lng (5px Offset, da Emoji-Tip nicht ganz unten)
  }), []);

  // 2026-05-05 (Wolf-Skizze): Pin-Kopf = runder Team-Color-Disc mit Avatar
  // drauf (Emoji-Mode: Emoji-Glyph; PNG-Mode: cozyCast-PNG). Schaft = sauberer
  // schwarzer CSS-Cone (kein 📍-Emoji mehr — sah „basteln" aus, war Wolfs
  // Beschwerde 'pin köpfe sollen die avatare mit rundem bg sein').
  const makeTeamIcon = (color: string, mode: 'png' | 'emoji', srcOrEmoji: string, emojiFallback: string) => L.divIcon({
    className: 'qq-team-pin',
    html: `<div style="
      position: relative; width: 56px; height: 84px;
      animation: qqTeamPinDrop 0.55s var(--qq-ease-bounce) both;
      transform-origin: 50% 100%;
      filter: drop-shadow(0 6px 8px rgba(0,0,0,0.55));
    ">
      <!-- Schaft (schwarzer CSS-Cone unter Avatar-Disc) -->
      <div style="
        position: absolute; left: 50%; top: 38px;
        transform: translateX(-50%);
        width: 0; height: 0;
        border-left: 9px solid transparent;
        border-right: 9px solid transparent;
        border-top: 44px solid #1A1A1A;
        z-index: 1;
      "></div>
      <!-- Avatar-Disc Kopf (Team-Color BG, Avatar/Emoji drauf) -->
      <div style="
        position: absolute; left: 4px; top: 0;
        width: 48px; height: 48px; border-radius: 50%;
        background: ${color};
        border: 2.5px solid #1A1A1A;
        box-shadow: 0 0 22px ${color}66, inset 0 -3px 6px rgba(0,0,0,0.18), inset 0 2px 4px rgba(255,255,255,0.22);
        display: flex; align-items: center; justify-content: center;
        overflow: hidden;
        z-index: 2;
      ">
        ${mode === 'png' ? `
        <img src="${srcOrEmoji}" alt="" draggable="false"
          onerror="this.style.display='none';this.nextElementSibling.style.display='flex';"
          style="width:100%;height:100%;object-fit:cover;display:block;border-radius:50%;" />
        <span style="display:none;align-items:center;justify-content:center;width:100%;height:100%;font-size:28px;line-height:1;">${emojiFallback}</span>
        ` : `
        <span style="display:flex;align-items:center;justify-content:center;width:100%;height:100%;font-size:30px;line-height:1;filter:drop-shadow(0 1px 2px rgba(0,0,0,0.5));">${srcOrEmoji}</span>
        `}
      </div>
    </div>`,
    iconSize: [56, 84] as any,
    iconAnchor: [28, 82] as any, // Pin-Spitze (Cone-Tip) an lat/lng
  });

  const title = (lang === 'en' ? 'Where on the map?' : 'Wo auf der Karte?');

  return (
    <div style={{ flex: 1, display: 'flex', position: 'relative', overflow: 'hidden', background: '#0A0814' }}>
      {/* Karte */}
      <div style={{ flex: 1, position: 'relative', transition: 'flex 0.7s var(--qq-ease-smooth)' }}>
        <MapContainer
          center={[tLat, tLng] as any}
          zoom={3}
          zoomControl={false}
          attributionControl={false}
          scrollWheelZoom={false}
          doubleClickZoom={false}
          dragging={false}
          touchZoom={false}
          style={{ width: '100%', height: '100%', background: '#0a1120' }}
        >
          {/* CartoDB Voyager — bunte, freundliche Karte mit Labels darueber.
              War vorher 'dark_all' (grau-schwarz) — User wollte was Schoeneres. */}
          <TileLayer
            url="https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png"
            subdomains={['a', 'b', 'c', 'd']}
          />
          {/* Geoguessr-Style: erst Welt-Level (zoom 3), dann smoothes Reinzoomen
              auf den Zielbereich beim ersten Reveal-Schritt. */}
          <QQInitialTargetZoom lat={tLat} lng={tLng} />
          <QQMapResizer trigger={showRanking} />
          <QQFitBoundsOnTrigger bounds={bounds} trigger={step} />
          {/* v3 round 11: Wenn Ranking sichtbar ist (alle Pins revealed),
              zoom rein auf Ziel + Top 3 closest. Geoguessr-Style 'wie knapp
              war es'-Moment. Trigger ist showRanking-Bool als 0/1 */}
          {showRanking && (
            <QQFitBoundsOnTrigger bounds={closeUpBounds} trigger={1000 + step} />
          )}
          {showTarget && (
            // 2026-05-03 (Wolf-Bug 'Pin verdeckt Team-Avatare'): Leaflet
            // sortiert Marker nach Latitude (Norden hinten). zIndexOffset
            // negativ haelt Target-Pin hinter Team-Pins (die +1000 bekommen).
            <Marker position={[tLat, tLng] as any} icon={targetIcon} zIndexOffset={-100} />
          )}
          {/* v3 round 10 (User-Wunsch geoguessr-style 'ziel sieht man gar nicht'):
              Distanz-Polylines vom Team-Pin zum Ziel — nur wenn target sichtbar
              (showTarget) und beide on-map. team-color, dashed style fuer
              Map-Pin-Verbindung-Look wie Geoguessr. */}
          {showTarget && onMapPins.map(p => {
            const team = s.teams.find(t => t.id === p.teamId);
            if (!team) return null;
            const dp = displayPos.get(p.teamId);
            const lat = dp?.lat ?? p.lat;
            const lng = dp?.lng ?? p.lng;
            return (
              <Polyline
                key={`line-${p.teamId}`}
                positions={[[lat, lng], [tLat, tLng]] as any}
                pathOptions={{
                  color: team.color,
                  weight: 2.5,
                  opacity: 0.65,
                  dashArray: '6 8',
                }}
              />
            );
          })}
          {onMapPins.map(p => {
            const team = s.teams.find(t => t.id === p.teamId);
            if (!team) return null;
            const dp = displayPos.get(p.teamId);
            const lat = dp?.lat ?? p.lat;
            const lng = dp?.lng ?? p.lng;
            return (
              <Marker
                key={p.teamId}
                position={[lat, lng] as any}
                icon={(() => {
                  // 2026-05-05 (Wolf-Bug 'pin emoji nicht das gewaehlte'):
                  // serverEmojis + team.emoji werden jetzt durchgereicht,
                  // sodass der Map-Pin das vom Spieler gewaehlte Emoji zeigt.
                  const display = getAvatarDisplay(team.avatarId, s.avatarSetId, s.avatarSetEmojis, team.emoji);
                  if (display.kind === 'png') {
                    return makeTeamIcon(team.color, 'png', display.pngBase, team.emoji ?? qqGetAvatar(team.avatarId).emoji);
                  }
                  return makeTeamIcon(team.color, 'emoji', display.emoji, display.emoji);
                })()}
                zIndexOffset={1000}
              />
            );
          })}
        </MapContainer>

        {/* Off-Map Indikator: Pins die >2500km vom Ziel weg sind, werden auf
            der Map nicht eingerahmt (sonst zoomt sie auf Welt-Level raus).
            Stattdessen hier kompakt mit Distanz-Pfeil. */}
        {offMapPins.length > 0 && (
          <div style={{
            position: 'absolute', top: 88, left: '50%', transform: 'translateX(-50%)',
            display: 'flex', alignItems: 'center', gap: 10, flexWrap: 'wrap',
            padding: '8px 16px', borderRadius: 999,
            background: 'rgba(13,10,6,0.85)',
            border: '1.5px solid rgba(236,72,153,0.35)',
            zIndex: 1000, maxWidth: 'calc(100% - 80px)', justifyContent: 'center',
          }}>
            <span style={{
              fontSize: 13, fontWeight: 900, color: '#FBCFE8',
              letterSpacing: 0.3, textTransform: 'uppercase',
            }}>
              {lang === 'en' ? '✈ Far away' : '✈ Weit weg'}
            </span>
            {offMapPins.map(p => {
              const team = s.teams.find(t => t.id === p.teamId);
              if (!team) return null;
              return (
                <span key={p.teamId} style={{
                  display: 'inline-flex', alignItems: 'center', gap: 6,
                  padding: '4px 10px 4px 4px', borderRadius: 999,
                  background: 'rgba(15,23,42,0.6)',
                  border: `1.5px solid ${team.color}55`,
                }}>
                  <QQTeamAvatar avatarId={team.avatarId} teamEmoji={team.emoji} size={28} />
                  <span style={{
                    fontWeight: 900, color: team.color, fontSize: 13,
                    fontVariantNumeric: 'tabular-nums', letterSpacing: 0.2,
                  }}>
                    {(p.distKm ?? 0) >= 1000 ? `${((p.distKm ?? 0) / 1000).toFixed(1)} Mm` : `${Math.round(p.distKm ?? 0)} km`}
                  </span>
                </span>
              );
            })}
          </div>
        )}

        {/* Title-Overlay oben */}
        <div style={{
          position: 'absolute', top: 28, left: '50%', transform: 'translateX(-50%)',
          padding: '12px 28px', borderRadius: 999,
          background: 'rgba(15,23,42,0.85)', border: '2px solid rgba(236,72,153,0.4)',
          color: '#FBCFE8', fontWeight: 900, fontSize: 'clamp(20px, 2.4vw, 32px)',
          boxShadow: '0 8px 24px rgba(0,0,0,0.5), 0 0 28px rgba(236,72,153,0.25)',
          zIndex: 1000, letterSpacing: 0.3,
        }}>
          <QQEmojiIcon emoji="🌍"/> {title}
        </div>

      </div>

      {/* Ranking-Panel rechts (slide-in) — Sizing so dass min. 8 Teams reinpassen.
          2026-05-05 (Wolf): justifyContent center damit die Liste vertikal mittig
          sitzt statt top-aligned. Bei mehr Teams als reinpassen kicked overflow:auto. */}
      {showRanking && (
        <div style={{
          flex: '0 0 38%', padding: '34px 22px 22px',
          background: 'linear-gradient(180deg, rgba(15,23,42,0.96), rgba(13,10,6,0.96))',
          borderLeft: '2px solid rgba(236,72,153,0.2)',
          boxShadow: '-12px 0 40px rgba(0,0,0,0.5)',
          animation: 'qqMapRankSlideIn 0.7s var(--qq-ease-out-cubic) both',
          display: 'flex', flexDirection: 'column', justifyContent: 'center',
          gap: 8, overflowY: 'auto',
        }}>
          <div style={{
            fontWeight: 900, fontSize: 'clamp(22px, 2.4vw, 32px)',
            color: '#FBCFE8', marginBottom: 6, textAlign: 'center', letterSpacing: 0.4,
          }}>
            <QQEmojiIcon emoji="🏆"/> {lang === 'en' ? 'Closest to target' : 'Am nächsten dran'}
          </div>
          {(() => {
            // Tie-Erkennung: Teams mit (gerundet) gleicher Distanz — dann entscheidet Speed.
            // Gruppen nach Distanz-Bucket (auf Anzeige-Präzision, also ganze Meter bzw. 0.1 km).
            const bucket = (km: number | null): string => {
              if (km == null) return '—';
              return km < 1 ? `${Math.round(km * 1000)}m` : `${km.toFixed(1)}km`;
            };
            const tieGroups: Record<string, number> = {};
            bestFirst.forEach(p => { const k = bucket(p.distKm); tieGroups[k] = (tieGroups[k] ?? 0) + 1; });
            const groupEarliest: Record<string, number> = {};
            bestFirst.forEach(p => {
              const k = bucket(p.distKm);
              const at = p.submittedAt ?? 0;
              if (groupEarliest[k] == null || at < groupEarliest[k]) groupEarliest[k] = at;
            });
            return bestFirst.map((p, i) => {
              const team = s.teams.find(t => t.id === p.teamId);
              if (!team) return null;
              const medal = i === 0 ? <QQEmojiIcon emoji="🥇"/> : i === 1 ? <QQEmojiIcon emoji="🥈"/> : i === 2 ? <QQEmojiIcon emoji="🥉"/> : `#${i+1}`;
              const dist = p.distKm == null ? '—' : p.distKm < 1 ? `${Math.round(p.distKm * 1000)} m` : `${p.distKm.toFixed(1)} km`;
              const isTop = i === 0;
              const key = bucket(p.distKm);
              const isTied = (tieGroups[key] ?? 0) > 1;
              const deltaMs = isTied && p.submittedAt ? p.submittedAt - (groupEarliest[key] ?? p.submittedAt) : 0;
              const timeLabel = isTied ? (deltaMs === 0 ? '⚡ zuerst' : `+${(deltaMs / 1000).toFixed(1)}s`) : null;
              return (
                <div key={p.teamId} style={{
                  display: 'flex', alignItems: 'center', gap: 12,
                  padding: '10px 14px', borderRadius: 16,
                  background: isTop ? `linear-gradient(90deg, ${team.color}22, ${team.color}0a)` : 'rgba(255,255,255,0.04)',
                  border: `2px solid ${isTop ? team.color + '88' : 'rgba(255,255,255,0.08)'}`,
                  boxShadow: isTop ? `0 0 24px ${team.color}44` : 'none',
                  animation: `contentReveal 0.45s var(--qq-ease-pop-fast) ${0.15 + i * 0.08}s both`,
                }}>
                  <span style={{ fontSize: 'clamp(26px, 2.8vw, 38px)', width: 52, textAlign: 'center', fontWeight: 900, fontFamily: "'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif", color: isTop ? '#FBCFE8' : '#cbd5e1' }}>{medal}</span>
                  <QQTeamAvatar avatarId={team.avatarId} teamEmoji={team.emoji} size={'clamp(36px, 3.8vw, 54px)'} />
                  <span title={team.name} style={{ flex: 1, minWidth: 0, fontWeight: 900, fontSize: 'clamp(20px, 2.2vw, 30px)', color: team.color, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{team.name}</span>
                  {timeLabel && (
                    <span style={{
                      fontWeight: 900, fontSize: 'clamp(14px, 1.3vw, 18px)',
                      padding: '3px 10px', borderRadius: 999,
                      background: deltaMs === 0 ? 'rgba(250,204,21,0.18)' : 'rgba(148,163,184,0.12)',
                      color: deltaMs === 0 ? '#FBCFE8' : '#94a3b8',
                      border: `1px solid ${deltaMs === 0 ? 'rgba(250,204,21,0.4)' : 'rgba(148,163,184,0.25)'}`,
                    }}>{timeLabel}</span>
                  )}
                  <span style={{ fontWeight: 900, fontSize: 'clamp(19px, 1.9vw, 26px)', color: isTop ? '#86efac' : '#94a3b8', fontFamily: "'Bricolage Grotesque', 'Inter', 'Nunito', system-ui, sans-serif" }}><QQEmojiIcon emoji="📍"/> {dist}</span>
                </div>
              );
            });
          })()}
        </div>
      )}

      {/* Antwort-Label unten — 2026-05-09 (Wolf 'reveal text leicht rechts
          versetzt'): pill ist jetzt im OUTER container statt im map-flex-item.
          Bei eingeblendetem Ranking-Panel (38%) bleibt die Pill mittig im
          gesamten Beamer-Viewport, nicht nur im Map-Bereich. */}
      {showTarget && q.answer && (
        <div style={{
          position: 'absolute', bottom: 28, left: '50%', transform: 'translateX(-50%)',
          padding: '14px 32px', borderRadius: 16,
          background: 'rgba(13,10,6,0.92)',
          border: '2.5px solid rgba(34,197,94,0.7)',
          color: '#86efac', fontWeight: 900, fontSize: 'clamp(22px, 2.8vw, 38px)',
          boxShadow: '0 0 50px rgba(34,197,94,0.35), 0 8px 24px rgba(0,0,0,0.45)',
          textShadow: '0 2px 4px rgba(0,0,0,0.5)',
          textAlign: 'center',
          animation: 'revealAnswerBam 0.6s var(--qq-ease-out-cubic) both',
          zIndex: 1000, pointerEvents: 'none',
        }}>
          {formatRevealedAnswer(lang, q.answer, q.answerEn)}
        </div>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// QUESTION VIEW (active + reveal)
// ═══════════════════════════════════════════════════════════════════════════════

export function QuestionView({ state: s, revealed, hideCutouts }: { state: QQStateUpdate; revealed: boolean; hideCutouts?: boolean }) {
  const q = s.currentQuestion;
  if (!q) return null;
  const cat = q.category as QQCategory;
  const catLabel = QQ_CATEGORY_LABELS[cat];
  const accent = CAT_ACCENT[cat] ?? '#e2e8f0';
  const badgeBg = CAT_BADGE_BG[cat] ?? '#374151';
  const glow = CAT_GLOW[cat] ?? 'transparent';
  // Dekorative Corner-Emojis pro Kategorie — aktuell ausgeblendet (Tester fanden sie
  // verwirrend: "was macht das?"). Zum Reaktivieren: SHOW_CAT_CUTOUTS auf true setzen.
  const SHOW_CAT_CUTOUTS = false;
  const cutouts = SHOW_CAT_CUTOUTS ? (CAT_CUTOUTS[cat] ?? []) : [];
  // Per-question emoji override: replace default cutout emojis
  const effectiveCutouts = q.emojis?.length
    ? cutouts.map((c, i) => q.emojis![i] ? { ...c, emoji: q.emojis![i] } : c)
    : cutouts;
  const cardBg = s.theme?.cardBg ?? COZY_CARD_BG;
  const img = q.image;
  // For CHEESE (Picture This): show image even with layout='none' — it's the main visual
  const isCheese = cat === 'CHEESE';
  const hasImg = img && img.url && (isCheese || img.layout !== 'none');
  const isWindow = hasImg && !isCheese && (img.layout === 'window-left' || img.layout === 'window-right');
  const lang = useLangFlip(s.language);

  // 2026-05-05 (Wolf): CozyGuessr-Active mit Bild = Cheese-Landscape-Layout.
  // Bild fullscreen + Frosted Card unten + Timer + Avatar-Progress.
  // Reveal greift frueher (isMapReveal -> CozyGuessrReveal), daher nur Active-Phase.
  const isMapKind = cat === 'BUNTE_TUETE' && (q.bunteTuete as any)?.kind === 'map';
  const useMapPicture = isMapKind && !!hasImg && !revealed;

  // 2026-04-30 v3 (User-Wunsch): Cheese Portrait → 2-Spalten-Layout.
  // Image links voll Top-to-Bottom, Question-Card rechts vertikal mittig.
  // Detection via natural-dimensions preload — kein Backend-Feld noetig.
  // 2026-05-05: gilt auch fuer CozyGuessr-Active mit Bild.
  // 2026-05-05 v2 (Wolf-Bug 'bei cheese sieht man kurz etwas bevor die seite
  // angeordnet erscheint, wirkt unruhig'): imgReady hält das Cheese-Layout
  // unsichtbar bis Portrait-Detection durch ist — sonst rendert der Container
  // mit isCheesePortrait=false (Default) und shifted dann sichtbar wenn ein
  // Portrait erkannt wurde.
  // 2026-05-10 (Wolf-Wunsch): img.cheeseLayout-Override gewinnt vor Auto-
  // Detection. Damit Wolf bei Edge-Cases (quadratische Bilder, fast-Quadrat
  // Karten) explizit forcen kann was er will.
  const [isCheesePortrait, setIsCheesePortrait] = useState(false);
  const [imgReady, setImgReady] = useState(false);
  useEffect(() => {
    if ((!isCheese && !useMapPicture) || !img?.url) {
      setIsCheesePortrait(false);
      setImgReady(true); // kein Bild → kein Detection-Bedarf
      return;
    }
    // Manueller Override per Builder gewinnt vor Auto-Detection.
    if (img.cheeseLayout === 'portrait') {
      setIsCheesePortrait(true);
      setImgReady(true);
      return;
    }
    if (img.cheeseLayout === 'landscape') {
      setIsCheesePortrait(false);
      setImgReady(true);
      return;
    }
    setImgReady(false);
    const tester = new globalThis.Image();
    tester.onload = () => {
      setIsCheesePortrait(tester.naturalHeight > tester.naturalWidth * 1.05); // 5% Toleranz
      setImgReady(true);
    };
    tester.onerror = () => { setIsCheesePortrait(false); setImgReady(true); };
    tester.src = img.url;
  }, [isCheese, useMapPicture, img?.url, img?.cheeseLayout]);

  // 2026-05-04 v3 (Wolf): Timer-Outro-Animation klappt nicht bei Frueh-Abbruch
  // (alle abgegeben → Backend reveal → s.timerEndsAt wird null → Component
  // unmountet sofort → keine Outro-Anim). Loesung: stickyTimer haelt das letzte
  // gueltige endsAt ~1s nach Verschwinden, sodass die qqTimerOutro-Anim 0.85s
  // sauber durchlaufen kann. expireNow=true wird gesetzt sobald das Original-
  // Prop weg ist ODER revealed=true.
  const [stickyTimer, setStickyTimer] = useState<{ endsAt: number; duration: number } | null>(
    s.timerEndsAt ? { endsAt: s.timerEndsAt, duration: s.timerDurationSec } : null
  );
  useEffect(() => {
    if (s.timerEndsAt) {
      setStickyTimer({ endsAt: s.timerEndsAt, duration: s.timerDurationSec });
    }
  }, [s.timerEndsAt, s.timerDurationSec]);
  useEffect(() => {
    if (!s.timerEndsAt && stickyTimer) {
      const t = window.setTimeout(() => setStickyTimer(null), 1000);
      return () => window.clearTimeout(t);
    }
  }, [s.timerEndsAt, stickyTimer]);
  const timerExpiring = stickyTimer !== null && (!s.timerEndsAt || revealed);

  // ── CHEESE Cascade-Audit (2026-05-01): vorher fielen alle Treffer-Avatare
  // gleichzeitig + stumm rein. Jetzt 850ms-Stagger pro Avatar (CSS) + synchron
  // Pentatonik-Cascade-Toene wie Top5/Order. Spannung-Score 1/5 → 4/5.
  const cheeseCorrectCount = useMemo(() => {
    if (cat !== 'CHEESE' || !revealed) return 0;
    // 2026-05-02: Backend-Truth via currentQuestionWinners (war vorher strict-
    // Match, hat Schreibfehler-Akzeptanzen ignoriert).
    const winners = s.currentQuestionWinners ?? (s.correctTeamId ? [s.correctTeamId] : []);
    return winners.length;
  }, [cat, revealed, s.currentQuestionWinners, s.correctTeamId]);

  useEffect(() => {
    if (cat !== 'CHEESE' || !revealed || cheeseCorrectCount === 0) return;
    if (s.sfxMuted) return;
    // 2026-05-06 (Wolf 'letzter Sound der Cascade passiert ohne Animation auf
    // dem Screen, reveal-Reihenfolge tauschen von langsamster zu schnellster
    // Winner und besonderen Sound auf den schnellsten'):
    // Reihenfolge slow→fast Winner. Letzter (= schnellster Winner = Climax)
    // bekommt playRevealHighlight statt Pentatonik-Note (= 'Lösung aufgedeckt'-
    // Sound aus MUCHO/ZvZ). Avatar-Stagger im JSX matched (850ms statt 160ms),
    // damit jedes Sound-Event eine sichtbare Avatar-Drop-Animation hat.
    const cascadeTotal = cheeseCorrectCount + 1;
    const handles: number[] = [];
    for (let i = 0; i < cheeseCorrectCount; i++) {
      const delay = i * 850 - 60; // 60ms Vorlauf fuer psychoakustische Sync
      const isLast = i === cheeseCorrectCount - 1;
      handles.push(window.setTimeout(() => {
        try {
          if (isLast) playRevealHighlight();
          else playAvatarCascadeNote(i, cascadeTotal);
        } catch {}
      }, Math.max(0, delay)));
    }
    return () => handles.forEach(h => window.clearTimeout(h));
  }, [cat, revealed, cheeseCorrectCount, s.sfxMuted]);

  // ── MUCHO: Winner-Card erst nach Jäger-Lock zeigen ──────────────────────
  // Spiegelt die Akt-2-Timing aus MuchoOptionsReveal (hop + lock + speedrun).
  // Solange Winner-Card verborgen ist bleibt die Spannungskurve intakt.
  const muchoNonEmpty = useMemo(() => {
    if (cat !== 'MUCHO' || !q.options) return 0;
    let n = 0;
    for (let i = 0; i < q.options.length; i++) {
      if (s.answers.some(a => a.text === String(i))) n++;
    }
    return n;
  }, [cat, q.options, s.answers]);
  const muchoLockStep = muchoNonEmpty + 1;
  const muchoLocked = cat === 'MUCHO' && revealed && (s.muchoRevealStep ?? 0) >= muchoLockStep;
  // Winner-Card erscheint nach dem Doppelblink (1.1s Animation + 100ms Puffer).
  const [muchoAkt3Ready, setMuchoAkt3Ready] = useState(false);
  useEffect(() => {
    if (!muchoLocked) { setMuchoAkt3Ready(false); return; }
    const t = window.setTimeout(() => setMuchoAkt3Ready(true), 1200);
    return () => window.clearTimeout(t);
  }, [muchoLocked]);

  // ── ZEHN_VON_ZEHN: Step-Reveal — Bet-Cascade + Doppelblink ──────────────
  // Step 0: alle Chips sichtbar AUSSER höchste(r) Bet(s) pro Option; kein Grün, keine Winner-Card.
  // Step 1: höchste Bets kaskadieren pro Option (leere Optionen überspringen).
  // Step 2: Doppelblink auf korrekte Option → Grün + Winner-Card (analog MUCHO).
  const zvzStep = s.zvzRevealStep ?? 0;
  const zvzHighestPerOption = useMemo(() => {
    if (cat !== 'ZEHN_VON_ZEHN' || !q.options) return [] as Array<{ maxPts: number; teamIds: string[]; isEmpty: boolean }>;
    const parsed = s.answers
      .map(a => ({ teamId: a.teamId, pts: String(a.text ?? '').split(',').map(x => parseInt(x.trim(), 10)) }))
      .filter(p => p.pts.length === q.options!.length && !p.pts.some(Number.isNaN));
    return q.options!.map((_, i) => {
      const entries = parsed.map(p => ({ teamId: p.teamId, pts: p.pts[i] ?? 0 })).filter(e => e.pts > 0);
      if (entries.length === 0) return { maxPts: 0, teamIds: [], isEmpty: true };
      const maxPts = Math.max(...entries.map(e => e.pts));
      return { maxPts, teamIds: entries.filter(e => e.pts === maxPts).map(e => e.teamId), isEmpty: false };
    });
  }, [cat, q.options, s.answers]);
  const zvzNonEmptyOptions = useMemo(() => zvzHighestPerOption.map((h, i) => (h.isEmpty ? -1 : i)).filter(i => i >= 0), [zvzHighestPerOption]);
  const [zvzRevealed, setZvzRevealed] = useState<Set<number>>(new Set());
  useEffect(() => {
    if (cat !== 'ZEHN_VON_ZEHN' || !revealed) { setZvzRevealed(new Set()); return; }
    if (zvzStep === 0) { setZvzRevealed(new Set()); return; }
    // Step 2+ (Lock): alle Top-Bets bleiben stationaer sichtbar — KEIN Reset
    // und keine neue Cascade, sonst "erscheinen" die Chips nochmal obwohl
    // sie schon da sind.
    if (zvzStep >= 2) {
      setZvzRevealed(new Set(zvzNonEmptyOptions));
      return;
    }
    // Step 1: Kaskade pro Option (200ms Initial + 550ms pro Option).
    const timers: number[] = [];
    setZvzRevealed(new Set());
    zvzNonEmptyOptions.forEach((optIdx, i) => {
      timers.push(window.setTimeout(() => {
        setZvzRevealed(prev => {
          const next = new Set(prev); next.add(optIdx); return next;
        });
        // 2026-05-05 (Wolf-Bug 'mehrere sounds gleichzeitig'): playTick
        // entfernt — Avatar-Cascade-Note (line 1435) liefert schon den
        // hoerbaren Cascade-Effekt, Tick legte sich oben drauf und matschte.
      }, 200 + i * 550));
    });
    return () => timers.forEach(t => window.clearTimeout(t));
  }, [cat, revealed, zvzStep, zvzNonEmptyOptions.join(','), s.sfxMuted]); // eslint-disable-line react-hooks/exhaustive-deps
  // Lock-Phase (Step 2): Doppelblink auf korrekte Option, Winner-Card nach 1.2s
  const zvzLocked = cat === 'ZEHN_VON_ZEHN' && revealed && zvzStep >= 2 && q.correctOptionIndex != null;
  const [zvzWinnerReady, setZvzWinnerReady] = useState(false);
  useEffect(() => {
    if (!zvzLocked) { setZvzWinnerReady(false); return; }
    const t = window.setTimeout(() => setZvzWinnerReady(true), 1200);
    return () => window.clearTimeout(t);
  }, [zvzLocked]);
  const zvzAkt3Ready = cat === 'ZEHN_VON_ZEHN' ? zvzWinnerReady : true;

  // ── CHEESE: Lösung sofort gruen + Avatare cascadieren (850ms Stagger).
  // 2026-05-01: Cascade-Audit — vorher fielen alle Avatare gleichzeitig rein,
  // WinnerCard erschien direkt = "alles auf einmal"-Gefuehl. Jetzt: Avatare
  // staffeln sich, WinnerCard wartet bis Cascade fertig ist.
  const cheeseShowGreen = true;
  const cheeseShowAvatars = true;
  const [cheeseCascadeDone, setCheeseCascadeDone] = useState(false);
  useEffect(() => {
    if (cat !== 'CHEESE' || !revealed) { setCheeseCascadeDone(false); return; }
    if (cheeseCorrectCount === 0) { setCheeseCascadeDone(true); return; }
    const totalMs = cheeseCorrectCount * 850 + 200;
    const t = window.setTimeout(() => setCheeseCascadeDone(true), totalMs);
    return () => window.clearTimeout(t);
  }, [cat, revealed, cheeseCorrectCount]);

  const showMuchoWinner = cat !== 'MUCHO' || muchoAkt3Ready;
  const showZvzWinner = cat !== 'ZEHN_VON_ZEHN' || zvzAkt3Ready;
  const showCheeseWinner = cat !== 'CHEESE' || cheeseCascadeDone;
  const showUnifiedWinner = showMuchoWinner && showZvzWinner && showCheeseWinner;

  // 2026-04-30: Sound bei Sieger-Card-Einblendung (false→true Transition).
  // Synchron zur Animation: revealWinnerIn nutzt bannerDelay=0.7s, davor ist
  // die Card auf scaleY(0)/opacity:0 — der Sound MUSS auch 700ms warten,
  // sonst kommt er vor dem sichtbaren Banner (User-Feedback: 'sound kommt
  // etwas früh'). 60ms Vorlauf damit Ton minimal vor dem Pop einsetzt =
  // psychoakustisch synchron.
  // 2026-04-30 v3 (User-Wunsch climax IMMER bei WinnerCard): Beim Pop
  // der WinnerCard layern wir Cascade-Top-Ton + Climax-Finish-Akkord
  // gemeinsam — fuer alle Kategorien. So gibt's einheitlich den
  // „Yeah!"-Moment beim Erscheinen der Sieger-Karte. playWinnerCardReveal
  // bleibt als zusaetzlicher Bell-Layer (User kann es im Sound-Panel mute'n).
  const prevShowWinnerRef = useRef(false);
  useEffect(() => {
    const prev = prevShowWinnerRef.current;
    prevShowWinnerRef.current = showUnifiedWinner;
    // 2026-05-05 (Wolf-Bug 'cheese reveal sound passt nicht, gewinnercard fehlt'):
    // Bei CHEESE mit mehreren Winnern ist correctTeamId oft null/leer — nur
    // currentQuestionWinners ist gefuellt.
    // 2026-05-05 v2 (Wolf-Bug 'cheese sound fuer winnercard, aber keine card'):
    // hasWinner muss zusaetzlich pruefen ob die Winner-IDs auch wirklich in
    // s.teams existieren — sonst spielt der Sound aber Render fellt auf das
    // 'team not found → return null'-Branch und Card erscheint nicht.
    const winnerIds = s.currentQuestionWinners ?? (s.correctTeamId ? [s.correctTeamId] : []);
    const hasRenderableWinner = !!s.teams.find(t => t.id === s.correctTeamId)
      || winnerIds.some(id => s.teams.find(t => t.id === id));
    if (!s.sfxMuted && showUnifiedWinner && !prev && revealed && hasRenderableWinner) {
      const cat = s.currentQuestion?.category;
      const subKind = (s.currentQuestion?.bunteTuete as { kind?: string } | undefined)?.kind;
      const isCascadeCategory =
        cat === 'MUCHO' ||
        cat === 'ZEHN_VON_ZEHN' ||
        (cat === 'BUNTE_TUETE' && (subKind === 'top5' || subKind === 'order'));
      const handle = window.setTimeout(() => {
        try {
          // v3 round 11 (User-Bug 'mehrere parallele sounds'): Vorher fired
          // immer climaxFinish + (cascade-top ODER winnerCardReveal). Jetzt
          // nur climaxFinish — der ist schon ein 6-Layer-Akkord, weitere
          // Layer machen es matschig statt klimaktisch.
          playClimaxFinish();
        } catch {}
        // isCascadeCategory referenziert, eslint-friendly
        void isCascadeCategory;
      }, 640);
      return () => window.clearTimeout(handle);
    }
  }, [showUnifiedWinner, revealed, s.correctTeamId, s.currentQuestionWinners, s.sfxMuted, s.currentQuestion?.category, s.currentQuestion?.bunteTuete]);

  // ── CozyGuessr (map) full-screen reveal ─────────────────────────────────
  const isMapReveal = revealed
    && q.category === 'BUNTE_TUETE'
    && (q.bunteTuete as any)?.kind === 'map';
  if (isMapReveal) {
    return <CozyGuessrReveal state={s} lang={lang} />;
  }

  // ── Top-5 two-column reveal ─────────────────────────────────────────────
  const isTop5Reveal = revealed
    && q.category === 'BUNTE_TUETE'
    && (q.bunteTuete as any)?.kind === 'top5';
  if (isTop5Reveal) {
    return <Top5Reveal state={s} lang={lang} />;
  }

  // ── 4 gewinnt / Only Connect: eigene Layout-Komponente für active + reveal ──
  const isOnlyConnect = q.category === 'BUNTE_TUETE'
    && (q.bunteTuete as any)?.kind === 'onlyConnect';
  if (isOnlyConnect) {
    return <OnlyConnectBeamerView state={s} lang={lang} revealed={revealed} />;
  }

  // ── Bluff: eigene 3-Phasen-Layout-Komponente ─────────────────────────────
  const isBluff = q.category === 'BUNTE_TUETE'
    && (q.bunteTuete as any)?.kind === 'bluff';
  if (isBluff) {
    return <BluffBeamerView state={s} lang={lang} revealed={revealed} />;
  }

  // ── Order two-column reveal (Lucky Bag: bring in correct order) ────────
  const isOrderReveal = revealed
    && q.category === 'BUNTE_TUETE'
    && (q.bunteTuete as any)?.kind === 'order';
  if (isOrderReveal) {
    return <OrderReveal state={s} lang={lang} />;
  }

  // ── Schätzchen two-column reveal (Frage + Lösung oben, Winner + Rangliste) ──
  const isSchaetzReveal = revealed && q.category === 'SCHAETZCHEN';
  if (isSchaetzReveal) {
    return <SchaetzchenReveal state={s} lang={lang} />;
  }

  // ── CHEESE / Picture-Active "Overlay" layout ────────────────────────────
  // Image stays fullscreen. Frosted card overlays with question/answer.
  // No separate "image only" phase — question + image appear together.
  // Active: fullscreen image + frosted question card + timer + avatar-progress
  // Reveal (CHEESE only): fullscreen image + frosted answer card + winner.
  //   CozyGuessr-Reveal hat seinen eigenen Pfad (CozyGuessrReveal — siehe oben).
  // Hinweis: CHEESE-Overlay-UI (Antwort-Card, Team-Avatare, Reveal) MUSS auch ohne Bild
  // rendern — sonst ist die Frage unspielbar. Nur der fullscreen-Image-Layer wird ausgeblendet.
  const cheeseOverlay = isCheese || useMapPicture;
  const cheeseWithQuestion = cheeseOverlay && !revealed;
  const isCheeseReveal = isCheese && revealed; // map-reveal laeuft via CozyGuessrReveal
  const cheeseFullscreen = cheeseOverlay && !!hasImg;

  // Auto-size: shorter fontSize for long questions (no size change on reveal — prevents reflow)
  const qText = (lang === 'en' && q.textEn ? q.textEn : q.text) ?? '';
  const isOrderBt = q.category === 'BUNTE_TUETE' && (q.bunteTuete as any)?.kind === 'order';
  // 2026-04-28-v3 (User: 'fragecards die kleiner werden zappelig — könnten
  // wir die cards nicht von Anfang an etwas kleiner machen?'). Wir wählen
  // jetzt EINE moderate Größe für ALLE Phasen (Question + Reveal). Kein
  // shrink mehr → kein zappeln. Sizing knapp aber lesbar; Reveal-Phase
  // dimmt nur opacity statt zu shrinken.
  // 2026-05-04 (Wolf #3): Beamer-Schrift +15-20% damit aus 8m Distanz lesbar.
  const qFontSize = qText.length > 200 ? 'clamp(26px, min(3vw, 4.6vh), 44px)'
    : qText.length > 120 ? 'clamp(32px, min(3.7vw, 5.8vh), 56px)'
    : qText.length > 80  ? 'clamp(38px, min(4.4vw, 6.5vh), 68px)'
    : qText.length > 40  ? 'clamp(42px, min(4.8vw, 7vh), 76px)'
    : 'clamp(46px, min(5.5vw, 7.5vh), 88px)';

  // Category intro overlay removed — category is already shown in PHASE_INTRO

  return (
    <div style={{ flex: 1, display: 'flex', position: 'relative', overflow: 'hidden' }}>
      {/* I1 Kategorie-Partikel (fliegende Zahlen/Buchstaben) entfernt —
          lenkten vom Fragentext ab. Stattdessen faerben wir die Fireflies
          weiter unten in der Kategorie-Farbe. */}
      {/* CHEESE ohne Bild: dezenter Placeholder im Hintergrund (Gradient + 📸-Icon),
          damit die Frage spielbar bleibt aber visuell klar ist „hier sollte ein Bild sein".
          position:absolute (NICHT fixed) — fixed wird durch BeamerFrame-Transform-Stacking-Context geclippt. */}
      {isCheese && !hasImg && (
        <div style={{
          position: 'absolute', inset: 0, zIndex: 1,
          background: 'radial-gradient(ellipse at 50% 50%, rgba(139,92,246,0.18), transparent 60%), radial-gradient(ellipse at 80% 20%, rgba(168,85,247,0.10), transparent 50%), #0A0814',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          flexDirection: 'column', gap: 14,
          pointerEvents: 'none',
        }}>
          <div style={{
            fontSize: 'clamp(120px, 18vw, 240px)', opacity: 0.18,
            animation: 'cfloat 4s ease-in-out infinite',
          }}>📸</div>
          <div style={{
            fontSize: 'clamp(14px, 1.4vw, 18px)', fontWeight: 900,
            color: '#a78bfa', letterSpacing: '0.1em', textTransform: 'uppercase', opacity: 0.55,
          }}>
            {lang === 'de' ? 'Bild fehlt — Frage trotzdem spielbar' : 'No image — question still playable'}
          </div>
        </div>
      )}
      {/* Fullscreen background image: non-overlay fullscreen layout OR CHEESE/Map-Picture overlay.
          2026-05-05 v2 (Wolf-Bug 'kurz etwas vor anordnung sichtbar'): cheeseFullscreen
          wartet auf imgReady (Portrait-Detection durch) damit kein Layout-Shift sichtbar ist. */}
      {((hasImg && img.layout === 'fullscreen' && !cheeseOverlay) || (cheeseFullscreen && imgReady)) && (() => {
        // CHEESE: 3-Schicht-Aufbau gegen Aspect-Ratio-Crop.
        // 1) Blurred cover backdrop — füllt 16:9-Beamer, kein schwarzer Rand
        // 2) Sharp CONTAIN foreground — komplettes Bild sichtbar (Mona Lisas Kopf bleibt drin)
        // 3) Dunkler Vignette-Overlay — Lesbarkeit der Antwort-Card
        // offsetX/Y/scale wirken auf Layer 2; scale=1 (default) zeigt vollständiges Bild.
        const cheeseOX = img!.offsetX ?? 0;
        const cheeseOY = img!.offsetY ?? 0;
        const cheeseZoom = img!.scale ?? 1;
        const cheesePosX = 50 + cheeseOX / 2;
        const cheesePosY = 50 + cheeseOY / 2;
        return (
        <>
          {/* 2026-04-30 v3 (User-Wunsch): Bei Portrait-Foto in CHEESE clippen
              wir alle Bild-Layer auf die LINKE Bildschirm-Haelfte. Question-
              Card-Overlay wandert in den rechten Streifen (siehe Overlay
              weiter unten). Nicht-Cheese und Landscape bleiben unveraendert. */}
          {/* Layer 1: blurred cover backdrop (CHEESE only).
              2026-04-30 v3: Bei Portrait fuellt diese ueberall (full-screen),
              damit der rechte Streifen (Card) nicht schwarz/leer wirkt. Sharp
              Foreground (Layer 2) bleibt nur links — rechts sieht man also
              das Bild als sanft-blurred Backdrop hinter der Card.
              v3 round 5 (User-Bug 'fliegt aus mitte nach links'): fsExpand
              clip-path ersetzt durch reinen opacity-Fade. Das clip-path-
              Expand wirkte wie 'aus Mitte rauslaufen'. */}
          {cheeseFullscreen && (
            <div style={{
              position: 'fixed', inset: 0,
              zIndex: 49,
              backgroundImage: `url(${img!.url})`,
              backgroundSize: 'cover',
              backgroundPosition: 'center',
              backgroundRepeat: 'no-repeat',
              filter: 'blur(36px) brightness(0.45) saturate(1.1)',
              transform: 'scale(1.15)',
              transformOrigin: 'center',
              animation: 'contentReveal 0.6s var(--qq-ease-pop-fast) both',
            }} />
          )}
          {/* Layer 2: sharp foreground (contain für CHEESE, cover für legacy fullscreen).
              2026-05-04 (Wolf): bei cheeseFullscreen sitzt das Bild jetzt in
              einem Wrapper mit overflow:hidden + borderRadius matching Rahmen,
              damit es niemals ueber den Bilderrahmen hinausragt — auch nicht
              bei transform: scale(zoom). */}
          {cheeseFullscreen ? (
            <div style={{
              position: 'fixed',
              top: 'clamp(10px, 1.4vh, 22px)',
              bottom: 'clamp(10px, 1.4vh, 22px)',
              left: 'clamp(12px, 1.6vw, 28px)',
              right: isCheesePortrait
                ? `calc(50% + clamp(6px, 0.8vw, 14px))`
                : 'clamp(12px, 1.6vw, 28px)',
              zIndex: 50,
              borderRadius: 22,
              overflow: 'hidden',
              clipPath: (revealed && !cheeseOverlay) ? 'inset(8% 8% 8% 52% round 18px)' : undefined,
              animation: 'contentReveal 0.7s var(--qq-ease-pop-fast) both',
              transition: 'clip-path 0.8s var(--qq-ease-smooth), right 0.5s ease',
            }}>
              {/* 2026-05-04 v4 (Wolf-Bug 'graue Raender im Rahmen'): vorher
                  backgroundSize:contain → Letterbox-Bars wenn Bild-Aspect nicht
                  zum Rahmen-Aspect passt. Die dahinter liegende Blur-Backdrop
                  ist mit brightness(0.45) so dunkel, dass die Bars als „grau"
                  rauskommen. Jetzt: cover + center (mod kann via offsetX/Y
                  feintunen). Bild fuellt den Rahmen vollstaendig. */}
              <div style={{
                position: 'absolute', inset: 0,
                backgroundImage: `url(${img!.url})`,
                backgroundSize: 'cover',
                backgroundPosition: `${cheesePosX}% ${cheesePosY}%`,
                backgroundRepeat: 'no-repeat',
                transform: `scale(${cheeseZoom})${img!.rotation ? ` rotate(${img!.rotation}deg)` : ''}`,
                transformOrigin: `${cheesePosX}% ${cheesePosY}%`,
                opacity: img!.opacity ?? 1,
                filter: imgFilter(img!),
                transition: 'background-position 0.4s ease, transform 0.4s ease',
              }} />
            </div>
          ) : (
            <div style={{
              position: 'absolute',
              top: 0, bottom: 0,
              left: 0,
              right: 0,
              zIndex: 1,
              backgroundImage: `url(${img!.url})`,
              backgroundSize: 'cover',
              backgroundPosition: 'center',
              backgroundRepeat: 'no-repeat',
              clipPath: (revealed && !cheeseOverlay) ? 'inset(8% 8% 8% 52% round 18px)' : undefined,
              animation: (revealed && !cheeseOverlay) ? undefined : 'fsExpand 1.2s var(--qq-ease-smooth) 0.2s both',
              transition: 'clip-path 0.8s var(--qq-ease-smooth), background-position 0.4s ease, transform 0.4s ease, right 0.5s ease',
              transform: `translate(${img!.offsetX ?? 0}%, ${img!.offsetY ?? 0}%) scale(${img!.scale ?? 1}) rotate(${img!.rotation ?? 0}deg)`,
              transformOrigin: 'center',
              opacity: img!.opacity ?? 1,
              filter: imgFilter(img!),
            }} />
          )}
          {/* Layer 3: vignette overlay.
              2026-04-30 v3: Portrait → vignette FULL-screen (statt left-half),
              damit der rechte Streifen denselben warmen dunklen Wash bekommt
              wie der linke Bildbereich. Sharp Foreground bleibt nur links.
              v3 round 5 (User-Bug 'Bild oben/unten minimal abgeschnitten'):
              Top/Bottom-Vignette deutlich reduziert (0.35/0.40 → 0.15/0.20),
              damit das Bild bis an die Kanten sichtbar bleibt. */}
          <div style={{
            position: cheeseFullscreen ? 'fixed' : 'absolute',
            inset: 0,
            zIndex: cheeseFullscreen ? 51 : 2,
            background: cheeseFullscreen
              ? 'linear-gradient(180deg, rgba(13,10,6,0.15) 0%, rgba(13,10,6,0.06) 30%, rgba(13,10,6,0.06) 70%, rgba(13,10,6,0.20) 100%)'
              : [
                'linear-gradient(90deg, rgba(13,10,6,0.92) 0%, rgba(13,10,6,0.78) 45%, rgba(13,10,6,0.45) 100%)',
                'linear-gradient(180deg, rgba(13,10,6,0.5) 0%, transparent 25%, transparent 70%, rgba(13,10,6,0.6) 100%)',
              ].join(', '),
            opacity: (revealed && !cheeseOverlay) ? 0.4 : 1,
            transition: 'opacity 0.8s ease',
          }} />
          {/* Layer 4: Bilderrahmen in Kategorie-Farbe (Wolf-Wunsch 2026-05-04).
              Dezenter Innen-Rahmen (kein full-bleed Border-Strich) um das Bild,
              damit es als „eingerahmtes Foto" liest statt zu bleeden. Bei
              Portrait-CHEESE umrahmt er nur die linke Bildhaelfte. */}
          {cheeseFullscreen && (
            <div aria-hidden style={{
              position: 'fixed',
              top: 'clamp(10px, 1.4vh, 22px)',
              bottom: 'clamp(10px, 1.4vh, 22px)',
              left: 'clamp(12px, 1.6vw, 28px)',
              right: isCheesePortrait
                ? `calc(50% + clamp(6px, 0.8vw, 14px))`
                : 'clamp(12px, 1.6vw, 28px)',
              borderRadius: 22,
              border: `4px solid ${accent}`,
              boxShadow: `0 0 32px ${accent}55, inset 0 0 0 2px rgba(0,0,0,0.45), inset 0 0 20px rgba(0,0,0,0.35)`,
              pointerEvents: 'none',
              zIndex: 52,
              animation: 'contentReveal 0.7s var(--qq-ease-pop-fast) 0.15s both',
            }} />
          )}
        </>
        );
      })()}


      {/* Cutout floating image (bg-removed) */}
      {hasImg && img.layout === 'cutout' && (
        <img
          src={img.bgRemovedUrl || img.url}
          alt={isCheese ? (q.text || 'Question image') : ''}
          style={{
            position: 'absolute', zIndex: 3, pointerEvents: 'none',
            right: '8%', top: '15%',
            maxWidth: '35%', maxHeight: '70%',
            objectFit: 'contain',
            filter: `drop-shadow(0 16px 40px rgba(0,0,0,0.6))${imgFilter(img) ? ' ' + imgFilter(img) : ''}`,
            animation: imgAnim(img.animation, 'cutout', img.animDelay, img.animDuration),
            transform: `translate(${img.offsetX ?? 0}%, ${img.offsetY ?? 0}%) scale(${img.scale ?? 1}) rotate(${img.rotation ?? 0}deg)`,
            opacity: img.opacity ?? 1,
          }}
        />
      )}
      {/* Cutout emojis — hidden when template overlay handles them */}
      {!hideCutouts && effectiveCutouts.map((c, i) => (
        <div key={i} style={{
          position: 'absolute', pointerEvents: 'none', zIndex: 3,
          top: c.top, bottom: c.bottom, left: c.left, right: c.right,
          fontSize: c.size, lineHeight: 1, userSelect: 'none',
          filter: 'drop-shadow(0 12px 28px rgba(0,0,0,0.5))',
          ['--r' as string]: `${c.rot}deg`,
          animation: c.alt ? `cfloata ${4 + i}s ease-in-out infinite` : `cfloat ${4 + i * 0.7}s ease-in-out infinite`,
        }}>
          {c.emoji}
        </div>
      ))}

      {/* Fireflies in Kategorie-Farbe — subtile Stimmung passend zum Thema */}
      <Fireflies color={`${accent}99`} />

      {/* ── CHEESE overlay cards (Phase 2 + Reveal) ── */}
      {/* 2026-05-05 v2 (Wolf-Bug): Cards warten auf imgReady damit Portrait-Layout
          nicht erst landscape-aligned reinpoppt und dann nach rechts springt. */}
      {(cheeseWithQuestion || isCheeseReveal) && imgReady && (
        <div style={{
          // 2026-04-30 v3: Bei Portrait-Foto wandert der Card-Container in den
          // rechten Bildschirm-Streifen (50% breit) und Card sitzt dort vertikal
          // mittig. Bei Landscape klassisch fullscreen + Card am unteren Rand.
          position: 'fixed',
          top: 0, bottom: 0,
          left: isCheesePortrait ? '50%' : 0,
          right: 0,
          zIndex: 52,
          display: 'flex', flexDirection: 'column',
          justifyContent: isCheesePortrait ? 'center' : 'flex-end',
          alignItems: 'center',
          // 2026-05-04 (Wolf): kleinere Raender auf der Schau-Mal-Seite
          // damit das Bild mehr Bildflaeche bekommt. Vorher: 40-92px Padding.
          padding: isCheesePortrait
            ? 'clamp(12px, 2vh, 24px) clamp(12px, 1.6vw, 24px)'
            : (revealed ? '20px 24px 16px' : '20px 24px clamp(28px, 4vh, 48px)'),
          transition: 'padding 0.55s var(--qq-ease-bounce), left 0.5s ease',
          pointerEvents: 'none',
        }}>
          {/* Konsistente Kategorie-Pill oben links — bleibt im Reveal sichtbar
              (User-Wunsch 2026-04-28: Kategorie-Identität nicht verlieren).
              v3 round 5 (User-Bug 'Badge nicht left wie andere Kategorien'):
              position:absolute relativ zum cheese-overlay-Container war bei
              Portrait bei viewport-x:50%+48 (= rechts der Bildhälfte). Jetzt
              position:fixed = viewport-top-left, stimmt mit anderen Kategorien
              überein. zIndex 70 ueber alle Cheese-Layer (49-52) und Top-Bar (60). */}
          <div style={{
            position: 'fixed', top: 'clamp(22px, 3.2vh, 50px)', left: 'clamp(28px, 4vw, 64px)', zIndex: 70,
            pointerEvents: 'auto',
            animation: 'contentReveal 0.35s var(--qq-ease-pop-fast) both',
          }}>
            {/* v3 round 8 (User-Bug 'badge braucht dunklen bg bei hellem
                untergrund'): Cozy-Dark-Backdrop (rgba 13,10,6 / 82% opacity)
                + accent-color Border. Vorher war background nur accent22 =
                ~13% opacity, was auf hellem Foto kaum lesbar war. */}
            <div style={{
              display: 'inline-flex', alignItems: 'center', gap: 10,
              padding: '8px 22px', borderRadius: 999,
              background: 'rgba(13,10,6,0.82)', border: `2px solid ${accent}aa`,
              boxShadow: `0 4px 18px rgba(0,0,0,0.45), 0 0 18px ${accent}33`,
              backdropFilter: 'blur(10px)',
              WebkitBackdropFilter: 'blur(10px)',
            }}>
              {/* 2026-05-04 (Wolf): Icon im Kategorie-Badge bobbt subtil hoch/runter
                  — selbe Sprache wie im Cat-Intro, nur leiser. Wrapper-Span mit
                  inline-block, damit transform greift. */}
              <span style={{ display: 'inline-block', animation: 'qqBadgeIconBob 3.4s ease-in-out infinite' }}>
                {(() => {
                  const slug = qqCatSlug(cat as string);
                  return slug
                    ? <QQIcon slug={slug} size={'clamp(22px, 2.4vw, 32px)'} alt={catLabel.de} />
                    : <span style={{ fontSize: 'clamp(18px, 2vw, 26px)' }}>{catLabel.emoji}</span>;
                })()}
              </span>
              <span style={{
                fontSize: 'clamp(14px, 1.5vw, 20px)', fontWeight: 900,
                color: accent, letterSpacing: '0.1em', textTransform: 'uppercase',
              }}>{lang === 'en' ? catLabel.en : catLabel.de}</span>
            </div>
          </div>
          {/* Timer ring — top right (matches non-CHEESE layout), fade out on reveal.
              v3 round 8 (User-Bug 'timer auch bei hellem hintergrund schwer
              sichtbar'): zusaetzlicher dunkler Kreis-Backdrop hinter dem
              Timer-Ring fuer Kontrast auf hellen Fotos. */}
          {stickyTimer && (
            <div style={{
              position: 'fixed', top: 'clamp(22px, 3.2vh, 50px)', right: 'clamp(28px, 4vw, 64px)', zIndex: 70,
              animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.3s both',
              pointerEvents: revealed ? 'none' : 'auto',
              padding: 12, borderRadius: '50%',
              background: 'radial-gradient(circle, rgba(13,10,6,0.82) 55%, rgba(13,10,6,0.55) 78%, transparent 100%)',
              backdropFilter: 'blur(8px)',
              WebkitBackdropFilter: 'blur(8px)',
              boxShadow: `0 4px 22px rgba(0,0,0,0.45)`,
            }}>
              <BeamerTimer endsAt={stickyTimer.endsAt} durationSec={stickyTimer.duration} accent={accent} expireNow={timerExpiring} />
            </div>
          )}

          {/* Frosted question/answer card — bottom.
              POP-Transition: minHeight waechst dynamisch beim Reveal.
              Beim Reveal: Border + Glow in der Farbe des SCHNELLSTEN korrekten
              Teams (User-Wunsch 2026-04-28: konsistent mit Mucho/ZvZ wo der
              Sieger-Frame bunt ist). Wenn niemand richtig: Standard-Akzent. */}
          {(() => {
            // Schnellstes korrektes Team finden (für Reveal-Glow)
            const fastestColor = (() => {
              if (!isCheeseReveal) return null;
              const correctDE = (q.answer ?? '').trim().toLowerCase();
              const correctEN = (q.answerEn ?? '').trim().toLowerCase();
              const correctSet = [correctDE, correctEN].filter(Boolean);
              if (correctSet.length === 0) return null;
              const matchesAns = (sub: string) => {
                const ss = sub.trim().toLowerCase();
                if (ss.length < 2) return false;
                return correctSet.some(c => c === ss || ss.includes(c) || (c.length > 3 && c.includes(ss) && ss.length >= 3));
              };
              const earliest = [...s.answers]
                .filter(a => matchesAns(a.text))
                .sort((a, b) => a.submittedAt - b.submittedAt)[0];
              if (!earliest) return null;
              return s.teams.find(t => t.id === earliest.teamId)?.color ?? null;
            })();
            const revealGlowColor = fastestColor ?? '#22C55E';
            return (
          <div style={{
            position: 'relative',
            // 2026-04-30: Bei Reveal width:auto -> Card schrumpft auf Inhalt
            // (Antwort-Text + Avatare). User-Feedback: 'cheese reveal feld
            // dynamisch breit an text angepasst (ist extra breit aber da steht
            // nichts)'. Vor-Reveal weiter full-width fuer die Frage.
            // 2026-04-30 v3: Portrait-Mode → Card sitzt im rechten 50%-Streifen,
            // also schon eingeschraenkt im Container. width:100% reicht dort.
            width: isCheesePortrait ? '100%' : (isCheeseReveal ? 'auto' : 'calc(100% - clamp(40px, 6vw, 96px))'),
            minWidth: isCheeseReveal && !isCheesePortrait ? 'clamp(360px, 50vw, 720px)' : undefined,
            maxWidth: isCheesePortrait ? '100%' : (isCheeseReveal ? 'min(calc(100% - clamp(40px, 6vw, 96px)), 1100px)' : 1600),
            marginInline: 'auto',
            // 2026-04-29 (User-Feedback): Reveal-Card ~25% flacher — vorher
            // verdeckte sie ~60% der Bildflaeche bei Picture-This-Bildern.
            minHeight: revealed
              ? (hasImg ? 'clamp(240px, 30vh, 360px)' : 'clamp(180px, 22vh, 260px)')
              : (hasImg ? 'clamp(120px, 16vh, 200px)' : 'clamp(110px, 14vh, 170px)'),
            background: 'rgba(13,10,6,0.38)',
            backdropFilter: 'blur(18px) saturate(1.25)',
            WebkitBackdropFilter: 'blur(18px) saturate(1.25)',
            // Vor Reveal: kräftiger Kategorie-Glow wie bei MUCHO/ZvZ. (User-Wunsch
            // 2026-04-28: 'bei cheese darf die frage vor reveal umrandet sein
            // von kategorie farben glow wie bei anderen').
            border: `${isCheeseReveal ? 3 : 2.5}px solid ${isCheeseReveal ? `${revealGlowColor}cc` : `${accent}88`}`,
            borderRadius: 24,
            // Reveal-Padding kompakter (20 statt 28) damit das Bild oben mehr Platz behaelt.
            padding: isCheeseReveal ? '20px 48px' : '36px 56px',
            boxShadow: isCheeseReveal
              ? `0 0 0 1px ${revealGlowColor}55, 0 0 80px ${revealGlowColor}55, 0 0 32px ${revealGlowColor}88, 0 24px 80px rgba(0,0,0,0.5)`
              : `0 0 0 1px ${accent}33, 0 0 80px ${accent}33, 0 0 32px ${accent}55, 0 24px 80px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.06)`,
            // 2026-05-05 (Wolf 'Cheese-Reveal-Card wiggelt beim Auftauchen,
            // wirkt chaotisch'): revealAnswerBam (scale+wiggle) entfernt —
            // die Card ist beim Reveal eh schon sichtbar (war im Question-
            // Mode bereits da), nur Inhalt aendert sich. Kein Pop-Effekt
            // nötig, Border-Color-Transition reicht als Reveal-Marker.
            // 2026-05-06 v6 (Wolf 'Cheese-Reveal: Card wiggelt heftig beim
            // Reveal-Start'): min-height + transform Transitions auf
            // ease-bounce sprangen ueber — die min-height-Aenderung
            // (~+120px beim Reveal) mit Bounce hat die Card sichtbar
            // wackeln lassen. Beide auf ease-smooth.
            animation: cheeseWithQuestion ? 'bQuestionIn 0.5s var(--qq-ease-bounce) 0.1s both' : 'none',
            transform: revealed ? 'scale(1)' : 'scale(0.985)',
            transformOrigin: 'center',
            transition: 'padding 0.7s var(--qq-ease-smooth), border-color 0.55s ease, min-height 0.7s var(--qq-ease-smooth), transform 0.7s var(--qq-ease-smooth), width 0.7s var(--qq-ease-smooth), min-width 0.7s var(--qq-ease-smooth), max-width 0.7s var(--qq-ease-smooth)',
            pointerEvents: 'auto',
            textAlign: 'center',
            display: 'flex', flexDirection: 'column', justifyContent: 'center',
          }}>
            {/* Avatar-Reihe wurde 2026-05-04 v3 (Wolf-Feedback) RAUS aus der
                Card verlegt — sitzt jetzt als Flex-Sibling unter der Card im
                Overlay-Container. Damit landen die Avatare in der rechten
                Bildschirmhaelfte direkt unter der Fragecard (Portrait) bzw.
                unter der Card am unteren Rand (Landscape) statt halb in der
                Card-Unterkante zu kleben. Code: siehe direkt nach diesem
                Card-IIFE im Overlay-Container. */}

            {/* Category pill IN der Card entfernt — die Pill sitzt jetzt
                konsistent oben links wie bei den anderen Kategorien. */}

            {/* Question text — vor Reveal voll, beim Reveal kleiner + gedimmt
                (2026-04-29: damit Reveal-Card flacher wird und das Bild
                oberhalb sichtbar bleibt).
                2026-05-07 v2 (Wolf 'Buchstaben wiggeln sichtbar zwischen
                Question und Reveal'): font-size + margin-bottom in der
                Transition liessen den Text waehrend des Uebergangs neu
                fliessen → jeder Frame andere Letter-Positionen = Wiggle.
                Fix: key enthaelt jetzt isCheeseReveal → Re-Mount bei
                Reveal-Start, neuer Element mit neuer font-size sofort,
                kein animiertes Resize mehr. Transition raus, nur
                langFadeIn als Entry-Animation. */}
            <div key={`cheese-${lang}-${isCheeseReveal ? 'rev' : 'q'}`} style={{
              fontSize: isCheeseReveal
                ? 'clamp(20px, 2.6vw, 36px)'
                : (qText.length > 120 ? 'clamp(32px, 4vw, 60px)' : 'clamp(42px, 5.8vw, 84px)'),
              fontWeight: 900, lineHeight: 1.22,
              color: '#F1F5F9',
              marginBottom: isCheeseReveal ? 8 : 0,
              animation: 'langFadeIn 0.4s ease both',
              opacity: isCheeseReveal ? 0.55 : 1,
            }}>
              {lang === 'en' && q.textEn ? q.textEn : q.text}
            </div>

            {/* Revealed answer.
                2026-05-06 v6 (Wolf 'Cheese-Reveal: Buchstaben wiggeln stark
                beim Reveal-Start, sieht unprofessionell aus'): revealAnswerBam
                (scale 0.8→1.04→0.98→1, bouncy) durch langFadeIn ersetzt — nur
                opacity + 8px translateY, kein Wiggle. Konsistent zum Question-
                Text drueber, der bereits langFadeIn nutzt. */}
            {isCheeseReveal && s.revealedAnswer && (
              <div style={{
                position: 'relative', overflow: 'hidden',
                fontSize: 'clamp(28px, 3.8vw, 56px)', fontWeight: 900,
                color: '#4ADE80',
                animation: 'langFadeIn 0.5s var(--qq-ease-out-cubic) 0.15s both',
                textShadow: '0 0 30px rgba(34,197,94,0.4)',
                marginBottom: 6,
              }}>
                <div style={{
                  position: 'absolute', top: 0, width: '60%', height: '100%',
                  background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.18), transparent)',
                  animation: 'revealShimmer 0.8s ease 0.5s both',
                  pointerEvents: 'none',
                }} />
                {s.revealedAnswer}
              </div>
            )}

            {/* Alle richtigen Teams mit Zeit — analog zu MUCHO/ZEHN_VON_ZEHN */}
            {/* 2026-05-02 (Phone-Beamer-Sync-Audit): strict-Match durch
                Backend-Truth (currentQuestionWinners) ersetzt - sonst fehlten
                Schreibfehler-akzeptierte Avatare in der Frosted-Card. */}
            {isCheeseReveal && (() => {
              const winnerSet = new Set(s.currentQuestionWinners ?? (s.correctTeamId ? [s.correctTeamId] : []));
              const correctAnswers = [...s.answers]
                .filter(a => winnerSet.has(a.teamId))
                .sort((a, b) => a.submittedAt - b.submittedAt);
              if (correctAnswers.length === 0) {
                return (
                  <div style={{
                    marginTop: 14,
                    fontSize: 'clamp(16px, 1.9vw, 24px)', fontWeight: 900,
                    color: '#94a3b8',
                    animation: 'revealWinnerIn 0.5s ease 0.4s both',
                  }}>
                    {lang === 'en' ? 'No team got it right.' : 'Kein Team hatte die richtige Antwort.'}
                  </div>
                );
              }
              const t0 = s.timerEndsAt
                ? s.timerEndsAt - (s.timerDurationSec * 1000)
                : (correctAnswers[0].submittedAt);
              const winnerTeam = s.teams.find(t => t.id === correctAnswers[0].teamId);
              const multiCorrect = correctAnswers.length > 1;
              const winMsg = multiCorrect
                ? (lang === 'en' ? 'recognized it fastest!' : 'hat es am schnellsten erkannt!')
                : (lang === 'en' ? 'got it right!' : 'hat es erkannt!');
              return (
                <>
                <div style={{
                  marginTop: 8,
                  display: 'flex', alignItems: 'flex-start', justifyContent: 'center',
                  gap: 12, flexWrap: 'wrap', width: '100%',
                }}>
                  {correctAnswers.map((a, i) => {
                    const team = s.teams.find(t => t.id === a.teamId);
                    if (!team) return null;
                    const timeSec = Math.max(0, (a.submittedAt - t0) / 1000);
                    const isFastest = i === 0;
                    // 2026-05-06 (Wolf 'schnellstes Team als letztes — habe das
                    // schon 2x als Aufgabe geschrieben'): Cheese-Overlay-IIFE
                    // hatte popDelay = i*850+200 (fastest first). Umgedreht:
                    // (N-1-i)*850+200 → slowest dropt zuerst, fastest zuletzt.
                    // Synchron zur Sound-Cascade (letzte Note = playRevealHighlight
                    // auf fastest team) und zur WinnerCard-Slam-Animation.
                    const popDelay = (correctAnswers.length - 1 - i) * 850 + 200;
                    return (
                      <div key={a.teamId} style={{
                        display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 4,
                        animation: `top5RowSlideIn 0.55s var(--qq-ease-out-cubic) ${popDelay}ms both`,
                      }}>
                        <div style={{
                          position: 'relative',
                          display: 'inline-block',
                          animation: isFastest ? `celebShake 0.6s ease ${popDelay + 600}ms both` : 'none',
                        }}>
                          <QQTeamAvatar
                            avatarId={team.avatarId} teamEmoji={team.emoji}
                            // 2026-04-29: Avatare bei Reveal etwas kleiner — Card flacher.
                            size={isFastest ? 'clamp(60px, 6.8vw, 92px)' : 'clamp(46px, 5.2vw, 70px)'}
                            style={{
                              border: isFastest ? '4px solid #EC4899' : 'none',
                              boxShadow: isFastest
                                ? '0 0 28px rgba(236,72,153,0.65), 0 4px 14px rgba(0,0,0,0.45)'
                                : '0 4px 12px rgba(0,0,0,0.4)',
                            }}
                          />
                        </div>
                        <span style={{
                          padding: '3px 10px', borderRadius: 999,
                          background: isFastest ? 'rgba(236,72,153,0.22)' : 'rgba(0,0,0,0.55)',
                          border: isFastest ? '1.5px solid rgba(236,72,153,0.7)' : '1px solid rgba(255,255,255,0.15)',
                          color: isFastest ? '#EC4899' : '#cbd5e1',
                          fontWeight: 900,
                          fontSize: 'clamp(15px, 1.6vw, 20px)',
                          whiteSpace: 'nowrap',
                        }}>
                          {timeSec.toFixed(1)}s
                        </span>
                      </div>
                    );
                  })}
                </div>
                {/* 2026-05-06 v3 (Wolf 'gewinnercard ausserhalb der avatar
                    card unten drunter'): Cheese-WinnerCard wurde aus der
                    frosted-card heraus genommen und als Sibling unter dem
                    cheese-overlay-Container plaziert (siehe weiter unten,
                    nach dem Frosted-Card-IIFE). */}
                </>
              );
            })()}

          </div>
            );
          })()}

          {/* Cheese WinnerCard — Sibling UNTER der Frosted-Card.
              2026-05-06 v3 (Wolf 'gewinnercard ausserhalb der avatar card
              unten drunter, sound an die card anpassen ton kommt zu spaet
              bzw card zu frueh').
              Timing-Sync: Climax-Sound feuert bei N×850 + 840ms. Card-Anim
              ist 0.6s; Anim-Peak (max scale/glow ~70%) ist bei card-start
              + 420ms. Damit Card-Peak und Sound zusammenfallen:
                card-start = sound-time − 420 = N×850 + 420ms.
              Card faded leicht ein, knallt im Peak mit dem Climax-Sound. */}
          {isCheeseReveal && (() => {
            const winnerSet = new Set(s.currentQuestionWinners ?? (s.correctTeamId ? [s.correctTeamId] : []));
            const correctAnswers = [...s.answers]
              .filter(a => winnerSet.has(a.teamId))
              .sort((a, b) => a.submittedAt - b.submittedAt);
            if (correctAnswers.length === 0) return null;
            const winnerTeam = s.teams.find(t => t.id === correctAnswers[0].teamId);
            if (!winnerTeam) return null;
            const multiCorrect = correctAnswers.length > 1;
            const winMsg = multiCorrect
              ? (lang === 'en' ? 'recognized it fastest!' : 'hat es am schnellsten erkannt!')
              : (lang === 'en' ? 'got it right!' : 'hat es erkannt!');
            const cardDelaySec = (correctAnswers.length * 850 + 420) / 1000;
            return (
              <div style={{
                pointerEvents: 'auto',
                marginTop: 'clamp(10px, 1.4vh, 18px)',
                display: 'inline-flex', alignItems: 'center',
                gap: 'clamp(12px, 1.6vw, 20px)',
                padding: 'clamp(10px, 1.4vh, 16px) clamp(20px, 2.4vw, 32px)',
                borderRadius: 999,
                background: `linear-gradient(135deg, ${winnerTeam.color}33, ${winnerTeam.color}10)`,
                border: `2.5px solid ${winnerTeam.color}aa`,
                boxShadow: `0 0 36px ${winnerTeam.color}55, 0 4px 14px rgba(0,0,0,0.45)`,
                backdropFilter: 'blur(8px)',
                WebkitBackdropFilter: 'blur(8px)',
                animation: `revealWinnerIn 0.6s var(--qq-ease-bounce) ${cardDelaySec}s both`,
              }}>
                <span style={{ fontSize: 'clamp(26px, 2.8vw, 36px)', lineHeight: 1 }}>
                  <QQEmojiIcon emoji="🏆"/>
                </span>
                <QQTeamAvatar
                  avatarId={winnerTeam.avatarId}
                  teamEmoji={winnerTeam.emoji}
                  size={'clamp(40px, 4vw, 56px)'}
                  style={{ flexShrink: 0, boxShadow: `0 0 18px ${winnerTeam.color}88` }}
                />
                <div style={{
                  fontSize: 'clamp(22px, 2.4vw, 32px)', fontWeight: 900,
                  color: winnerTeam.color, lineHeight: 1.1,
                  textShadow: `0 0 18px ${winnerTeam.color}55`,
                }}>
                  {teamDisplayName(winnerTeam.name, true)}
                </div>
                <div style={{
                  fontSize: 'clamp(15px, 1.6vw, 22px)', fontWeight: 800,
                  color: '#cbd5e1', lineHeight: 1.2,
                }}>
                  {winMsg}
                </div>
              </div>
            );
          })()}

          {/* Avatar-Progress-Reihe — 2026-05-04 v3 (Wolf-Feedback):
              RAUS aus der Card als Flex-/Absolute-Sibling im Overlay-Container.
              - PORTRAIT (Bild links, Card rechts): Flex-Flow-Sibling unter dem Card.
                Parent ist flexCol+justify-center → Card + Avatars werden als Block
                vertikal mittig zentriert, Avatare sitzen direkt UNTER der Card im
                rechten Bildschirmstreifen.
              - LANDSCAPE (Card unten am Rand): absolute oben mittig — sonst wuerden
                Avatare unter der bottom-aligned Card aus dem Bildschirm fallen. */}
          {!revealed && s.teams.length > 0 && (() => {
            const tc = s.teams.length;
            // 2026-05-05 (Wolf 'Cheese-Portrait Avatare zu klein, fast unter
            // ganze Frage-Card passen lassen'): Portrait-Sizes fast verdoppelt
            // (40/46/52 → 60/72/84) damit sie aus Beamer-Distanz erkennbar
            // sind und die rechte Halbflaeche unter der Frage-Card sinnvoll
            // ausnutzen. Gap entsprechend vergroessert.
            const av = isCheesePortrait
              ? (tc > 6 ? 60 : tc > 4 ? 72 : 84)
              : (tc > 6 ? 48 : tc > 4 ? 54 : 60);
            // 2026-05-09 (Wolf 'Footer-Avatare zu eng'): Gap vergrössert
            // damit grüner Glow sichtbar atmet, nicht ineinander fließt.
            const gap = isCheesePortrait
              ? (tc > 6 ? 14 : tc > 4 ? 18 : 22)
              : (tc > 6 ? 14 : tc > 4 ? 18 : 22);
            const portraitFlow = {
              marginTop: 'clamp(10px, 1.6vh, 22px)' as const,
            };
            const landscapeAbs = {
              position: 'absolute' as const,
              top: 'clamp(28px, 4vh, 60px)' as const,
              left: 0, right: 0,
            };
            return (
              <div style={{
                ...(isCheesePortrait ? portraitFlow : landscapeAbs),
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                gap, flexWrap: 'wrap',
                pointerEvents: 'none', zIndex: 65,
                animation: 'contentReveal 0.45s var(--qq-ease-pop-fast) 0.4s both',
              }}>
                {/* Mini-Progress-Text "X/Y TEAMS" zwischen Card-Unterkante und
                    Avataren — nur sichtbar solange nicht alle dran sind. */}
                {!s.allAnswered && (
                  <div style={{
                    width: '100%', textAlign: 'center',
                    fontSize: 'clamp(11px, 1.1vw, 14px)', fontWeight: 900,
                    color: 'rgba(226,232,240,0.85)',
                    letterSpacing: '0.04em', textTransform: 'uppercase',
                    marginBottom: -2,
                  }}>
                    {`${s.answers.length}/${s.teams.length} Teams`}
                  </div>
                )}
                {s.teams.map(tm => {
                  const answered = s.answers.some(a => a.teamId === tm.id);
                  return (
                    <div key={tm.id} style={{
                      position: 'relative',
                      display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                      flexShrink: 0,
                      opacity: answered ? 1 : 0.55,
                      filter: answered
                        ? 'drop-shadow(0 0 10px rgba(34,197,94,0.6)) drop-shadow(0 0 3px rgba(34,197,94,0.4))'
                        : 'grayscale(0.4)',
                      transition: 'opacity 0.4s ease, filter 0.4s ease',
                    }}>
                      <div style={{
                        borderRadius: '50%',
                        boxShadow: answered ? '0 0 0 3px #22C55E' : 'none',
                        transition: 'box-shadow 0.45s ease',
                        display: 'inline-flex',
                      }}>
                        <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={av} />
                      </div>
                    </div>
                  );
                })}
              </div>
            );
          })()}
        </div>
      )}

      {/* Main content (non-CHEESE or hidden during CHEESE overlay) */}
      <div style={{
        flex: 1, display: cheeseOverlay ? 'none' : 'flex', gap: 0,
        flexDirection: (hasImg && img.layout === 'window-left') ? 'row-reverse' : 'row',
        animation: 'contentReveal 0.35s var(--qq-ease-pop-fast) both',
      }}>
        {/* ── Main content — full width, vertically distributed ──
            Final approach (2026-04-28-v4):
            - space-between für MUCHO/ZvZ Reveal: Frage-Card top-anchored,
              Winner-Card (last item) bottom-anchored, dazwischen verteilen
              sich Options/Voter-Reihe natürlich.
            - Hinzu kommt ein <Spacer flex:1/> zwischen Voter-Avataren und
              Winner-Card → der Spacer absorbiert Layout-Änderungen, sodass
              upper Cards stabil stehen wenn Winner erscheint.
            - Bei nicht-revealed (active) center bleibt für saubere Mitte.
            Vertikales overflow visible erlaubt, dass Card-Glow + Winner-Border
            nicht durch overflow:hidden geclipped werden. */}
        {(() => {
          // 2026-04-29 (User-Feedback): Bei HotPotato mit vielen genannten
          // Antworten kollidiert das Chip-Layout (bottom:16, wrap-up) mit der
          // mittig-zentrierten Frage-Card. Ab 12 Chips Frage hochschieben
          // (justifyContent: flex-start) damit unten Platz für den Chip-Block
          // bleibt. Chips skalieren ihrerseits in HotPotatoBeamerView.
          const isHotPotatoActive = q.category === 'BUNTE_TUETE'
            && q.bunteTuete?.kind === 'hotPotato' && !revealed;
          const hpUsedCount = (s.hotPotatoUsedAnswers?.length ?? 0);
          // 2026-04-30 v2 (User-Feedback): Trigger 12->16 fuer ruhigeres
          // mid-game-Layout (selteneres Snap-down). Transition wird in der
          // Card-Style 0.4s -> 0.7s entspannter.
          const hpCompact = isHotPotatoActive && hpUsedCount > 16;
          // 2026-05-05 v3 (Wolf-Bug 'Luecke zwischen Card und Chips'): Chips
          // sitzen jetzt im natuerlichen Flex-Flow direkt unter der Card
          // (HotPotatoBeamerView ohne position:absolute). Card + Chip-Block
          // werden als 1 Block vertikal mittig zentriert, mit definiertem Gap
          // dazwischen. Keine Luecke mehr, kein Snap, kein paddingBottom-Hack.
          const innerJustify = 'center';
          const innerGap = isHotPotatoActive ? 'clamp(16px, 2.5vh, 32px)' : 0;
          return (
        <div style={{
          flex: 1, display: 'flex', flexDirection: 'column',
          // 2026-05-08 (Wolf-Bug 'kategorie badge ueberdeckt frage card'):
          // paddingTop vergroessert (22-50px → 90-130px) damit die absolute
          // Top-Bar (Badge + Timer auf top:22-50px, ~50px hoch) nicht in die
          // Card hineinragt. Die Card sitzt jetzt klar UNTER der Top-Bar mit
          // ~30-40px Gap. Horizontal- und Bottom-Padding bleiben.
          // 2026-05-08 (Wolf-Bug 'HP-feld schiebt sich unten raus'):
          // Bei HotPotato braucht das Layout mehr Vertical-Space (Slot-Machine
          // + Voter-Chips + Winner-Card) — paddingTop reduziert auf 60-90 px.
          // 2026-05-10 (Spacing-Audit P0): paddingTop von 60-90 auf 80-110 px
          // bumpt — Top-Bar (Badge+Timer, top 22-50 + Höhe ~50-60 = endet bei
          // 72-110 px) konnte mit altem upper-clamp 90 überlappen. Neue 80-110
          // gibt Min 10-20 px Buffer zur Top-Bar-Bottom-Edge, behält aber
          // 20 px Vertical-Space-Vorteil gegenüber Standard (90-130).
          padding: isHotPotatoActive
            ? 'clamp(80px, 9vh, 110px) clamp(28px, 4vw, 64px) clamp(16px, 2.4vh, 36px)'
            : 'clamp(90px, 11vh, 130px) clamp(28px, 4vw, 64px) clamp(22px, 3.2vh, 50px)',
          alignItems: 'center', position: 'relative', zIndex: 5,
          // 2026-05-05 (Wolf-Bug 'Scrollbar rechts auf /beamer'): overflow
          // hart auf hidden — Beamer darf NIE scrollen, lieber Inhalt clippen
          // (overflowY:visible konnte vorher Body-Level-Scroll triggern wenn
          // Card+Voters+Winner zusammen ueber 100vh wuchsen).
          overflow: 'hidden',
        }}>

          {/* 2026-04-30 v3: Top-Bar position:absolute damit der Inner-Wrapper
              die volle Höhe nutzt — Card im Inner-Wrapper-Center == Viewport-
              Center (User-Feedback: Card wirkte zu tief, weil Top-Bar in der
              Flex-Höhe Platz fraß und Card-Center darunter rutschte).
              Card ueberlappt das Badge nicht, weil Card-Maxima (Glow/Padding)
              klein genug sind und Top-Bar oben bleibt.
              v3 round 5 (User-Bug 'CHEESE Kategorie-Badge soll top-left'):
              zIndex 10 → 60, damit das Badge ueber dem Cheese-Overlay (z=52)
              sichtbar bleibt. Sonst verdeckte Cheese den Badge. */}
          <div style={{
            position: 'absolute',
            top: 'clamp(22px, 3.2vh, 50px)',
            left: 'clamp(28px, 4vw, 64px)',
            right: 'clamp(28px, 4vw, 64px)',
            display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between',
            gap: 16,
            zIndex: 60,
          }}>
            {/* 2026-05-03 (App-Designer-Audit B3): Pill jetzt opak (solid bg)
                statt accent-18%-tinted — accent-Text auf accent-tinted-bg verschwamm
                aus 10m. */}
            <div style={{
              display: 'inline-flex', alignItems: 'center', gap: 10,
              padding: '10px 22px', borderRadius: 999,
              background: '#0A0814', border: `2px solid ${accent}`,
              boxShadow: `0 0 24px ${accent}33`,
              animation: 'contentReveal 0.35s var(--qq-ease-pop-fast) both',
              flexShrink: 0,
            }}>
              {/* 2026-05-04 (Wolf): Icon im Kategorie-Badge bobbt subtil hoch/runter
                  — selbe Sprache wie im Cat-Intro, nur leiser. Wrapper-Span mit
                  inline-block, damit transform greift. */}
              <span style={{ display: 'inline-block', animation: 'qqBadgeIconBob 3.4s ease-in-out infinite' }}>
                {(() => {
                  // 2026-05-11 (Wolf 'Badge soll Sub-Mechanik-Emoji zeigen,
                  // nicht generisches 🎁 für Bunte-Tüte'): bei BUNTE_TUETE
                  // mit Sub-Kind das Sub-Icon nehmen, sonst Cat-Icon.
                  const btKind = q.category === 'BUNTE_TUETE' ? q.bunteTuete?.kind : undefined;
                  const subSlug = btKind ? qqSubSlug(btKind) : null;
                  const slug = btKind ? subSlug : qqCatSlug(cat as string);
                  const fallbackEmoji = btKind
                    ? QQ_BUNTE_TUETE_LABELS[btKind].emoji
                    : catLabel.emoji;
                  return slug
                    ? <QQIcon slug={slug} size={'clamp(22px, 2.4vw, 32px)'} alt={catLabel.de} />
                    : <span style={{ fontSize: 'clamp(18px, 2vw, 26px)' }}>{fallbackEmoji}</span>;
                })()}
              </span>
              <span style={{
                fontSize: 'clamp(18px, 1.8vw, 26px)', fontWeight: 900,
                color: accent, letterSpacing: '0.1em', textTransform: 'uppercase',
              }}>
                {(() => {
                  const btKind = q.category === 'BUNTE_TUETE' ? q.bunteTuete?.kind : undefined;
                  if (btKind) {
                    return lang === 'en'
                      ? QQ_BUNTE_TUETE_LABELS[btKind].en
                      : QQ_BUNTE_TUETE_LABELS[btKind].de;
                  }
                  return lang === 'en' ? catLabel.en : catLabel.de;
                })()}
              </span>
            </div>
            {/* Timer auf der rechten Seite — versteckt fuer HotPotato (eigener
                per-Turn-Timer in HotPotatoBeamerView).
                2026-05-03: Round/Frage-Counter wieder entfernt — Wolf-Entscheidung:
                "brauchen wir das überhaupt?" PhaseIntro vor jeder Runde sagt das
                schon, Pub-Publikum spielt zum Spass + Counter frass Horizontal-
                Platz mit Kollisionen in manchen Kategorien. */}
            {stickyTimer && !(q.category === 'BUNTE_TUETE' && q.bunteTuete?.kind === 'hotPotato') && (
              <div style={{
                pointerEvents: revealed ? 'none' : 'auto',
                flexShrink: 0,
              }}>
                {/* 2026-05-04 v3 (Wolf): stickyTimer haelt das letzte gueltige
                    endsAt ~1s nachdem das Backend timerEndsAt nullt — sonst
                    unmountet die Component bevor qqTimerOutro durchlaeuft.
                    timerExpiring=true sobald Original-Prop weg ODER revealed. */}
                <BeamerTimer endsAt={stickyTimer.endsAt} durationSec={stickyTimer.duration} accent={accent} expireNow={timerExpiring} />
              </div>
            )}
          </div>

          {/* 2026-04-30: Inner-Content-Wrapper mit flex:1 — hier sitzt die
              Frage-Card + alle Reveal-Inhalte. Bekommt das vertikale
              Centering / space-between, die Top-Bar bleibt davon unbetroffen
              an ihrem Platz oben. */}
          <div style={{
            flex: 1, display: 'flex', flexDirection: 'column',
            justifyContent: innerJustify,
            gap: innerGap,
            alignItems: 'center', width: '100%',
          }}>

          {/* Question card — KEIN Resize mehr zwischen Question und Reveal
              (User-Feedback 2026-04-28: 'cards zappelig beim kleiner werden').
              Card und Text behalten ihre Größe, nur Opacity dimmt (1 → 0.45)
              und Padding bleibt konstant. So gibt's GAR keine Resize-Bewegung
              mehr — der Reveal-Indikator ist allein das Dimmen + die neuen
              Avatar/Answer-Cards die darunter erscheinen.
              2026-04-29 (User-Feedback): Bei HotPotato mit vielen Chips
              (hpCompact) wird die Card flacher + Text kleiner, damit unten
              Platz fuer den Chip-Block bleibt. */}
          {(() => {
            // 2026-05-07 (Layout-Audit): horizontal-padding clamp(110-180) →
            // clamp(60-120). Vorher: Card 1400 breit aber bis 360 Innen-Padding
            // → nur 1040px Textbreite, Frage wirkte klein. Jetzt 240px max
            // Innen-Padding → ~1160px Text bei voller Breite.
            const cardPadding = hpCompact
              ? 'clamp(10px, 1.4vh, 18px) clamp(60px, 8vw, 120px) clamp(10px, 1.4vh, 18px)'
              : 'clamp(18px, 2.6vh, 32px) clamp(60px, 8vw, 120px) clamp(18px, 2.6vh, 32px)';
            const cardMarginBottom = hpCompact ? 'clamp(8px, 1.2vh, 16px)' : 'clamp(16px, 2.2vh, 32px)';
            // v3 round 11 (User-Wunsch 'textgroesse muss nicht zwangsweise
            // kleiner werden'): Font-Size bleibt voll, nur Padding/Margin
            // werden im hpCompact-Modus kleiner. Card-Shift uebernimmt das
            // Platzproblem.
            const cardFontSize = qFontSize;
            // 2026-05-07 v2 (Wolf-Bug 'Frage-Card faellt bei HotPotato BunteTüte
            // immernoch nach oben raus, hatte den auftrag schon mal'):
            // chipShiftVh war Legacy-Code aus 2026-04-29 als die Chips noch
            // position:absolute waren. Seit 2026-05-05 v3 sitzen Card + Chips
            // im gleichen Flex-Column-Container (innerJustify=center, gap
            // dazwischen) — Card+Chips werden als ein Block zentriert. Der
            // shift bewegt aber NUR die Card-Wrapper-translateY, NICHT die
            // Chips → Card knallt aus dem Viewport waehrend Chips stabil
            // bleiben. Loesung: Shift komplett deaktivieren. Centering
            // erledigt das jetzt natuerlich.
            const chipShiftVh = 0;
            return (
              // 2026-05-07 (Audit P0): bQuestionIn × transform-shift Konflikt.
              // Vorher: Card hatte parallel `animation: bQuestionIn` + inline
              // `transform: translateY(...)` + `transition: transform 0.9s`.
              // CSS-`animation` overrided transform → bei Reveal-Klick (akut
              // bei HotPotato wenn chipShiftVh kippt) Mikro-Sprung.
              // Fix: Outer-Wrapper traegt den translateY-Shift (mit transform-
              // Transition), Inner-Card traegt die bQuestionIn-Mount-Animation.
              // Beide kollidieren nicht mehr.
              <div style={{
                width: '100%', maxWidth: 1400,
                flexShrink: 0,
                transform: chipShiftVh !== 0 ? `translateY(${chipShiftVh}vh)` : undefined,
                transition: 'transform 0.9s var(--qq-ease-smooth)',
                willChange: 'transform',
              }}>
                <div style={{
                  background: cardBg,
                  border: `2.5px solid ${revealed ? `${accent}55` : `${accent}88`}`,
                  borderRadius: 24,
                  boxShadow: revealed
                    ? `0 0 0 1px ${accent}22, 0 0 50px ${accent}22, 0 0 22px ${accent}33, 0 8px 28px rgba(0,0,0,0.4)`
                    : `0 0 0 1px ${accent}33, 0 0 80px ${accent}33, 0 0 32px ${accent}55, 0 12px 40px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.06)`,
                  padding: cardPadding,
                  marginBottom: cardMarginBottom,
                  width: '100%',
                  textAlign: 'center',
                  animation: 'bQuestionIn 0.5s var(--qq-ease-bounce) both',
                  // 2026-04-30 v2: padding/margin-Transition 0.4s -> 0.7s
                  // entspannt, damit hpCompact-Snap weniger hektisch wirkt.
                  // 2026-05-02 (App-Designer-Audit B4): opacity-Dim mit 0.45s Delay,
                  // damit zuerst die Voter-Cascade rausschwingen kann (laeuft 0.5s)
                  // bevor die Frage-Card transparent wird.
                  transition: 'box-shadow 0.55s ease, border-color 0.55s ease, opacity 0.4s ease 0.45s, padding 0.7s var(--qq-ease-smooth), margin-bottom 0.7s var(--qq-ease-smooth)',
                  opacity: revealed ? 0.55 : 1,
                }}>
                  {/* 2026-05-07 (Audit P0): font-size-transition liess Buchstaben
                      bei qFontSize/hpCompact-Wechsel sichtbar wandern. Key-Remount
                      macht den Wechsel atomic, langFadeIn als saubere Entry-Anim. */}
                  <div key={`${lang}-${cardFontSize}`} style={{
                    fontSize: cardFontSize,
                    fontWeight: 900, lineHeight: 1.22,
                    color: '#F1F5F9',
                    animation: 'langFadeIn 0.4s ease both',
                  }}>
                    {qText}
                  </div>
                </div>
              </div>
            );
          })()}


          {/* Mobile-Hint („📱 Antwort auf dem Handy") entfernt 2026-04-26:
              Teams haben bereits die Eingabe-UI auf ihren Geraeten — der
              Beamer-Hint zielte auf niemanden, der ihn lesen muss. Die
              Avatare-mit-Haekchen-Reihe (z.B. bei Cheese) zeigt die
              Antwort-Progress visueller. */}

          {/* BUNTE_TÜTE order — Items während QUESTION_ACTIVE sichtbar
              (Teams sortieren am Handy, Publikum muss wissen worum es geht) */}
          {!revealed && q.category === 'BUNTE_TUETE' && (q.bunteTuete as any)?.kind === 'order' && (() => {
            const btt = q.bunteTuete as any;
            const items: string[] = (lang === 'en' && btt.itemsEn?.length) ? btt.itemsEn : (btt.items ?? []);
            const criteria: string | undefined = (lang === 'en' && btt.criteriaEn) ? btt.criteriaEn : btt.criteria;
            if (items.length === 0) return null;
            const cols = Math.min(items.length, items.length <= 4 ? items.length : items.length === 5 ? 5 : 3);
            return (
              <div style={{
                display: 'flex', flexDirection: 'column', gap: 14,
                width: '100%', maxWidth: 1400, marginBottom: 16,
                animation: 'contentReveal 0.35s var(--qq-ease-pop-fast) 0.1s both',
              }}>
                {criteria && (
                  <div style={{
                    fontSize: 'clamp(14px, 1.5vw, 22px)', fontWeight: 900,
                    color: '#EC4899', letterSpacing: '0.1em', textTransform: 'uppercase',
                    textAlign: 'center',
                  }}>
                    {lang === 'en' ? `Sort ${criteria}` : `Sortiert ${criteria}`}
                  </div>
                )}
                <div style={{
                  display: 'grid',
                  gridTemplateColumns: `repeat(${cols}, minmax(0, 1fr))`,
                  gap: 14,
                }}>
                  {items.map((item, i) => (
                    <div key={i} style={{
                      borderRadius: 16, padding: '22px 24px',
                      background: cardBg,
                      border: '2px solid rgba(236,72,153,0.4)',
                      boxShadow: '0 4px 16px rgba(0,0,0,0.3), inset 0 0 0 1px rgba(255,255,255,0.04)',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      fontSize: 'clamp(20px, 2.4vw, 34px)', fontWeight: 900, color: '#F1F5F9',
                      textAlign: 'center', lineHeight: 1.25,
                      minHeight: 80,
                      animation: `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.1 + i * 0.06}s both`,
                    }}>
                      {item}
                    </div>
                  ))}
                </div>
              </div>
            );
          })()}

          {/* MUCHO: 2-Akt-Reveal (Akt 1 Voter-Steps, Akt 2 Lock via Doppelblink) */}
          {q.options && q.category === 'MUCHO' && (
            <MuchoOptionsReveal
              options={q.options}
              optionsEn={q.optionsEn}
              correctOptionIndex={q.correctOptionIndex}
              optionImages={q.optionImages}
              answers={s.answers}
              teams={s.teams}
              lang={lang}
              cardBg={cardBg}
              timerEndsAt={s.timerEndsAt}
              timerDurationSec={s.timerDurationSec}
              revealStep={revealed ? s.muchoRevealStep : 0}
            />
          )}

          {/* ZEHN_VON_ZEHN: Options-Grid. Top-Bet-Chips haengen an der unteren
              Card-Linie (analog MUCHO-Reveal) — nicht mehr im Card-Inhalt. */}
          {q.options && q.category === 'ZEHN_VON_ZEHN' && (() => {
            // Fallback auf frueheste submittedAt, weil timerEndsAt zum Reveal
            // bereits null ist → ohne Fallback keine Zeit-Anzeige.
            const earliestSubmit = s.answers.length > 0
              ? Math.min(...s.answers.map(a => a.submittedAt))
              : null;
            const t0 = s.timerEndsAt && s.timerDurationSec
              ? s.timerEndsAt - s.timerDurationSec * 1000
              : earliestSubmit;
            // Analog Mucho: kompakt waehrend QUESTION_ACTIVE, Rows ziehen sich
            // smooth auseinander sobald Top-Bet-Chips einfliegen (zvzStep>=1).
            const expandedLayout = zvzStep >= 1;
            // Wenn auf einer Option viele Top-Bets liegen (4+ Teams gleicher
            // Höchstwert), brauchen wir mehr Platz unter den Cards damit die
            // Avatare nicht in die nächste Reihe rutschen.
            const maxChips = Math.max(0, ...zvzHighestPerOption.map(h => h?.teamIds?.length ?? 0));
            const heavyChips = maxChips >= 4;
            return (
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
              columnGap: 18,
              // 2026-04-30 v3 (User-Bug): Avatare am Voter-Grid-Tile-Boden
              // wurden abgeschnitten weil paddingBottom zu knapp. Werte
              // raufgesetzt: heavyChips 96→140, leicht 62→100. Avatare
              // (Hängen unter dem Tile) brauchen genug Luft.
              rowGap: expandedLayout ? (heavyChips ? 'clamp(140px, 17vh, 200px)' : 'clamp(100px, 12vh, 140px)') : 18,
              paddingBottom: expandedLayout ? (heavyChips ? 'clamp(130px, 14vh, 180px)' : 'clamp(100px, 11vh, 140px)') : 0,
              // 2026-05-10 (Wolf-Live-Test L9 '10v10 unten viel Platz, Cards
              // nach oben gequetscht'): minHeight + paddingTop damit Cards
              // vertikal-mittig statt top-aligned sitzen. Nutzt verfügbaren
              // Platz unter der Question-Card aus.
              minHeight: 'clamp(280px, 38vh, 460px)',
              alignContent: 'center',
              marginTop: 16,
              marginBottom: 16,
              width: '100%', maxWidth: 1400,
              animation: 'contentReveal 0.35s var(--qq-ease-pop-fast) 0.1s both',
              // 2026-04-30 v2: 0.6s → 0.9s entspanntes Easing analog MUCHO.
              transition: 'row-gap 0.9s var(--qq-ease-smooth), padding-bottom 0.9s var(--qq-ease-smooth)',
            }}>
              {q.options.map((opt, i) => {
                const optImg = q.optionImages?.[i];
                const isCorrect = zvzLocked && i === q.correctOptionIndex;
                const isWrong = zvzLocked && i !== q.correctOptionIndex;
                // 2026-05-09 v2 (Wolf): Plain-Number als großer Text in
                // Option-Color statt Box+Keycap-Emoji.
                const label = `${i + 1}`;
                const optColor = accent;
                const optText = lang === 'en' && q.optionsEn?.[i] ? q.optionsEn[i] : opt;
                const highestForOpt = zvzHighestPerOption[i];
                const highestIdsForOpt = new Set(highestForOpt?.teamIds ?? []);
                // Top-Bets inkl. submittedAt fuer Tiebreaker-Anzeige
                const highestBets = s.answers
                  .map(a => {
                    const team = s.teams.find(t => t.id === a.teamId);
                    if (!team || !highestIdsForOpt.has(team.id)) return null;
                    const pts = (a.text.split(',').map(n => Number(n) || 0))[i] ?? 0;
                    return pts > 0 ? { team, pts, submittedAt: a.submittedAt } : null;
                  })
                  .filter((x): x is { team: NonNullable<ReturnType<typeof s.teams.find>>; pts: number; submittedAt: number } => !!x)
                  .sort((a, b) => a.submittedAt - b.submittedAt);
                const highestVisibleOpt = zvzStep >= 1 && zvzRevealed.has(i);
                // Blitz + Zeit NUR bei Tiebreak (mehrere Top-Bets mit gleichen Hoechstpunkten
                // auf der korrekten Option). Solo-Top-Bet braucht keinen Speed-Indikator —
                // der Chip mit Goldrand reicht.
                const showTimePills = isCorrect && highestBets.length > 1;
                return (
                  <div key={i} style={{ position: 'relative', display: 'flex', height: '100%' }}>
                    <div style={{
                      position: 'relative', overflow: 'hidden',
                      // 2026-04-28: User-Wunsch — alle 3 ZvZ-Cards gleich hoch.
                      // Wenn eine Option 2-zeilig wird, soll der Rest mitwachsen,
                      // sonst wirken die Cards inkonsistent. flex:1 + height:100%
                      // zwingt die Inner-Card auf Row-Höhe.
                      flex: 1,
                      // 2026-05-09 (Wolf 'Mini-Sprung'): box-sizing border-box
                      // + einheitliche 3px-Border verhindert Layout-Shift wenn
                      // Sieger-Card kommt (war 2/3/2 = +2px höher → andere Cards
                      // schoben mit).
                      boxSizing: 'border-box',
                      borderRadius: 24, padding: '20px 24px',
                      background: isCorrect ? 'rgba(34,197,94,0.2)' : cardBg,
                      border: isCorrect ? '3px solid #22C55E' : isWrong ? `3px solid rgba(255,255,255,0.06)` : `3px solid ${optColor}55`,
                      boxShadow: isCorrect
                        ? '0 0 40px rgba(34,197,94,0.35), 0 0 80px rgba(34,197,94,0.15)'
                        : `0 4px 16px rgba(0,0,0,0.3)`,
                      display: 'flex', alignItems: 'center', gap: 16,
                      transition: 'background 0.25s ease, border-color 0.25s ease, box-shadow 0.25s ease',
                      animation: isCorrect
                        ? 'revealDoubleBlink 1.1s ease both'
                        : isWrong
                          ? 'revealWrongDim 0.4s ease 0.15s both'
                          : `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.1 + i * 0.08}s both`,
                    }}>
                      {optImg?.url && (
                        <img src={optImg.url} alt="" style={{
                          position: 'absolute', inset: 0, width: '100%', height: '100%',
                          objectFit: optImg.fit ?? 'cover', opacity: optImg.opacity ?? 0.4,
                          pointerEvents: 'none',
                        }} />
                      )}
                      {optImg?.url && (
                        <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(90deg, rgba(0,0,0,0.7) 0%, rgba(0,0,0,0.3) 100%)', pointerEvents: 'none' }} />
                      )}
                      {/* 2026-05-09 v2 (Wolf): Box weg, große Zahl in
                          Option-Color statt Container-Box. Bei isCorrect
                          grün, bei isWrong gedimmt grau, sonst optColor. */}
                      <div style={{
                        position: 'relative', zIndex: 1,
                        width: 56, height: 56,
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        fontSize: 56, fontWeight: 900, flexShrink: 0,
                        color: isCorrect ? '#22C55E' : isWrong ? '#475569' : optColor,
                        textShadow: isCorrect ? '0 0 18px rgba(34,197,94,0.6)' : `0 0 12px ${optColor}55`,
                        letterSpacing: '-0.04em',
                        transition: 'all 0.3s ease',
                      }}>{label}</div>
                      <div style={{
                        position: 'relative', zIndex: 1,
                        flex: 1, minWidth: 0,
                        fontSize: 'clamp(24px, 2.8vw, 40px)', fontWeight: 900,
                        color: isWrong ? '#475569' : '#F1F5F9', lineHeight: 1.25,
                        textShadow: optImg?.url ? '0 2px 8px rgba(0,0,0,0.8)' : 'none',
                        transition: 'color 0.3s ease',
                      }}>{optText}</div>
                    </div>
                    {/* Top-Bet-Chips: haengen UNTER der Card (nur ein kleiner Lip
                        ueberlappt den Card-Rand). ZvZ-Cards sind flach → wenn
                        Chips mittig auf der Linie sitzen, ueberdecken sie das Label. */}
                    {highestVisibleOpt && highestBets.length > 0 && (() => {
                      const cnt = highestBets.length;
                      // Chip-Tiers nach Anzahl gleichplatzierter Top-Bets pro Option:
                      // bei 4+ massiv schrumpfen, sonst rutschen Chips in 2. Reihe und
                      // ueberlagern die naechste Card-Zeile.
                      const tier: 'lg' | 'md' | 'sm' | 'xs' =
                        cnt >= 5 ? 'xs' : cnt >= 4 ? 'sm' : cnt >= 3 ? 'md' : 'lg';
                      const avSz =
                        tier === 'xs' ? 'clamp(28px, 2.8vw, 40px)' :
                        tier === 'sm' ? 'clamp(36px, 3.6vw, 52px)' :
                        tier === 'md' ? 'clamp(44px, 4.6vw, 64px)' :
                                        'clamp(52px, 5.4vw, 76px)';
                      const ptsFs =
                        tier === 'xs' ? 'clamp(14px, 1.5vw, 20px)' :
                        tier === 'sm' ? 'clamp(16px, 1.8vw, 24px)' :
                        tier === 'md' ? 'clamp(18px, 2vw, 28px)' :
                                        'clamp(20px, 2.2vw, 30px)';
                      const padR = tier === 'xs' ? 10 : tier === 'sm' ? 12 : tier === 'md' ? 14 : 18;
                      const innerGap = tier === 'xs' ? 4 : tier === 'sm' ? 6 : 8;
                      const outerGap = cnt >= 4 ? 4 : cnt > 2 ? 6 : 10;
                      return (
                      <div style={{
                        position: 'absolute', left: 8, right: 8, bottom: 0,
                        transform: 'translateY(72%)',
                        display: 'flex', flexWrap: 'wrap', alignItems: 'flex-start',
                        justifyContent: 'center',
                        gap: outerGap,
                        pointerEvents: 'none', zIndex: 5,
                      }}>
                        {highestBets.map(({ team: tm, pts, submittedAt }, bi) => {
                          const timeSec = t0 ? Math.max(0, (submittedAt - t0) / 1000) : null;
                          const isFastest = showTimePills && bi === 0;
                          // Dim-Logik bewusst entfernt (User-Feedback): ZvZ-Voter-Chips
                          // bleiben voll opak auf allen Optionen, Falsch-Markierung
                          // laeuft nur ueber die Card selbst (Rand + Text gedimmt).
                          return (
                            <div key={tm.id} title={`${tm.name}: ${pts}`} style={{
                              position: 'relative',
                              display: 'flex', alignItems: 'center', gap: innerGap,
                              padding: `2px ${padR}px 2px 2px`,
                              borderRadius: 999,
                              background: 'rgba(0,0,0,0.7)',
                              border: isFastest ? '3px solid #EC4899' : `2px solid ${tm.color}`,
                              boxShadow: isFastest
                                ? '0 0 22px rgba(236,72,153,0.55), 0 6px 14px rgba(0,0,0,0.55)'
                                : `0 6px 14px rgba(0,0,0,0.55), 0 0 14px ${tm.color}55`,
                              animation: `muchoVoterDrop 0.55s cubic-bezier(0.34,1.5,0.64,1) ${0.1 + bi * 0.08}s both`,
                            }}>
                              <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={avSz} />
                              <span style={{
                                fontSize: ptsFs,
                                fontWeight: 900,
                                // Bet-Zahl in Team-Farbe (sofort erkennbar wer wo gesetzt
                                // hat) + Gold-Text-Shadow als gemeinsamer Akzent.
                                color: tm.color, fontVariantNumeric: 'tabular-nums',
                                textShadow: '0 0 12px rgba(236,72,153,0.45), 0 1px 2px rgba(0,0,0,0.6)',
                              }}>{pts}</span>
                              {/* Zeit-Pill immer auf korrekter Option (konsistent mit Mucho/Cheese) */}
                              {showTimePills && timeSec != null && (
                                <span style={{
                                  position: 'absolute',
                                  left: '50%', bottom: -8,
                                  transform: 'translate(-50%, 50%)',
                                  padding: '2px 9px', borderRadius: 999,
                                  background: isFastest ? 'rgba(236,72,153,0.95)' : 'rgba(15,23,42,0.95)',
                                  border: isFastest ? '1.5px solid rgba(236,72,153,1)' : `1.5px solid ${tm.color}`,
                                  color: isFastest ? '#0A0814' : '#e2e8f0',
                                  fontWeight: 900,
                                  fontSize: 'clamp(11px, 1.2vw, 15px)',
                                  whiteSpace: 'nowrap',
                                  boxShadow: '0 4px 10px rgba(0,0,0,0.5)',
                                  lineHeight: 1.1,
                                }}>
                                  {timeSec.toFixed(1)}s
                                </span>
                              )}
                            </div>
                          );
                        })}
                      </div>
                      );
                    })()}
                  </div>
                );
              })}
            </div>
            );
          })()}

          {/* ZEHN_VON_ZEHN: Unter-Bets (alle außer Top-Bets) — Top-Bets werden
              direkt auf der Option oben eingeblendet. Hier also nur die restlichen
              Tipps pro Option, von Anfang an in einheitlicher Größe.
              Sobald die Korrektheit gelockt ist (zvzLocked), gleiten die Sub-Bets
              nach unten weg + fade — clean Spotlight auf die richtige Option. */}
          {revealed && q.category === 'ZEHN_VON_ZEHN' && q.options && (
            <div style={{
              width: '100%', maxWidth: 1400,
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
              gap: 18,
              marginBottom: zvzLocked ? 0 : 16,
              maxHeight: zvzLocked ? 0 : 600,
              overflow: 'hidden',
              opacity: zvzLocked ? 0 : 1,
              transform: zvzLocked ? 'translateY(20px)' : 'translateY(0)',
              transition: 'opacity 0.55s ease 0.2s, transform 0.55s ease 0.2s, max-height 0.55s ease 0.2s, margin-bottom 0.55s ease 0.2s',
              pointerEvents: zvzLocked ? 'none' : 'auto',
            }}>
              {q.options.map((_, i) => {
                const bets = s.answers.map(a => {
                  const pts = a.text.split(',').map(n => Number(n) || 0);
                  return { team: s.teams.find(t => t.id === a.teamId), pts: pts[i] ?? 0 };
                }).filter((b): b is { team: NonNullable<typeof b.team>; pts: number } => !!b.team && b.pts > 0);
                const highest = zvzHighestPerOption[i];
                const highestIds = new Set(highest?.teamIds ?? []);
                const otherBets = bets.filter(b => !highestIds.has(b.team.id));
                return (
                  <div key={`bets-${i}`} style={{
                    display: 'flex', flexWrap: 'wrap', gap: 6,
                    justifyContent: 'center', alignItems: 'center',
                    minHeight: 'clamp(40px, 5vw, 56px)',
                  }}>
                    {otherBets.length === 0 ? (
                      <span style={{ fontSize: 'clamp(13px, 1.4vw, 18px)', color: '#475569', fontStyle: 'italic' }}>—</span>
                    ) : otherBets.map(({ team: tm, pts }) => (
                      <div key={tm.id} title={`${tm.name}: ${pts}`} style={{
                        display: 'flex', alignItems: 'center', gap: 6,
                        padding: '3px 12px 3px 3px',
                        borderRadius: 999,
                        background: 'rgba(0,0,0,0.55)',
                        border: `2px solid ${tm.color}`,
                        boxShadow: `0 3px 10px rgba(0,0,0,0.5), 0 0 8px ${tm.color}44`,
                      }}>
                        <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(28px, 3vw, 40px)'} />
                        <span style={{
                          fontSize: 'clamp(14px, 1.6vw, 22px)',
                          fontWeight: 900,
                          color: tm.color, fontVariantNumeric: 'tabular-nums',
                          textShadow: '0 0 10px rgba(236,72,153,0.4), 0 1px 2px rgba(0,0,0,0.6)',
                        }}>{pts}</span>
                      </div>
                    ))}
                  </div>
                );
              })}
            </div>
          )}

          {/* Answer reveal (skip for MUCHO/ZEHN_VON_ZEHN + Hot Potato — handled separately).
              Rechts im Feld: Avatare der Teams, die das Richtige getippt haben,
              sortiert nach Reaktionszeit (schnellster mit <QQEmojiIcon emoji="⚡"/>-Krone).
              CHEESE: step-based — erst bei cheeseShowGreen (Step 1) sichtbar; Avatare kaskadieren bei Step 2. */}
          {revealed && s.revealedAnswer && q.category !== 'MUCHO' && q.category !== 'ZEHN_VON_ZEHN'
            && !(q.category === 'BUNTE_TUETE' && q.bunteTuete?.kind === 'hotPotato') && (() => {
              // CHEESE: Box immer sichtbar (Layout fix), Inhalt erst bei Step 1.
              const cheeseHideContent = q.category === 'CHEESE' && !cheeseShowGreen;
              // 2026-05-02 (Wolfs Bug 'CHEESE-Cascade nicht nacheinander wie sonst'):
              // Vorher Frontend-strict-Match - Schreibfehler-akzeptierte Antworten
              // (Backend similarityScore>=0.8) wurden NICHT als korrekt erkannt,
              // betroffene Avatare fehlten in der Cascade. Jetzt Backend-Truth via
              // currentQuestionWinners. Bei SCHAETZCHEN bleibt's leer (Zeitstrahl
              // uebernimmt). Sortierung weiterhin nach submittedAt.
              const isSchaetz = q.category === 'SCHAETZCHEN';
              const winnerIdSet = new Set(s.currentQuestionWinners ?? (s.correctTeamId ? [s.correctTeamId] : []));
              const correctTeams = isSchaetz ? [] : [...s.answers]
                .filter(a => winnerIdSet.has(a.teamId))
                .sort((a, b) => a.submittedAt - b.submittedAt)
                .map(a => {
                  const team = s.teams.find(t => t.id === a.teamId);
                  return team ? { team, submittedAt: a.submittedAt } : null;
                })
                .filter((x): x is { team: NonNullable<ReturnType<typeof s.teams.find>>; submittedAt: number } => !!x);
              const t0 = s.timerEndsAt && s.timerDurationSec
                ? s.timerEndsAt - s.timerDurationSec * 1000
                : correctTeams[0]?.submittedAt;
              return (
                <div style={{
                  position: 'relative', overflow: 'hidden',
                  padding: 'clamp(16px, 2vh, 32px) clamp(24px, 3vw, 52px)', borderRadius: 24,
                  background: cheeseHideContent ? 'rgba(34,197,94,0.06)' : 'rgba(34,197,94,0.12)',
                  border: cheeseHideContent ? '3px dashed rgba(34,197,94,0.22)' : '3px solid rgba(34,197,94,0.50)',
                  boxShadow: cheeseHideContent ? 'none' : '0 0 60px rgba(34,197,94,0.25), 0 0 120px rgba(34,197,94,0.1)',
                  marginBottom: 'clamp(8px, 1.2vh, 24px)',
                  width: '100%', maxWidth: 1400,
                  display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
                  gap: 'clamp(10px, 1.4vh, 18px)',
                  // 2026-05-07 (Audit P1): Cheese hat oben schon Frage-Card-
                  // Animation + Step-Cascade — der scale-bounce hier bringt
                  // die Card doppelt in Bewegung. Cheese bekommt langFadeIn,
                  // andere Kategorien behalten den Standard-Bam.
                  animation: cheeseHideContent
                    ? undefined
                    : (q.category === 'CHEESE'
                        ? 'langFadeIn 0.5s ease both'
                        : 'revealAnswerBam 0.6s var(--qq-ease-out-cubic) 0.15s both'),
                  transition: 'background 0.4s ease, border-color 0.4s ease, box-shadow 0.4s ease',
                }}>
                  {/* Shimmer sweep */}
                  <div style={{
                    position: 'absolute', top: 0, width: '60%', height: '100%',
                    background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.15), transparent)',
                    animation: 'revealShimmer 0.8s ease 0.5s both',
                    pointerEvents: 'none',
                  }} />
                  <span style={{
                    fontSize: 'clamp(28px, 4vw, 64px)', fontWeight: 900, color: '#4ade80',
                    flexShrink: 1, minWidth: 0,
                    overflow: 'hidden', textOverflow: 'ellipsis',
                    position: 'relative', zIndex: 1,
                    visibility: cheeseHideContent ? 'hidden' : 'visible',
                  }}>
                    {formatRevealedAnswer(lang, s.revealedAnswer ?? q.answer, q.answerEn)}
                  </span>
                  {correctTeams.length > 0 && (
                    <div style={{
                      display: 'flex', alignItems: 'flex-start', justifyContent: 'center',
                      gap: 12, flexWrap: 'wrap',
                      flexShrink: 0, width: '100%',
                      position: 'relative', zIndex: 1,
                      // Bei CHEESE vor Step 2: Platz reserviert, Inhalt unsichtbar — verhindert Card-Dehnung
                      visibility: (q.category === 'CHEESE' && !cheeseShowAvatars) ? 'hidden' : 'visible',
                    }}>
                      {correctTeams.map((ct, vi) => {
                        const timeSec = t0 ? Math.max(0, (ct.submittedAt - t0) / 1000) : null;
                        const isFastest = vi === 0;
                        // CHEESE: 850ms-Stagger pro Avatar synchron zur Pentatonik-
                        // Cascade (siehe useEffect oben). Vorher 160ms war zu schnell
                        // und unspannend ("alle auf einmal"-Gefuehl).
                        const isCheeseCascade = q.category === 'CHEESE' && cheeseShowAvatars;
                        const cascadeDelay = isCheeseCascade ? vi * 0.85 : 0.6;
                        const avatarAnim = isCheeseCascade
                          ? `muchoVoterDrop 0.55s cubic-bezier(0.34,1.5,0.64,1) ${cascadeDelay}s both`
                          : `revealAnswerBam 0.5s var(--qq-ease-bounce) ${cascadeDelay}s both`;
                        return (
                          <div key={ct.team.id} style={{
                            display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 3,
                            animation: avatarAnim,
                          }}>
                            <div style={{ position: 'relative', display: 'inline-block' }}>
                              <QQTeamAvatar
                                avatarId={ct.team.avatarId}
                                size={isFastest ? 'clamp(78px, 8.6vw, 116px)' : 'clamp(58px, 6.4vw, 88px)'}
                                style={{
                                  border: isFastest ? '4px solid #EC4899' : 'none',
                                  boxShadow: isFastest
                                    ? `0 0 28px rgba(236,72,153,0.65), 0 4px 14px rgba(0,0,0,0.45)`
                                    : '0 4px 12px rgba(0,0,0,0.4)',
                                }}
                              />
                            </div>
                            {timeSec != null && (
                              <span style={{
                                padding: '3px 10px', borderRadius: 999,
                                background: isFastest ? 'rgba(236,72,153,0.22)' : 'rgba(0,0,0,0.55)',
                                border: isFastest ? '1.5px solid rgba(236,72,153,0.7)' : '1px solid rgba(255,255,255,0.15)',
                                color: isFastest ? '#EC4899' : '#cbd5e1',
                                fontWeight: 900,
                                fontSize: 'clamp(15px, 1.6vw, 20px)',
                                whiteSpace: 'nowrap',
                              }}>
                                {timeSec.toFixed(1)}s
                              </span>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })()}

          {/* Hot Potato reveal: show full answer list as chips, mark which were named */}
          {revealed && q.category === 'BUNTE_TUETE' && q.bunteTuete?.kind === 'hotPotato' && (() => {
            const raw = (lang === 'en' && q.answerEn ? q.answerEn : q.answer) ?? '';
            const allAnswers = raw.split(/[,;]/).map(a => a.replace(/[…\.]+$/, '').trim()).filter(Boolean);
            const used = s.hotPotatoUsedAnswers ?? [];
            const authors = s.hotPotatoAnswerAuthors ?? [];
            const usedNorm = used.map((u: string) => u.toLowerCase().trim());
            // Map each revealed answer (from q.answer) → authoring team (if any)
            const findAuthor = (a: string): string | null => {
              const aLower = a.toLowerCase().trim();
              for (let i = 0; i < usedNorm.length; i++) {
                const u = usedNorm[i];
                if (u === aLower || u.includes(aLower) || aLower.includes(u)) return authors[i] ?? null;
              }
              return null;
            };
            // Density-Skalierung: bei vielen Antworten Pills/Font kompakter,
            // sonst sprengen sie den Beamer. 2026-05-09 v3 (Wolf 'all possible
            // answers immer noch zu klein, dynamisch hochziehen wenn Platz'):
            // neue 'xxl'-Stufe für ≤4 Antworten + xl/lg deutlich vergrößert.
            // Schwellen großzügiger: xl bis 8 (war 6), lg bis 16 (war 12).
            const N = allAnswers.length;
            // 2026-05-11 (Wolf-Bug 'Antworten zu klein, Platz oben/unten frei'):
            // Tier-Schwellen erweitert damit mehr Antworten in größere Tiers
            // fallen. Sprung md→lg war besonders steil (13→22px), war Bug-
            // Ursache. Neue Schwellen: ≤4 xxl, ≤12 xl (war 8), ≤24 lg (war 16),
            // ≤40 md (war 30), ≤80 sm (war 60).
            const tier =
              N <= 4  ? 'xxl'
              : N <= 12 ? 'xl'
              : N <= 24 ? 'lg'
              : N <= 40 ? 'md'
              : N <= 80 ? 'sm'
              : 'xs';
            // 2026-05-06 (Wolf 'keine Cascade-Animation bei Hot Potato, aber
            // Cascade-Sound schon — Animation anpassen'): Stagger deutlich
            // langsamer (war 50/25/12/8ms), jetzt sichtbar als Cascade-Effekt.
            // Sync zur Sound-Cascade (Pentatonik-Notes pro qualified Team).
            // 2026-05-11 (Wolf 'lesbar von weiten, Platz nutzen'): font-sizes
            // ausgewogener — kein steiler Drop mehr von lg auf md. md geht von
            // 13/1.4/18 → 17/1.85/26, sm von 11/1.2/15 → 14/1.5/20, xs 10/1/13 → 12/1.2/16.
            const tierStyles = {
              xxl: { fontSize: 'clamp(40px, 4.4vw, 72px)', pad: '20px 40px', padAvatar: '12px 36px 12px 12px', avatarSize: 'clamp(60px, 6vw, 88px)',   gap: 22, headerFs: 'clamp(36px, 4vw, 60px)', containerPad: '40px 44px', stagger: 0.28 },
              xl:  { fontSize: 'clamp(30px, 3.4vw, 52px)', pad: '15px 32px', padAvatar: '9px 30px 9px 9px',    avatarSize: 'clamp(48px, 4.8vw, 68px)', gap: 18, headerFs: 'clamp(30px, 3.4vw, 50px)', containerPad: '30px 34px', stagger: 0.22 },
              lg:  { fontSize: 'clamp(24px, 2.6vw, 38px)', pad: '12px 26px', padAvatar: '7px 24px 7px 7px',    avatarSize: 'clamp(40px, 4vw, 56px)',   gap: 14, headerFs: 'clamp(26px, 3vw, 42px)',  containerPad: '24px 28px', stagger: 0.16 },
              md:  { fontSize: 'clamp(17px, 1.85vw, 26px)', pad: '9px 18px', padAvatar: '5px 16px 5px 5px',    avatarSize: 'clamp(28px, 2.8vw, 38px)', gap: 9,  headerFs: 'clamp(20px, 2.2vw, 30px)', containerPad: '16px 20px', stagger: 0.09 },
              sm:  { fontSize: 'clamp(14px, 1.5vw, 20px)', pad: '6px 14px',  padAvatar: '4px 12px 4px 4px',    avatarSize: 'clamp(22px, 2.2vw, 30px)', gap: 6,  headerFs: 'clamp(16px, 1.8vw, 24px)', containerPad: '12px 16px', stagger: 0.05 },
              xs:  { fontSize: 'clamp(12px, 1.2vw, 16px)', pad: '4px 10px',  padAvatar: '3px 10px 3px 3px',    avatarSize: 'clamp(18px, 1.8vw, 24px)', gap: 4,  headerFs: 'clamp(14px, 1.5vw, 20px)', containerPad: '10px 14px', stagger: 0.03 },
            }[tier];
            return (
              <div style={{
                width: '100%', maxWidth: 1400,
                marginBottom: 'clamp(8px, 1.2vh, 24px)',
                display: 'flex', flexDirection: 'column', alignItems: 'center',
                gap: tier === 'xxl' ? 22 : tier === 'xl' ? 18 : tier === 'lg' ? 14 : tier === 'md' ? 10 : 8,
                // 2026-05-07 (Audit P2): revealAnswerBam (scale-bounce) auf dem
                // Container sprang mit den Chip-Cascades durch — alle Chips
                // huepften synchron mit dem Container-Scale, plus jeder Chip
                // hat seine eigene contentReveal. langFadeIn als ruhige
                // Container-Entry, die Chip-Cascade traegt allein die Energie.
                animation: 'langFadeIn 0.5s ease 0.15s both',
              }}>
                <div style={{
                  fontSize: tierStyles.headerFs, fontWeight: 900,
                  color: '#86efac', letterSpacing: 0.5,
                }}>
                  <QQEmojiIcon emoji="🥔"/> {lang === 'en' ? 'All possible answers' : 'Alle möglichen Antworten'}
                  <span style={{ marginLeft: 8, fontSize: '0.7em', opacity: 0.7 }}>· {N}</span>
                </div>
                <div style={{
                  display: 'flex', flexWrap: 'wrap', justifyContent: 'center',
                  gap: tierStyles.gap,
                  padding: tierStyles.containerPad, borderRadius: 24,
                  background: 'rgba(34,197,94,0.08)',
                  border: '2px solid rgba(34,197,94,0.3)',
                  // 2026-05-11 (Wolf 'Antworten zu klein, Platz oben/unten frei'):
                  // maxHeight von 78vh → 86vh + cap von 920 → 1000. Container
                  // streckt sich jetzt in den freien Slide-Space rein damit die
                  // neuen größeren Tier-Fonts (xxl 40-72px, xl 30-52px) Platz
                  // haben. Q-Card und Trivia-Trio bleiben darüber/darunter.
                  maxHeight: 'clamp(520px, 86vh, 1000px)', overflow: 'hidden',
                }}>
                  {allAnswers.map((a, i) => {
                    const authorId = findAuthor(a);
                    const named = authorId !== null || usedNorm.some((u: string) =>
                      u === a.toLowerCase().trim() || u.includes(a.toLowerCase().trim()) || a.toLowerCase().trim().includes(u)
                    );
                    const authorTeam = authorId ? s.teams.find(t => t.id === authorId) : null;
                    // Bei xs/sm-Density: Avatare nur bei genannten Antworten anzeigen
                    const showAvatar = !!authorTeam && (tier !== 'xs');
                    return (
                      <div key={`${a}-${i}`} style={{
                        display: 'inline-flex', alignItems: 'center', gap: tier === 'xxl' ? 14 : tier === 'xl' ? 12 : tier === 'lg' ? 8 : 4,
                        padding: showAvatar ? tierStyles.padAvatar : tierStyles.pad,
                        borderRadius: 999,
                        fontSize: tierStyles.fontSize, fontWeight: 900,
                        background: named ? 'rgba(34,197,94,0.22)' : 'rgba(15,23,42,0.5)',
                        border: `${tier === 'xs' ? 1 : 2}px solid ${authorTeam ? authorTeam.color : (named ? '#22C55E' : 'rgba(148,163,184,0.25)')}`,
                        color: named ? '#86efac' : '#94a3b8',
                        animation: `contentReveal 0.4s var(--qq-ease-pop-fast) ${0.2 + i * tierStyles.stagger}s both`,
                        boxShadow: authorTeam && tier !== 'xs' ? `0 0 8px ${authorTeam.color}44` : 'none',
                      }}>
                        {showAvatar && authorTeam && (
                          <QQTeamAvatar avatarId={authorTeam.avatarId} teamEmoji={authorTeam.emoji} size={tierStyles.avatarSize} title={authorTeam.name} style={{
                            flexShrink: 0,
                          }} />
                        )}
                        <span>{named ? (tier === 'xs' || tier === 'sm' ? '✓' : '✓ ') : ''}{a}</span>
                      </div>
                    );
                  })}
                </div>
              </div>
            );
          })()}

          {/* Background flash on reveal */}
          {revealed && (
            <div style={{
              position: 'absolute', inset: 0, zIndex: 0, pointerEvents: 'none',
              background: s.correctTeamId
                ? `radial-gradient(ellipse at center, rgba(34,197,94,0.3) 0%, transparent 70%)`
                : `radial-gradient(ellipse at center, rgba(239,68,68,0.2) 0%, transparent 70%)`,
              animation: 'revealFlash 1.2s ease-out both',
            }} />
          )}

          {/* Schätzchen: number-line visualization (above leaderboard) */}
          {revealed && q.category === 'SCHAETZCHEN' && s.answers.length > 0 && q.targetValue != null && (() => {
            const target = q.targetValue as number;
            const parsed = s.answers
              .map(a => {
                const num = Number(a.text.replace(/[^0-9.,\-]/g, '').replace(',', '.'));
                const team = s.teams.find(t => t.id === a.teamId);
                return { teamId: a.teamId, num, team, text: a.text };
              })
              .filter(p => Number.isFinite(p.num) && p.team);
            if (parsed.length === 0) return null;
            const values = [target, ...parsed.map(p => p.num)];
            const rawMin = Math.min(...values);
            const rawMax = Math.max(...values);
            const rawSpan = rawMax - rawMin;
            // Padding 10% auf beiden Seiten, mindestens 10% relativ zum Target.
            const pad = Math.max(rawSpan * 0.1, Math.abs(target) * 0.05, 1);
            const axMin = rawMin - pad;
            const axMax = rawMax + pad;
            const axSpan = Math.max(axMax - axMin, 1);
            const pctOf = (v: number) => ((v - axMin) / axSpan) * 100;
            // Worst → best für Animation-Reihenfolge (Trommelwirbel bis Gewinner)
            const sorted = [...parsed].sort((a, b) =>
              Math.abs(b.num - target) - Math.abs(a.num - target)
            );
            // 2026-05-11 (Wolf-Bug: bei Target 14, Antworten 13 + 15 wurde nur
            // EIN Team als Winner highlighted obwohl beide distance=1 haben.
            // Root-Cause: isWinner verglich nur mit sorted[length-1].teamId.
            // Fix: alle Teams mit minimaler Distanz sind Winner.
            const minDistance = Math.min(...parsed.map(p => Math.abs(p.num - target)));
            const isWinnerTeam = (teamId: string) => {
              const p = parsed.find(x => x.teamId === teamId);
              return p ? Math.abs(p.num - target) === minDistance : false;
            };
            // 4-Slot-Kollisionssystem: Avatare werden auf die erste freie Reihe
            // gelegt, die genug horizontalen Abstand hat. Reihenfolge der Reihen:
            // 0=oben nah, 1=unten nah, 2=oben weit, 3=unten weit.
            // MIN_DIST_PCT = minimaler X-Abstand in % für dieselbe Reihe.
            // Avatar 72px bei ~1400px Breite ≈ 5.2%, + 2% Luft = 7.2% → 8%.
            const pinRows = new Map<string, number>();
            const pinXNudge = new Map<string, number>();
            const MIN_DIST_PCT = 8;
            const rowLastPct: number[] = [-Infinity, -Infinity, -Infinity, -Infinity];
            const sortedByPos = [...parsed].sort((a, b) => a.num - b.num);
            sortedByPos.forEach((p) => {
              const pct = pctOf(p.num);
              // Probiere die 4 Reihen in bevorzugter Reihenfolge durch
              const preferredOrder = [0, 1, 2, 3];
              let chosen = 3; // Fallback = weit-unten
              for (const row of preferredOrder) {
                if (pct - rowLastPct[row] >= MIN_DIST_PCT) {
                  chosen = row;
                  break;
                }
              }
              pinRows.set(p.teamId, chosen);
              rowLastPct[chosen] = pct;
            });

            // ═══════════════════════════════════════════════════════════════
            // DYNAMIC CHIP PLACEMENT mit echter Kollisionserkennung.
            // Pixel-basiert auf einer virtuellen Bühne von 1400px Breite.
            // Für jeden Pin werden 4 Chip-Kandidaten geprüft (below, above,
            // right, left relativ zum Avatar) und der erste freie gewählt.
            // Geprüft wird gegen ALLE bereits platzierten Avatare & Chips.
            // Die Chip-Offsets werden dann per CSS-Var an den Chip gereicht.
            // ═══════════════════════════════════════════════════════════════
            type Rect = { x: number; y: number; w: number; h: number };
            const STAGE_W = 1400;
            const rectsOverlap = (a: Rect, b: Rect, pad = 4) =>
              !(a.x + a.w + pad <= b.x ||
                b.x + b.w + pad <= a.x ||
                a.y + a.h + pad <= b.y ||
                b.y + b.h + pad <= a.y);
            const placedRects: Rect[] = [];
            // Zielmarker sitzt jetzt ALS Pill direkt AUF der Rail —
            // nur ein schmales Rect in Rail-Höhe sperren, damit Avatar-Chips
            // oben/unten drumherum frei platziert werden können.
            const targetPx = (pctOf(target) / 100) * STAGE_W;
            placedRects.push({ x: targetPx - 50, y: -16, w: 100, h: 32 });
            // Alle Pin-Avatare als Rects für Kollision vormerken.
            parsed.forEach((p) => {
              const r = pinRows.get(p.teamId) ?? 0;
              const isWinner = isWinnerTeam(p.teamId);
              const isTop = r === 0 || r === 2;
              const gap = r === 0 || r === 1 ? 110 : 180;
              const wrapperY = isTop ? -gap : gap;
              const aSize = isWinner ? 86 : 72;
              const px = (pctOf(p.num) / 100) * STAGE_W;
              placedRects.push({
                x: px - aSize / 2, y: wrapperY - aSize / 2,
                w: aSize, h: aSize,
              });
            });
            // Chip-Offsets pro Team berechnen.
            const pinChipOffset = new Map<string, { dx: number; dy: number; side: 'below' | 'above' | 'right' | 'left' }>();
            // In Reihenfolge der sortierten Enthüllung (sorted = worst→best),
            // damit Gewinner zuletzt platziert wird und freie Plätze wählt.
            // Aber bessere Verteilung: erst die engsten Cluster (mittlere Pcts)
            // durchgehen — wir gehen links→rechts, das klappt in der Praxis.
            [...parsed].sort((a, b) => a.num - b.num).forEach((p) => {
              const r = pinRows.get(p.teamId) ?? 0;
              const isWinner = isWinnerTeam(p.teamId);
              const isTop = r === 0 || r === 2;
              const gap = r === 0 || r === 1 ? 110 : 180;
              const wrapperY = isTop ? -gap : gap;
              const aSize = isWinner ? 86 : 72;
              const px = (pctOf(p.num) / 100) * STAGE_W;
              const chipW = isWinner ? 140 : 100;
              const chipH = isWinner ? 64 : 48;
              // Kandidaten relativ zum Avatar-Wrapper-Zentrum (px-Koordinaten).
              // Primär: Richtung "Rail" (zur Mitte hin) bleibt erhalten —
              // unten-Avatare → Chip nach oben, oben-Avatare → Chip nach unten.
              // Dann Fallbacks: außen, rechts, links.
              const primaryBelow = !isTop; // !isTop = Avatar unten der Rail → Chip über dem Avatar (Richtung Rail)
              const candidates: Array<{ dx: number; dy: number; side: 'below' | 'above' | 'right' | 'left' }> = [];
              // Rail-zugewandt (primär)
              if (primaryBelow) {
                candidates.push({ dx: 0, dy: -aSize / 2 - 6 - chipH, side: 'above' });
              } else {
                candidates.push({ dx: 0, dy: aSize / 2 + 6, side: 'below' });
              }
              // Rail-abgewandt (sekundär)
              if (primaryBelow) {
                candidates.push({ dx: 0, dy: aSize / 2 + 6, side: 'below' });
              } else {
                candidates.push({ dx: 0, dy: -aSize / 2 - 6 - chipH, side: 'above' });
              }
              // Rechts / links vom Avatar
              candidates.push({ dx: aSize / 2 + 8, dy: -chipH / 2, side: 'right' });
              candidates.push({ dx: -aSize / 2 - 8 - chipW, dy: -chipH / 2, side: 'left' });
              // Weitere Fallbacks: weiter oben/unten
              candidates.push({ dx: 0, dy: -aSize / 2 - 6 - chipH - 28, side: 'above' });
              candidates.push({ dx: 0, dy: aSize / 2 + 6 + 28, side: 'below' });

              let picked = candidates[0];
              for (const c of candidates) {
                const chipRect: Rect = {
                  x: px + c.dx - chipW / 2 + (c.side === 'right' || c.side === 'left' ? chipW / 2 : 0),
                  y: wrapperY + c.dy,
                  w: chipW, h: chipH,
                };
                // Für side=right/left: dx bereits inkl. Chip-Breite gesetzt.
                if (c.side === 'right' || c.side === 'left') {
                  chipRect.x = px + c.dx;
                } else {
                  chipRect.x = px + c.dx - chipW / 2;
                }
                const collides = placedRects.some(r2 => rectsOverlap(chipRect, r2));
                if (!collides) {
                  placedRects.push(chipRect);
                  picked = c;
                  break;
                }
              }
              // Falls alle kollidieren → trotzdem primary nehmen, platzieren.
              if (!picked) picked = candidates[0];
              pinChipOffset.set(p.teamId, picked);
            });
            const targetPct = pctOf(target);
            const unitStrInline = (lang === 'en' && q.unitEn ? q.unitEn : q.unit) ?? '';
            const looksLikeYearI = (n: number) => Number.isInteger(n) && n >= 1000 && n <= 2100;
            const isYearUnitInline = !!q.isYearAnswer || /jahr|year/i.test(unitStrInline) || (target != null && looksLikeYearI(target));
            const fmt = (n: number) => {
              const abs = Math.abs(n);
              if (isYearUnitInline) return String(Math.round(n));
              if (abs >= 1000000) return (n / 1000000).toFixed(1).replace(/\.0$/, '') + 'M';
              if (abs >= 10000) return (n / 1000).toFixed(0) + 'k';
              if (abs >= 1000) return n.toLocaleString(lang === 'en' ? 'en-US' : 'de-DE');
              return n % 1 === 0 ? String(n) : n.toFixed(1);
            };
            return (
              <div style={{
                width: '100%', maxWidth: 1400,
                // Oben/unten: weit-Row (180 + Avatar 41 + Chip 36 ≈ 250). Target sitzt jetzt ON-Rail.
                padding: '235px clamp(24px, 3vw, 48px) 235px',
                marginBottom: 'clamp(8px, 1vh, 16px)',
                position: 'relative',
                background: 'rgba(255,255,255,0.03)',
                border: '1.5px solid rgba(255,255,255,0.08)',
                borderRadius: 24,
                boxShadow: '0 8px 24px rgba(0,0,0,0.3)',
                animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.3s both',
              }}>
                {/* Axis line — mittig im Container, genug Luft oben/unten für die Pins */}
                <div style={{
                  position: 'relative', height: 4,
                }}>
                  {/* Rail */}
                  <div style={{
                    position: 'absolute', left: 0, right: 0, top: '50%',
                    height: 4, borderRadius: 2,
                    background: 'linear-gradient(90deg, rgba(148,163,184,0.15), rgba(148,163,184,0.35), rgba(148,163,184,0.15))',
                    transform: 'translateY(-50%)',
                  }} />
                  {/* Axis endpoints labels */}
                  <div style={{
                    position: 'absolute', left: 0, top: 'calc(50% + 22px)',
                    fontSize: 'clamp(18px, 1.8vw, 26px)', color: '#94a3b8', fontWeight: 900,
                  }}>{fmt(axMin)}</div>
                  <div style={{
                    position: 'absolute', right: 0, top: 'calc(50% + 22px)',
                    fontSize: 'clamp(18px, 1.8vw, 26px)', color: '#94a3b8', fontWeight: 900,
                  }}>{fmt(axMax)}</div>

                  {/* Target marker — kompakte Pille direkt AUF der Rail.
                      Etwas kleiner, damit nahe Avatare nicht verdeckt werden. */}
                  <div style={{
                    position: 'absolute', left: `${targetPct}%`, top: '50%',
                    transform: 'translate(-50%, -50%)',
                    display: 'flex', alignItems: 'center', gap: 5,
                    padding: '4px 11px 4px 7px',
                    borderRadius: 999,
                    background: 'linear-gradient(135deg, #22C55E, #16A34A)',
                    boxShadow: '0 0 14px rgba(34,197,94,0.55), 0 2px 8px rgba(0,0,0,0.38)',
                    border: '2px solid rgba(255,255,255,0.9)',
                    animation: 'pinRevealIn 0.55s var(--qq-ease-bounce) 0.5s both',
                    ['--pin-x' as any]: '0px',
                    ['--pin-y' as any]: '0px',
                    zIndex: 30,
                    whiteSpace: 'nowrap',
                  }}>
                    <span style={{
                      fontSize: 'clamp(16px, 1.7vw, 22px)', lineHeight: 1,
                    }}><QQEmojiIcon emoji="🎯"/></span>
                    <span style={{
                      color: '#fff', fontWeight: 900,
                      fontSize: 'clamp(14px, 1.6vw, 20px)', lineHeight: 1,
                      textShadow: '0 1px 3px rgba(0,0,0,0.3)',
                    }}>{fmt(target)}</span>
                  </div>

                  {/* Team pins — Avatar und Wert-Chip liegen als stack klar ÜBER bzw.
                      UNTER der Rail. Bei "oben" (negative yOffset) kommt der Chip
                      über den Avatar, die Verbindungslinie zieht unterhalb des
                      Avatars Richtung Rail. Bei "unten" (positive yOffset) steht der
                      Avatar unter der Rail, der Chip darunter. Dadurch sind Avatare
                      eindeutig nicht mehr "auf der Linie". */}
                  {parsed.map((p) => {
                    const pct = pctOf(p.num);
                    const r = pinRows.get(p.teamId) ?? 0;
                    const xNudge = pinXNudge.get(p.teamId) ?? 0;
                    const isWinner = isWinnerTeam(p.teamId);
                    const orderIdx = sorted.findIndex(x => x.teamId === p.teamId);
                    const delay = 0.7 + orderIdx * 0.18;
                    const tColor = p.team!.color;
                    // r: 0 = oben nah, 1 = unten nah, 2 = oben weit, 3 = unten weit.
                    const isTop = r === 0 || r === 2;
                    // gap = Entfernung Rail ↔ Avatar-Mittelpunkt — kompakter, aber Avatare klar von der Rail getrennt.
                    // Nah: 110, Weit: 180 (zweite Reihe bei Kollision)
                    const gap = r === 0 || r === 1 ? 110 : 180;
                    const avatarSize = isWinner ? 86 : 72;
                    // Nudge/Animation-Deltas (Gewinner hüpft Richtung Ziel)
                    const nudgePctDelta = targetPct - pct;
                    const nudgeXPx = Math.max(-160, Math.min(160, nudgePctDelta * 12));
                    const nudgeDelay = delay + 0.8;
                    // Das äußere Wrapper-Div wird per translate auf Rail-Ebene
                    // bzw. Avatar-Ebene zentriert — isTop: nach oben, sonst nach
                    // unten. Wrapper ist ein Punkt; die Kinder werden relativ
                    // zum Avatar-Zentrum absolut positioniert.
                    const wrapperY = isTop ? -gap : gap;
                    return (
                      <div key={p.teamId} style={{
                        position: 'absolute', left: `${pct}%`, top: '50%',
                        width: 0, height: 0,
                        // CSS-Vars für pinRevealIn + winnerNudge — Wrapper-Position
                        // bleibt erhalten (nicht von animation overschrieben).
                        ['--pin-x' as any]: `${xNudge}px`,
                        ['--pin-y' as any]: `${wrapperY}px`,
                        ['--base-x' as any]: `${xNudge}px`,
                        ['--nudge-x' as any]: `${nudgeXPx}px`,
                        ['--nudge-y' as any]: `${wrapperY}px`,
                        transform: `translate(calc(-50% + ${xNudge}px), calc(-50% + ${wrapperY}px))`,
                        animation: isWinner
                          ? `pinRevealIn 0.55s var(--qq-ease-bounce) ${delay}s both, winnerNudge 1.4s var(--qq-ease-bounce) ${nudgeDelay}s 1 both`
                          : `pinRevealIn 0.55s var(--qq-ease-bounce) ${delay}s both`,
                        zIndex: isWinner ? 20 : 10,
                      }}>
                        {/* Verbindungslinie vom Avatar zur Rail (in Richtung Rail) */}
                        <div style={{
                          position: 'absolute', left: '50%',
                          top: isTop ? `${avatarSize / 2}px` : `${-gap}px`,
                          width: 2, height: gap - avatarSize / 2,
                          background: `${tColor}88`,
                          transform: 'translateX(-50%)',
                          zIndex: -1,
                        }} />
                        {/* Avatar pin (zentriert auf Wrapper-Punkt) */}
                        <QQTeamAvatar avatarId={p.team!.avatarId} teamEmoji={p.team!.emoji} size={isWinner ? 'clamp(72px, 7vw, 96px)' : 'clamp(60px, 6vw, 82px)'} style={{
                          position: 'absolute', left: '50%', top: 0,
                          transform: 'translate(-50%, -50%)',
                          border: isWinner ? '3px solid #EC4899' : 'none',
                          boxShadow: isWinner
                            ? `0 0 24px ${tColor}aa, 0 0 44px rgba(236,72,153,0.5)`
                            : `0 4px 12px rgba(0,0,0,0.5)`,
                        }} />
                        {/* Value-Chip mit DYNAMISCHER Kollisionsvermeidung.
                            Der Chip wird relativ zum Avatar-Zentrum in eine der
                            4 Richtungen gelegt (oben/unten/rechts/links), je
                            nachdem wo Platz frei ist. Position kam aus
                            pinChipOffset (px-basierte Kollisionserkennung). */}
                        {(() => {
                          const off = pinChipOffset.get(p.teamId) ?? { dx: 0, dy: avatarSize / 2 + 10, side: 'below' as const };
                          const isChipTopOfAvatar = off.dy < 0;
                          // Connector-Linie vom Avatar zum Chip (Team-Farbe),
                          // damit Zuordnung klar bleibt wenn Chip seitlich sitzt.
                          const connectorH = off.side === 'above'
                            ? Math.abs(off.dy) - avatarSize / 2
                            : off.side === 'below'
                              ? off.dy - avatarSize / 2
                              : 0;
                          return (
                            <>
                              {/* Connector (nur oben/unten, seitlich nicht nötig da Chip direkt am Avatar) */}
                              {(off.side === 'above' || off.side === 'below') && connectorH > 2 && (
                                <div style={{
                                  position: 'absolute', left: '50%',
                                  top: isChipTopOfAvatar ? `${-(avatarSize / 2 + connectorH)}px` : `${avatarSize / 2}px`,
                                  width: 2, height: connectorH,
                                  background: `${tColor}99`,
                                  transform: 'translateX(-50%)',
                                  zIndex: 0,
                                }} />
                              )}
                              <div style={{
                                position: 'absolute',
                                left: off.side === 'right'
                                  ? `${off.dx}px`
                                  : off.side === 'left'
                                    ? `${off.dx}px`
                                    : '50%',
                                top: `${off.dy}px`,
                                transform: off.side === 'right' || off.side === 'left'
                                  ? 'translate(0, 0)'
                                  : 'translate(-50%, 0)',
                                // 2026-05-05 (Wolf 'low-bets zu klein, groesser'):
                                // Loser-Bet 24-34 → 30-44, Winner-Bet 32-46 → 38-56.
                                // Padding entsprechend hoch.
                                padding: isWinner ? '11px 26px' : '9px 22px',
                                borderRadius: 16,
                                background: 'rgba(0,0,0,0.88)',
                                border: `2px solid ${tColor}`,
                                color: '#fff', fontWeight: 900,
                                fontSize: isWinner ? 'clamp(38px, 4vw, 56px)' : 'clamp(30px, 3.2vw, 44px)',
                                whiteSpace: 'nowrap',
                                boxShadow: `0 4px 12px rgba(0,0,0,0.6)`,
                                zIndex: 1,
                              }}>
                                {fmt(p.num)}
                              </div>
                            </>
                          );
                        })()}
                      </div>
                    );
                  })}
                </div>
              </div>
            );
          })()}

          {/* Schätzchen: schlanker Gewinner-Chip unter dem Zeitstrahl (kein redundantes Riesen-Panel,
              Avatare/Werte sind am Strahl bereits sichtbar).
              Bei Distanz-Gleichstand entscheidet die Reaktionszeit — dann zeigt der Chip
              zusätzlich „und am schnellsten!". */}
          {revealed && q.category === 'SCHAETZCHEN' && s.answers.length > 0 && (() => {
            const ranked = s.answers
              .map(a => {
                const num = Number(a.text.replace(/[^0-9.,\-]/g, '').replace(',', '.'));
                const team = s.teams.find(t => t.id === a.teamId);
                const distance = Number.isNaN(num) || q.targetValue == null ? Infinity : Math.abs(num - q.targetValue);
                return { ...a, num, distance, team };
              })
              // Primär Distanz, sekundär Speed — so gewinnt bei gleichem Abstand der schnellste.
              .sort((a, b) => (a.distance - b.distance) || (a.submittedAt - b.submittedAt));
            const w = ranked[0];
            if (!w || w.distance === Infinity || !w.team) return null;
            const tColor = w.team.color;
            // Gleichstand auf der Distanz → Speed war der Tiebreaker.
            const distanceTied = ranked.filter(r => r.distance === w.distance).length > 1;
            return (
              <div style={{
                display: 'flex', justifyContent: 'center', width: '100%',
                animation: 'revealWinnerIn 0.55s var(--qq-ease-bounce) 0.9s both',
              }}>
                <div style={{
                  display: 'inline-flex', alignItems: 'center', gap: 18,
                  padding: '14px 30px', borderRadius: 999,
                  background: `linear-gradient(135deg, ${tColor}2a, ${tColor}0a)`,
                  border: `2px solid ${tColor}55`,
                  boxShadow: `0 0 32px ${tColor}44`,
                }}>
                  <span style={{ fontSize: 'clamp(26px, 2.8vw, 36px)', lineHeight: 1 }}><QQEmojiIcon emoji="🏆"/></span>
                  <QQTeamAvatar avatarId={w.team.avatarId} teamEmoji={w.team.emoji} size={'clamp(28px, 3vw, 40px)'} style={{ flexShrink: 0 }} />
                  <span style={{
                    fontWeight: 900, fontSize: 'clamp(22px, 2.4vw, 32px)', color: tColor, lineHeight: 1.1,
                  }}>{w.team.name}</span>
                  <span style={{
                    color: '#cbd5e1', fontSize: 'clamp(19px, 2.1vw, 28px)', fontWeight: 700, lineHeight: 1.1,
                  }}>
                    {distanceTied
                      ? (lang === 'en' ? 'was closest — and fastest! ⚡' : 'war am nächsten dran — und am schnellsten! ⚡')
                      : (lang === 'en' ? 'was closest!' : 'war am nächsten dran!')}
                  </span>
                </div>
              </div>
            );
          })()}

          {/* Correct team — winner banner (non-Schätzchen).
              2026-05-05 v2 (Wolf 'zvz cards rutschen runter beim low-bet-out
              und wieder hoch wenn winner-card kommt'): Slot-Hoehe wird jetzt
              SOFORT bei revealed=true reserviert (nicht erst wenn showUnified-
              Winner). Damit gibt es keinen Layout-Shift mehr zwischen
              Bet-Cascade-Step 1 (low-bets out) und Step 2 (winner-card pop) —
              der Slot ist die ganze Zeit da, nur der Inhalt fadet rein.
              MUCHO/CHEESE/HotPotato profitieren auch. */}
          {revealed && q.category !== 'SCHAETZCHEN' && (
            <div style={{
              width: '100%', maxWidth: 1400,
              overflow: 'visible',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              // 2026-05-06 v2 (Wolf 'obere Cards springen leicht hoch wenn
              // Winner-Card kommt' fuer MUCHO + ZvZ): Slot wird jetzt SOFORT
              // beim Eintritt in QUESTION_REVEAL reserviert (nicht erst wenn
              // correctTeamId arrives). Damit kein Layout-Shift mehr zwischen
              // 'reveal-phase aber noch keine winner-id' und 'winner-id da'.
              // Inner content gated auf showUnifiedWinner + (correctTeamId
              // ODER winners.length>0) damit keine leere Card pop't.
              minHeight: 'clamp(120px, 14vh, 200px)',
              marginBottom: 12,
              opacity: showUnifiedWinner ? 1 : 0,
              transform: showUnifiedWinner ? 'scale(1)' : 'scale(0.96)',
              transformOrigin: 'top center',
              transition: 'opacity 0.7s var(--qq-ease-out-cubic), transform 0.7s var(--qq-ease-bounce)',
            }}>
              {showUnifiedWinner && (s.correctTeamId || (s.currentQuestionWinners?.length ?? 0) > 0) && (() => {
            const isEn = lang === 'en';
            const bannerDelay = 0.7;
            const avatarDelay = 1.1;

            // ZEHN_VON_ZEHN: Tie-Info ermitteln, damit Text stimmt, wenn mehrere Teams
            // die gleiche Höchstpunktzahl auf die richtige Antwort gesetzt haben
            // (Reihenfolge per Schnelligkeit). Bei echtem Zeit-Gleichstand → alle als Co-Sieger.
            let allInTie: {
              maxPointsTied: boolean;  // mehrere Teams mit Höchstpunkten
              speedTied: string[];     // Team-IDs mit max Punkten UND schnellstem Submit
              winnerPts: number;
            } | null = null;
            if (cat === 'ZEHN_VON_ZEHN' && q.correctOptionIndex != null && q.options) {
              const correctIdx = q.correctOptionIndex;
              const onCorrect = s.answers
                .map(a => {
                  const parts = a.text.split(',').map(n => parseInt(n.trim(), 10));
                  const pts = parts[correctIdx] ?? 0;
                  return { teamId: a.teamId, pts, submittedAt: a.submittedAt };
                })
                .filter(x => x.pts > 0);
              if (onCorrect.length > 0) {
                const maxPts = Math.max(...onCorrect.map(x => x.pts));
                const atMax = onCorrect.filter(x => x.pts === maxPts);
                const minT  = Math.min(...atMax.map(x => x.submittedAt));
                const atMaxAndFastest = atMax.filter(x => x.submittedAt === minT);
                allInTie = {
                  maxPointsTied: atMax.length > 1,
                  speedTied: atMaxAndFastest.map(x => x.teamId),
                  winnerPts: maxPts,
                };
              }
            }

            const coWinners = allInTie && allInTie.speedTied.length > 1
              ? s.teams.filter(t => allInTie!.speedTied.includes(t.id))
              : null;

            // Single-team Banner (Default-Fall)
            // 2026-05-05 (Wolf-Bug 'cheese keine gewinnercard'): Fallback auf
            // ersten Winner aus currentQuestionWinners — bei CHEESE ohne fastest
            // ist correctTeamId leer, aber wir haben trotzdem Sieger.
            const winnerIds = s.currentQuestionWinners ?? (s.correctTeamId ? [s.correctTeamId] : []);
            const team = s.teams.find(t => t.id === s.correctTeamId)
              ?? s.teams.find(t => t.id === winnerIds[0]);
            if (!coWinners && !team) return null;

            const muchoSpeedWin = cat === 'MUCHO' && q.correctOptionIndex != null
              && s.answers.filter(a => a.text === String(q.correctOptionIndex)).length > 1;
            const allInTied = allInTie?.maxPointsTied ?? false;

            // CHEESE: Wenn mehrere Teams richtig geraten haben, ist „am schnellsten"
            // die entscheidende Info. 2026-05-02 (Audit): Backend-Truth statt
            // strict-Match - sonst zaehlte Schreibfehler-Akzeptanzen nicht.
            const cheeseCorrectCount = cat === 'CHEESE'
              ? (s.currentQuestionWinners ?? (s.correctTeamId ? [s.correctTeamId] : [])).length
              : 0;
            const cheeseSpeedWin = cat === 'CHEESE' && cheeseCorrectCount > 1;

            const winMsg = cat === 'CHEESE'
              ? (cheeseSpeedWin
                  ? (isEn ? 'recognized it fastest!' : 'hat es am schnellsten erkannt!')
                  : (isEn ? 'got it right!' : 'hat es erkannt!'))
              : cat === 'BUNTE_TUETE'
                ? (isEn ? 'wins the round!' : 'gewinnt die Runde!')
                : cat === 'ZEHN_VON_ZEHN'
                  ? (allInTied
                      ? (isEn ? 'had the most points — and was fastest!' : 'hatte die meisten Punkte — und war am schnellsten!')
                      : (isEn ? 'bet the most points on the correct answer!' : 'hat die meisten Punkte auf die richtige Antwort gesetzt!'))
                  : muchoSpeedWin
                    ? (isEn ? 'fastest & correct!' : 'am schnellsten & richtig!')
                    : (isEn ? 'correct!' : 'richtig!');

            // Hot Potato: bei pool-exhausted (>=2 Ueberlebende) haben alle
            // Ueberlebenden gewonnen und ein Feld bekommen. Zeige sie alle an,
            // sonst wirkt die Folie wie "Harald gewinnt allein".
            let hpCoWinners: typeof s.teams | null = null;
            if (cat === 'BUNTE_TUETE' && (q.bunteTuete as any)?.kind === 'hotPotato') {
              const eliminated = new Set((s.hotPotatoEliminated ?? []) as string[]);
              const alive = s.teams.filter(t => !eliminated.has(t.id));
              if (alive.length >= 2) hpCoWinners = alive;
            }
            if (hpCoWinners) {
              const survivorCount = hpCoWinners.length;
              const totalCount = s.teams.length;
              const everyoneSurvived = survivorCount === totalCount;
              const hpMsg = isEn
                ? (everyoneSurvived
                    ? 'all survived — each gets an action!'
                    : `${survivorCount} survived — each gets an action!`)
                : (everyoneSurvived
                    ? 'alle überlebt — jedes Team bekommt eine Aktion!'
                    : `${survivorCount} haben überlebt — jedes Team bekommt eine Aktion!`);
              return (
                <div style={{
                  display: 'flex', flexDirection: 'column', alignItems: 'center',
                  gap: 'clamp(10px, 1.4vh, 18px)',
                  padding: 'clamp(16px, 2vh, 26px) clamp(22px, 3vw, 42px)',
                  borderRadius: 24,
                  width: '100%', maxWidth: 1400,
                  background: 'linear-gradient(135deg, rgba(34,197,94,0.18), rgba(34,197,94,0.05))',
                  border: '2px solid rgba(34,197,94,0.55)',
                  boxShadow: '0 0 60px rgba(34,197,94,0.25), 0 8px 24px rgba(0,0,0,0.4)',
                  animation: `revealWinnerIn 0.65s var(--qq-ease-bounce) ${bannerDelay}s both`,
                }}>
                  {/* Zeile 1: Kartoffel + alle Team-Chips (wrappt bei vielen Teams) */}
                  <div style={{
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    gap: 'clamp(12px, 1.5vw, 20px)', flexWrap: 'wrap',
                  }}>
                    <span style={{ fontSize: 'clamp(34px, 4.2vw, 56px)', lineHeight: 1 }}><QQEmojiIcon emoji="🥔"/></span>
                    {hpCoWinners.map((tm, i) => (
                      <div key={tm.id} style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                        <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(52px, 5.6vw, 78px)'} style={{
                          flexShrink: 0, boxShadow: `0 0 22px ${tm.color}55`,
                          animation: `celebShake 0.6s ease ${avatarDelay + i * 0.1}s both`,
                        }} />
                        <TeamNameLabel
                          name={tm.name}
                          maxLines={2}
                          shrinkAfter={18}
                          color={tm.color}
                          fontWeight={900}
                          fontSize="clamp(20px, 2.6vw, 34px)"
                          style={{
                            textShadow: `0 0 24px ${tm.color}44`,
                            maxWidth: 240,
                          }}
                        />
                      </div>
                    ))}
                  </div>
                  {/* Zeile 2: Message — eigene Zeile, immer zentriert, nie geclippt */}
                  <div style={{
                    color: '#86efac', fontSize: 'clamp(18px, 2.3vw, 30px)', fontWeight: 900, lineHeight: 1.2,
                    textAlign: 'center',
                  }}>
                    {hpMsg}
                  </div>
                </div>
              );
            }

            // Echter Zeit-Gleichstand (gleiche max Punkte + gleiche ms) → mehrere Sieger
            if (coWinners && coWinners.length > 1) {
              const coMsg = isEn
                ? `all tied on points & speed${allInTie ? ` (+${allInTie.winnerPts})` : ''}!`
                : `gleich viele Punkte und gleich schnell${allInTie ? ` (+${allInTie.winnerPts})` : ''}!`;
              return (
                <div style={{
                  display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 22,
                  padding: '22px 38px', borderRadius: 24,
                  width: '100%', maxWidth: 1400, flexWrap: 'wrap',
                  background: 'linear-gradient(135deg, rgba(236,72,153,0.15), rgba(236,72,153,0.05))',
                  border: '2px solid rgba(236,72,153,0.55)',
                  boxShadow: '0 0 60px rgba(236,72,153,0.25), 0 8px 24px rgba(0,0,0,0.4)',
                  animation: `revealWinnerIn 0.65s var(--qq-ease-bounce) ${bannerDelay}s both`,
                }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 14, flexWrap: 'wrap', justifyContent: 'center' }}>
                    {coWinners.map((tm, i) => (
                      <div key={tm.id} style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                        <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(64px, 7vw, 96px)'} style={{
                          flexShrink: 0, boxShadow: `0 0 24px ${tm.color}55`,
                          animation: `celebShake 0.6s ease ${avatarDelay + i * 0.1}s both`,
                        }} />
                        <div style={{
                          fontWeight: 900, fontSize: 'clamp(26px, 3.4vw, 48px)', color: tm.color, lineHeight: 1.1,
                          textShadow: `0 0 24px ${tm.color}44`,
                        }}>{tm.name}</div>
                      </div>
                    ))}
                  </div>
                  <div style={{
                    color: '#EC4899', fontSize: 'clamp(18px, 2.4vw, 30px)', fontWeight: 900, lineHeight: 1.2,
                  }}>
                    {coMsg}
                  </div>
                </div>
              );
            }

            // Single-winner Banner — Team-Farben-Card (User-Feedback:
            // Gewinner-Card unten in Team-Farbe statt nur am Loesungsfeld oben).
            // 2026-05-10 (Wolf-Live-Test L8 'Mu-Cho untere Card abgeschnitten'):
            // Avatar 8vw→7vw, font 5vw→4.2vw, padding 2vh→1.6vh, sub-margin
            // 6→4 — Banner ~15-20% kompakter damit Reveal bei Mu-Cho mit 4 Optionen
            // + Frage nicht den viewport-Bottom verlässt (overflow:hidden global).
            return (
              <div style={{
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                gap: 'clamp(16px, 2vw, 30px)',
                padding: 'clamp(12px, 1.6vh, 22px) clamp(20px, 2.6vw, 36px)',
                width: '100%', maxWidth: 1400,
                borderRadius: 22,
                background: `linear-gradient(135deg, ${team!.color}26, ${team!.color}08)`,
                border: `3px solid ${team!.color}88`,
                boxShadow: `0 0 60px ${team!.color}33, 0 8px 24px rgba(0,0,0,0.4)`,
                animation: `revealWinnerIn 0.65s var(--qq-ease-bounce) ${bannerDelay}s both`,
              }}>
                <QQTeamAvatar avatarId={team!.avatarId} teamEmoji={team!.emoji} size={'clamp(56px, 7vw, 92px)'} style={{
                  flexShrink: 0,
                  boxShadow: `0 0 24px ${team!.color}88`,
                  animation: `celebShake 0.6s ease ${avatarDelay}s both`,
                }} />
                <div style={{ minWidth: 0 }}>
                  <TeamNameLabel
                    name={team!.name}
                    maxLines={2}
                    shrinkAfter={18}
                    color={team!.color}
                    fontWeight={900}
                    fontSize="clamp(30px, 4.2vw, 60px)"
                    style={{
                      textShadow: `0 0 24px ${team!.color}55`,
                      padding: '0 0.3em',
                    }}
                  />
                  <div style={{
                    color: '#cbd5e1', fontSize: 'clamp(17px, 2.4vw, 30px)', fontWeight: 900, marginTop: 4, lineHeight: 1.2,
                  }}>
                    {winMsg}
                  </div>
                </div>
              </div>
            );
          })()}
            </div>
          )}

          {/* Confetti overlay on correct answer (delayed to sync with winner) */}
          {revealed && s.correctTeamId && showUnifiedWinner && (
            <div style={{ animation: 'contentReveal 0.01s var(--qq-ease-pop-fast) 0.8s both' }}>
              <ConfettiOverlay eurovisionMode={s.theme?.eurovisionMode} />
            </div>
          )}

          {/* Nobody got it right banner */}
          {revealed && !s.correctTeamId && (
            <div style={{
              display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 20,
              padding: '24px 44px', borderRadius: 24, marginBottom: 12,
              width: '100%', maxWidth: 1400,
              background: 'rgba(239,68,68,0.08)',
              border: '2px solid rgba(239,68,68,0.30)',
              boxShadow: '0 0 40px rgba(239,68,68,0.15)',
              animation: 'revealWinnerIn 0.5s var(--qq-ease-bounce) 0.5s both',
            }}>
              <span style={{ fontSize: 'clamp(48px, 6vw, 80px)', lineHeight: 1 }}>
                {s.answers.length === 0 ? '⏱' : <QQEmojiIcon emoji="❌"/>}
              </span>
              <div style={{
                fontSize: 'clamp(24px, 3.5vw, 48px)', fontWeight: 900,
                color: s.answers.length === 0 ? '#94a3b8' : '#f87171',
              }}>
                {s.answers.length === 0
                  ? (lang === 'en' ? 'No answers!' : 'Keine Antworten!')
                  : (lang === 'en' ? 'Nobody got it right!' : 'Keiner hatte Recht!')}
              </div>
            </div>
          )}

          {/* Bottom: team answer progress — Hot Potato has its own indicator below */}
          {!revealed && s.teams.length > 0 && !(q.category === 'BUNTE_TUETE' && q.bunteTuete?.kind === 'hotPotato') && (
            <div style={{
              display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 10,
              position: 'absolute', bottom: 16, left: 0, right: 0,
            }}>
              {/* Progress text — verschwindet wenn alle dran sind (Avatare mit ✓ zeigen's eh) */}
              {!s.allAnswered && (
                <div style={{
                  fontSize: 'clamp(14px, 1.5vw, 20px)', fontWeight: 900,
                  color: '#64748b',
                }}>
                  {`${s.answers.length}/${s.teams.length} Teams`}
                </div>
              )}
              {/* Avatar row */}
              {(() => {
                const tc = s.teams.length;
                const av = tc > 6 ? 68 : tc > 4 ? 76 : 84;
                const gap = tc > 6 ? 10 : tc > 4 ? 13 : 16;
                return (
                  <div style={{
                    display: 'flex', alignItems: 'center', justifyContent: 'center', gap,
                    maxWidth: '100%',
                  }}>
                    {s.teams.map(tm => {
                      const answered = s.answers.some(a => a.teamId === tm.id);
                      return (
                        <div key={tm.id} style={{
                          position: 'relative',
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                          flexShrink: 0,
                          transition: 'opacity 0.4s ease, filter 0.4s ease',
                          opacity: answered ? 1 : 0.4,
                          // 2026-05-04 (Wolf): Submit-Status durch gruenen Glow am Avatar
                          // statt Haekchen-Badge. Filter dropshadow + Avatar-Ring kombiniert.
                          filter: answered
                            ? 'drop-shadow(0 0 16px rgba(34,197,94,0.7)) drop-shadow(0 0 6px rgba(34,197,94,0.5))'
                            : 'grayscale(0.5)',
                        }}>
                          {/* Green-Ring via Wrapper-Div — Avatar.style.boxShadow
                              wuerde im Emoji-Mode durch internen flatStyle
                              ueberschrieben. */}
                          <div style={{
                            borderRadius: '50%',
                            boxShadow: answered ? '0 0 0 3px #22C55E' : 'none',
                            transition: 'box-shadow 0.45s ease',
                            display: 'inline-flex',
                          }}>
                            <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={av} />
                          </div>
                        </div>
                      );
                    })}
                  </div>
                );
              })()}
            </div>
          )}

          {/* ── HOT POTATO: active team + turn timer + used answers ── */}
          {q.category === 'BUNTE_TUETE' && q.bunteTuete?.kind === 'hotPotato' && (
            <HotPotatoBeamerView state={s} lang={lang} revealed={revealed} />
          )}
          </div>{/* /Inner-Content-Wrapper */}
        </div>
          );
        })()}

        {/* ── Image window panel (window-left / window-right — NOT CHEESE, which uses overlay) ── */}
        {isWindow && (
          <div style={{
            width: '35%', flexShrink: 0, position: 'relative', zIndex: 5,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            padding: 24,
          }}>
            {/* Ambient blur glow behind image */}
            <img
              src={img.bgRemovedUrl || img.url}
              alt="" aria-hidden
              style={{
                position: 'absolute', inset: 0,
                width: '100%', height: '100%',
                objectFit: 'contain',
                filter: 'blur(60px) saturate(1.8) brightness(0.5)',
                opacity: 0.5, pointerEvents: 'none',
                transform: 'scale(1.15)',
              }}
            />
            {/* Main image */}
            <img
              src={img.bgRemovedUrl || img.url}
              alt={isCheese ? (q.text || 'Question image') : 'Question image'}
              style={{
                position: 'relative', zIndex: 1,
                maxWidth: '100%', maxHeight: '80vh',
                borderRadius: img.bgRemovedUrl ? 0 : 22,
                objectFit: 'contain',
                boxShadow: img.bgRemovedUrl
                  ? 'none'
                  : `0 12px 48px rgba(0,0,0,0.6), 0 0 32px ${glow}`,
                filter: img.bgRemovedUrl
                  ? `drop-shadow(0 16px 40px rgba(0,0,0,0.7))${imgFilter(img) ? ' ' + imgFilter(img) : ''}`
                  : imgFilter(img),
                animation: imgAnim(img.animation, img.layout, img.animDelay, img.animDuration),
                transform: `translate(${img.offsetX ?? 0}%, ${img.offsetY ?? 0}%) scale(${img.scale ?? 1}) rotate(${img.rotation ?? 0}deg)`,
                opacity: img.opacity ?? 1,
              }}
            />
            {/* Dark vignette frame to blend white-bg images into dark theme */}
            {!img.bgRemovedUrl && (
              <div style={{
                position: 'absolute', inset: 0, zIndex: 2, pointerEvents: 'none',
                borderRadius: 24,
                background: 'radial-gradient(ellipse at center, transparent 55%, rgba(13,10,6,0.7) 100%)',
              }} />
            )}
          </div>
        )}

        {/* No right panel — everything centered in main area */}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// PLACEMENT VIEW
// ═══════════════════════════════════════════════════════════════════════════════

export function PlacementView({ state: s, flashCell, use3D = false, enable3DTransition = false }: {
  state: QQStateUpdate;
  flashCell?: { row: number; col: number; teamId: string; wasSteal?: boolean } | null;
  use3D?: boolean;
  enable3DTransition?: boolean;
}) {
  const lang = useLangFlip(s.language);

  // Sticky Placer: Nachdem ein Team gesetzt hat, bleibt der Highlight noch
  // ~1.2s auf diesem Team (sonst springt die Markierung schon zum naechsten
  // Team, waehrend die Zell-Fuell-Animation des vorherigen Teams noch laeuft).
  const [stickyPlacer, setStickyPlacer] = useState<string | null>(null);
  const prevPlacedKey = useRef<string | null>(null);
  useEffect(() => {
    const lp = s.lastPlacedCell;
    const key = lp ? `${lp.row}-${lp.col}-${lp.teamId}` : null;
    if (!key) return;
    if (key === prevPlacedKey.current) return;
    prevPlacedKey.current = key;
    setStickyPlacer(lp!.teamId);
    const t = setTimeout(() => setStickyPlacer(cur => (cur === lp!.teamId ? null : cur)), 1200);
    return () => clearTimeout(t);
  }, [s.lastPlacedCell?.row, s.lastPlacedCell?.col, s.lastPlacedCell?.teamId]);

  // Aufloesungsreihenfolge: Flash > Sticky Placer > pendingFor.
  // Comeback-Steal-Pause: pendingFor ist null, also Fallback auf comebackTeamId,
  // damit das aktive Team in der ScoreBar markiert bleibt waehrend wir auf
  // Moderator-Space warten.
  const isComebackStealActive =
    !!s.comebackHL && s.comebackHL.phase === 'steal' && !!s.comebackTeamId;
  const activeTeamId = flashCell?.teamId
    ?? stickyPlacer
    ?? s.pendingFor
    ?? (isComebackStealActive ? s.comebackTeamId : null);
  const team = s.teams.find(tm => tm.id === activeTeamId);
  const teamColor = team?.color ?? '#94a3b8';

  // 2026-04-30 v3 (User-Klaerung): playPlacementTurn entfernt — User meinte
  // mit 'platzieren page' die Action-Cards (PHASE_INTRO), nicht das Grid.
  // Per-Turn-Sound ueberlappte playFieldPlaced (Stamp) → Stamp wirkte weg.

  // ── 3D transition state machine ──
  // 'flat' = show 2D grid
  // 'transitioning' = 2D→3D camera animation in progress
  // '3d' = fully in 3D mode
  const [viewMode, setViewMode] = useState<'flat' | 'transitioning' | '3d'>(() => {
    // If use3D (instant toggle) is on, start in 3D directly
    if (use3D) return '3d';
    return 'flat';
  });
  const hasTransitioned = useRef(false);
  const transitionTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  // When the beamer instant toggle changes, update immediately
  useEffect(() => {
    if (use3D) {
      setViewMode('3d');
      hasTransitioned.current = true;
    } else {
      setViewMode('flat');
      hasTransitioned.current = false;
    }
  }, [use3D]);

  // Track lastPlacedCell changes — only trigger on NEW placements, not stale values from mount
  const cellTrigger = flashCell || s.lastPlacedCell;
  const cellKey = cellTrigger ? `${cellTrigger.row}-${cellTrigger.col}-${cellTrigger.teamId}` : null;
  const prevCellKey = useRef<string | null>(cellKey); // capture initial value to skip on mount

  useEffect(() => {
    // Skip if nothing changed (including initial mount with stale lastPlacedCell)
    if (cellKey === prevCellKey.current) return;
    prevCellKey.current = cellKey;

    if (!enable3DTransition || use3D || hasTransitioned.current || !cellTrigger) return;
    // First cell placed this round → start 2D→3D transition
    hasTransitioned.current = true;
    setViewMode('transitioning');
    // After transition animation completes (~1.2s), switch to full 3D
    transitionTimer.current = setTimeout(() => {
      setViewMode('3d');
    }, 1200);
    return () => { if (transitionTimer.current) clearTimeout(transitionTimer.current); };
  }, [cellKey, enable3DTransition, use3D]);

  // Reset transition state when entering a fresh placement round (questionIndex changes)
  const prevQIdx = useRef(s.questionIndex);
  useEffect(() => {
    if (prevQIdx.current !== s.questionIndex) {
      prevQIdx.current = s.questionIndex;
      hasTransitioned.current = false;
      if (!use3D) setViewMode('flat');
    }
  }, [s.questionIndex, use3D]);

  const show3D = viewMode === '3d' || viewMode === 'transitioning';
  // 2-spaltiges Layout: Grid links darf nicht zu groß werden, sonst bleibt rechts
  // kein Platz für die Team-Liste bei 8 Teams.
  // 2026-05-05 (Wolf 'grid und tabelle koennten groesser sein, viel rand'):
  // Cap 720→1100, vh 0.72→0.86, vw 0.48→0.55 — Beamer-Whitespace minimiert.
  const gridMaxSize = typeof window !== 'undefined'
    ? Math.min(1100, window.innerHeight * 0.86, window.innerWidth * 0.55)
    : 800;

  // Manual flyover hotkey (F): trigger a cinematic orbit over the grid
  const [flyoverSignal, setFlyoverSignal] = useState(0);
  useEffect(() => {
    if (viewMode !== '3d') return;
    const onKey = (e: KeyboardEvent) => {
      // 2026-05-05 (Live-Mod-Audit #7): nur wenn Beamer-Tab fokussiert.
      if (document.hidden || !document.hasFocus()) return;
      if (e.key === 'f' || e.key === 'F') {
        // Avoid triggering if user is typing in an input
        const tgt = e.target as HTMLElement | null;
        if (tgt && (tgt.tagName === 'INPUT' || tgt.tagName === 'TEXTAREA' || tgt.isContentEditable)) return;
        setFlyoverSignal(v => v + 1);
      }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [viewMode]);

  // G2 Entry-Sweep beim Mount einer neuen Question-Placement-Phase.
  // Ein heller Streifen laeuft einmalig von links nach rechts uebers Grid.
  // Key bindet an questionIndex, damit React beim Phase-Re-Mount die
  // Animation neu triggert.
  return (
    <div style={{ flex: 1, display: 'flex', flexDirection: 'column', position: 'relative', overflow: 'hidden' }}>
      <Fireflies color={`${teamColor}88`} />
      {s.theme?.eurovisionMode && <EurovisionHearts />}

      {/* G2 Placement-Sweep — weicher Licht-Streak nach Phase-Entry. */}
      <div key={`sweep-${s.questionIndex}`} aria-hidden style={{
        position: 'absolute', top: 12, left: 0, right: 0, bottom: 0,
        pointerEvents: 'none', zIndex: 4, overflow: 'hidden',
      }}>
        <div style={{
          position: 'absolute', top: 0, bottom: 0,
          width: '40%',
          background: 'linear-gradient(90deg, transparent 0%, rgba(255,255,255,0.18) 45%, rgba(255,255,255,0.28) 50%, rgba(255,255,255,0.18) 55%, transparent 100%)',
          animation: 'placementSweep 1.1s var(--qq-ease-smooth) 0.15s both',
        }} />
      </div>

      {/* Top banner — schrumpft auf 0 wenn Team aktiv. Das aktive Team wird
          stattdessen rechts in der ScoreBar prominent markiert (inkl. Aktions-Pill).
          Feste 12px Abstand bleibt damit das Grid nicht an den Viewport-Rand rutscht. */}
      <div style={{
        height: 12, flexShrink: 0,
        position: 'relative', zIndex: 5,
      }} />

      {/* Center: 2-spaltig — Grid links, ScoreBar rechts (Platz für 8 Teams ohne Scroll).
          Beide Spalten bekommen height = gridMaxSize (fix quadratisches Grid) damit
          die Team-Liste exakt so hoch ist wie das Grid — nicht länger.
          2026-05-05 (Wolf): padding + gap reduziert um Whitespace zu minimieren. */}
      <div style={{
        flex: 1, display: 'flex', flexDirection: 'row', alignItems: 'center', justifyContent: 'center',
        padding: '6px 16px', position: 'relative', zIndex: 5, gap: 20,
        minHeight: 0,
      }}>
        <div style={{
          width: gridMaxSize, height: gridMaxSize,
          display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0,
        }}>
          {show3D ? (
            <QQ3DGrid
              state={s}
              maxSize={gridMaxSize}
              animateCell={cellTrigger ? { row: cellTrigger.row, col: cellTrigger.col, teamId: cellTrigger.teamId, wasSteal: cellTrigger.wasSteal } : null}
              interactive={viewMode === '3d'}
              entering={viewMode === 'transitioning'}
              flyoverSignal={flyoverSignal}
            />
          ) : (
            <GridDisplay state={s} maxSize={gridMaxSize} highlightTeam={activeTeamId} showJoker={s.phase !== 'CONNECTIONS_4X4'} flashCellKey={flashCell ? `${flashCell.row}-${flashCell.col}` : null} />
          )}
        </div>
        <div style={{
          // Fixe Breite statt flex:1 + maxWidth — sonst verschiebt sich der Grid-
          // Container, sobald ein Team-Name die intrinsische Spaltenbreite ändert.
          // Höhe = gridMaxSize sorgt dafür dass die Liste exakt Grid-Höhe hat.
          // 2026-05-05 (Wolf): Breite 540→620 damit Liste mehr Atemraum hat.
          width: 620, height: gridMaxSize, flexShrink: 0,
          display: 'flex', alignItems: 'stretch', justifyContent: 'flex-start',
        }}>
          {/* 2026-05-05 (Wolf): activeActionLabel/Desc NICHT mehr gesetzt —
              das Action-Verb ('Setzen/Klauen/Stapeln') war aus 8m Beamer-
              Distanz unlesbar. Der Active-Team-Glow + Border in der ScoreBar
              sagt schon „dieses Team ist dran"; das exakte Verb sieht das
              Team auf seinem /team-Phone. */}
          <ScoreBar
            teams={s.teams}
            activeTeamId={activeTeamId}
            teamPhaseStats={s.teamPhaseStats}
            correctTeamId={s.correctTeamId}
            eurovisionMode={!!s.theme?.eurovisionMode}
          />
        </div>
      </div>

    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// SlotMachineNumber — Slot-Machine-Roll-Animation für H/L-Reveal.
// Pro Digit rollt ein Roller mit Random-Ziffern (~70ms/frame). Stoppt
// staggered von links nach rechts auf der Zielziffer mit kurzem Bounce-Pulse.
// Trennzeichen (.,/) bleiben statisch. Total ~1.4-1.8s je nach Stellenzahl.
// ═══════════════════════════════════════════════════════════════════════════════
function SlotMachineNumber({ value, fontSize, color, glow, isYear }: {
  value: number;
  fontSize: string;
  color: string;
  glow?: string;
  isYear?: boolean;
}) {
  // Jahreszahlen ohne Tausendertrennzeichen (z.B. „1900"), sonst „1.500.000".
  const targetStr = isYear ? String(Math.round(value)) : value.toLocaleString('de-DE');
  const chars = useMemo(() => targetStr.split(''), [targetStr]);
  const digitPositions = useMemo(() => chars.map((c, i) => /\d/.test(c) ? i : -1).filter(i => i >= 0), [chars]);

  // Globale Tick-Counter für die Roller — alle Digits rollen synchron, aber
  // jeder Digit "stoppt" nacheinander bei einem bestimmten Tick-Threshold.
  const [tick, setTick] = useState(0);
  // Wieviele Digits sind schon "gelandet" (von links).
  const [landed, setLanded] = useState(0);
  const totalDigits = digitPositions.length;

  useEffect(() => {
    // Roller-Frequenz: 70ms pro Tick → flackernde Random-Ziffer
    const rollId = setInterval(() => setTick(t => t + 1), 70);
    return () => clearInterval(rollId);
  }, []);

  useEffect(() => {
    // Staggered Stop: erster Digit landet nach 800ms, dann jeder weitere nach +280ms.
    const timeouts: ReturnType<typeof setTimeout>[] = [];
    for (let i = 0; i < totalDigits; i++) {
      timeouts.push(setTimeout(() => setLanded(i + 1), 800 + i * 280));
    }
    return () => { timeouts.forEach(clearTimeout); };
  }, [totalDigits]);

  return (
    <span style={{
      display: 'inline-flex', alignItems: 'baseline', gap: 0,
      fontVariantNumeric: 'tabular-nums', lineHeight: 1,
    }}>
      {chars.map((char, idx) => {
        const isDigit = /\d/.test(char);
        if (!isDigit) {
          // Trennzeichen statisch
          return (
            <span key={idx} style={{
              fontSize, fontWeight: 900, color, textShadow: glow ? `0 0 28px ${glow}` : undefined,
            }}>{char}</span>
          );
        }
        const digitOrderIdx = digitPositions.indexOf(idx);
        const stopped = digitOrderIdx < landed;
        const display = stopped ? char : String((tick + idx * 7) % 10);
        return (
          <span
            key={`${idx}-${stopped ? 'l' : 'r'}`}
            style={{
              fontSize, fontWeight: 900, color, textShadow: glow ? `0 0 28px ${glow}` : undefined,
              display: 'inline-block',
              animation: stopped ? 'slotMachineStop 0.36s var(--qq-ease-bounce) both' : undefined,
            }}
          >{display}</span>
        );
      })}
      <style>{`
        @keyframes slotMachineStop {
          0%   { transform: translateY(-30%) scale(0.85); opacity: 0.4; filter: blur(2px); }
          55%  { transform: translateY(6%)  scale(1.18); opacity: 1;   filter: blur(0); }
          100% { transform: translateY(0)   scale(1);    opacity: 1;   filter: blur(0); }
        }
      `}</style>
    </span>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// COMEBACK VIEW
// ═══════════════════════════════════════════════════════════════════════════════

export function ComebackView({ state: s }: { state: QQStateUpdate }) {
  const lang = useLangFlip(s.language);
  const cardBg = s.theme?.cardBg ?? COZY_CARD_BG;
  const hl = s.comebackHL;
  // H/L: alle tied-letzten Teams. Ohne H/L: Fallback auf altes 1-Team-Verhalten.
  const hlTeams = hl ? hl.teamIds.map(id => s.teams.find(tm => tm.id === id)).filter(Boolean) as typeof s.teams : [];
  const team = s.teams.find(tm => tm.id === s.comebackTeamId);
  const teamColor = team?.color ?? '#EC4899';
  const step = s.comebackIntroStep ?? 0;
  const targets = s.comebackStealTargets ?? [];
  const leaderTeams = targets.map(id => s.teams.find(tm => tm.id === id)).filter(Boolean) as typeof s.teams;
  const showTeam = step >= 1;
  // 2026-05-06 v2 (Wolf 'so funktionierts unter COMEBACK schreiben, dann
  // nur noch Teams+Leader-Seite — separate H/L-Erklaer-Seite weg'):
  // - Step 0: COMEBACK-Title + H/L-Erklaerung direkt darunter
  // - Step 1: Team-Hero + 'Klauen bei: [Leader]'
  // (kein Step 2 mehr — Backend maxStep 1)
  const showAction = step >= 1;

  // Action-Text nur noch fuer Legacy-Comeback (kein H/L). H/L-Spiele zeigen
  // im Step 1 keinen Text in der Action-Card — nur 'Klauen bei [Leader]'.
  const actionTextDe = hl
    ? null
    : (leaderTeams.length === 1
        ? `Klaut 2 Felder von ${leaderTeams[0]?.name ?? 'dem Führenden'}.`
        : `Klaut je 1 Feld von jedem der ${leaderTeams.length} Führenden.`);
  const actionTextEn = hl
    ? null
    : (leaderTeams.length === 1
        ? `Steals 2 cells from ${leaderTeams[0]?.name ?? 'the leader'}.`
        : `Steals 1 cell from each of the ${leaderTeams.length} leaders.`);

  // Nummer kompakt formatieren: 3800000 → 3,8M | 15000 → 15k | 300 → 300
  // Bei Jahreszahlen kein Tausendertrennzeichen (1900 statt 1.900).
  // Auto-Detection ergänzt: Werte 1000-2100 als Integer = Jahreszahl.
  const looksLikeYearHL = (n: number) => Number.isInteger(n) && n >= 1000 && n <= 2100;
  const isYearUnitHL = /jahr|year/i.test(hl?.currentPair?.unit ?? '') ||
    (hl?.currentPair?.subjectValue != null && looksLikeYearHL(hl.currentPair.subjectValue)) ||
    (hl?.currentPair?.anchorValue != null && looksLikeYearHL(hl.currentPair.anchorValue));
  const fmtHL = (n: number) => {
    if (isYearUnitHL) return String(Math.round(n));
    const abs = Math.abs(n);
    // 2026-05-10 (Wolf 'EN-Mode zeigt DE-Suffix'): Mrd./Mio. nur bei DE,
    // bn/M bei EN. Plus thousands-Separator schon lang-bedingt.
    const isEn = lang === 'en';
    if (abs >= 1_000_000_000) return (n / 1_000_000_000).toFixed(1).replace(/\.0$/, '') + (isEn ? ' bn' : ' Mrd.');
    if (abs >= 1_000_000) return (n / 1_000_000).toFixed(1).replace(/\.0$/, '') + (isEn ? ' M' : ' Mio.');
    if (abs >= 10_000) return Math.round(n / 1000) + 'k';
    if (abs >= 1000) return n.toLocaleString(isEn ? 'en-US' : 'de-DE');
    return n % 1 === 0 ? String(n) : n.toFixed(1);
  };

  // ── H/L UNIFIED Frage- und Reveal-Ansicht ──────────────────────────────
  // Question und Reveal teilen sich exakt dieselbe Composition. Beim Wechsel
  // wird KEINE neue Folie eingeblendet — nur die Subject-Wert-Stelle (??? →
  // Slot-Machine-Roll), der Direction-Indikator (? → MEHR ↑ / WENIGER ↓) und
  // die Avatar-Status-Layer (Tipp-Status → richtig/falsch + Winnings) wechseln
  // smooth in-place.
  if (hl && (hl.phase === 'question' || hl.phase === 'reveal') && hl.currentPair) {
    const pair = hl.currentPair;
    const isReveal = hl.phase === 'reveal';
    const correctChoice = pair.subjectValue > pair.anchorValue ? 'higher' : 'lower';
    const correctIds = new Set(hl.correctThisRound);
    // Frage-Text: bei Format-B customQuestion direkt, bei Format-A auto-generieren
    // („Hat München mehr oder weniger Einwohner als Berlin?"). Macht den Quiz-Show-
    // Moment deutlich starker als nur zwei Cards mit Zahlen.
    // 2026-05-10 (Wolf-Bug 'EN-Spiel zeigt DE-Frage'): Fallback auf *En-Felder
    // wenn lang='en'. Falls *En fehlt → DE-Wert (Backward-Compat zu alten
    // Einträgen ohne EN-Übersetzung).
    const isEn = lang === 'en';
    const pAnchor = isEn ? (pair.anchorLabelEn ?? pair.anchorLabel) : pair.anchorLabel;
    const pSubject = isEn ? (pair.subjectLabelEn ?? pair.subjectLabel) : pair.subjectLabel;
    const pUnit = isEn ? (pair.unitEn ?? pair.unit) : pair.unit;
    const pCustom = isEn ? (pair.customQuestionEn ?? pair.customQuestion) : pair.customQuestion;
    const questionText = pCustom
      ? pCustom
      : (isEn
          ? `Does ${pSubject} have more or less ${pUnit} than ${pAnchor}?`
          : `Hat ${pSubject} mehr oder weniger ${pUnit} als ${pAnchor}?`);
    return (
      <div style={{
        flex: 1, display: 'flex', flexDirection: 'column',
        alignItems: 'center', justifyContent: 'center',
        padding: 'clamp(16px, 2.4vh, 36px) clamp(28px, 3.5vw, 56px)',
        gap: 'clamp(14px, 2vh, 28px)',
        position: 'relative', overflow: 'hidden',
        minHeight: 0,
      }}>
        <Fireflies color="#EC489955" />
        {/* Header: Mehr-oder-Weniger-Pille (Question-Mode).
            2026-05-06 (Konsistenz-Audit S2#4): Auflösung-Variante entfernt —
            keine andere Standard-Kategorie zeigt eine Reveal-Pille. Avatar-
            Position an gold-pulsender MEHR/WENIGER-Pille zeigt das Ergebnis.
            Question-Mode-Pille bleibt als Mechanik-Indikator. */}
        {!isReveal && (
          <div style={{
            position: 'absolute', top: 'clamp(20px, 3vh, 40px)', left: 0, right: 0,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            zIndex: 6,
            animation: 'contentReveal 0.35s var(--qq-ease-pop-fast) both',
          }}>
            <div style={{
              padding: 'clamp(8px, 1vh, 12px) clamp(20px, 2.2vw, 32px)', borderRadius: 999,
              background: 'rgba(236,72,153,0.16)',
              border: '2px solid rgba(236,72,153,0.5)',
              color: '#FBCFE8',
              fontWeight: 900,
              fontSize: 'clamp(14px, 1.4vw, 20px)', letterSpacing: '0.1em', textTransform: 'uppercase',
            }}>
              <QQEmojiIcon emoji="⚡"/> {lang === 'en' ? 'More or Less' : 'Mehr oder Weniger'}
            </div>
          </div>
        )}

        {/* Frage-Text — Hero-Look analog Standard-Quiz-Frage (cozyQuestionHero).
            Groesser, mit Border + Shadow, damit die H/L-Folie nicht mehr wie
            ein Fremdkoerper im Quiz wirkt sondern als „besondere Variante".
            Inner-key auf hl.round → smoother Cross-Fade nur des Texts beim
            Rundenwechsel, Card selbst bleibt stabil. */}
        <div style={{
          maxWidth: 1400, width: '94%',
          padding: 'clamp(18px, 2.6vh, 36px) clamp(28px, 3.5vw, 56px)',
          borderRadius: 24,
          background: 'linear-gradient(180deg, rgba(15,23,42,0.78), rgba(11,16,28,0.72))',
          border: '2px solid rgba(236,72,153,0.32)',
          boxShadow: '0 4px 0 rgba(236,72,153,0.18), 0 12px 36px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.05)',
          minHeight: 'clamp(96px, 12vh, 168px)',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          animation: 'contentReveal 0.45s var(--qq-ease-pop-fast) 0.08s both',
        }}>
          <div
            key={`hlq-${hl.round}`}
            style={{
              fontSize: 'clamp(32px, 4.5vw, 72px)', fontWeight: 900, color: '#F8FAFC',
              textAlign: 'center', lineHeight: 1.18,
              textShadow: '0 2px 18px rgba(0,0,0,0.4)',
              animation: 'qqHlQuestionFade 0.6s ease both',
            }}
          >
            {questionText}
          </div>
        </div>

        {/* Anchor + Subject - zwei Karten nebeneinander */}
        <div style={{
          // 2026-05-05 v3: alignItems center (war stretch) — sonst zwingt der
          // groessere VS-Area minHeight die Anchor/Subject-Cards auf seine
          // Hoehe und sie wirken aufgeblaeht.
          display: 'flex', gap: 'clamp(16px, 2.2vw, 36px)', alignItems: 'center',
          justifyContent: 'center', flexWrap: 'wrap', maxWidth: 1400, width: '100%',
          animation: 'contentReveal 0.45s var(--qq-ease-pop-fast) 0.15s both',
        }}>
          {/* Anchor-Card: bekannter Wert.
              2026-05-05 v2 (Wolf 'avatar verdeckt pille immer noch — cards
              hoeher, mehr/weniger tiefer'): padding-vertical 44-72 → 60-100,
              minHeight 220-320 → 280-400. */}
          <div style={{
            flex: '1 1 0', maxWidth: 560, minWidth: 260,
            padding: 'clamp(60px, 7vh, 100px) clamp(22px, 3vw, 40px)', borderRadius: 24,
            minHeight: 'clamp(280px, 34vh, 400px)',
            background: 'linear-gradient(135deg, rgba(34,197,94,0.14), rgba(34,197,94,0.04))',
            border: '2px solid rgba(34,197,94,0.42)',
            boxShadow: '0 0 40px rgba(34,197,94,0.18), 0 8px 28px rgba(0,0,0,0.4)',
            textAlign: 'center',
            display: 'flex', flexDirection: 'column', gap: 14, justifyContent: 'center',
          }}>
            <div style={{
              fontSize: 'clamp(14px, 1.6vw, 22px)', fontWeight: 900,
              color: '#86efac', letterSpacing: '0.1em', textTransform: 'uppercase',
              opacity: 0.8,
            }}>{pAnchor}</div>
            <div style={{
              fontSize: 'clamp(44px, 6vw, 92px)', fontWeight: 900, color: '#86efac',
              fontVariantNumeric: 'tabular-nums', lineHeight: 1,
              textShadow: '0 0 28px rgba(34,197,94,0.35)',
            }}>{fmtHL(pair.anchorValue)}</div>
            <div style={{
              fontSize: 'clamp(14px, 1.4vw, 20px)', fontWeight: 700, color: '#cbd5e1', opacity: 0.7,
            }}>{pUnit}</div>
          </div>

          {/* VS-Badge — der Hero zwischen den beiden Cards. Question: grosse
              VS-Pille mit Marken-Gold-Glow + sanftem Pulse. Reveal: Cross-Fade
              auf MEHR ↑ / WENIGER ↓. Width FIX 380px (wegen langem „WENIGER ↓"
              + letterSpacing) — User-Bug 2026-04-30 v3 r5.
              2026-05-04 v4 (Wolf-Bug 'VS nicht mittig'): alignSelf:center +
              fixierte Hoehe-Buchung damit der Container auf Card-Mitte sitzt
              (vorher fiel er bei alignItems:stretch + explicit height auf
              Top-aligned zurueck). minHeight matcht Card-Hoehe damit Card-
              Hoehe + VS-Hoehe gleich sind und visuell zentriert wirken. */}
          <div style={{
            display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
            // FIXED width — keine flex-Expansion + breit genug fuer „WENIGER ↓".
            width: 'clamp(260px, 22vw, 380px)',
            flexShrink: 0,
            alignSelf: 'center',
            position: 'relative',
            // 2026-05-05 v3: minHeight erhoeht damit Pillen-Stack mit groesserem
            // gap reinpasst und Avatare oberhalb/unterhalb landen koennen.
            // v5 (Wolf 'cards hoeher, avatar Platz'): minHeight matched auf
            // neue Card-Hoehe (280-400 statt 220-320).
            minHeight: 'clamp(280px, 34vh, 400px)',
          }}>
            {/* 2026-05-05 (Wolf): App-Pillen statt Goldkreise — MEHR oben (grün-
                Akzent), WENIGER unten (rot-Akzent). Same Pille-Style wie
                Kategorie-Badges. Bei Reveal: korrekte Pille pulst gold + scaled
                up, falsche fadet — Avatare landen direkt an der gewählten Pille
                und feiern dort. Direction-Big-Text-Indikator entfaellt
                (Pille-Label zeigt's schon). */}
            <div style={{
              position: 'absolute', inset: 0,
              // 2026-05-06 (Wolf 'higher und lower wieder zentriert mit Cards
              // horizontal angeordnet'): Pillen-Stack vertikal MITTIG (was
              // flex-end). Avatare landen oben/unten an der Pille leicht
              // ueberlappend — siehe flyTransform unten.
              display: 'flex', flexDirection: 'column', alignItems: 'center',
              justifyContent: 'center',
              gap: 'clamp(50px, 6.5vh, 90px)',
              pointerEvents: 'none',
            }}>
              {(['higher', 'lower'] as const).map((dir, idx) => {
                const isHigher = dir === 'higher';
                // Higher = Brand-Grün, Lower = Brand-Pink (Default-Farben).
                const accentCol = isHigher ? '#22C55E' : '#EC4899';
                // 2026-05-10 (Wolf 'comeback weniger/mehr — eines grün wenn richtig,
                // eines pink wenn richtig, jeweils in der Anfangs-Textfarbe'):
                // Vorher waren beide bei isCorrect universal grün. Jetzt behält
                // jede Pille ihre Anfangs-Farbe — Higher leuchtet grün, Lower
                // leuchtet pink wenn richtig. Light-Variante für Text-Lesbarkeit.
                const correctTextLight = isHigher ? '#86EFAC' : '#F9A8D4';
                const isCorrect = isReveal && correctChoice === dir;
                const isWrong = isReveal && correctChoice !== dir;
                return (
                  <div key={dir} style={{
                    display: 'inline-flex', alignItems: 'center', gap: 12,
                    padding: 'clamp(10px, 1.4vh, 16px) clamp(20px, 2.4vw, 32px)',
                    borderRadius: 999,
                    background: isCorrect
                      ? `${accentCol}33`
                      : `${accentCol}14`,
                    border: `2.5px solid ${isCorrect ? accentCol : `${accentCol}66`}`,
                    boxShadow: isCorrect
                      ? `0 0 44px ${accentCol}aa, 0 0 14px ${accentCol}88, inset 0 1px 0 rgba(255,255,255,0.10)`
                      : `0 0 22px ${accentCol}33, inset 0 1px 0 rgba(255,255,255,0.05)`,
                    backdropFilter: 'blur(10px)',
                    WebkitBackdropFilter: 'blur(10px)',
                    transform: isCorrect ? 'scale(1.08)' : isWrong ? 'scale(0.94)' : 'scale(1)',
                    opacity: isWrong ? 0.4 : 1,
                    transition: 'transform 0.5s var(--qq-ease-out-cubic), background 0.45s ease, border-color 0.45s ease, box-shadow 0.45s ease, opacity 0.45s ease',
                    animation: !isReveal
                      ? `qqVsPulse 2.4s ease-in-out ${idx * 0.3}s infinite`
                      : (isCorrect ? 'celebShake 0.6s ease 0.45s both' : undefined),
                    whiteSpace: 'nowrap',
                  }}>
                    <span style={{
                      fontSize: 'clamp(24px, 2.8vw, 38px)', lineHeight: 1, fontWeight: 900,
                      color: accentCol,
                      transition: 'color 0.4s ease',
                    }}>{isHigher ? '↑' : '↓'}</span>
                    <span style={{
                      fontSize: 'clamp(18px, 2.2vw, 30px)', fontWeight: 900,
                      color: isCorrect ? correctTextLight : accentCol,
                      letterSpacing: '0.12em', textTransform: 'uppercase',
                      transition: 'color 0.4s ease',
                    }}>
                      {isHigher
                        ? (lang === 'en' ? 'Higher' : 'Mehr')
                        : (lang === 'en' ? 'Lower' : 'Weniger')}
                    </span>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Subject-Card: 100 % statisches Layout — Border, Background,
              Glow ALLES KONSTANT zwischen Question und Reveal. Nur die
              ??? → Zahl-Stelle innen wechselt via Cross-Fade. User-Wunsch
              2026-04-28: 'Cards sollen sich nicht verändern, richte gleich
              so aus dass es passt'. */}
          {/* Subject-Card — siehe Anchor-Card oben (gleicher Wolf-Wunsch). */}
          <div style={{
            flex: '1 1 0', maxWidth: 560, minWidth: 260,
            padding: 'clamp(60px, 7vh, 100px) clamp(22px, 3vw, 40px)', borderRadius: 24,
            minHeight: 'clamp(280px, 34vh, 400px)',
            background: 'linear-gradient(135deg, rgba(236,72,153,0.18), rgba(236,72,153,0.05))',
            border: '3px solid rgba(236,72,153,0.7)',
            boxShadow: '0 0 44px rgba(236,72,153,0.28), 0 8px 28px rgba(0,0,0,0.4)',
            textAlign: 'center',
            display: 'flex', flexDirection: 'column', gap: 14, justifyContent: 'center',
          }}>
            <div style={{
              fontSize: 'clamp(14px, 1.6vw, 22px)', fontWeight: 900,
              color: '#FBCFE8', letterSpacing: '0.1em', textTransform: 'uppercase',
              opacity: 0.9,
            }}>{pSubject}</div>
            <div style={{
              lineHeight: 1, height: 'clamp(44px, 6vw, 92px)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              position: 'relative',
              // 2026-05-08 (Wolf-Wunsch zurück): perspective ermöglicht den
              // 3D-Slot-Machine-Drop in Y-Achse. Container-Höhe + Width sind
              // via Hidden-Placeholder schon FIX → keine Card-Größen-Sprünge
              // mehr (das war der historische Grund warum Slot-Machine raus war).
              perspective: 600,
            }}>
              {/* Unsichtbarer Platzhalter mit dem ECHTEN Wert reserviert die
                  Breite schon in der Frage-Phase. Sonst springt die Card beim
                  Reveal von „???" (~3em) auf z.B. „1.500.000" (~12em) →
                  ganzes Grid reflowt → wirkt wie eine neue Folie. */}
              <span aria-hidden style={{
                fontSize: 'clamp(44px, 6vw, 92px)', fontWeight: 900,
                fontVariantNumeric: 'tabular-nums', lineHeight: 1,
                visibility: 'hidden', whiteSpace: 'nowrap',
              }}>{fmtHL(pair.subjectValue)}</span>
              <div style={{
                position: 'absolute', inset: 0,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                overflow: 'hidden',
              }}>
                {/* 2026-05-08 (Wolf-Wunsch 3D-Slot-Machine-Drop wieder rein,
                    aber mit fixer Card-Größe): Beide Spans absolute, beim Reveal
                    rotiert „???" 3D nach oben raus, echte Zahl rotiert von unten
                    rein. Pattern aus /animations Slot-4 (slotOut/slotIn keyframes).
                    Card-Container hat perspective:600 + overflow:hidden, beide
                    Spans sind absolut → Card-Layout bleibt 100 % stabil. */}
                <span style={{
                  position: 'absolute',
                  fontSize: 'clamp(44px, 6vw, 92px)', fontWeight: 900, color: '#EC4899',
                  fontVariantNumeric: 'tabular-nums', lineHeight: 1,
                  textShadow: '0 0 28px rgba(236,72,153,0.45), 0 0 60px rgba(236,72,153,0.25)',
                  animation: isReveal
                    ? 'hlSlotOut 0.4s cubic-bezier(0.4, 0, 0.6, 1) both'
                    : 'hlQuestionMarkPulse 1.6s ease-in-out infinite',
                  willChange: 'transform, opacity',
                }}>???</span>
                <span style={{
                  position: 'absolute',
                  fontSize: 'clamp(44px, 6vw, 92px)', fontWeight: 900, color: '#EC4899',
                  fontVariantNumeric: 'tabular-nums', lineHeight: 1,
                  textShadow: '0 0 32px rgba(236,72,153,0.55)',
                  animation: isReveal
                    ? 'hlSlotIn 0.55s cubic-bezier(0.34, 1.56, 0.64, 1) 0.28s both'
                    : undefined,
                  opacity: isReveal ? undefined : 0,
                  whiteSpace: 'nowrap',
                  willChange: 'transform, opacity',
                }}>{fmtHL(pair.subjectValue)}</span>
              </div>
            </div>
            <div style={{
              fontSize: 'clamp(14px, 1.4vw, 20px)', fontWeight: 700, color: '#cbd5e1', opacity: 0.7,
            }}>{pUnit}</div>
          </div>
        </div>

        {/* Team-Progress: gleiche Avatare-Reihe in beiden Phasen.
            Nur das Status-Badge (✓ answered → ✓ correct / ✕ wrong) und
            die optionale Winnings-Pill ergaenzen sich beim Reveal. */}
        <div style={{
          display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 12,
          animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.25s both',
        }}>
          {/* 2026-05-06 (Wolf 'who got it right weg, in den meisten Faellen
              spielt nur 1 Team'): Header-Label entfernt. Avatar-Position +
              Pillen-Glow zeigen das Ergebnis schon — der Text war redundant. */}
          {/* 2026-05-05 v3 (Wolf-Bug 'avatar overlappt pillen extrem'): Avatar
              schrumpft beim Flug auf scale(0.55) (visual ~40-60px) + landet
              IM Pillen-Gap dicht an seiner Pille — nicht darauf. 'higher'
              parkt direkt UNTER MEHR-Pille (oberer Gap-Bereich), 'lower'
              parkt direkt ÜBER WENIGER-Pille (unterer Gap-Bereich). Pillen
              bleiben sichtbar + Label lesbar. Stack-Pile mit kleinem 14px-
              Spread für mehrere Avatare auf gleicher Pille. */}
          <div style={{ display: 'flex', gap: 'clamp(14px, 1.8vw, 24px)', flexWrap: 'wrap', justifyContent: 'center' }}>
            {hlTeams.map(tm => {
              const choice = hl.answers[tm.id];  // 'higher' | 'lower' | undefined
              const answered = !!choice || hl.answeredThisRound.includes(tm.id);
              const correct = correctIds.has(tm.id);
              const teamWin = hl.winnings[tm.id] ?? 0;
              // Im Reveal: dim if wrong; Glow if correct.
              const dim = isReveal && !correct;
              const sameChoiceTeams = choice
                ? hlTeams.filter(t => hl.answers[t.id] === choice)
                : [];
              const stackIdx = choice ? sameChoiceTeams.findIndex(t => t.id === tm.id) : 0;
              const groupSize = sameChoiceTeams.length;
              const xCenter = groupSize > 0 ? (stackIdx - (groupSize - 1) / 2) * 14 : 0;
              // Y-Werte zielen mit visual-center auf den Gap-Slot direkt
              // angrenzend an die jeweilige Pille (nicht IN die Pille).
              // Plus scale(0.55) macht den Avatar klein genug damit Pillen-
              // Label lesbar bleibt.
              // 2026-05-06 v2 (Wolf-Screenshot 'Avatar verdeckt WENIGER-Text'):
              // Y-Translates groesser — Avatar muss DEUTLICH ueber/unter der
              // Pille sitzen, nur leichter Overlap an der Pillen-AUSSENKANTE
              // (nicht auf dem Text). Higher: noch hoeher; Lower: noch tiefer
              // (weniger negativ = naeher am Avatar-Start unter dem VS-Container).
              // 2026-05-10 (Spacing-Audit P0): Higher-Translate von -510/-38vh/-360
              // auf -390/-30vh/-300 reduziert. Vorher konnten 3-4 gestapelte Teams
              // bis IN die Frage-Card oder ganz oben aus dem 1080p-Viewport fliegen.
              // Endposition liegt jetzt deutlich UNTER der Frage-Card; Flug-Look
              // bleibt ähnlich, nur ohne Top-Edge-Overshoot.
              const flyTransform = choice === 'higher'
                ? `translate(${xCenter}px, clamp(-390px, -30vh, -300px)) scale(0.7)`
                : choice === 'lower'
                  ? `translate(${xCenter}px, clamp(-110px, -8vh, -60px)) scale(0.7)`
                  : 'translate(0, 0) scale(1)';
              return (
                <div key={tm.id} style={{
                  position: 'relative',
                  display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6,
                  opacity: dim ? 0.45 : (answered || isReveal ? 1 : 0.55),
                  filter: dim
                    ? 'grayscale(0.6)'
                    : correct
                      ? `drop-shadow(0 0 22px rgba(34,197,94,0.85)) drop-shadow(0 0 8px rgba(34,197,94,0.55))`
                      : (answered || isReveal ? `drop-shadow(0 0 14px ${tm.color}88)` : 'grayscale(0.4)'),
                  transform: flyTransform,
                  transition: 'opacity 0.4s ease, filter 0.4s ease, transform 0.65s var(--qq-ease-bounce)',
                  zIndex: stackIdx + 1,
                }}>
                  <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(70px, 7.5vw, 110px)'} style={{
                    // 2026-05-05 (Wolf 'in der ganzen App konsistent gruener Glow
                    // fuer Submit-Status'): in Question-Phase answered=true →
                    // gruener Ring + Glow. Reveal-Phase: Team-Color-Glow bleibt
                    // (Ring kommt vom unten Status-Badge ✓/✕).
                    boxShadow: !isReveal && answered
                      ? `0 0 0 3px #22C55E, 0 0 22px rgba(34,197,94,0.55)`
                      : (correct || (answered && !isReveal))
                        ? `0 0 22px ${tm.color}88`
                        : '0 0 14px rgba(148,163,184,0.18)',
                    transition: 'box-shadow 0.4s ease',
                  }} />
                  {/* 2026-05-06 (Wolf 'rotes X weg weil aufgeloest wird, +1 cell
                      weg, who got it right weg'): ✓/✕ Status-Badge UND
                      Winnings-Pille entfernt. Avatar-Position (an gold-pulsender
                      MEHR/WENIGER-Pille) zeigt das Ergebnis bereits visuell —
                      die zusaetzlichen Labels waren redundant. */}
                </div>
              );
            })}
          </div>
        </div>

        {/* Timer-Pill unten rechts — nur in question phase */}
        {!isReveal && hl.timerEndsAt != null && (
          <div style={{
            position: 'absolute', bottom: 32, right: 48, zIndex: 8,
          }}>
            <BeamerTimer endsAt={hl.timerEndsAt} durationSec={s.comebackHLTimerSec ?? 10} accent="#EC4899" />
          </div>
        )}
      </div>
    );
  }

  // ── (alter separater Reveal-Block entfernt — jetzt unified mit question) ─

  // B1 BAM-Entry: nur beim initialen Mount + beim Step 0 spielen. Bei spaeteren
  // Steps (1, 2) soll die Folie ruhig bleiben, sonst reissen wir den User raus.
  const bamActive = step === 0;

  return (
    <div style={{
      flex: 1, display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center',
      position: 'relative', overflow: 'hidden',
      padding: 'clamp(20px, 2.6vh, 40px) clamp(32px, 4vw, 64px)',
      gap: 'clamp(12px, 1.8vh, 22px)',
      minHeight: 0,
      animation: bamActive ? 'comebackShake 0.65s ease 0.1s both' : undefined,
    }}>
      <Fireflies color={`${teamColor}55`} />

      {/* B1 Screen-Flash: weisser Puls ueber dem ganzen Screen (0.6s). */}
      {bamActive && (
        <div aria-hidden style={{
          position: 'absolute', inset: 0,
          background: 'radial-gradient(ellipse at center, rgba(255,247,220,0.95) 0%, rgba(236,72,153,0.55) 45%, transparent 80%)',
          animation: 'comebackFlash 0.6s ease-out both',
          pointerEvents: 'none', zIndex: 20,
        }} />
      )}

      {/* B1 Lightning-Bolts: 6 gelbe Streifen fallen schraeg durchs Bild. */}
      {bamActive && [
        { left: '8%',  rot: -12, size: 64, delay: 0.05 },
        { left: '22%', rot: 8,   size: 44, delay: 0.22 },
        { left: '38%', rot: -6,  size: 52, delay: 0.14 },
        { left: '58%', rot: 10,  size: 48, delay: 0.30 },
        { left: '74%', rot: -14, size: 60, delay: 0.18 },
        { left: '88%', rot: 4,   size: 40, delay: 0.38 },
      ].map((b, i) => (
        <div key={i} aria-hidden style={{
          position: 'absolute', left: b.left, top: 0,
          fontSize: b.size, lineHeight: 1,
          color: '#FDE047',
          filter: `drop-shadow(0 0 14px rgba(253,224,71,0.9)) drop-shadow(0 0 28px rgba(236,72,153,0.6))`,
          ['--bolt-rot' as string]: `${b.rot}deg`,
          animation: `comebackBoltFall 1.1s var(--qq-ease-smooth-out) ${b.delay}s both`,
          pointerEvents: 'none', zIndex: 6,
        }}><QQEmojiIcon emoji="⚡"/></div>
      ))}

      {/* 2026-05-04 v4 (Wolf-Bug 'Comeback-Text symmetrisch'): Vorher nur 1 Blitz
          links, jetzt beidseitig — Title-Block wirkt mittig ausbalanciert. Inline-
          Flex statt Text-Concatenation damit Blitze als feste Grafik-Anker
          zentriert mit dem Wort sitzen, nicht als variable Buchstaben. */}
      <div style={{
        // 2026-05-07 (Wolf 'comeback ansicht ist zu klein, viel platz aussen
        // rum'): post-bam Title von clamp(28-50) auf clamp(56-104) bumpen —
        // aus 8m Beamer-Distanz gut lesbar, statt mickrig in der Mitte.
        fontSize: bamActive ? 'clamp(68px, 9vw, 128px)' : 'clamp(56px, 6.5vw, 104px)',
        fontWeight: 900,
        color: '#EC4899', textAlign: 'center',
        textShadow: '0 0 50px rgba(234,179,8,0.55)',
        letterSpacing: bamActive ? '0.04em' : 'normal',
        animation: bamActive
          ? 'comebackSlam 1s var(--qq-ease-bounce) both'
          : 'roundBam 0.6s var(--qq-ease-out-cubic) both',
        transition: 'font-size 0.5s var(--qq-ease-bounce)',
        position: 'relative', zIndex: 7,
        display: 'inline-flex', alignItems: 'center', gap: '0.4em',
        alignSelf: 'center',
      }}>
        <QQEmojiIcon emoji="⚡"/>
        <span>{lang === 'en' ? 'COMEBACK!' : 'COMEBACK!'}</span>
        <QQEmojiIcon emoji="⚡"/>
      </div>
      {/* B14 (2026-04-29): Sub-Header 'Die Letzten werden die Ersten' komplett
          entfernt — User-Wunsch: 'doppelt im Intro, beides Mal raus'. */}

      {/* Step 0: COMEBACK + 'So funktioniert's' direkt darunter.
          2026-05-06 v2 (Wolf 'so funktionierts unter COMEBACK schreiben,
          dann nur noch Teams+Leader-Seite — separate H/L-Erklaer-Seite weg'):
          H/L-Mechanik-Card unter den Lightning-Title gezogen, alte 'Letzter
          Platz bekommt Boost'-Card entfernt. Step 2 (separate Erklaerseite)
          entfaellt. */}
      {step === 0 && hl && (
        <div key="intro0-hl" style={{
          width: '100%', maxWidth: 1100,
          animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.4s both',
          position: 'relative', zIndex: 5,
          display: 'flex', flexDirection: 'column', alignItems: 'center',
          gap: 'clamp(10px, 1.4vh, 18px)',
        }}>
          <div style={{
            display: 'inline-flex', alignItems: 'center', gap: 10,
            padding: '6px 18px', borderRadius: 999,
            background: 'rgba(236,72,153,0.18)', border: '2px solid rgba(236,72,153,0.5)',
            fontSize: 'clamp(13px, 1.4vw, 18px)', fontWeight: 900,
            color: '#fde68a', letterSpacing: '0.1em', textTransform: 'uppercase',
          }}>
            <QQEmojiIcon emoji="📖"/> {lang === 'en' ? 'How it works' : 'So funktioniert’s'}
          </div>
          <div style={{
            padding: 'clamp(20px, 2.6vh, 32px) clamp(28px, 3.2vw, 44px)', borderRadius: 20,
            // 2026-05-07 (Wolf 'Comeback-Step-0 translucent in ESC'): Pink-
            // Gradient mit ~68 % Opacity damit das ESC-Heart-BG durchscheint.
            // Normaler Mode behaelt den warmen Gold-Glass-Look.
            background: s.theme?.eurovisionMode
              ? 'linear-gradient(135deg, rgba(45,22,68,0.72), rgba(31,15,61,0.62))'
              : 'linear-gradient(135deg, rgba(236,72,153,0.10), rgba(236,72,153,0.03))',
            border: s.theme?.eurovisionMode
              ? '2px solid rgba(255,45,123,0.55)'
              : '2px solid rgba(236,72,153,0.4)',
            boxShadow: s.theme?.eurovisionMode
              ? '0 0 32px rgba(255,45,123,0.22), 0 6px 18px rgba(0,0,0,0.4)'
              : '0 0 32px rgba(236,72,153,0.18), 0 6px 18px rgba(0,0,0,0.4)',
            textAlign: 'center',
            // 2026-05-07 (Layout-Audit): 900 → 1100, sonst sitzt die Mechanik-Card
            // schmaler als der COMEBACK-Title darüber → wirkt zentriert-zu-eng.
            maxWidth: 1100,
            display: 'flex', flexDirection: 'column', gap: 'clamp(10px, 1.4vh, 16px)',
          }}>
            <div style={{
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              gap: 'clamp(20px, 2.4vw, 36px)',
              fontSize: 'clamp(28px, 3.6vw, 52px)', fontWeight: 900,
            }}>
              <span style={{ color: '#22C55E', display: 'inline-flex', alignItems: 'center', gap: 6 }}>
                <span>↑</span><span>{lang === 'en' ? 'HIGHER' : 'MEHR'}</span>
              </span>
              <span style={{ color: '#94a3b8', fontWeight: 700, fontSize: '0.6em' }}>
                {lang === 'en' ? 'or' : 'oder'}
              </span>
              <span style={{ color: '#EF4444', display: 'inline-flex', alignItems: 'center', gap: 6 }}>
                <span>↓</span><span>{lang === 'en' ? 'LOWER' : 'WENIGER'}</span>
              </span>
            </div>
            <div style={{
              fontSize: 'clamp(18px, 2.1vw, 28px)', fontWeight: 800,
              color: '#fef3c7', lineHeight: 1.5,
            }}>
              {lang === 'en'
                ? 'Tip: Does the unknown number lie above or below the shown one?'
                : 'Tippt: Liegt die unbekannte Zahl über oder unter der gezeigten?'}
            </div>
            <div style={{
              fontSize: 'clamp(15px, 1.6vw, 22px)', fontWeight: 700,
              color: '#cbd5e1', opacity: 0.85, lineHeight: 1.5,
            }}>
              {lang === 'en'
                ? 'Up to 3 rounds — each correct answer steals 1 cell from the leader.'
                : 'Bis zu 3 Runden — jede richtige Antwort klaut 1 Feld vom Führenden.'}
            </div>
          </div>
        </div>
      )}
      {/* Legacy-Comeback (kein H/L) faellt zurueck auf alte Boost-Card */}
      {step === 0 && !hl && (
        <div key="intro0-legacy" style={{
          maxWidth: 1100, textAlign: 'center',
          padding: '36px 48px', borderRadius: 24,
          background: 'rgba(236,72,153,0.08)',
          border: '2px solid rgba(236,72,153,0.35)',
          boxShadow: '0 0 60px rgba(236,72,153,0.15), 0 8px 32px rgba(0,0,0,0.4)',
          animation: 'contentReveal 0.5s var(--qq-ease-pop-fast) 0.4s both',
          position: 'relative', zIndex: 5,
        }}>
          <div style={{ fontSize: 'clamp(22px, 2.6vw, 34px)', lineHeight: 1.45, color: '#fde68a', fontWeight: 900, marginBottom: 18 }}>
            {lang === 'en'
              ? 'Last place gets a Comeback-Boost.'
              : 'Letzter Platz bekommt einen Comeback-Boost.'}
          </div>
          <div style={{ fontSize: 'clamp(18px, 2vw, 26px)', color: '#fef3c7', opacity: 0.85, lineHeight: 1.5 }}>
            {lang === 'en'
              ? 'Steal cells from the leader.'
              : 'Klauen beim Führenden.'}
          </div>
        </div>
      )}

      {/* Step 1+: Team hero — bei H/L mit Tied-Last mehrere Teams zeigen,
          sonst Fallback auf Einzel-Team (Legacy-Comeback). */}
      {showTeam && (hl ? hlTeams.length > 0 : !!team) && (
        <div key="team" style={{
          display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 22,
          // 2026-05-08 (Wolf-Audit #4): vorher contentReveal (nur Y-Fade) —
          // wirkte statisch in Comeback (Game-Climax). Jetzt qqStepSlideIn
          // (Slide-from-Left) → Step-Wechsel wird sequentiell.
          animation: 'qqStepSlideIn 0.6s cubic-bezier(0.16, 1, 0.3, 1) both',
          position: 'relative', zIndex: 5,
        }}>
          {hl && hlTeams.length > 1 ? (
            <>
              <div style={{ display: 'flex', gap: 'clamp(24px, 3vw, 44px)', flexWrap: 'wrap', justifyContent: 'center' }}>
                {hlTeams.map(tm => (
                  <div key={tm.id} style={{
                    display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 14,
                  }}>
                    {/* 2026-05-07 (Wolf): Multi-Team Avatare clamp(120-180) -> clamp(170-260). */}
                    <QQTeamAvatar avatarId={tm.avatarId} teamEmoji={tm.emoji} size={'clamp(170px, 16vw, 260px)'} style={{
                      boxShadow: `0 0 44px ${tm.color}88, 0 0 100px ${tm.color}33`,
                    }} />
                    <TeamNameLabel
                      name={tm.name}
                      maxLines={2}
                      shrinkAfter={18}
                      color={tm.color}
                      fontWeight={900}
                      fontSize="clamp(30px, 3.2vw, 48px)"
                      style={{ textShadow: `0 0 26px ${tm.color}55`, maxWidth: 320 }}
                    />
                  </div>
                ))}
              </div>
              {/* Wolf 2026-05-05: 'X teams tied for last place'-Pille raus —
                  redundant zum COMEBACK-Title + den Avataren selbst. */}
            </>
          ) : team && (
            <>
              {/* 2026-05-07 (Wolf 'ansicht zu klein, viel platz aussenrum'):
                  Single-Team Avatar clamp(110-170) -> clamp(180-280). Aus
                  Zuschauer-Distanz dominant lesbar statt klein in der Mitte. */}
              <QQTeamAvatar avatarId={team.avatarId} teamEmoji={team.emoji} size={'clamp(180px, 17vw, 280px)'} style={{
                boxShadow: `0 0 56px ${teamColor}88, 0 0 130px ${teamColor}33`,
                animation: 'activeTeamGlow 2s ease-in-out infinite',
                ['--team-color' as any]: `${teamColor}55`,
              }} />
              <TeamNameLabel
                name={team.name}
                maxLines={2}
                shrinkAfter={18}
                color={teamColor}
                fontWeight={900}
                fontSize="clamp(40px, 4.8vw, 76px)"
                style={{ textShadow: `0 0 36px ${teamColor}55`, maxWidth: '80vw', textAlign: 'center' }}
              />
              {/* Wolf 2026-05-05: 'liegt auf dem letzten Platz — schlag zurück!'
                  Pille raus — redundant zum COMEBACK-Title + Lightning-Bolts. */}
            </>
          )}
        </div>
      )}

      {/* Step 2: Aktion (H/L-Regeln + Leader-Anzeige) */}
      {showAction && (hl ? hlTeams.length > 0 : !!team) && (
        <div style={{
          width: '100%', maxWidth: 1100,
          // 2026-05-08 (Wolf-Audit #4): qqStepSlideIn statt contentReveal —
          // Action-Card slidet von links rein (Drama-Climax-Moment).
          animation: 'qqStepSlideIn 0.6s cubic-bezier(0.16, 1, 0.3, 1) 0.15s both',
          position: 'relative', zIndex: 5,
          display: 'flex', flexDirection: 'column', alignItems: 'center',
          gap: 'clamp(8px, 1.2vh, 14px)',
        }}>
          {/* Wolf 2026-05-05: Round-Counter komplett raus — Wolf moderiert,
              weiß welche Runde. Auch der "DURCHGANG"-Header + Dots war zu
              viel auf der ohnehin vollen Intro-Seite. */}
          {/* Action-Card mit inline Leader (Wolf 2026-05-05: war vorher
              separater "AKTUELLER 1. PLATZ"-Header + Pille darunter — jetzt
              direkt in einer Zeile, spart 2 Items auf der Seite). */}
          <div style={{
            // 2026-05-07 (Wolf 'comeback ansicht zu klein'): Action-Card-Padding
            // + Font + Pille-Groesse signifikant gebumpt. Pille mit kleinem
            // Avatar (28px) und Mini-Label (12-16px) war aus Beamer-Distanz
            // unleserlich.
            padding: 'clamp(18px, 2.2vh, 28px) clamp(28px, 3.2vw, 48px)', borderRadius: 22,
            textAlign: 'center',
            background: cardBg,
            border: hl ? '2.5px solid rgba(236,72,153,0.55)' : `2.5px solid #EF444455`,
            boxShadow: hl
              ? '0 0 44px rgba(236,72,153,0.25), 0 8px 22px rgba(0,0,0,0.4)'
              : `0 0 44px rgba(239,68,68,0.22), 0 8px 22px rgba(0,0,0,0.4)`,
            fontSize: 'clamp(22px, 2.6vw, 36px)', fontWeight: 900,
            color: hl ? '#fde68a' : '#fecaca',
            maxWidth: 1000,
            lineHeight: 1.4,
            display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 14,
          }}>
            {/* 2026-05-06: H/L-Mechanik-Text raus, nur Klau-Ziel anzeigen.
                Erklaerung der Mechanik kommt in Step 2 als eigene Card. */}
            {!hl && (
              <div>
                <QQEmojiIcon emoji="⚡"/> {lang === 'en' ? actionTextEn : actionTextDe}
              </div>
            )}
            {leaderTeams.length > 0 && (
              <div style={{
                display: 'flex', alignItems: 'center', gap: 14, flexWrap: 'wrap',
                justifyContent: 'center',
              }}>
                <span style={{
                  fontSize: 'clamp(18px, 1.9vw, 26px)', fontWeight: 900,
                  color: '#94a3b8', letterSpacing: '0.08em', textTransform: 'uppercase',
                }}>
                  {leaderTeams.length === 1
                    ? (lang === 'en' ? 'Leader:' : 'Klauen bei:')
                    : (lang === 'en' ? 'Leaders:' : 'Klauen bei:')}
                </span>
                {leaderTeams.map(lt => (
                  <div key={lt.id} style={{
                    display: 'inline-flex', alignItems: 'center', gap: 12,
                    padding: '10px 20px', borderRadius: 999,
                    background: `${lt.color}18`, border: `2px solid ${lt.color}55`,
                  }}>
                    <QQTeamAvatar avatarId={lt.avatarId} teamEmoji={lt.emoji} size={48} />
                    <TeamNameLabel
                      name={lt.name}
                      maxLines={1}
                      shrinkAfter={14}
                      color={lt.color}
                      fontWeight={900}
                      fontSize="clamp(20px, 2.2vw, 30px)"
                      style={{ maxWidth: 220 }}
                    />
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      {/* 2026-05-06 v2: Separate Step-2-Erklaerseite entfernt — die H/L-
          Erklaerung steht jetzt zusammen mit dem COMEBACK-Title auf Step 0. */}

      {/* 2026-05-06 v4 (Wolf 'bei Comeback ueberrascht ist gut'): Wolf
          mit Oh!-Pose unten links waehrend BAM-Step 0. Verstaerkt den
          Drama-Moment 'Wer kommt zurueck?'. Step 1 (Team-Hero) ist eh
          fokussiert auf das Comeback-Team — Wolf koennte da ablenken.
          2026-05-06 v6 (Wolf 'wenn er den Mund offen hat, soll er was
          sagen — auch auf Comeback'): Sprechblase mit Surprise-Slogans. */}
      {step === 0 && (
        <div style={{
          position: 'absolute',
          left: 'clamp(20px, 2.5vw, 48px)',
          bottom: 'clamp(20px, 2.5vh, 40px)',
          zIndex: 8,
          pointerEvents: 'none',
          animation: 'panelSlideIn 0.6s var(--qq-ease-bounce) 0.85s both',
        }}>
          <WolfUeberraschtWithBubble lang={lang === 'de' ? 'de' : 'en'} eurovisionMode={s.theme?.eurovisionMode} />
        </div>
      )}
    </div>
  );
}

// Ueberrascht-Wolf mit Sprechblase fuer ComebackView Step 0. Bubble-Tail
// links unten (Wolf links unten), Surprise-Slogans. Mund bleibt im
// ueberrascht-Mode konstant offen (kein Flap), deshalb keine
// speaking-Gate — die Bubble ist rein 'Beifall-Reaktion' auf den
// Comeback-Drama-Moment.
function WolfUeberraschtWithBubble({ lang, eurovisionMode }: { lang: 'de' | 'en'; eurovisionMode?: boolean }) {
  // 2026-05-07 v8 (Wolf 'gib dem wolf eurovision sprueche'): ESC-Drama-Pool
  // mit Französisch/Englisch-Mix wie auf der ESC-Buehne. 'Quel choc!' /
  // 'Mon dieu!' bringen den Watchparty-Vibe, beim Comeback-Surprise-Moment.
  const slogans: Slogan[] = eurovisionMode
    ? (lang === 'de'
        ? [
            { text: 'Quel choc!', mouths: 2 },
            { text: 'Mon dieu!', mouths: 2 },
            { text: 'Sensationell!', mouths: 3 },
            { text: 'Ein Comeback!', mouths: 3 },
            { text: 'Magnifique!', mouths: 3 },
          ]
        : [
            { text: 'Quel choc!', mouths: 2 },
            { text: 'Mon dieu!', mouths: 2 },
            { text: 'Sensational!', mouths: 3 },
            { text: 'A comeback!', mouths: 3 },
            { text: 'Magnifique!', mouths: 3 },
          ])
    : (lang === 'de'
        ? [
            { text: 'Was?!', mouths: 1 },
            { text: 'Krass!', mouths: 1 },
            { text: 'Ohhh!', mouths: 1 },
            { text: 'Echt jetzt?', mouths: 3 },
            { text: 'Holla!', mouths: 2 },
          ]
        : [
            { text: 'What?!', mouths: 1 },
            { text: 'Whoa!', mouths: 1 },
            { text: 'No way!', mouths: 2 },
            { text: 'Really?', mouths: 2 },
            { text: 'Wild!', mouths: 1 },
          ]);
  const [idx, setIdx] = useState(0);
  // 2026-05-07 v14 (Bug-Fix): safe index — siehe WolfLobbyGreeter.
  const slogan = slogans[idx % Math.max(1, slogans.length)] ?? slogans[0] ?? { text: '', mouths: 2 };
  const speakMs = Math.min(3000, Math.max(1100, slogan.mouths * 500));
  const enterMs = 200;
  const exitMs = 400;
  const gapMs = 500;
  const totalMs = enterMs + speakMs + exitMs + gapMs;
  useEffect(() => {
    const id = window.setTimeout(() => {
      setIdx(p => (p + 1) % slogans.length);
    }, totalMs);
    return () => window.clearTimeout(id);
  }, [idx, totalMs, slogans.length]);
  return (
    <div style={{
      display: 'flex', flexDirection: 'column', alignItems: 'flex-start',
      gap: 14, pointerEvents: 'none',
    }}>
      <SpeechBubble
        text={slogan.text}
        bubbleKey={idx}
        enterMs={enterMs}
        speakMs={speakMs}
        exitMs={exitMs}
        eurovisionMode={eurovisionMode}
      />
      <AnimatedCozyWolf widthCss="clamp(120px, 12vw, 180px)" mode="ueberrascht" />
    </div>
  );
}

